public static void main(String[] args) {
    InputReader sc = new InputReader(System.in);
    int n = sc.ni();
    int r = sc.ni();
    int[] arr = sc.nia(n);

    int ans = countOnes(arr);
    int[] h = new int[n];
    buildCoverage(arr, r, h);

    if (!allCovered(h)) {
        w.println(-1);
    } else {
        ans = reduceAnswer(arr, r, h, ans);
        w.println(ans);
    }
    w.close();
}

/* ---------- helper methods ---------- */

private static int countOnes(int[] arr) {
    int cnt = 0;
    for (int v : arr) {
        if (v == 1) cnt++;
    }
    return cnt;
}

private static void buildCoverage(int[] arr, int r, int[] coverage) {
    int n = arr.length;
    for (int i = 0; i < n; i++) {
        if (arr[i] == 1) {
            int left = Math.max(0, i - r + 1);
            int right = Math.min(n - 1, i + r - 1);
            for (int j = left; j <= right; j++) {
                coverage[j]++;
            }
        }
    }
}

private static boolean allCovered(int[] coverage) {
    for (int v : coverage) {
        if (v == 0) return false;
    }
    return true;
}

private static int reduceAnswer(int[] arr, int r, int[] coverage, int currentAns) {
    int n = arr.length;
    for (int i = 0; i < n; i++) {
        if (arr[i] != 1) continue;

        int left = Math.max(0, i - r + 1);
        int right = Math.min(n - 1, i + r - 1);

        if (!hasUniqueCoverage(coverage, left, right)) {
            decrementCoverage(coverage, left, right);
            currentAns--;
        } else {
            addExtraCoverage(coverage, left, right);
        }
    }
    return currentAns;
}

/* ----- small utilities used by reduceAnswer ----- */

private static boolean hasUniqueCoverage(int[] coverage, int left, int right) {
    for (int j = left; j <= right; j++) {
        if (coverage[j] == 1) {
            return true;
        }
    }
    return false;
}

private static void decrementCoverage(int[] coverage, int left, int right) {
    for (int j = left; j <= right; j++) {
        coverage[j]--;
    }
}

private static void addExtraCoverage(int[] coverage, int left, int right) {
    for (int j = left; j <= right; j++) {
        coverage[j] += 4;
    }
}

public static void main(String[] args) {
    InputReader sc = new InputReader(System.in);
    int n = sc.ni();
    int r = sc.ni();
    int[] arr = sc.nia(n);

    int ans = countLamps(arr);
    int[] h = new int[n];

    // first pass – mark coverage of every lamp
    addCoverageForAllLamps(arr, r, h);

    if (hasUncoveredPosition(h)) {
        w.println(-1);
        w.close();
        return;
    }

    // second pass – try to remove redundant lamps
    for (int i = 0; i < n; i++) {
        if (arr[i] != 1) continue;

        if (isLampRedundant(i, r, h)) {
            removeLamp(i, r, h);
            ans--;
        } else {
            boostCoverage(i, r, h);
        }
    }

    w.println(ans);
    w.close();
}

/* ---------- extracted helper methods ---------- */

private static int countLamps(int[] arr) {
    int cnt = 0;
    for (int v : arr) {
        if (v == 1) cnt++;
    }
    return cnt;
}

/**
 * Increments h[j] for every position j that lies within distance r‑1
 * of a lamp (arr[i] == 1).
 */
private static void addCoverageForAllLamps(int[] arr, int r, int[] h) {
    int n = arr.length;
    for (int i = 0; i < n; i++) {
        if (arr[i] != 1) continue;
        int left = Math.max(0, i - r + 1);
        int right = Math.min(n - 1, i + r - 1);
        for (int j = left; j <= right; j++) {
            h[j]++;
        }
    }
}

/** Returns true if at least one position is not covered at all. */
private static boolean hasUncoveredPosition(int[] h) {
    for (int v : h) {
        if (v == 0) return true;
    }
    return false;
}

/**
 * A lamp is redundant when every position it covers currently has
 * exactly one covering lamp (i.e., h[j] == 1 for all j in its range).
 */
private static boolean isLampRedundant(int i, int r, int[] h) {
    int n = h.length;
    int left = Math.max(0, i - r + 1);
    int right = Math.min(n - 1, i + r - 1);
    for (int j = left; j <= right; j++) {
        if (h[j] != 1) {
            return false;
        }
    }
    return true;
}

/** Decrements the coverage counters for the range of lamp i. */
private static void removeLamp(int i, int r, int[] h) {
    int n = h.length;
    int left = Math.max(0, i - r + 1);
    int right = Math.min(n - 1, i + r - 1);
    for (int j = left; j <= right; j++) {
        h[j]--;
    }
}

/**
 * When a lamp cannot be removed, we artificially increase the coverage
 * of its range by 4 (mirrors the original logic).
 */
private static void boostCoverage(int i, int r, int[] h) {
    int n = h.length;
    int left = Math.max(0, i - r + 1);
    int right = Math.min(n - 1, i + r - 1);
    for (int j = left; j <= right; j++) {
        h[j] += 4;
    }
}

