 * @param lengthB length of the second string
 */
private static void processCommonDivisors(int lengthA, int lengthB) {
    int max = Math.max(lengthA, lengthB);
    for (int i = 1; i <= max; i++) {
        if (lengthA % i == 0 && lengthB % i == 0) {
            check(i);
        }
    }
