public static void main(String[] args) {
    FastScanner scanner = new FastScanner();
    PrintWriter out = new PrintWriter(System.out);
    int T = scanner.nextInt();
    while (T-- > 0) {
        runSingleTest(scanner, out);
    }
    out.flush();
}

/** Executes one test case: reads data, computes the assignment and prints the result. */
private static void runSingleTest(FastScanner scanner, PrintWriter out) {
    int N = scanner.nextInt();
    PriorityQueue<Point> queue = buildQueue(N, scanner);
    AssignmentResult result = assignNumbers(queue, N);
    printResult(out, result);
}

/** Builds the priority queue containing start‑ and end‑points of all intervals. */
private static PriorityQueue<Point> buildQueue(int n, FastScanner scanner) {
    PriorityQueue<Point> queue = new PriorityQueue<>();
    for (int i = 0; i < n; i++) {
        queue.offer(new Point(scanner.nextInt(), true, i));   // start point
        queue.offer(new Point(scanner.nextInt(), false, i)); // end point
    }
    return queue;
}

/** Core algorithm – walks through the sorted points and assigns 1 or 2. */
private static AssignmentResult assignNumbers(PriorityQueue<Point> queue, int n) {
    int cur = 0;          // number of currently open intervals
    int assign = 1;       // 1 = only one segment used, 2 = at least two needed
    int[] outArr = new int[n];

    while (!queue.isEmpty()) {
        Point next = queue.poll();
        if (next.start) {
            cur++;
            outArr[next.num] = assign;
        } else {
            cur--;
        }
        if (cur == 0 && !queue.isEmpty()) {
            assign = 2;
        }
    }
    return new AssignmentResult(outArr, assign);
}

/** Prints the answer for a single test case. */
private static void printResult(PrintWriter out, AssignmentResult result) {
    if (result.assign == 1) {
        out.println(-1);
        return;
    }
    for (int i = 0; i < result.assignments.length; i++) {
        if (i > 0) out.print(' ');
        out.print(result.assignments[i]);
    }
    out.println();
}

/** Simple holder for the algorithm result. */
private static class AssignmentResult {
    final int[] assignments;
    final int assign;

    AssignmentResult(int[] assignments, int assign) {
        this.assignments = assignments;
        this.assign = assign;
    }
}

public static void main(String[] args) {
    FastScanner scanner = new FastScanner();
    PrintWriter out = new PrintWriter(System.out);
    int T = scanner.nextInt();
    while (T-- > 0) {
        int N = scanner.nextInt();

        PriorityQueue<Point> queue = buildQueue(scanner, N);
        int[] assignments = assignSegments(queue, N);
        printResult(out, assignments);
    }
    out.flush();
}

/**
 * Builds the priority queue containing start and end points for N intervals.
 */
private static PriorityQueue<Point> buildQueue(FastScanner scanner, int n) {
    PriorityQueue<Point> q = new PriorityQueue<>();
    for (int i = 0; i < n; i++) {
        q.offer(new Point(scanner.nextInt(), true, i));   // start point
        q.offer(new Point(scanner.nextInt(), false, i));  // end point
    }
    return q;
}

/**
 * Executes the sweep‑line algorithm.
 * Returns an array of size n where each entry is 1 or 2,
 * or an array containing a single element -1 if assignment is impossible.
 */
private static int[] assignSegments(PriorityQueue<Point> queue, int n) {
    int cur = 0;
    int assign = 1;
    int[] outArr = new int[n];

    while (!queue.isEmpty()) {
        Point next = queue.poll();
        if (next.start) {
            cur++;
            outArr[next.num] = assign;
        } else {
            cur--;
        }
        if (cur == 0 && !queue.isEmpty()) {
            assign = 2;
        }
    }

    // If assign never changed, the whole set belongs to a single group → impossible.
    if (assign == 1) {
        return new int[] { -1 };
    }
    return outArr;
}

/**
 * Prints the result for a single test case.
 * If the first element is -1, prints -1; otherwise prints the assignment list.
 */
private static void printResult(PrintWriter out, int[] assignments) {
    if (assignments.length == 1 && assignments[0] == -1) {
        out.println(-1);
        return;
    }
    for (int i = 0; i < assignments.length; i++) {
        if (i > 0) out.print(' ');
        out.print(assignments[i]);
    }
    out.println();
}

