    for (int aa = arr.length - 1; aa > 0; aa--) {
        if (arr[rightz] == 0) {
            continue;
        }
        rightz = aa;
    }
    return rightz;
}

/** Forward pass: fills `dist` counting distance from the most recent zero. */
private static void computeForwardDistances(int[] arr, int[] dist, int leftz) {
    int count = 0;
    for (int a = leftz; a < arr.length; a++) {
        if (arr[a] == 0) {
            dist[a] = 0;
            count = 1;
        } else {
            dist[a] = count;
            count++;
        }
    }
}

/** Backward pass: refines `dist` by taking the minimum distance from the right side. */
private static void computeBackwardDistances(int[] arr, int[] dist, int rightz) {
    int count = 0;
    for (int b = arr.length - 1; b >= 0; b--) {
        if (arr[b] == 0) {
            dist[b] = 0;
            count = 1;
        } else {
            dist[b] = Math.min(dist[b], count);
            if (dist[b] == count) {
                count++;
            }
        }
    }
}

