private static long computeResult(long n, long m) {
    // special case when the board is 1x1
    if (n == 1 && m == 1) {
        return 1;
    }

    if (isEven(n)) {
        // n is even: the middle split is exactly n/2
        return (m <= n / 2) ? m + 1 : m - 1;
    } else {
        // n is odd: the middle split is (n+1)/2
        return (m < (n + 1) / 2) ? m + 1 : m - 1;
    }
}

private static boolean isEven(long value) {
    return value % 2 == 0;
}

