/**
 * Simple vertical distance when both points lie on the same column.
 */
private static int distanceOnSameColumn(int y1, int y2) {
    return Math.abs(y1 - y2);
}

/**
 * Clamps the given y‑coordinate to the interval [a, b] and returns the
 * movement cost required to perform the clamp. The corrected value is
 * written back to {@code corrected[0]}.
 */
private static int clampAndCost(int y, int a, int b, int[] corrected) {
    if (y > b) {
        corrected[0] = b;
        return y - b;
    }
    if (y < a) {
        corrected[0] = a;
        return a - y;
    }
    corrected[0] = y;
    return 0;
}

/**
 * Computes the total number of steps required to travel from the start
 * point (x1, y1) to the end point (x2, y2) while staying within the allowed
 * vertical range [a, b]. The algorithm mirrors the original nested logic.
 */
private static int computePathCost(int[] query, int a, int b) {
    // query layout: [x1, y1, x2, y2]
    int horizontal = Math.abs(query[0] - query[2]);

    int[] startY = new int[1];
    int startCost = clampAndCost(query[1], a, b, startY);

    int[] endY = new int[1];
    int endCost = clampAndCost(query[3], a, b, endY);

    int vertical = Math.abs(startY[0] - endY[0]);

    return horizontal + startCost + endCost + vertical;
}

