    int[][] qs = in.nextIntMatrix(k, 4);

    for (int i = 0; i < k; i++) {
        int[] q = qs[i];
        int result = calculatePathLength(q[0], q[1], q[2], q[3], a, b);
        out.println(result);
    }

    out.close();
}

/**
 * Computes the distance a traveller must walk from (x1,y1) to (x2,y2)
 * while staying inside the vertical interval [a, b].
 *
 * If the two points are on the same vertical line, the answer is the
 * pure vertical distance. Otherwise we:
 *   1. Add the horizontal distance |x1‑x2|.
 *   2. Clamp each y‑coordinate to the interval, adding the distance
 *      required to reach the nearest bound.
 *   3. Add the vertical distance between the clamped y‑coordinates.
 *
 * The method mirrors the original algorithm exactly.
 */
private static int calculatePathLength(int x1, int y1, int x2, int y2, int a, int b) {
    if (x1 == x2) {
        return Math.abs(y1 - y2);
    }

    int distance = Math.abs(x1 - x2);

    // Clamp y1 to the allowed interval and account for extra travel
    if (y1 > b) {
        distance += y1 - b;
        y1 = b;
    } else if (y1 < a) {
        distance += a - y1;
        y1 = a;
    }

    // Clamp y2 to the allowed interval and account for extra travel
    if (y2 > b) {
        distance += y2 - b;
        y2 = b;
    } else if (y2 < a) {
        distance += a - y2;
        y2 = a;
    }

    // Final vertical segment after both y‑coordinates are within bounds
    distance += Math.abs(y1 - y2);
    return distance;
}

