    int[] sticks = in.nextIntArray(n);
    int[] cnt = new int[MAX];
    for (int l : sticks) {
        cnt[l]++;
    }

    long[] prev = new long[]{-1};
    long[] res = new long[]{0};

    for (int l = MAX - 2; l >= 1; l--) {
        if (cnt[l + 1] == 1) {
            if (handleSingleNext(l, cnt, prev, res)) {
                l++;                // neutralises the for‑loop's l--, keep same index
            }
        } else {
            if (handlePairSameLength(l, cnt, prev, res)) {
                l++;
            }
        }
    }
    System.out.println(res[0]);
