/**
 * Handles the situation where there is exactly one stick of length l+1.
 * Tries to pair it with a stick of length l.
 *
 * @return true if the caller should execute l++ (a pair was formed)
 */
private boolean handleSingleNext(int l, int[] cnt, long[] prev, long[] res) {
    // cnt[l+1] is known to be 1
    cnt[l + 1]--;
    if (cnt[l] > 0) {
        cnt[l]--;
        if (prev[0] != -1) {
            res[0] += prev[0] * l;
            prev[0] = -1;
        } else {
            prev[0] = l;
        }
        return true;
    }
    return false;
}

/**
 * Handles the situation where there are at least two sticks of the current length.
 *
 * @return true if the caller should execute l++ (a pair was formed)
 */
private boolean handlePairSameLength(int l, int[] cnt, long[] prev, long[] res) {
    if (cnt[l] >= 2) {
        cnt[l] -= 2;
        if (prev[0] != -1) {
            res[0] += prev[0] * l;
            prev[0] = -1;
        } else {
            prev[0] = l;
        }
        return true;
    }
    return false;
}

private static final int MAX = 100001; // keep the original constant
private long prev = -1;
private long res = 0;
private int[] cnt;

/**
 * Main entry – unchanged behaviour, but the inner logic is now delegated.
 */
public void run() {
    int n = in.nextInt();
