    cnt = new int[MAX];
    for (int l : sticks) {
        cnt[l]++;
    }

    for (int l = MAX - 2; l >= 1; l--) {
        if (processLength(l)) {
            // original code performed l++ after a successful pairing,
            // which cancels the loop’s upcoming l-- and keeps the same length.
            l++;
        }
    }
    System.out.println(res);
    out.close();
}

/**
 * Tries to form a rectangle side using sticks of length {@code l}.
 *
 * @return {@code true} if a pair was consumed and the loop should stay on the
 *         same length for the next iteration; {@code false} otherwise.
 */
private boolean processLength(int l) {
    // case 1: there is exactly one stick of length l+1 that can be paired
    // with a stick of length l
    if (cnt[l + 1] == 1) {
        cnt[l + 1]--;
        if (cnt[l] > 0) {
            cnt[l]--;
            updateResultOrPrev(l);
            return true;
        }
    } else {
        // case 2: at least two sticks of the same length l are available
        if (cnt[l] >= 2) {
            cnt[l] -= 2;
            updateResultOrPrev(l);
            return true;
        }
    }
    return false;
}

/**
 * Stores the current length as {@code prev} if none is pending, otherwise
 * combines it with the pending {@code prev} to contribute to the result.
 *
 * @param length the length just taken from the inventory
 */
private void updateResultOrPrev(int length) {
    if (prev != -1) {
        res += prev * length;
        prev = -1;
    } else {
        prev = length;
    }
}

