/**
 * Builds an int[] where each entry is:
 *   0 – draw, 1 – first player (s) wins, 2 – second player (p) wins
 */
private static int[] buildPeriodOutcomeArray(String s, String p, int lcm) {
    int l1 = s.length();
    int l2 = p.length();
    int[] outcome = new int[lcm];
    for (int i = 0; i < lcm; i++) {
        char ch1 = s.charAt(i % l1);
        char ch2 = p.charAt(i % l2);
        outcome[i] = roundOutcome(ch1, ch2);
    }
    return outcome;
}

/**
 * Counts how many times each player wins inside the given period array.
 * Returns an int[2] → [wins of first player, wins of second player].
 */
private static int[] countWinsInPeriod(int[] period) {
    int firstWins = 0, secondWins = 0;
    for (int win : period) {
        if (win == 1) {
            firstWins++;
        } else if (win == 2) {
            secondWins++;
        }
    }
    return new int[]{firstWins, secondWins};
}

/**
 * Determines the outcome of a single round.
 * Returns 0 for draw, 1 if first player wins, 2 if second player wins.
 */
private static int roundOutcome(char a, char b) {
    if (a == 'R') {
        if (b == 'P') return 2;
        if (b == 'S') return 1;
        return 0;               // b == 'R'
    } else if (a == 'P') {
        if (b == 'S') return 2;
        if (b == 'R') return 1;
        return 0;               // b == 'P'
    } else { // a == 'S'
        if (b == 'R') return 2;
        if (b == 'P') return 1;
        return 0;               // b == 'S'
    }
}

public void solve(int testNumber, Scanner in, PrintWriter out) {
    int n = in.nextInt();
    String s = in.next(), p = in.next();
    int l1 = s.length();
    int l2 = p.length();

    int gcd = (int) IntegerUtils.gcd(l1, l2);
    int lcm = (l1 * l2) / gcd;

    int fullCycles = n / lcm;
    int remainder   = n % lcm;

    int[] roundResult = new int[lcm];
    int player1Wins = 0, player2Wins = 0;

    // evaluate one full LCM cycle
    for (int i = 0; i < lcm; i++) {
        char ch1 = s.charAt(i % l1);
        char ch2 = p.charAt(i % l2);
        int win = determineRoundResult(ch1, ch2);
        roundResult[i] = win;

        if (win == 1) {
            player1Wins++;
        } else if (win == 2) {
            player2Wins++;
        }
    }

    // scale by the number of complete cycles
    player1Wins *= fullCycles;
    player2Wins *= fullCycles;

    // handle the remaining rounds
    for (int i = 0; i < remainder; i++) {
        int win = roundResult[i];
        if (win == 1) {
            player1Wins++;
        } else if (win == 2) {
            player2Wins++;
        }
    }

    out.println(player2Wins + " " + player1Wins);
}

/**
 * Returns the outcome of a single round:
 *   0 – draw
 *   1 – first player (s) wins
 *   2 – second player (p) wins
 */
private int determineRoundResult(char a, char b) {
    // a = move of player 1, b = move of player 2
    if (a == 'R') {
        if (b == 'P') return 2;
        if (b == 'S') return 1;
        return 0; // b == 'R'
    } else if (a == 'P') {
        if (b == 'S') return 2;
        if (b == 'R') return 1;
        return 0; // b == 'P'
    } else { // a == 'S'
        if (b == 'R') return 2;
        if (b == 'P') return 1;
        return 0; // b == 'S'
    }
}

