/* ---------- Linear (non‑ternary) path ---------- */
private long evaluateLinear(long x) {
    clampCurrentIndex();
    advanceUntilBest(x);
    return valueAt(curIt, x);
}

/* Clamp curIt to the last valid index (A.size() - 1). */
private void clampCurrentIndex() {
    curIt = MaxMin.Min(curIt, A.size() - 1);
}

/* Move curIt forward while the next line gives a greater (or equal) value. */
private void advanceUntilBest(long x) {
    while (curIt < A.size() - 1 && 
           valueAt(curIt, x) <= valueAt(curIt + 1, x)) {
        curIt++;
    }
}

/* ---------- Ternary (search) path ---------- */
private long evaluateTernary(long x) {
    int[] bounds = ternarySearchBounds(x);
    int l = bounds[0];
    int r = bounds[1];
    long best = (long) -1e18;
    for (int i = l; i <= r; i++) {
        best = MaxMin.Max(best, valueAt(i, x));
    }
    return best;
}

/* Perform the ternary‑search loop and return the final [l, r] interval. */
private int[] ternarySearchBounds(long x) {
    int l = 0;
    int r = A.size();
    while (r - l > 2) {
        int mid1 = (l * 2 + r) / 3;
        int mid2 = (l + 2 * r) / 3;
        long val1 = valueAt(mid1, x);
        long val2 = valueAt(mid2, x);
        if (val1 == val2) {
            l = mid1;
            r = mid2;
        } else if (val1 < val2) {
            l = mid1;
        } else {
            r = mid2;
        }
    }
    return new int[]{l, r};
}

/* Compute A[i] * x + B[i] for a given index. */
private long valueAt(int i, long x) {
    return A.get(i) * x + B.get(i);
}

public long get(long x) {
    if (!needTenary) {
        return linearSearch(x);
    }
    return ternarySearch(x);
}

/*--- Helper for the linear‑scan branch -----------------------------------*/
private long linearSearch(long x) {
    // Ensure curIt is within valid range
    curIt = MaxMin.Min(curIt, A.size() - 1);

    // Move forward while the next line gives a better (larger) value
    while (curIt < A.size() - 1 && lineValue(curIt, x) <= lineValue(curIt + 1, x)) {
        curIt++;
    }
    return lineValue(curIt, x);
}

/*--- Helper for the ternary‑search branch ---------------------------------*/
private long ternarySearch(long x) {
    int l = 0;
    int r = A.size();               // exclusive upper bound as in original code

    // Narrow the interval until only a few candidates remain
    while (r - l > 2) {
        int mid1 = (l * 2 + r) / 3;
        int mid2 = (l + 2 * r) / 3;

        long val1 = lineValue(mid1, x);
        long val2 = lineValue(mid2, x);

        if (val1 == val2) {
            l = mid1;
            r = mid2;
        } else if (val1 < val2) {
            l = mid1;
        } else {
            r = mid2;
        }
    }

    // Final brute‑force check of the remaining indices
    long ret = (long) -1e18;
    for (int i = l; i <= r; i++) {
        ret = MaxMin.Max(ret, lineValue(i, x));
    }
    return ret;
}

/*--- Shared calculation ----------------------------------------------------*/
private long lineValue(int idx, long x) {
    return A.get(idx) * x + B.get(idx);
}

