/**
 * Reads a 9×9 Sudoku board from standard input.
 * Each line is consumed by rl() and parsed by nca().
 */
private static int[][] readBoard() throws IOException {
    int[][] a = new int[9][];
    for (int i = 0; i < 9; ++i) {
        a[i] = new int[9];
        rl();                     // move to the next line
        char[] chars = nca();     // characters of the current line
        for (int j = 0; j < 9; ++j) {
            a[i][j] = chars[j] - '0';
        }
    }
    return a;
}

/**
 * Performs the fixed increment pattern required by the problem:
 * (0,0), (1,3), (2,6), (3,1), (4,4), (5,7), (6,2), (7,5), (8,8)
 */
private static void incrementPattern(int[][] a) {
    a[0][0]++; a[1][3]++; a[2][6]++;
    a[3][1]++; a[4][4]++; a[5][7]++;
    a[6][2]++; a[7][5]++; a[8][8]++;
}

/**
 * Converts any cell that became 10 back to 1, as Sudoku digits are 1‑9.
 */
private static void normalizeValues(int[][] a) {
    for (int i = 0; i < 9; ++i) {
        for (int j = 0; j < 9; ++j) {
            if (a[i][j] == 10) {
                a[i][j] = 1;
            }
        }
    }
}

/**
 * Builds the textual representation of the board, one line per row.
 */
private static String buildOutput(int[][] a) {
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < 9; ++i) {
        for (int j = 0; j < 9; ++j) {
            sb.append(a[i][j]);
        }
        sb.append('\n');
    }
    return sb.toString();
}

