/** Reads an n×m matrix using the supplied Reader. */
private static int[][] readMatrix(Reader s, int n, int m) throws IOException {
    int[][] matrix = new int[n][m];
    for (int i = 0; i < n; i++) {
        int[] row = s.arr(m);
        System.arraycopy(row, 0, matrix[i], 0, m);
    }
    return matrix;
}

/**
 * For each cell verifies that the required number of neighbours
 * (the value stored in the cell) does not exceed the actual neighbour count.
 * If the check succeeds, the cell is overwritten with its neighbour count.
 * Returns {@code true} if every cell is valid; {@code false} otherwise.
 */
private static boolean validateAndFill(int[][] arr, int n, int m) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            int neighbourCount = 0;
            if (i > 0) neighbourCount++;          // up
            if (j > 0) neighbourCount++;          // left
            if (i < n - 1) neighbourCount++;      // down
            if (j < m - 1) neighbourCount++;      // right

            if (neighbourCount < arr[i][j]) {
                return false;                      // invalid cell
            }
            arr[i][j] = neighbourCount;            // store the actual count
        }
    }
    return true;
}

/** Prints “YES” and the matrix, or “NO” if the validation failed. */
private static void printResult(PrintWriter out, boolean ok, int[][] arr) {
    if (!ok) {
        out.println("NO");
        return;
    }

    out.println("YES");
    for (int[] row : arr) {
        for (int val : row) {
            out.print(val + " ");
        }
        out.println();
    }
}

