/** Reads an n×m matrix using the provided Reader. */
private static int[][] readMatrix(Reader s, int n, int m) throws IOException {
    int[][] arr = new int[n][m];
    for (int i = 0; i < n; i++) {
        int[] row = s.arr(m);
        System.arraycopy(row, 0, arr[i], 0, m);
    }
    return arr;
}

/** Checks each cell against the maximum number of orthogonal neighbours.
 *  If the original value fits, the cell is replaced with that maximum count.
 *  Returns false as soon as an invalid cell is found. */
private static boolean validateAndFill(int[][] arr) {
    int n = arr.length;
    int m = arr[0].length;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            int maxNeighbours = neighborCount(i, j, n, m);
            if (maxNeighbours < arr[i][j]) {
                return false;
            }
            arr[i][j] = maxNeighbours;
        }
    }
    return true;
}

/** Returns the number of orthogonal neighbours for the cell (i, j) in an n×m grid. */
private static int neighborCount(int i, int j, int n, int m) {
    int count = 0;
    if (i > 0)      count++;
    if (j > 0)      count++;
    if (i < n - 1)  count++;
    if (j < m - 1)  count++;
    return count;
}

/** Prints the matrix, one row per line, values separated by a space. */
private static void printMatrix(PrintWriter out, int[][] arr) {
    for (int[] row : arr) {
        for (int val : row) {
            out.print(val + " ");
        }
        out.println();
    }
}

