/**
 * Computes the number of segments that need to be turned on to change the current
 * pattern into each possible digit (0‑9). If a segment would have to be turned off,
 * the entry is set to -1 to mark the digit as impossible.
 */
private void fillPrecompForPosition(int at, char[] current) {
    for (int digit = 0; digit <= 9; digit++) {
        precomp[at][digit] = computeDifference(digit, current);
    }
}

/**
 * Returns the count of additional segments required to transform {@code current}
 * into the representation of {@code digit}. Returns -1 if the transformation is
 * impossible because it would require turning an ‘on’ segment off.
 */
private int computeDifference(int digit, char[] current) {
    int needed = 0;
    for (int pos = 0; pos < 7; pos++) {
        char cur = current[pos];
        char target = s[digit].charAt(pos);
        if (cur == '1' && target == '0') {
            return -1;               // impossible – would need to turn a segment off
        }
        if (cur == '0' && target == '1') {
            needed++;                // this segment must be turned on
        }
    }
    return needed;
}

/**
 * After a successful DP, reconstructs the chosen digits using the {@code next}
 * table and prints them without spaces.
 */
private void printResult(PrintWriter out) {
    int remaining = k;
    for (int i = 0; i < n; i++) {
        int digit = next[i][remaining];
        out.print(digit);
        remaining -= precomp[i][digit];
    }
}

