}

/** Fill the shared set with all characters that are allowed everywhere. */
private void populateGoodSet(StringBuilder goodStr) {
    for (int i = 0, len = goodStr.length(); i < len; i++) {
        set.add(goodStr.charAt(i));
    }
}

/** Simple case – pattern contains no '*', just compare whole strings. */
private boolean evaluateWithoutAsterisk(StringBuilder curr, StringBuilder orig) {
    return checkConditions(curr.toString(), orig.toString());
}

/**
 * Complex case – pattern contains a '*'.
 * 1️⃣ Compare the prefix before '*'.
 * 2️⃣ Compare the suffix after '*', using reversal to reuse the same check.
 * 3️⃣ Verify that the substring covering the '*'-expansion does not contain any
 *    character from the good‑set.
 */
private boolean evaluateWithAsterisk(StringBuilder curr, StringBuilder orig, int starPos) {
    int originalLen = orig.length();
    int currentLen = curr.length();

    // 1️⃣ left side (prefix) must match
    boolean ok = checkConditions(
            curr.substring(0, starPos),
            orig.substring(0, starPos));

    // 2️⃣ right side (suffix) – compare after reversing both builders
    int revPos = originalLen - starPos - 1;
    curr.reverse();
    orig.reverse();
    ok &= checkConditions(
            curr.substring(0, revPos),
            orig.substring(0, revPos));
    // restore original order for later use
    curr.reverse();
    orig.reverse();

    // 3️⃣ middle part (the part that replaces '*') must contain no good characters
    for (int j = starPos; j < currentLen - originalLen + starPos + 1; j++) {
        ok &= !set.contains(curr.charAt(j));
    }
    return ok;
}

