}

/** Fill the character set with every character that appears in the “good” string. */
private void addGoodCharacters(StringBuilder goodStr) {
    for (int i = 0, len = goodStr.length(); i < len; i++) {
        set.add(goodStr.charAt(i));
    }
}

/** Simple comparison when the original string does not contain '*'. */
private boolean checkSimpleCase(StringBuilder curr, StringBuilder orig) {
    return checkConditions(curr.toString(), orig.toString());
}

/**
 * Handles the case where the original string contains a single '*'.
 * The method checks:
 *   1. the left part (before '*'),
 *   2. the right part (after '*') by reversing both strings,
 *   3. that the “wild‑card” segment does not contain any good character.
 */
private boolean checkComplexCase(StringBuilder curr, StringBuilder orig, int starPos) {
    int leftLen = starPos;                     // characters before '*'
    int rightLen = len1 - starPos - 1;          // characters after '*'

    // 1. compare the left part
    boolean ok = checkConditions(
            curr.substring(0, leftLen),
            orig.substring(0, leftLen));

    // 2. compare the right part (reverse both strings temporarily)
    StringBuilder revCurr = new StringBuilder(curr).reverse();
    StringBuilder revOrig = new StringBuilder(orig).reverse();
    ok &= checkConditions(
            revCurr.substring(0, rightLen),
            revOrig.substring(0, rightLen));

    // 3. ensure the wildcard segment contains no good character
    int middleStart = leftLen;
    int middleEndExclusive = len2 - rightLen; // exclusive bound
    for (int j = middleStart; j < middleEndExclusive; j++) {
        ok &= !set.contains(curr.charAt(j));
    }
    return ok;
}

