			char c = line.charAt(i);
			if(c == ' ') break;

			int d = c - '0';
			n = 10 * n + d;
		}

		int[] nums = new int[n];
		for(i = i + 1; i < line.length(); i++) {
			char c = line.charAt(i);
			if(c == ' ') idx++;
