private static void readInput(FS in) {
    R = in.nextInt();
    C = in.nextInt();
    // allocate with a one‑cell border on each side
    b = new char[R + 2][C + 2];
    for (char[] row : b) {
        Arrays.fill(row, '.');
    }

    // fill the interior (original size)
    for (int i = 1; i <= R; i++) {
        char[] line = in.next().toCharArray();
        for (int j = 1; j <= C; j++) {
            b[i][j] = line[j - 1];
        }
    }

    // enlarge R and C to include the border
    R += 2;
    C += 2;

    // distance/box array initialisation
    box = new int[R][C];
    for (int[] row : box) {
