/* -------------------------------------------------------------
   2️⃣  Breadth‑first search that populates `box` and returns
       the greatest distance discovered.
   ------------------------------------------------------------- */
private static int bfsCompute() {
    int max = -1;
    ArrayDeque<Pair> q = new ArrayDeque<>();

    // enqueue every '.' cell (including the artificial border)
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            if (b[i][j] == '.') {
                q.add(new Pair(i, j));
                box[i][j] = 0;
            }
