            int nc = p.c + dc[k];
            if (!valid(nr, nc) || box[nr][nc] != -1) continue;
            box[nr][nc] = box[p.r][p.c] + 1;
            q.add(new Pair(nr, nc));
        }
    }
    return max;
}

/* ---------- binary search for the best radius ---------- */
private static int binarySearchBest(int max) {
    int lo = 0, hi = max;
    int best = -1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (works(mid)) {
            best = Math.max(best, mid);
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return best;
}

