int nextInt() {
    try {
        // 1. Parse sign, limit and obtain the first printable character
        ParseInfo info = parseSignAndFirstChar();

        int multMin = info.limit / info.radix;
        int res = 0;
        int ch = info.firstChar;

        // 2. Process each digit while characters are printable
        do {
            int digit = ch - '0';
            if (digit < 0 || digit >= info.radix) {
                throw new NumberFormatException();
            }
            res = accumulateDigit(res, digit, info.limit, multMin);
        } while (isPrintable(ch = br.read()));

        // 3. Apply sign
        return info.negative ? res : -res;
    } catch (IOException e) {
        throw new NoSuchElementException();
    }
}

/** Holds the state produced by the sign‑parsing phase. */
private static final class ParseInfo {
    final boolean negative;
    final int limit;
    final int radix = 10;
    final int firstChar;

    ParseInfo(boolean negative, int limit, int firstChar) {
        this.negative = negative;
        this.limit = limit;
        this.firstChar = firstChar;
    }
}

/**
 * Determines the sign, sets the proper overflow limit and returns the first
 * printable character that belongs to the numeric literal.
 */
private ParseInfo parseSignAndFirstChar() throws IOException {
    boolean negative = false;
    int limit = -Integer.MAX_VALUE; // positive range limit
    int fc = nextPrintable();

    if (fc < '0') {
        if (fc == '-') {
            negative = true;
            limit = Integer.MIN_VALUE;
        } else if (fc != '+') {
            throw new NumberFormatException();
        }
        fc = br.read();
    }

    return new ParseInfo(negative, limit, fc);
}

/**
 * Updates the accumulated result with one digit, performing the same
 * overflow checks as the original implementation.
 */
private int accumulateDigit(int res, int digit, int limit, int multMin) {
    if (res < multMin) {
        throw new NumberFormatException();
    }
    int tmp = res * 10;
    if (tmp < limit + digit) {
        throw new NumberFormatException();
    }
    return tmp - digit;
}

