static int solve(int[] a, int b) {
    // Chunk 1 – build the interval map
    TreeMap<Integer, Integer> intervals = buildIntervals(a, b - 1);

    int cnt = 0;
    int start = 0;
    int end = -1;
    boolean feasible = true;

    // Chunk 2 – walk the road using the interval map
    while (end < a.length - 1) {
        int[] next = nextSegment(intervals, end, start);
        if (next == null) {
            feasible = false;
            break;
        }
        start = next[0];
        end   = next[1];
        cnt++;
    }
    return feasible ? cnt : -1;
}

/**
 * Builds a map where each key is the start index of a reachable segment
 * and the value is the farthest index that can be reached from that start.
 */
private static TreeMap<Integer, Integer> buildIntervals(int[] a, int radius) {
    TreeMap<Integer, Integer> tm = new TreeMap<>();
    for (int i = 0; i < a.length; i++) {
        if (a[i] != 0) {
            int s = i - radius < 0 ? 0 : i - radius;
            int e = i + radius;
            tm.put(s, e);
        }
    }
    return tm;
}

/**
 * Determines the next segment to advance to.
 * Returns an int[2] = {newStart, newEnd} or {@code null} if advancement is impossible.
 */
private static int[] nextSegment(TreeMap<Integer, Integer> tm, int currentEnd, int currentStart) {
    // Direct continuation: there is a segment that starts exactly after the current end.
    if (tm.containsKey(currentEnd + 1)) {
        int newStart = currentEnd + 1;
        int newEnd   = tm.get(newStart);
        return new int[] { newStart, newEnd };
    }

    // Need to jump backwards to the greatest start ≤ currentEnd.
    Integer floorKey = tm.floorKey(currentEnd);
    if (floorKey == null || floorKey <= currentStart) {
        return null; // No viable segment.
    }
    int newStart = floorKey;
    int newEnd   = tm.get(newStart);
    return new int[] { newStart, newEnd };
}

