/* ---------- helper methods ---------- */

private int[] readArray(InputReader in, int size) {
    int[] arr = new int[size];
    for (int i = 0; i < size; i++) {
        arr[i] = in.nextInt();
    }
    return arr;
}

/* Returns the first index of A that is not a leading zero.
   If A[0] is zero we start from 1, otherwise from 0. */
private int firstNonZeroStart(int[] A) {
    return A[0] == 0 ? 1 : 0;
}

/* Finds the first position in B whose value equals target.
   Returns -1 if not found (behaviour identical to original). */
private int findMatchingStart(int[] B, int target) {
    for (int i = 0; i < B.length; i++) {
        if (B[i] == target) {
            return i;
        }
    }
    return -1;
}

/* Advances idx until it points to a non‑zero element,
   wrapping around the array of length N. */
private int nextIndexSkippingZeros(int[] arr, int idx, int N) {
    while (arr[idx] == 0) {
        idx = (idx + 1) % N;
    }
    return idx;
}

/* Performs the circular comparison of A and B starting at the given
   indices. Returns true if the sequences match after skipping zeros,
   false otherwise. */
private boolean areCircularSequencesEqual(int[] A, int aStart,
                                          int[] B, int bStart,
                                          int N) {
    for (int i = 0; i < N; i++) {
        aStart = nextIndexSkippingZeros(A, aStart, N);
        bStart = nextIndexSkippingZeros(B, bStart, N);

        if (A[aStart] != B[bStart]) {
            return false;
        }

        aStart = (aStart + 1) % N;
        bStart = (bStart + 1) % N;
    }
    return true;
}

public void solve(int testNumber, InputReader in, PrintWriter out) {
    int N = in.nextInt();

    int[] A = readArray(in, N);
    int[] B = readArray(in, N);

    int aStart = (A[0] == 0) ? 1 : 0;
    int bStart = findMatchingStart(A, aStart, B);
    if (bStart == -1) {
        out.println("NO");
        return;
    }

    boolean ok = circularMatch(A, aStart, B, bStart);
    out.println(ok ? "YES" : "NO");
}

/** Reads exactly {@code n} integers from {@code in}. */
private int[] readArray(InputReader in, int n) {
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = in.nextInt();
    }
    return arr;
}

/**
 * Finds the first index {@code i} in {@code B} such that {@code B[i] == A[aStart]}.
 * Returns -1 if no such element exists.
 */
private int findMatchingStart(int[] A, int aStart, int[] B) {
    for (int i = 0; i < B.length; i++) {
        if (B[i] == A[aStart]) {
            return i;
        }
    }
    return -1;
}

/**
 * Walks both arrays circularly, skipping positions that contain zero,
 * and checks whether the remaining sequences are identical.
 */
private boolean circularMatch(int[] A, int aStart, int[] B, int bStart) {
    int N = A.length; // both arrays have the same length
    for (int count = 0; count < N; count++) {
        // Skip zeros in both arrays
        if (A[aStart] == 0) {
            aStart = (aStart + 1) % N;
        }
        if (B[bStart] == 0) {
            bStart = (bStart + 1) % N;
        }

        // Compare current elements
        if (A[aStart] != B[bStart]) {
            return false;
        }

        // Advance to next positions
        aStart = (aStart + 1) % N;
        bStart = (bStart + 1) % N;
    }
    return true;
}

