    int[] a = new int[m];
    int[] b = new int[m];
    int[] q = new int[m];
    readConstraints(sc, a, b, q, m);

    RangeTree orTree = buildOrTree(n, a, b, q, m);
    RangeTree andTree = buildAndTree(n, orTree);

    boolean ok = verifyConstraints(andTree, a, b, q, m);
    PrintWriter out = new PrintWriter(System.out);
    printResult(out, ok, orTree, n);
    out.flush();
    out.close();
}

/**
 * Reads the triples (a[i], b[i], q[i]) from input.
 */
private static void readConstraints(FastScanner sc, int[] a, int[] b, int[] q, int m) {
    for (int i = 0; i < m; i++) {
        a[i] = sc.nextInt() - 1;
        b[i] = sc.nextInt() - 1;
        q[i] = sc.nextInt();
    }
}

/**
 * Builds the segment tree that stores the OR‑constraints.
 */
private static RangeTree buildOrTree(int n, int[] a, int[] b, int[] q, int m) {
    RangeTree orTree = new RangeTree(n, 0);
    for (int i = 0; i < m; i++) {
        orTree.update(a[i], b[i], q[i], 0);
    }
    return orTree;
}

/**
 * Builds the segment tree that stores the AND‑constraints,
 * using the values already computed in the OR‑tree.
 */
private static RangeTree buildAndTree(int n, RangeTree orTree) {
    RangeTree andTree = new RangeTree(n, 1);
    for (int i = 0; i < n; i++) {
        long value = orTree.query(i, i, 0);
        andTree.update(i, i, value, 1);
    }
    return andTree;
}

/**
 * Verifies that every original constraint is satisfied by the AND‑tree.
 */
private static boolean verifyConstraints(RangeTree andTree, int[] a, int[] b, int[] q, int m) {
    for (int i = 0; i < m; i++) {
        long obtained = andTree.query(a[i], b[i], 1);
        if (obtained != q[i]) {
            return false;
        }
    }
    return true;
}

/**
 * Prints “YES” and the resulting array if the constraints are consistent,
 * otherwise prints “NO”.
 */
private static void printResult(PrintWriter out, boolean ok, RangeTree orTree, int n) {
    if (!ok) {
        out.println("NO");
        return;
    }
    out.println("YES");
    out.print(orTree.query(0, 0, 0));
    for (int i = 1; i < n; i++) {
        out.print(' ');
        out.print(orTree.query(i, i, 0));
    }
    out.println();
}

public static void main(String[] args) {
    FastScanner sc = new FastScanner(System.in);
    int n = sc.nextInt();
    int m = sc.nextInt();

    int[] a = new int[m];
    int[] b = new int[m];
    int[] q = new int[m];
    readQueries(sc, a, b, q);

    RangeTree orTree = buildOrTree(n, a, b, q);
    RangeTree andTree = buildAndTree(n, orTree, a, b, q);

    boolean consistent = validateConstraints(andTree, a, b, q);

    PrintWriter out = new PrintWriter(System.out);
    if (consistent) {
        printSolution(out, orTree, n);
    } else {
        out.println("NO");
    }
    out.flush();
    out.close();
}

/** reads the m triples (a[i], b[i], q[i]) */
private static void readQueries(FastScanner sc, int[] a, int[] b, int[] q) {
    for (int i = 0; i < a.length; i++) {
        a[i] = sc.nextInt() - 1;
        b[i] = sc.nextInt() - 1;
        q[i] = sc.nextInt();
    }
}

/** creates the OR‑segment tree and applies all range updates */
private static RangeTree buildOrTree(int n, int[] a, int[] b, int[] q) {
    RangeTree or = new RangeTree(n, 0);
    for (int i = 0; i < a.length; i++) {
        or.update(a[i], b[i], q[i], 0);
    }
    return or;
}

/** constructs the AND‑segment tree using the values stored in the OR tree */
private static RangeTree buildAndTree(int n, RangeTree orTree,
                                      int[] a, int[] b, int[] q) {
    RangeTree and = new RangeTree(n, 1);
    for (int i = 0; i < n; i++) {
        long value = orTree.query(i, i, 0);
        and.update(i, i, value, 1);
    }
    return and;
}

/** checks whether every original constraint is satisfied */
private static boolean validateConstraints(RangeTree andTree,
                                            int[] a, int[] b, int[] q) {
    for (int i = 0; i < a.length; i++) {
        long obtained = andTree.query(a[i], b[i], 1);
        if (obtained != q[i]) {
            return false;
        }
    }
    return true;
}

/** prints “YES” and the final array built from the OR tree */
private static void printSolution(PrintWriter out, RangeTree orTree, int n) {
    out.println("YES");
    out.print(orTree.query(0, 0, 0));
    for (int i = 1; i < n; i++) {
        out.print(' ');
        out.print(orTree.query(i, i, 0));
    }
    out.println();
}

