/**
 * Builds a prefix‑sum array where each entry i stores the number of mismatches
 * between {@code colors[i]} and the expected colour for the pattern that starts
 * with an offset {@code shift}.
 *
 * Expected colour at position i = (i + shift) % 3.
 */
private static int[] buildPrefix(int[] colors, int shift) {
    int n = colors.length;
    int[] prefix = new int[n];
    for (int i = 0; i < n; i++) {
        int mismatch = (colors[i] != ((i + shift) % 3)) ? 1 : 0;
        prefix[i] = mismatch + (i > 0 ? prefix[i - 1] : 0);
    }
    return prefix;
}

/**
