 * mismatches among the three possible patterns.
 */
private static int findMinMismatches(int[] pref0, int[] pref1, int[] pref2, int k) {
    int n = pref0.length;
    int INF = Integer.MAX_VALUE;
    int min = INF;

    for (int start = 0; start + k - 1 < n; start++) {
        int end = start + k - 1;

        int sum0 = pref0[end] - (start > 0 ? pref0[start - 1] : 0);
        int sum1 = pref1[end] - (start > 0 ? pref1[start - 1] : 0);
        int sum2 = pref2[end] - (start > 0 ? pref2[start - 1] : 0);

        min = Math.min(min, Math.min(sum0, Math.min(sum1, sum2)));
    }
    return min;
}

