/**
 * Builds three prefix‑sum arrays:
 *   a – mismatches when pattern starts with 0 (R)
 *   b – mismatches when pattern starts with 1 (G)
 *   c – mismatches when pattern starts with 2 (B)
 * Each array at index i contains the total mismatches in the prefix [0..i].
 */
private static int[][] buildPrefixArrays(int[] arr) {
    int n = arr.length;
    int[] a = new int[n];
    int[] b = new int[n];
    int[] c = new int[n];

    for (int i = 0; i < n; i++) {
        if (arr[i] != (i % 3)) a[i] = 1;
        if (i > 0) a[i] += a[i - 1];
    }
    for (int i = 0; i < n; i++) {
        if (arr[i] != ((i + 1) % 3)) b[i] = 1;
        if (i > 0) b[i] += b[i - 1];
    }
    for (int i = 0; i < n; i++) {
        if (arr[i] != ((i + 2) % 3)) c[i] = 1;
        if (i > 0) c[i] += c[i - 1];
    }
    return new int[][]{a, b, c};
}

/**
 * Scans all windows of length k and returns the minimal number of changes
 * required to make the window match any of the three colour patterns.
 */
private static int findMinChanges(int[][] prefix, int k) {
    int[] a = prefix[0];
    int[] b = prefix[1];
    int[] c = prefix[2];
    int n = a.length;
    int min = Integer.MAX_VALUE;

    for (int i = 0; i + k - 1 < n; i++) {
        int end = i + k - 1;

        int sum = a[end] - (i > 0 ? a[i - 1] : 0);
        min = Math.min(min, sum);

        sum = b[end] - (i > 0 ? b[i - 1] : 0);
        min = Math.min(min, sum);

        sum = c[end] - (i > 0 ? c[i - 1] : 0);
        min = Math.min(min, sum);
    }
    return min;
}

