        int[] pref1 = buildPrefix(colours, 1); // pattern G,B,R,...
        int[] pref2 = buildPrefix(colours, 2); // pattern B,R,G,...

        int min = Math.min(
                minChangesInWindow(pref0, k),
                Math.min(minChangesInWindow(pref1, k), minChangesInWindow(pref2, k))
        );

