/**
 * Converts a string composed of the characters 'R', 'G', 'B' into an int array
 * where R → 0, G → 1, B → 2.
 */
private static int[] mapStringToIntArray(String s) {
    int n = s.length();
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        char ch = s.charAt(i);
        if (ch == 'R') {
            arr[i] = 0;
        } else if (ch == 'G') {
            arr[i] = 1;
        } else if (ch == 'B') {
            arr[i] = 2;
        } else {
            throw new IllegalArgumentException("Invalid colour character: " + ch);
        }
    }
    return arr;
}

/**
 * Builds a prefix‑sum array that counts mismatches between the colour sequence
 * and the repeating pattern (i + offset) % 3.
 *
 * @param colours the original colour array (0 = R, 1 = G, 2 = B)
 * @param offset  the shift of the pattern (0, 1 or 2)
 * @return prefix sum where prefix[i] = number of mismatches in colours[0..i]
 */
private static int[] buildPrefix(int[] colours, int offset) {
    int n = colours.length;
    int[] prefix = new int[n];
    for (int i = 0; i < n; i++) {
        if (colours[i] != ((i + offset) % 3)) {
            prefix[i] = 1;
        }
        if (i > 0) {
            prefix[i] += prefix[i - 1];
        }
    }
    return prefix;
}

/**
 * Finds the minimum number of mismatches in any contiguous sub‑array of length k,
 * using a previously computed prefix‑sum array.
 *
 * @param prefix prefix‑sum of mismatches
 * @param k      window size
 * @return minimal mismatches for any window of size k
 */
private static int minChangesInWindow(int[] prefix, int k) {
    int n = prefix.length;
    int min = Integer.MAX_VALUE;
    for (int i = 0; i + k - 1 < n; i++) {
        int sum = prefix[i + k - 1];
        if (i > 0) {
            sum -= prefix[i - 1];
        }
        if (sum < min) {
            min = sum;
        }
    }
    return min;
}

