/** Chunk C – iterate over all possible neighbours of q. */
private void exploreNeighbors(int l, int q) {
    for (int i = 1; i <= n; i++) {
        if (mat[q][i]) {
            if (attemptEdgeAndRecurse(l, q, i)) {
                // Successful recursion – stop further processing.
                return;
            }
        }
    }
}

/**
 * Chunk D – try to add the edge (q,i), test feasibility,
 * recurse if possible, and restore the edge otherwise.
 *
 * @return true if recursion happened (caller should return immediately)
 */
private boolean attemptEdgeAndRecurse(int l, int q, int i) {
    // try the edge in the forward direction
    addedge(q, i, false);
    Arrays.fill(ww, false);

    // check whether the current partial solution is still viable
    if (ss[q] == 0 || dfs(q, i)) {
        genans(l + 1, i);
        return true;    // recursion succeeded
    }

    // restore the edge to its original state
    addedge(q, i, true);
    return false;
}

void genans(int l, int q) {
    initializeAnswerIfNeeded(l);
    ans[l] = q;

    for (int i = 1; i <= n; i++) {
        if (mat[q][i]) {
            if (processEdge(l, q, i)) {
                return;                 // successful recursion – stop further scanning
            }
        }
    }
}

/** Initialise the answer array on first use, copying the prefix from `a`. */
private void initializeAnswerIfNeeded(int l) {
    if (ans == null) {
        ans = new int[m + 1];
        // Preserve original loop semantics
        for (int i = 0; i < l; i++) {
            ans[i] = a[i];
        }
    }
}

/**
 * Handles the edge (q,i) exactly as the original nested block did.
 *
 * @return true if the recursive call to {@code genans} succeeded,
 *         signalling the caller to return immediately.
 */
private boolean processEdge(int l, int q, int i) {
    addedge(q, i, false);
    Arrays.fill(ww, false);

    if (ss[q] == 0 || dfs(q, i)) {
        genans(l + 1, i);
        return true;                 // recursion performed
    }

    // backtrack – restore the edge to its original state
    addedge(q, i, true);
    return false;
}

