/**
 * Reads the m pairs of strings and fills the mapping arrays.
 * {@code temp[i]} is set to 1 when {@code arr[i]} is the shorter (or equal) word,
 * otherwise it is set to 0.
 */
private static void readMappings(Scanner s, int m,
                                 String[] arr, String[] arr1, int[] temp) {
    for (int i = 0; i < m; i++) {
        String a = s.next();
        String b = s.next();
        arr[i] = a;
        arr1[i] = b;
        temp[i] = (a.length() <= b.length()) ? 1 : 0;
    }
}

/**
 * Consumes any remaining input and returns the last line read.
 * This mirrors the original “while (s.hasNext()) { str2 = s.nextLine(); }”.
 */
private static String readRemainingLine(Scanner s) {
    String line = "";
    while (s.hasNextLine()) {
        line = s.nextLine();
    }
    return line;
}

/**
 * Translates each word in {@code words} according to the mappings.
 * The original double‑loop logic and the side‑effect of printing {@code null}
 * (the uninitialised {@code ans[i]}) are kept intact.
 */
private static void translateWords(String[] words,
                                   String[] arr, String[] arr1, int[] temp) {
    int m = arr.length;
    for (int i = 0; i < words.length; i++) {
        boolean replaced = false;

        // first try to match the word with the left side of the mapping
        for (int j = 0; j < m; j++) {
            if (words[i].equals(arr[j])) {
                words[i] = (temp[j] == 1) ? arr[j] : arr1[j];
                replaced = true;
                break;
            }
        }
        if (replaced) {
            continue;
        }

        // if not found, try the right side of the mapping
        for (int j = 0; j < m; j++) {
            if (words[i].equals(arr1[j])) {
                words[i] = (temp[j] == 1) ? arr[j] : arr1[j];
                // original code printed ans[i] which was never set (null)
                System.out.println((String) null);
                break;
            }
        }
    }
}

public static void main(String[] args) {
    Scanner s = new Scanner(System.in);
    int n = s.nextInt();          // number of words to translate
    int m = s.nextInt();          // number of synonym pairs

    String[] first  = new String[m];
    String[] second = new String[m];
    int[]    preferFirst = new int[m];   // 1 → first word is shorter or equal

    readPairs(s, m, first, second, preferFirst);

    String wordsLine = readWordsLine(s);
    String[] words   = wordsLine.split(" ");

    for (int i = 0; i < n; i++) {
        words[i] = replaceWithShorter(words[i], first, second, preferFirst);
    }

    for (int i = 0; i < n; i++) {
        System.out.print(words[i] + " ");
    }
}

/** Reads the m synonym pairs and fills the three parallel arrays. */
private static void readPairs(Scanner s, int m,
                              String[] first, String[] second, int[] preferFirst) {
    for (int i = 0; i < m; i++) {
        String a = s.next();      // first word of the pair
        String b = s.next();      // second word of the pair
        first[i]  = a;
        second[i] = b;
        preferFirst[i] = (a.length() <= b.length()) ? 1 : 0;
    }
}

/** Consumes the rest of the input and returns the line that contains the n words. */
private static String readWordsLine(Scanner s) {
    String line = "";
    while (s.hasNextLine()) {
        line = s.nextLine();
        if (!line.trim().isEmpty()) {   // skip possible empty line after the pairs
            break;
        }
    }
    return line;
}

/**
 * Returns the shorter synonym for {@code word}.
 * If the word matches the first column, the decision is based on {@code preferFirst}.
 * If it matches the second column, the same {@code preferFirst} entry is used.
 * If the word is not found in any column, it is returned unchanged.
 */
private static String replaceWithShorter(String word,
                                         String[] first, String[] second,
                                         int[] preferFirst) {
    // try to match the first column
    for (int i = 0; i < first.length; i++) {
        if (word.equals(first[i])) {
            return (preferFirst[i] == 1) ? first[i] : second[i];
        }
    }
    // try to match the second column
    for (int i = 0; i < second.length; i++) {
        if (word.equals(second[i])) {
            return (preferFirst[i] == 1) ? first[i] : second[i];
        }
    }
    // no match – return the original word
    return word;
}

