    Scanner s = new Scanner(System.in);
    int n = s.nextInt();          // number of words to translate
    int m = s.nextInt();          // number of translation pairs

    Mapping mapping = readMappings(s, m);
    String wordsLine = readRemainingLine(s);
    String[] words = wordsLine.isEmpty() ? new String[0] : wordsLine.split(" ");

