/* -------------------------------------------------------------
 * Helper data structure that groups the three parallel arrays.
 * ------------------------------------------------------------- */
private static class Mapping {
    final String[] first;      // first string of each pair
    final String[] second;     // second string of each pair
    final int[] preferFirst;   // 1 if first <= second length, else 0

    Mapping(String[] first, String[] second, int[] preferFirst) {
        this.first = first;
        this.second = second;
        this.preferFirst = preferFirst;
    }
}

/* -------------------------------------------------------------
 * Reads the `m` translation pairs and builds the Mapping object.
 * ------------------------------------------------------------- */
private static Mapping readMappings(Scanner s, int m) {
    String[] first = new String[m];
    String[] second = new String[m];
    int[] preferFirst = new int[m];

    for (int i = 0; i < m; i++) {
        String f = s.next();
        String sec = s.next();
        first[i] = f;
        second[i] = sec;
        preferFirst[i] = (f.length() <= sec.length()) ? 1 : 0;
    }
    return new Mapping(first, second, preferFirst);
}

/* -------------------------------------------------------------
 * Consumes the rest of the input and returns the last line,
 * exactly as the original while‑loop did.
 * ------------------------------------------------------------- */
private static String readRemainingLine(Scanner s) {
    String line = "";
    while (s.hasNext()) {
        line = s.nextLine();
    }
    return line;
}

/* -------------------------------------------------------------
 * Performs the word‑replacement logic that was previously
 * embedded inside `main`.  The behaviour (including the stray
 * `System.out.println(ans[i])`) is kept unchanged.
 * ------------------------------------------------------------- */
private static void processWords(String[] words, Mapping map, String[] ans) {
    int m = map.first.length;

    for (int i = 0; i < words.length; i++) {
        boolean replaced = false;

        // Try to match the word with the first column
        for (int j = 0; j < m; j++) {
            if (words[i].equals(map.first[j])) {
                words[i] = (map.preferFirst[j] == 1) ? map.first[j] : map.second[j];
                replaced = true;
                break;
            }
        }

        // If not found, try the second column
        if (!replaced) {
            for (int j = 0; j < m; j++) {
                if (words[i].equals(map.second[j])) {
                    words[i] = (map.preferFirst[j] == 1) ? map.first[j] : map.second[j];
                    // Preserve the original stray output (ans[i] is always null)
                    System.out.println(ans[i]);
                    break;
                }
            }
        }
    }
}

