/** Builds an undirected adjacency list for a tree of size n. */
@SuppressWarnings("unchecked")
private HashSet<Integer>[] buildTree(int n) {
    HashSet<Integer>[] adj = (HashSet<Integer>[]) new HashSet[n + 1];
    for (int i = 0; i <= n; i++) {
        adj[i] = new HashSet<>();
    }
    for (int i = 0; i < n - 1; i++) {
        int a = ni(), b = ni();
        adj[a].add(b);
        adj[b].add(a);
    }
    return adj;
}

/** Checks whether the permutation starts with the root node (1). */
private boolean startsWithRoot(int[] order) {
    return order.length > 0 && order[0] == 1;
}

/** Validates that the given order can be produced by a BFS that visits
 *  all children of a node consecutively. */
private boolean isValidOrder(int n, HashSet<Integer>[] tree, int[] order) {
    Queue<Integer> queue = new LinkedList<>();
    boolean[] visited = new boolean[n + 1];
    visited[1] = true;
    queue.add(1);
    int idx = 1;                     // next position in order to check

    while (!queue.isEmpty()) {
        int u = queue.poll();
        Set<Integer> nextLevel = unvisitedNeighbours(u, tree, visited);
        int expectedCount = nextLevel.size();

        while (expectedCount-- > 0) {
            if (idx >= order.length) {
                return false;       // order ended prematurely
            }
            int candidate = order[idx++];
            if (!nextLevel.contains(candidate)) {
                return false;       // candidate not a child of current node
            }
            queue.add(candidate);
        }
    }
    // All vertices must be consumed exactly once
    return idx == order.length;
}

/** Returns the set of neighbours of u that have not been visited yet,
 *  and marks them as visited. */
private Set<Integer> unvisitedNeighbours(int u,
                                         HashSet<Integer>[] tree,
                                         boolean[] visited) {
    Set<Integer> result = new HashSet<>();
    for (int v : tree[u]) {
        if (!visited[v]) {
            visited[v] = true;
            result.add(v);
        }
    }
    return result;
}

