 * @param ch current character
 * @param signOut int[1] where signOut[0] will be set to -1 or 1
 * @return the next character after the sign (or the original character if no sign)
 */
private int parseSign(int ch, int[] signOut) throws IOException {
    if (ch == '-') {
        signOut[0] = -1;
        return scan();
    }
    signOut[0] = 1;
    return ch;
}

/**
 * Consumes digit characters building up the integer part of the number.
 * @param ch current character (must not be whitespace or '.')
 * @param holder mutable holder for the accumulating double value
 * @return the next character after the integer part (could be whitespace or '.')
 */
private int parseIntegerPart(int ch, DoubleHolder holder) throws IOException {
    while (!isWhiteSpace(ch) && ch != '.') {
        if (ch >= '0' && ch <= '9') {
            holder.value = holder.value * 10 + (ch - '0');
            ch = scan();
        } else {
            throw new InputMismatchException();
        }
    }
    return ch;
}

/**
 * Consumes the fractional part after a decimal point, if present.
 * @param ch current character (expected to be '.' or something else)
 * @param holder mutable holder for the accumulating double value
 * @return the next character after the fraction (usually whitespace)
 */
private int parseFractionPart(int ch, DoubleHolder holder) throws IOException {
    if (ch != '.') {
        return ch;                     // no fractional part
    }
    ch = scan();                       // skip the '.'
    double factor = 1.0;
    while (!isWhiteSpace(ch)) {
        if (ch >= '0' && ch <= '9') {
            factor /= 10;
            holder.value += (ch - '0') * factor;
            ch = scan();
        } else {
            throw new InputMismatchException();
        }
    }
    return ch;
}

/* ----------- tiny mutable holder class ----------- */
private static class DoubleHolder {
    double value;
    DoubleHolder(double value) { this.value = value; }
}

private double scanDouble() throws IOException {
    double[] value = new double[] {0.0};

    // 1. skip leading whitespace
    int ch = skipWhiteSpace(scan());

    // 2. read optional sign
    SignResult signResult = readSign(ch);
    int sign = signResult.sign;
    ch = signResult.nextChar;

    // 3. parse integer part (stops on '.' or whitespace)
    ch = parseIntegerPart(ch, value);

    // 4. parse fractional part if a '.' was found
    if (ch == '.') {
        ch = parseFractionalPart(scan(), value);
    }

    return value[0] * sign;
}

/** Skips whitespace characters and returns the first non‑whitespace character. */
private int skipWhiteSpace(int ch) throws IOException {
    while (isWhiteSpace(ch)) {
        ch = scan();
    }
    return ch;
}

/** Holds the sign and the next character after the sign has been processed. */
private static final class SignResult {
    final int sign;
    final int nextChar;

    SignResult(int sign, int nextChar) {
        this.sign = sign;
        this.nextChar = nextChar;
    }
}

/** Reads an optional leading '-' and returns the sign together with the following char. */
private SignResult readSign(int ch) throws IOException {
    int sign = 1;
    if (ch == '-') {
        sign = -1;
        ch = scan();
    }
    return new SignResult(sign, ch);
}

/**
 * Parses the integer part of the number.
 * Accumulates the value into {@code accumulator[0]} and returns the next character
 * (either '.' or whitespace).
 */
private int parseIntegerPart(int ch, double[] accumulator) throws IOException {
    while (!isWhiteSpace(ch) && ch != '.') {
        if (ch >= '0' && ch <= '9') {
            accumulator[0] = accumulator[0] * 10 + (ch - '0');
            ch = scan();
        } else {
            throw new InputMismatchException();
        }
    }
    return ch;
}

/**
 * Parses the fractional part after a decimal point.
 * Updates {@code accumulator[0]} with the fractional contribution and returns
 * the character that terminated the fraction (typically whitespace).
 */
private int parseFractionalPart(int ch, double[] accumulator) throws IOException {
    double factor = 0.1;
    while (!isWhiteSpace(ch)) {
        if (ch >= '0' && ch <= '9') {
            accumulator[0] += (ch - '0') * factor;
            factor *= 0.1;
            ch = scan();
        } else {
            throw new InputMismatchException();
        }
    }
    return ch;
}

