int twoPointer(char[] s, int n, int k, char not) {
    WindowState ws = new WindowState(); // l, r, hole, max are all zero‑initialised
    while (true) {
        expandWindow(s, n, k, not, ws);
        shrinkWindow(s, k, not, ws);

        // termination condition – unchanged from the original
        if (ws.r == n || ws.r == n - 1) {
            break;
        }
        ws.r++; // advance past the element that broke the expand loop
    }
    return ws.max;
}

/** Holds the sliding‑window state that is shared between the helpers. */
private static class WindowState {
    int l = 0;      // left index
    int r = 0;      // right index
    int hole = 0;   // number of characters equal to `not` inside the window
    int max = 0;    // longest valid window seen so far
}

/**
 * Expands the right side of the window while the number of “holes” does not exceed {@code k}.
 * Updates {@code ws.max} with the size of the current valid window.
 */
private static void expandWindow(char[] s, int n, int k, char not, WindowState ws) {
    while (ws.r < n && ws.hole <= k) {
        if (s[ws.r] == not) {
            ws.hole++;
        }
        if (ws.hole > k) {
            break;                  // window became invalid – stop expanding
        }
        ws.max = Math.max(ws.max, ws.r - ws.l + 1);
        ws.r++;
    }
}

/**
 * Shrinks the left side of the window until the window becomes valid again
 * (i.e., {@code ws.hole} ≤ {@code k}).
 */
private static void shrinkWindow(char[] s, int k, char not, WindowState ws) {
    while (ws.l <= ws.r && ws.hole > k) {
        if (s[ws.l++] == not) {
            ws.hole--;
        }
    }
}

