/**
 * Returns the index of the first element after the contiguous block that
 * starts at {@code start} and has the same character as {@code c[start]}.
 */
private static int findSegmentEnd(int start, char[] c) {
    int j = start + 1;
    while (j < c.length && c[j] == c[start]) {
        j++;
    }
    return j;
}

/**
 * Computes the sum of the largest {@code k} values in {@code a} between
 * {@code from} (inclusive) and {@code to} (exclusive). If the segment has
 * fewer than {@code k} elements, all of them are summed.
 */
private static long sumTopKInSegment(long[] a, int from, int to, int k) {
    PriorityQueue<Long> pq = new PriorityQueue<>();
    for (int idx = from; idx < to; idx++) {
        long val = a[idx];
        if (pq.size() < k) {
            pq.add(val);
        } else if (pq.peek() < val) {
            pq.poll();
            pq.add(val);
        }
    }

    long segmentSum = 0;
    while (!pq.isEmpty()) {
        segmentSum += pq.poll();
    }
    return segmentSum;
}

