public void solve(FastScanner br, PrintWriter pw) throws IOException {
    final long MOD = 1_000_000_007L;
    String s = br.nextToken();
    int n = s.length();

    long[][] dp = new long[n][5];

    // 1️⃣ initialise the first character
    initFirstChar(dp, s.charAt(0));

    // 2️⃣ process the remaining characters
    for (int i = 1; i < n; i++) {
        processChar(i, s.charAt(i), dp, MOD);
    }

    // 3️⃣ compute the answer from the last DP row
    int ans = sumValid(dp[n - 1], MOD);
    pw.println(ans);
    pw.close();
}

/**
 * Fills dp[0][*] according to the first character.
 */
private void initFirstChar(long[][] dp, char c) {
    if (c == '0') {
        dp[0][0] = 1;
    } else if (c == '1') {
        dp[0][2] = 1;
    } else if (c == '*') {
        dp[0][4] = 1;
    } else if (c == '?') {
        for (int i = 0; i < 5; i++) {
            if (i == 1 || i == 3) {
                continue;
            }
            dp[0][i] = 1;
        }
    }
}

/**
 * Updates dp[idx][*] according to the character at position idx.
 */
private void processChar(int idx, char c, long[][] dp, long MOD) {
    switch (c) {
        case '0':
            dp[idx][0] = (dp[idx - 1][1] + dp[idx - 1][0]) % MOD;
            break;
        case '1':
            dp[idx][1] = dp[idx - 1][4] % MOD;
            dp[idx][2] = (dp[idx - 1][1] + dp[idx - 1][0]) % MOD;
            break;
        case '2':
            dp[idx][3] = dp[idx - 1][4] % MOD;
            break;
        case '*':
            dp[idx][4] = ((dp[idx - 1][2] + dp[idx - 1][3]) % MOD + dp[idx - 1][4]) % MOD;
            break;
        case '?':
            dp[idx][0] = (dp[idx - 1][1] + dp[idx - 1][0]) % MOD;
            dp[idx][1] = dp[idx - 1][4] % MOD;
            dp[idx][2] = (dp[idx - 1][1] + dp[idx - 1][0]) % MOD;
            dp[idx][3] = dp[idx - 1][4] % MOD;
            dp[idx][4] = (dp[idx - 1][2] + dp[idx - 1][3] + dp[idx - 1][4]) % MOD;
            break;
        default:
            // No operation needed for other characters (should not occur)
    }
}

/**
 * Sums the DP values that correspond to valid final states (indices 0,1,4).
 */
private int sumValid(long[] lastRow, long MOD) {
    int ans = 0;
    for (int i = 0; i < 5; i++) {
        if (i == 2 || i == 3) {
            continue; // invalid terminating states
        }
        ans = (int) ((ans + lastRow[i]) % MOD);
    }
    return ans;
}

private void initFirstChar(char c, long[][] dp) {
    // set dp[0][*] according to the first character
    if (c == '0') {
        dp[0][0] = 1;
    } else if (c == '1') {
        dp[0][2] = 1;
    } else if (c == '*') {
        dp[0][4] = 1;
    } else if (c == '?') {
        for (int i = 0; i < 5; i++) {
            if (i == 1 || i == 3) {
                continue;
            }
            dp[0][i] = 1;
        }
    }
}

private void transition(char c, int i, long[][] dp, long MOD) {
    // update dp[i][*] from dp[i‑1][*] according to character c
    if (c == '0') {
        dp[i][0] = (dp[i - 1][1] + dp[i - 1][0]) % MOD;
    } else if (c == '1') {
        dp[i][1] = dp[i - 1][4] % MOD;
        dp[i][2] = (dp[i - 1][1] + dp[i - 1][0]) % MOD;
    } else if (c == '2') {
        dp[i][3] = dp[i - 1][4] % MOD;
    } else if (c == '*') {
        dp[i][4] = (((dp[i - 1][2] + dp[i - 1][3]) % MOD) + dp[i - 1][4]) % MOD;
    } else if (c == '?') {
        dp[i][0] = (dp[i - 1][1] + dp[i - 1][0]) % MOD;
        dp[i][1] = dp[i - 1][4] % MOD;
        dp[i][2] = (dp[i - 1][1] + dp[i - 1][0]) % MOD;
        dp[i][3] = dp[i - 1][4] % MOD;
        dp[i][4] = (dp[i - 1][2] + dp[i - 1][3] + dp[i - 1][4]) % MOD;
    }
}

private int computeAnswer(long[][] dp, int N, long MOD) {
    int ans = 0;
    for (int i = 0; i < 5; i++) {
        if (i == 2 || i == 3) {
            continue;
        }
        ans += dp[N - 1][i];
        ans %= MOD;
    }
    return ans;
}

public void solve(FastScanner br, PrintWriter pw) throws IOException {
    final long MOD = (long) 1e9 + 7;
    String s = br.nextToken();
    int N = s.length();

    long[][] dp = new long[N][5];

    // 1️⃣  Initialise the first character
    initFirstChar(s.charAt(0), dp);

    // 2️⃣  Process the remaining characters
    for (int i = 1; i < N; i++) {
        transition(s.charAt(i), i, dp, MOD);
    }

    // 3️⃣  Aggregate the result
    int ans = computeAnswer(dp, N, MOD);
    pw.println(ans);
    pw.close();
}

