/** Reads N integers and records their frequencies in the supplied array. */
private static void readFrequencies(IntReader cin, int N, int[] a) {
    for (int i = 0; i < N; ++i) {
        int x = cin.nextInt();
        a[x]++;
    }
}

/** Processes the whole frequency array, returns the number of odd‑frequency entries. */
private static long processFrequencies(int[] a) {
    long cnt = 0;
    for (int i = 0; i < MAX; ++i) {
        if (a[i] == 0) {
            continue;
        }
        cnt += handleSingleFrequency(i, a);
    }
    return cnt;
}

/**
 * Handles the logic for a single index:
 *   • counts the odd occurrence (returns 1 if odd, else 0),
 *   • propagates the binary carries to higher indices.
 */
private static int handleSingleFrequency(int index, int[] a) {
    long v = a[index];
    int oddContribution = (v & 1L) == 1L ? 1 : 0;

    v >>= 1;            // discard the least‑significant bit already handled
    int offset = 1;     // distance from the original index

    while (v > 0) {
        if ((v & 1L) == 1L) {
            a[index + offset]++;   // propagate carry
        }
        offset++;
        v >>= 1;
    }
    return oddContribution;
}

