public static BigInteger solve() {
    BigInteger three = BigInteger.valueOf(3);
    BigInteger two   = BigInteger.valueOf(2);

    // 1️⃣ Convert n to base‑3 digits (least‑significant first)
    List<BigInteger> digits = toBaseThree(n, three);

    // Keep a copy of the original digit list for later comparison
    List<BigInteger> originalDigits = new ArrayList<>(digits);
    int originalSize = digits.size();

    // 2️⃣ Normalise the digits (carry handling and the “2” case)
    normalizeDigits(digits, three, two);

    // 3️⃣ Zero‑out trailing digits that are no longer significant
    trimTrailingDigits(digits, originalSize, originalDigits);

    // 4️⃣ Build the final answer from the digit list
    return evaluateAnswer(digits, three);
}

/* ------------------------------------------------------------------ */
/*  Helper 1 – convert a number to a list of its base‑3 remainders       */
private static List<BigInteger> toBaseThree(BigInteger value, BigInteger three) {
    List<BigInteger> list = new ArrayList<>();
    BigInteger tp = value;

    while (!tp.equals(BigInteger.ZERO)) {
        list.add(tp.mod(three));
        tp = tp.divide(three);
    }
    return list;
}

/* ------------------------------------------------------------------ */
/*  Helper 2 – normalise the digit list (carry propagation, “2” rule) */
private static void normalizeDigits(List<BigInteger> list,
                                    BigInteger three,
                                    BigInteger two) {
    for (int i = 0; i < list.size(); i++) {
        BigInteger digit = list.get(i);

        // Carry case: digit ≥ 3
        BigInteger carry = digit.divide(three);
        if (carry.compareTo(BigInteger.ZERO) > 0) {
            BigInteger excess = digit.subtract(two);          // digit - 2
            if (i == list.size() - 1) {
                list.add(BigInteger.ZERO);                     // make room for carry
            }
            list.set(i + 1, list.get(i + 1).add(excess));
            digit = digit.mod(three);
            list.set(i, digit);
        }

        // Special case: digit == 2  → turn into 0 and carry 1
        if (digit.equals(two)) {
            if (i == list.size() - 1) {
                list.add(BigInteger.ZERO);
            }
            list.set(i + 1, list.get(i + 1).add(BigInteger.ONE));
            list.set(i, BigInteger.ZERO);
        }
    }
}

/* ------------------------------------------------------------------ */
/*  Helper 3 – zero out insignificant trailing digits                */
private static void trimTrailingDigits(List<BigInteger> list,
                                        int originalSize,
                                        List<BigInteger> original) {
    if (list.size() > originalSize) {
        // An extra most‑significant digit appeared → zero everything else
        for (int i = list.size() - 2; i >= 0; i--) {
            list.set(i, BigInteger.ZERO);
        }
    } else {
        // No extra digit – compare with the original list
        for (int i = list.size() - 2; i >= 0; i--) {
            BigInteger current = list.get(i);
            BigInteger before  = original.get(i);
            if (!current.equals(before)) {
                // From the first mismatch downwards, set to zero
                for (int j = i; j >= 0; j--) {
                    list.set(j, BigInteger.ZERO);
                }
                break;
            }
        }
    }
}

/* ------------------------------------------------------------------ */
/*  Helper 4 – compute the final answer from the digit list            */
private static BigInteger evaluateAnswer(List<BigInteger> list,
                                          BigInteger three) {
    BigInteger ans = BigInteger.ZERO;
    for (int i = 0; i < list.size(); i++) {
        if (list.get(i).equals(BigInteger.ONE)) {
            ans = ans.add(three.pow(i));
        }
    }
    return ans;
}

