/**
 * Tries to append the smallest possible character to a string that is shorter than 26.
 * Prints the result and returns true if a diverse string is found.
 */
private boolean handleShortString(char[] s, OutputWriter out) {
    char[] t = new char[s.length + 1];
    System.arraycopy(s, 0, t, 0, s.length);
    for (int ch = 'a'; ch <= 'z'; ch++) {
        t[s.length] = (char) ch;
        if (isDiverse(t)) {
            out.println(t);
            return true;
        }
    }
    return false;
}

/**
 * For a 26‑character (or longer) string, tries to replace a position with a larger
 * character and keep the prefix up to that position. Prints the first diverse prefix
 * found and returns true; otherwise returns false.
