/* -------------------------------------------------------------
 * Helper methods
 * ------------------------------------------------------------- */

/**
 * Reads the original sequence, shifts each value by its index
 * (arr[i] = input - i) and adds sentinel values at positions 0
 * and n+1.
 */
private int[] readAdjustedArray(Scanner in, int n) {
    int[] arr = new int[n + 2];
    arr[0] = -(int) 1e9;                         // very small sentinel
    arr[n + 1] = (int) 1e9 - n - 1;              // very large sentinel
    for (int i = 1; i <= n; i++) {
        arr[i] = in.nextInt() - i;
    }
    return arr;
}

/**
 * Reads the list of indices that must stay unchanged, adds
 * sentinel positions 0 and n+1 at the ends.
 */
private int[] readFixedPositions(Scanner in, int m, int n) {
    int[] fixed = new int[m + 2];
    fixed[0] = 0;
    fixed[m + 1] = n + 1;
    for (int i = 1; i <= m; i++) {
        fixed[i] = in.nextInt();
    }
    return fixed;
}

/**
 * Checks whether the values at the fixed positions are already
 * non‑decreasing. This corresponds to the original boolean `f`.
 */
private boolean areFixedPositionsNonDecreasing(int[] arr, int[] fixed) {
    for (int i = 1; i < fixed.length - 1; i++) {
        if (arr[fixed[i]] < arr[fixed[i - 1]]) {
            return false;
        }
    }
    return true;
}

/**
 * Computes the minimal number of elements that need to be changed
 * so that the whole array becomes non‑decreasing while keeping the
 * fixed positions unchanged.
 */
private int computeMinimumChanges(int[] arr, int[] fixed) {
    int totalChanges = 0;
    for (int i = 0; i < fixed.length - 1; i++) {
        totalChanges += changesNeededInSegment(arr, fixed[i], fixed[i + 1]);
    }
    return totalChanges;
}

/**
 * For a segment (l, r) = (previousFixed, nextFixed) exclusive,
 * counts how many interior positions must be altered.
 *
 * It builds the longest non‑decreasing subsequence (LNDS) of values
 * that lie within the allowed range [arr[l], arr[r]] and returns:
 *   segmentLength - LNDSsize
 *
 * The LNDS is constructed with a classic patience‑sorting binary search
 * (the same `bs` routine used in the original code).
 */
private int changesNeededInSegment(int[] arr, int left, int right) {
    int segmentLength = right - left - 1;
    if (segmentLength <= 0) {
        return 0;
    }

    ArrayList<Integer> lnds = new ArrayList<>();
    for (int idx = left + 1; idx < right; idx++) {
        int value = arr[idx];
        if (value < arr[left] || value > arr[right]) {
            continue; // value cannot belong to any valid non‑decreasing sequence
        }

        if (lnds.isEmpty()) {
            lnds.add(value);
        } else {
            int pos = bs(lnds, value); // returns last index with element < value
            if (pos + 1 == lnds.size()) {
                lnds.add(value);
            } else {
                lnds.set(pos + 1, value);
            }
        }
    }
    return segmentLength - lnds.size();
}

/**
 * Binary‑search helper used by the original code.
 * It returns the index of the greatest element in `list`
 * that is strictly less than `key`. If none exists, returns -1.
 * (Implementation unchanged from the original source.)
 */
private int bs(ArrayList<Integer> list, int key) {
    int lo = 0, hi = list.size() - 1, ans = -1;
    while (lo <= hi) {
        int mid = (lo + hi) >>> 1;
        if (list.get(mid) < key) {
            ans = mid;
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return ans;
}

public void solve(int testNumber, Scanner in, PrintWriter out) {
    int n = in.nextInt();
    int m = in.nextInt();

    int[] a = buildTransformedArray(in, n);
    int[] fixed = buildFixedPositions(in, m, n);
    boolean monotone = checkFixedMonotonicity(a, fixed);

    int answer = computeTotalChanges(a, fixed);
    out.println(monotone ? answer : -1);
}

/* ---------- helper methods ---------- */

private int[] buildTransformedArray(Scanner in, int n) {
    int[] a = new int[n + 2];
    a[0] = -(int) 1e9;
    a[n + 1] = (int) 1e9 - n - 1;
    for (int i = 1; i <= n; i++) {
        a[i] = in.nextInt() - i;
    }
    return a;
}

private int[] buildFixedPositions(Scanner in, int m, int n) {
    int[] fixed = new int[m + 2];
    fixed[0] = 0;
    fixed[m + 1] = n + 1;
    for (int i = 1; i <= m; i++) {
        fixed[i] = in.nextInt();
    }
    return fixed;
}

private boolean checkFixedMonotonicity(int[] a, int[] fixed) {
    boolean ok = true;
    for (int i = 1; i < fixed.length - 1; i++) {
        ok &= a[fixed[i]] >= a[fixed[i - 1]];
    }
    return ok;
}

private int computeTotalChanges(int[] a, int[] fixed) {
    int ans = 0;
    for (int i = 0; i < fixed.length - 1; i++) {
        int left = fixed[i];
        int right = fixed[i + 1];
        int lisLength = longestBoundedIncreasingSubsequence(a, left, right);
        ans += (right - left - 1) - lisLength;
    }
    return ans;
}

/**
 * Returns the length of the longest increasing subsequence of a[left+1 .. right-1]
 * whose values stay within the inclusive range [a[left], a[right]].
 */
private int longestBoundedIncreasingSubsequence(int[] a, int left, int right) {
    ArrayList<Integer> lis = new ArrayList<>();
    for (int j = left + 1; j < right; j++) {
        if (a[left] <= a[j] && a[j] <= a[right]) {
            if (lis.isEmpty()) {
                lis.add(a[j]);
            } else {
                int idx = binarySearchPrevSmaller(lis, a[j]);
                if (idx + 1 == lis.size()) {
                    lis.add(a[j]);
                } else {
                    lis.set(idx + 1, a[j]);
                }
            }
        }
    }
    return lis.size();
}

/**
 * Returns the greatest index i such that list.get(i) < value.
 * If no such element exists, returns -1.
 */
private int binarySearchPrevSmaller(ArrayList<Integer> list, int value) {
    int lo = 0, hi = list.size() - 1, ans = -1;
    while (lo <= hi) {
        int mid = (lo + hi) >>> 1;
        if (list.get(mid) < value) {
            ans = mid;
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return ans;
}

