/**
 * Advances the high pointer while the current window satisfies
 * a[hi] - a[i] < m and pushes those values onto the stack.
 *
 * @return the updated hi index
 */
private int advanceHi(int[] a, int i, int hi, int m, Stack<Integer> stack) {
    while (hi < a.length && a[hi] - a[i] < m) {
        stack.add(a[hi]);
        ++hi;
    }
    return hi;
}

/**
 * Pops elements from the stack as long as the BIT sum between the
 * current lower bound a[i] and the stack's top is at least k.
 * Updates the BIT and counts how many elements were removed.
 *
 * @return the number of elements removed (to be added to the result)
 */
private int processStack(int[] a, int i, BIT tree, int k, Stack<Integer> stack) {
    int removed = 0;
    while (!stack.isEmpty()) {
        int tail = stack.peek();
        int sum = tree.sum(a[i], tail);
        if (sum >= k) {
            ++removed;
            tree.update(tail, -1);
            stack.pop();
        } else {
            break;
        }
    }
    return removed;
}

