private static int BFS(int n, int m, ArrayList<ArrayList<Integer>> graph, int[] vArray) {
    boolean[] visited = new boolean[n + 1];
    initializeVisited(n, visited);

    Queue<Integer> q = new LinkedList<>();
    q.add(1);
    visited[1] = true;

    int result = 0;

    while (!q.isEmpty()) {
        int temp = q.poll();

        if (isLeaf(temp, graph)) {
            result++;
            continue;
        }

        for (int neighbour : graph.get(temp)) {
            if (enqueueIfPossible(temp, neighbour, vArray, m, visited, q)) {
                accumulateValue(temp, neighbour, vArray);
            }
        }
    }
    return result;
}

