private static void initializeVisited(int n, boolean[] visited) {
    // Explicitly set each entry to false (matching original intent)
    for (int i = 1; i <= n; i++) {
        visited[i] = false;
    }
}

private static boolean isLeaf(int node, ArrayList<ArrayList<Integer>> graph) {
    // node 1 is the root; any other node with exactly one incident edge is a leaf
    return node != 1 && graph.get(node).size() == 1;
}

private static boolean enqueueIfPossible(int cur,
                                         int nxt,
                                         int[] vArray,
                                         int m,
                                         boolean[] visited,
                                         Queue<Integer> q) {
    // capacity constraint + not visited yet
    if (vArray[cur] + vArray[nxt] <= m && !visited[nxt]) {
        q.add(nxt);
        visited[nxt] = true;
        return true;
    }
    return false;
}

private static void accumulateValue(int cur, int nxt, int[] vArray) {
    // only combine positive values, preserving the original semantics
    if (vArray[cur] > 0 && vArray[nxt] > 0) {
        vArray[nxt] = vArray[cur] + vArray[nxt];
    }
}

