/* Holds mutable loop variables so they can be passed around cleanly */
private static class LoopState {
    final int[] day;
    final int[] height;
    final int m;
    int ind;
    int nextDay;
    int nextValue;
    int curValue;
    int max;
    boolean justAdd;

    LoopState(int[] day, int[] height, int m) {
        this.day = day;
        this.height = height;
        this.m = m;
    }
}

/* Executes the branch where the current day equals a known observation */
private static void handleExactDay(int i, LoopState s) {
    s.curValue = s.nextValue;
    s.ind++;
    if (s.ind < s.m) {
        s.nextDay = s.day[s.ind];
        s.nextValue = s.height[s.ind];
    } else {
        s.justAdd = true;
    }
    s.max = Math.max(s.max, s.curValue);
}

/* Computes the next height for a day that is not an observation */
private static int computeCurrentValue(int i, LoopState s) {
    int difDay = s.nextDay - i;
    int difValue = s.nextValue - s.curValue;

    if (s.curValue == -1) {
        return s.nextValue + difDay;
    } else if (s.justAdd || difValue >= 0) {
        return s.curValue + 1;
    } else { // difValue < 0
        if (difDay >= (s.curValue + 1) - s.nextValue) {
            return s.curValue + 1;
        } else {
            return s.curValue - 1;
        }
    }
}

public static void main(String[] args) throws NumberFormatException, IOException {
    BufferedReader f = new BufferedReader(new InputStreamReader(System.in));
    PrintWriter out = new PrintWriter(System.out);
