    int[] day = new int[m], height = new int[m];
    for (int i = 0; i < m; i++) {
        split = f.readLine().split(" ");
        day[i] = Integer.parseInt(split[0]);
        height[i] = Integer.parseInt(split[1]);
    }

    if (!isValid(day, height)) {
        out.println("IMPOSSIBLE");
        out.flush();
        return;
    }

    int max = computeMaxHeight(n, day, height);
    out.println(max);
    out.close();
}

/**
 * Simulates the walk over the n days using the known observations
 * (day / height) and returns the maximal height reached.
 */
private static int computeMaxHeight(int n, int[] day, int[] height) {
    int ind = 0;
    int nextDay = day[ind];
    int nextValue = height[ind];
    int curValue = -1;
    boolean justAdd = false;
    int max = -1;

    for (int i = 1; i <= n; i++) {
        if (i == nextDay) {
            curValue = nextValue;
            ind++;
            if (ind < day.length) {
                nextDay = day[ind];
                nextValue = height[ind];
            } else {
                justAdd = true;               // no more known points
            }
            max = Math.max(max, curValue);
            continue;
        }

        int difDay = nextDay - i;
        int difValue = nextValue - curValue;

        curValue = updateCurrentValue(curValue, nextValue, difDay, difValue, justAdd);
        max = Math.max(max, curValue);
    }
    return max;
}

/**
 * Determines the new current height based on the relative position
 * to the next known observation.
 */
private static int updateCurrentValue(int curValue, int nextValue,
                                      int difDay, int difValue, boolean justAdd) {
    if (curValue == -1) {
        // we are before the first known day
        return nextValue + difDay;
    } else if (justAdd || difValue >= 0) {
        // monotonic increase or we are after the last known point
        return curValue + 1;
    } else {
        // need to descend towards nextValue
        if (difDay >= (curValue + 1) - nextValue) {
            return curValue + 1;
        } else {
            return curValue - 1;
        }
    }
}

