/** Reads `size` integers from the input and returns them in an array. */
private static int[] readArray(int size) throws IOException {
    int[] arr = new int[size];
    for (int i = 0; i < size; i++) {
        arr[i] = in.nextInt();
    }
    return arr;
}

/** Creates a DP matrix of dimensions (k1+1) x (k2+1) filled with Integer.MAX_VALUE
 *  and sets dp[0][0] = 0. */
private static int[][] createDP(int k1, int k2) {
    int[][] dp = new int[k1 + 1][k2 + 1];
    for (int i = 0; i <= k1; i++) {
        for (int j = 0; j <= k2; j++) {
            dp[i][j] = Integer.MAX_VALUE;
        }
    }
    dp[0][0] = 0;
    return dp;
}

/** Core DP transition that fills the table and leaves the answer in dp[k1][k2]. */
private static void fillDP(int[] a, int x, int k1, int k2, int[][] dp) {
    for (int i = 0; i <= k1; i++) {
        for (int j = 0; j <= k2; j++) {
            int cur = x * i + (x + 1) * j;      // number of elements already taken
            if (i != k1) {
                int cost = a[cur + x - 1] - a[cur];
                dp[i + 1][j] = Math.min(dp[i + 1][j], dp[i][j] + cost);
            }
            if (j != k2) {
                int cost = a[cur + x] - a[cur];
                dp[i][j + 1] = Math.min(dp[i][j + 1], dp[i][j] + cost);
            }
        }
    }
}

