    int k1 = k - (n % k);
    int k2 = n % k;

    int[][] dp = createDpTable(k1, k2);
    initializeDp(dp);
    processDp(dp, a, x, k1, k2);

    System.out.println(dp[k1][k2]);
}

/* ---------- helper methods ---------- */

private int[] readAndSortArray(int n) throws IOException {
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = in.nextInt();
    }
    Arrays.sort(arr);
    return arr;
}

private int[][] createDpTable(int k1, int k2) {
    return new int[k1 + 1][k2 + 1];
}

private void initializeDp(int[][] dp) {
    for (int i = 0; i < dp.length; i++) {
        for (int j = 0; j < dp[i].length; j++) {
            dp[i][j] = Integer.MAX_VALUE;
        }
    }
    dp[0][0] = 0;
}

private void processDp(int[][] dp, int[] a, int x, int k1, int k2) {
    for (int i = 0; i <= k1; i++) {
        for (int j = 0; j <= k2; j++) {
            int cur = x * i + (x + 1) * j;

            if (i != k1) {
                relaxSmallGroup(dp, a, cur, i, j, x);
            }
            if (j != k2) {
                relaxLargeGroup(dp, a, cur, i, j, x);
            }
        }
    }
}

private void relaxSmallGroup(int[][] dp, int[] a, int cur, int i, int j, int x) {
    int candidate = dp[i][j] + a[cur + x - 1] - a[cur];
    if (candidate < dp[i + 1][j]) {
        dp[i + 1][j] = candidate;
    }
}

private void relaxLargeGroup(int[][] dp, int[] a, int cur, int i, int j, int x) {
    int candidate = dp[i][j] + a[cur + x] - a[cur];
    if (candidate < dp[i][j + 1]) {
        dp[i][j + 1] = candidate;
    }
}

