 * turning a space that is directly between two digits into '#'.
 *
 * @return the number of bytes written to {@code out}
 */
private static int markSpacesBetweenNumbers(byte[] src, int length, byte[] out) {
    int outIdx = 0;
    for (int i = 0; i < length; i++) {
        if (src[i] == ' ') {
            boolean left = i > 0 && src[i - 1] >= '0' && src[i - 1] <= '9';
            boolean right = false;
            for (int j = i + 1; j < length; j++) {
