private static int buildResult(byte[] src, int srcLen, byte[] result) {
    int dotCount = 0;
    int resIdx = 0;

    for (int i = 0; i < srcLen; i++) {
        byte cur = src[i];
        if (cur == '.') {
            dotCount++;
            result[resIdx++] = '.';
            if (dotCount == 3) {
                if (resIdx != 3 && result[resIdx - 4] != ' ') {
                    // insert a space before the third dot
                    result[resIdx - 3] = ' ';
                    result[resIdx++] = '.';
                }
                dotCount = 0;
            }
        } else if (cur == ',') {
            result[resIdx++] = ',';
            if (i != srcLen - 1) {
                result[resIdx++] = ' ';
            }
        } else if (cur == '#') {
