 *  odd/even flips for the given depth. */
private static int computeAdjustedValue(int u, int level, int odd, int even) {
    int a = init[u];
    if (level % 2 == 0) {
        a ^= (even % 2);
    } else {
        a ^= (odd % 2);
    }
    return a;
