 *  - flips the node to its goal value,
 *  - increments the global answer count.
 *  Returns the possibly‑updated odd/even counters. */
private static int[] applyFlip(int u, int level, int odd, int even) {
    ans.append(u + 1).append('\n');
    if (level % 2 == 0) {
        even++;
    } else {
        odd++;
    }
    init[u] = goal[u];
    count++;
    return new int[]{odd, even};
