 * the current depth parity and the number of flips performed on even/odd levels.
 */
private static int computeAdjustedValue(int u, int level, int odd, int even) {
    int value = init[u];
    if ((level & 1) == 0) {               // even depth
        value ^= (even % 2);
    } else {                              // odd depth
        value ^= (odd % 2);
    }
    return value;
}

