 * If the current node value differs from the goal, records the flip,
 * updates the global answer builder and counter, and adjusts the odd/even
 * flip counters. Returns the possibly‑updated {@code odd} and {@code even}
 * counters as a two‑element array.
 */
private static int[] applyFlipIfNeeded(int u, int level, int odd, int even) {
    if (init[u] != goal[u]) {
        ans.append(u + 1).append('\n');
        if ((level & 1) == 0) {   // even depth
            even++;
        } else {                  // odd depth
            odd++;
        }
        init[u] = goal[u];
        count++;
    }
    return new int[] { odd, even };
}

