}

/**
 * Sorts indices by a[i] ascending, breaking ties by the index itself.
 */
private static Integer[] sortIndicesByValue(int[] a) {
    int n = a.length;
    Integer[] idx = new Integer[n];
    for (int i = 0; i < n; i++) {
        idx[i] = i;
    }
    Arrays.sort(idx, (i, j) -> a[i] != a[j] ? a[i] - a[j] : i - j);
    return idx;
}

/**
 * For each position i, prevSame[i] is the previous index (to the left) that has the same value as a[i],
 * or -1 if none exists.
 */
private static int[] computePrevSame(int[] a, Integer[] sortedIdx) {
    int n = a.length;
    int[] prev = new int[n];
    for (int i = 0, j; i < n; i = j) {
        j = i + 1;
        while (j < n && a[sortedIdx[j]] == a[sortedIdx[i]]) {
            j++;
        }
        int p = -1;
        for (int h = i; h < j; h++) {
            prev[sortedIdx[h]] = p;
            p = sortedIdx[h];
        }
    }
    return prev;
}

/**
 * leftNearest[i][h] = the nearest index ≤ i whose h‑th bit is set,
 * or -1 if none exists.
 */
private static int[][] computeLeftNearest(int[] a) {
    int n = a.length;
    int[][] left = new int[n][K];
    for (int h = 0; h < K; h++) {
        int last = -1;
        for (int i = 0; i < n; i++) {
            left[i][h] = last;
            if ((a[i] & (1 << h)) != 0) {
                last = i;
            }
        }
    }
    return left;
}

/**
 * rightNearest[i][h] = the nearest index ≥ i whose h‑th bit is set,
 * or n if none exists.
 */
private static int[][] computeRightNearest(int[] a) {
    int n = a.length;
    int[][] right = new int[n][K];
    for (int h = 0; h < K; h++) {
        int next = n;
        for (int i = n - 1; i >= 0; i--) {
            right[i][h] = next;
            if ((a[i] & (1 << h)) != 0) {
                next = i;
            }
        }
    }
    return right;
}

/**
 * dp[i] = the farthest index to the left of i (including i) that can be reached
 * while keeping all bits that are 0 in a[i] also 0.
 */
private static int[] computeLeftZeroMax(int[] a, int[][] leftNearest) {
    int n = a.length;
    int[] dp = new int[n];
    for (int i = 0; i < n; i++) {
        int max = -1;
        for (int h = 0; h < K; h++) {
            if ((a[i] & (1 << h)) == 0) {
                max = Math.max(max, leftNearest[i][h]);
            }
        }
        dp[i] = max;
    }
    return dp;
}

/**
 * dq[i] = the farthest index to the right of i (including i) that can be reached
 * while keeping all bits that are 0 in a[i] also 0.
 */
private static int[] computeRightZeroMin(int[] a, int[][] rightNearest) {
    int n = a.length;
    int[] dq = new int[n];
    for (int i = n - 1; i >= 0; i--) {
        int min = n;
        for (int h = 0; h < K; h++) {
            if ((a[i] & (1 << h)) == 0) {
                min = Math.min(min, rightNearest[i][h]);
            }
        }
        dq[i] = min;
    }
    return dq;
}

/**
 * Final answer calculation.
 */
private static long computeAnswer(int n, int[] dp, int[] dq, int[] prevSame) {
    long totalSubarrays = (long) n * (n + 1) / 2;
    long subtract = 0L;
    for (int i = 0; i < n; i++) {
        int leftBound = Math.max(dp[i], prevSame[i]);
        subtract += (long) (i - leftBound) * (dq[i] - i);
    }
    return totalSubarrays - subtract;
}

