 * or -1 if no such index exists.
 */
private static int[][] computePrevBitIndices(int[] aa) {
    int n = aa.length;
    int[][] bb = new int[n][K];
    for (int h = 0; h < K; h++) {
        int prev = -1;
        for (int i = 0; i < n; i++) {
