 * If all bits are 1, dp[i] stays -1.
 */
private static int[] computeDp(int[] aa, int[][] bb) {
    int n = aa.length;
    int[] dp = new int[n];
    for (int i = 0; i < n; i++) {
        int best = -1;
        for (int h = 0; h < K; h++) {
            if ((aa[i] & (1 << h)) == 0) {
                best = Math.max(best, bb[i][h]);
            }
        }
        dp[i] = best;
    }
    return dp;
}

/**
 * dq[i] = min over bits h that are 0 in aa[i] of dd[i][h].
 * If all bits are 1, dq[i] stays n.
 */
private static int[] computeDq(int[] aa, int[][] dd) {
    int n = aa.length;
    int[] dq = new int[n];
    for (int i = n - 1; i >= 0; i--) {
        int best = n;
        for (int h = 0; h < K; h++) {
            if ((aa[i] & (1 << h)) == 0) {
                best = Math.min(best, dd[i][h]);
            }
        }
        dq[i] = best;
    }
    return dq;
}

/**
 * Final combinatorial counting using the pre‑computed arrays.
 */
private static long computeAnswer(int[] pp, int[] dp, int[] dq, int n) {
    long total = (long) n * (n + 1) / 2;
    for (int i = 0; i < n; i++) {
        int left = Math.max(dp[i], pp[i]);
        long leftChoices = i - left;
        long rightChoices = dq[i] - i;
        total -= leftChoices * rightChoices;
    }
    return total;
}

