/**
 * Fills a frequency array with the occurrences of each input value.
 */
private static long[] buildFrequencyArray(InputReader jin, int n) {
    final int MAX_VALUE = 10001;               // original array size
    long[] freq = new long[MAX_VALUE];
    for (int i = 0; i < n; ++i) {
        int value = jin.nextInt();
        freq[value]++;                         // count occurrence
    }
    return freq;
}

/**
 * Computes the total number of unordered pairs (i, j) such that
 * the Hamming distance between i and j equals k.
 */
private static long calculateTotalPairs(long[] freq, int k) {
    long total = 0L;
    int len = freq.length;

    for (int i = 0; i < len; ++i) {
        if (freq[i] == 0) continue;            // nothing to pair with
        for (int j = i; j < len; ++j) {
            if (freq[j] == 0) continue;
            if (Integer.bitCount(i ^ j) == k) {
                total += (i == j)
                        ? combinationTwo(freq[i])   // same value case
                        : freq[i] * freq[j];        // different values
            }
        }
    }
    return total;
}

/**
 * Returns n choose 2 = n·(n‑1)/2 for non‑negative n.
 */
private static long combinationTwo(long n) {
    return (n * (n - 1)) / 2;
}

public static void main(String[] args) {
    InputStream inputStream = System.in;
    OutputStream outputStream = System.out;
    InputReader jin = new InputReader(inputStream);
    PrintWriter out = new PrintWriter(outputStream);

    int n = jin.nextInt();
    int k = jin.nextInt();

    long[] frequency = buildFrequencyArray(jin, n);
    long totalPairs = computeTotalPairs(frequency, k);

    out.println(totalPairs);
    out.close();
}

/**
 * Reads {@code n} integers from the input and builds a frequency array
 * where the index is the value read and the content is the count of that value.
 */
private static long[] buildFrequencyArray(InputReader jin, int n) {
    long[] arr = new long[10001];
    for (int i = 0; i < n; ++i) {
        int value = jin.nextInt();
        arr[value]++;
    }
    return arr;
}

/**
 * Calculates the number of unordered pairs (i, j) such that
 * the bitwise XOR of the indices has exactly {@code k} bits set.
 * The array {@code freq} holds the occurrence count for each possible index.
 */
private static long computeTotalPairs(long[] freq, int k) {
    long total = 0L;
    int length = freq.length;

    for (int i = 0; i < length; ++i) {
        if (freq[i] == 0) {
            continue;
        }
        for (int j = i; j < length; ++j) {
            if (freq[j] == 0) {
                continue;
            }
            if (Integer.bitCount(i ^ j) == k) {
