                Z[i] = Z[k];
            } else {
                // Case 2b: need to extend the window further
                L = i;
                R = extendMatch(str, L, R);
                Z[i] = R - L;
                R--;
            }
        }
    }
}

/**
 * Extends the right boundary R while the characters of the substring
 * starting at L match the characters starting at the current R.
 *
 * @param str the character array representing the string
 * @param L   left boundary of the current Z-box
 * @param R   right boundary (position to start comparing from)
 * @return the first index where the characters differ (or n)
 */
private int extendMatch(char[] str, int L, int R) {
    int n = str.length;
    while (R < n && str[R - L] == str[R]) {
        R++;
    }
    return R;
}

