/** Computes the final answer for the general case. */
private static int computeResult(int[] input) {
    int n = input.length;
    int min = findShortestSegmentWithGcdOne(input);

    if (min == 0) {
        int ones = countOnes(input);
        return n - ones;
    }
    if (min == -1) {
        return -1;
    }
    return min + n - 1;
}

/**
 * Returns the length of the shortest contiguous segment whose
 * cumulative GCD equals 1. Returns -1 if no such segment exists,
 * or 0 if a single element equals 1.
 */
private static int findShortestSegmentWithGcdOne(int[] input) {
    int n = input.length;
    int min = -1;

    for (int i = 0; i < n && min != 0; i++) {
        int nod = input[i];
        int j = i;

        while (j + 1 < n && nod != 1) {
            j++;
            nod = gcd(nod, input[j]);
        }

        if (nod == 1) {
            int length = j - i;
            min = (min == -1) ? length : Math.min(min, length);
        }
    }
    return min;
}

/** Counts how many elements in the array are equal to 1. */
private static int countOnes(int[] input) {
    int count = 0;
    for (int v : input) {
        if (v == 1) {
            count++;
        }
    }
    return count;
}

/** Euclidean algorithm for greatest common divisor. */
private static int gcd(int a, int b) {
    while (b != 0) {
        int tmp = a % b;
        a = b;
        b = tmp;
    }
    return a;
}

