/**
 * Constructs an array containing the starting point (0,0) followed by the
 * successive coordinates after each move in the input string.
 */
private Point[] buildPoints(String s) {
    int x = 0, y = 0;
    Point[] points = new Point[s.length() + 1];
    points[0] = new Point(0, 0);               // starting position

    for (int i = 0; i < s.length(); i++) {
        char move = s.charAt(i);
        switch (move) {
            case 'R': x++; break;
            case 'L': x--; break;
            case 'U': y++; break;
            default:  y--; break; // assumes any non‑R/L/U is a down move ('D')
        }
        points[i + 1] = new Point(x, y);
    }
    return points;
}

/**
 * Uses a sliding‑window (two‑pointer) technique to find the maximum length
 * of a contiguous sub‑array of {@code points} that contains no duplicate points.
 * The method reproduces the original debug prints while returning the computed maximum.
 */
private int findMaxUniqueLength(Point[] points, InputReader.OutputWriter out) {
    int max = 0;
    int left = 0;
    int right = 0;
    HashSet<Point> window = new HashSet<>();

    while (right < points.length) {
        while (window.contains(points[right])) {
            window.remove(points[left]);
            left++;
        }
        // Debug output preserved from the original implementation
        out.println(points[right] + " " + left);

        max = Math.max(max, right - left);
        window.add(points[right]);
        right++;
    }
    return max;
}

