private static int[] mergeWhileBoth(long[] arr1, long[] arr2, long[] merge) {
    int i = 0, j = 0, k = 0;
    while (i < arr1.length && j < arr2.length) {
        if (arr1[i] <= arr2[j]) {
            merge[k++] = arr1[i++];
        } else {
