        out.println(n);
        return;
    }

    int[] left = new int[n];
    int[] right = new int[n];
    left[0] = 1;
    right[n - 1] = 1;

    fillLeftRight(a, left, right);
    int high = initialHigh(left, right);
    high = computeBestHigh(a, left, right, high);

