}

/* read the n integers into an array */
private int[] readArray(InputReader in, int n) {
    int[] a = new int[n];
    for (int i = 0; i < n; i++) {
        a[i] = in.nextInt();
    }
    return a;
}

/* populate the left‑increasing and right‑increasing helper arrays */
private void fillLeftRight(int[] a, int[] left, int[] right) {
    int n = a.length;
    for (int i = 1; i < n; i++) {
        // left side
        if (a[i] > a[i - 1]) {
            left[i] = left[i - 1] + 1;
        } else {
            left[i] = 1;
        }

        // right side (traversed from the end)
        int rev = n - i;
        if (a[rev] > a[rev - 1]) {
            right[rev - 1] = right[rev] + 1;
        } else {
            right[rev - 1] = 1;
        }
    }
}

/* compute the initial high value using the borders of the helper arrays */
private int initialHigh(int[] left, int[] right) {
    return Math.max(right[1], left[left.length - 2]) + 1;
}

/* scan the interior positions and possibly raise the high value */
private int computeBestHigh(int[] a, int[] left, int[] right, int currentHigh) {
    int high = currentHigh;
    for (int i = 1; i < a.length - 1; i++) {
        int amt = 1;
        if (a[i + 1] - a[i - 1] > 1) {
            amt += left[i - 1] + right[i + 1];
        } else {
            amt += Math.max(left[i - 1], right[i + 1]);
        }
        high = Math.max(high, amt);
    }
    return high;
}

