    for (int i = 0; i < degree.length; i++) {
        if (degree[i] < k) que.add(i);
    }
}

/** Process a single vertex taken from the queue:
 *  - remove all still‑alive incident edges,
 *  - update neighbours' degrees,
 *  - enqueue neighbours that have just reached degree k‑1.
 */
private void processVertex(int id,
                           IntList[] adj,
                           int[] degree,
                           boolean[] alive,
                           int[] u,
                           int[] v,
                           IntList que) {
    for (int edgeId : adj[id]) {
        if (!alive[edgeId]) continue;

        int other = (u[edgeId] == id) ? v[edgeId] : u[edgeId];

        // neighbour will become critical (degree == k) after decrement → enqueue it now
        if (degree[other] == k) que.add(other);

        degree[other]--;
        degree[id]--;
        alive[edgeId] = false;
    }
}

/** Handle the edge that appears on the current day (if it is still alive):
 *  - possibly enqueue its endpoints,
 *  - decrement their degrees,
 *  - mark the edge as dead.
 */
private void handleDayEdge(int day,
                           int[] u,
                           int[] v,
                           int[] degree,
                           boolean[] alive,
                           IntList que) {
    if (!alive[day]) return;

    if (degree[u[day]] == k) que.add(u[day]);
    if (degree[v[day]] == k) que.add(v[day]);

    degree[u[day]]--;
    degree[v[day]]--;
    alive[day] = false;
}

