public boolean bfs(int s1, int s2) {
    Queue<Coordinate> q = new LinkedList<>();
    q.add(new Coordinate(s1, s2));
    board[s1][s2] = 'X';

    while (!q.isEmpty()) {
        Coordinate cur = q.remove();
        int r = cur.getX();
        int c = cur.getY();

        if (exploreNeighbors(r, c, q)) {
            return true;               // goal discovered during neighbour scan
        }
    }
    return false;                      // exhaust queue without reaching goal
}

/** Scan the four adjacent cells of (r,c). Returns true if the goal is reached. */
private boolean exploreNeighbors(int r, int c, Queue<Coordinate> q) {
    for (int i = 0; i < 4; i++) {
        int nr = r + d1[i];
        int nc = c + d2[i];

        if (!checkRange(nr, nc)) {
            continue;                  // outside board limits
        }

        if (board[nr][nc] == 'X') {    // already visited cell
            if (isGoal(nr, nc)) {
                return true;           // found the destination
            }
        } else {
            visitAndEnqueue(nr, nc, q);
        }
    }
    return false;                     // no goal found among neighbours
}

/** Returns true when the supplied coordinates match the target cell. */
private boolean isGoal(int r, int c) {
    return r == e1 && c == e2;
}

/** Marks a cell as visited and adds it to the BFS queue. */
private void visitAndEnqueue(int r, int c, Queue<Coordinate> q) {
    board[r][c] = 'X';
    q.add(new Coordinate(r, c));
}

public boolean bfs(int s1, int s2) {
    Queue<Coordinate> q = new LinkedList<>();
    q.add(new Coordinate(s1, s2));
    board[s1][s2] = 'X';

    while (!q.isEmpty()) {
        Coordinate current = q.remove();
        int x = current.getX();
        int y = current.getY();

        for (int i = 0; i < 4; i++) {
            int nx = x + d1[i];
            int ny = y + d2[i];

            if (!checkRange(nx, ny)) {
                continue;
            }

            // Delegate neighbour processing; return true if the goal is reached.
            if (handleNeighbor(nx, ny, q)) {
                return true;
            }
        }
    }
    return false;
}

/**
 * Handles a neighbour cell during BFS.
 *
 * @param nx neighbour row index
 * @param ny neighbour column index
 * @param q  the BFS queue to which new coordinates may be added
 * @return true if the neighbour is the target cell, otherwise false
 */
private boolean handleNeighbor(int nx, int ny, Queue<Coordinate> q) {
    if (board[nx][ny] == 'X') {
        // Already visited – check if it is the destination.
        return nx == e1 && ny == e2;
    }

    // Mark as visited and enqueue for further expansion.
    board[nx][ny] = 'X';
    q.add(new Coordinate(nx, ny));
    return false;
}

