public static void main(String[] args) {
    Scanner in = new Scanner(System.in);
    int r = in.nextInt();
    int c = in.nextInt();
    String[] arr = new String[r];
    for (int i = 0; i < r; i++) {
        arr[i] = in.next();
    }

    int[][] marked = new int[r][c];

    // Mark rows that do NOT contain 'S'
    for (int i = 0; i < r; i++) {
        if (!containsSInRow(arr, i)) {
            fillRowWithOnes(marked, i);
        }
    }

    // Mark columns that do NOT contain 'S'
    for (int j = 0; j < c; j++) {
        if (!containsSInColumn(arr, j)) {
            fillColumnWithOnes(marked, j);
        }
    }

    int result = countMarkedCells(marked);
    System.out.println(result);
}

/* Helper: does the given row contain an 'S'? */
private static boolean containsSInRow(String[] grid, int row) {
    for (int col = 0; col < grid[row].length(); col++) {
        if (grid[row].charAt(col) == 'S') {
            return true;
        }
    }
    return false;
}

/* Helper: does the given column contain an 'S'? */
private static boolean containsSInColumn(String[] grid, int col) {
    for (String line : grid) {
        if (line.charAt(col) == 'S') {
            return true;
        }
    }
    return false;
}

/* Helper: set every cell in the specified row to 1 */
private static void fillRowWithOnes(int[][] matrix, int row) {
    for (int col = 0; col < matrix[row].length; col++) {
        matrix[row][col] = 1;
    }
}

/* Helper: set every cell in the specified column to 1 */
private static void fillColumnWithOnes(int[][] matrix, int col) {
    for (int row = 0; row < matrix.length; row++) {
        matrix[row][col] = 1;
    }
}

/* Helper: count how many cells are marked with 1 */
private static int countMarkedCells(int[][] matrix) {
    int count = 0;
    for (int[] row : matrix) {
        for (int cell : row) {
            if (cell == 1) {
                count++;
            }
        }
    }
    return count;
}

