/* ------------------------------------------------------------------ *
 *  Helper methods – each one contains a single logical responsibility *
 * ------------------------------------------------------------------ */

private static void sortPairs(Pair[] p) {
    Arrays.sort(p, Comparator.comparingLong(o -> o.val));
}

private static long[][] computeDP(Pair[] p) {
    int n = p.length;
    long[][] dp = new long[n][3];
    for (int i = 0; i < n; ++i) {
        Arrays.fill(dp[i], Long.MAX_VALUE);
    }

    dp[0][0] = -p[0].val;
    for (int i = 1; i < n; ++i) {
        if (dp[i - 1][2] != Long.MAX_VALUE) {
            dp[i][0] = dp[i - 1][2] - p[i].val + p[i - 1].val;
        }
        if (dp[i - 1][0] != Long.MAX_VALUE) {
            dp[i][1] = dp[i - 1][0];
        }
        if (dp[i - 1][2] != Long.MAX_VALUE) {
            dp[i][2] = dp[i - 1][2];
        }
        if (dp[i - 1][1] != Long.MAX_VALUE && dp[i - 1][1] < dp[i][2]) {
            dp[i][2] = dp[i - 1][1];
        }
    }
    return dp;
}

/**
 * Reconstructs the team assignment.
 *
 * @param p    sorted pairs
 * @param dp   DP table produced by {@link #computeDP}
 * @param teams output array that will be filled with team numbers (indexed by original position)
 * @return the total number of teams used
 */
private static int reconstructTeams(Pair[] p, long[][] dp, int[] teams) {
    int n = p.length;
    int members = 3;
    int curTeam = 1;

    for (int i = n - 1; i >= 0; --i) {
        teams[p[i].ind] = curTeam;

        if (i == 0) {
            break;
        }

        if (members == 3) {
            if (dp[i - 1][1] == dp[i][2]) {
                members = 2;
            }
        } else if (members == 2) {
            members = 1;
        } else { // members == 1
            curTeam++;
            members = 3;
        }
    }
    return curTeam;
}

public void solve(int testNumber, InputReader sc, PrintWriter out) {
    int n = sc.nextInt();

    long[] a = readArray(sc, n);
    Pair[] pairs = buildPairs(a);
    sortPairs(pairs);

    long[][] dp = computeDp(pairs);
    int[] teams = reconstructTeams(pairs, dp);

    long minCost = dp[n - 1][2] + pairs[n - 1].val;
    int totalTeams = teams[pairs[0].ind]; // after reconstruction curTeam holds last id
    out.println(minCost + " " + totalTeams);
    for (int i = 0; i < n; ++i) {
        out.print(teams[i] + " ");
    }
}

