@Override
public void run() {
    String s = nextLine();
    int len = s.length();

    String max = genmax(len);

    // If the input already is the maximal string for its length, print it and exit.
    if (handleExactMaximum(s, max)) {
        close();
        return;
    }

    // Otherwise generate all candidate strings.
    populateCandidates(s, max, len);

    // From the generated candidates, print the first one that satisfies the condition.
    printFirstValidCandidate(s, len);

    close();
}

/**
 * Prints the string if it already equals the maximal possible string.
 *
 * @return true if the caller should stop further processing, false otherwise.
 */
private boolean handleExactMaximum(String s, String max) {
    if (s.equals(max)) {
        print(s);
        return true;
    }
    return false;
}

/**
 * Initializes the result set {@code hs} and populates it by invoking {@code gen}.
 * The seed string passed to {@code gen} depends on the lexical comparison
 * between the input and the maximal string.
 */
private void populateCandidates(String s, String max, int len) {
    hs = new HashSet<String>();

    if (s.compareTo(max) > 0) {
        // Input is lexically greater than the maximal string of the same length.
        // We need to consider strings of length + 1.
        String seed = new StringBuilder(genmax(len + 1)).reverse().toString();
        gen(new StringBuilder(seed), len + 1);
    } else {
        // Input is not greater; stay within the same length.
        String seed = new StringBuilder(max).reverse().toString();
        gen(new StringBuilder(seed), len);
    }
}

/**
 * Sorts the generated candidates and prints the first one that is either longer
 * than the original input or lexicographically not smaller.
 */
private void printFirstValidCandidate(String original, int originalLen) {
    Object[] sorted = hs.toArray();
    Arrays.sort(sorted);

    for (Object o : sorted) {
        String candidate = (String) o;
        int candidateLen = candidate.length();

        if (candidateLen > originalLen || candidate.compareTo(original) >= 0) {
            print(candidate);
            break;
        }
    }
}

