/**
 * Replaces a value that is out of the allowed range [1..M] with the first
 * number whose current count is below the target frequency `v`.
 *
 * @return 1 if a replacement was performed, otherwise 0
 */
private static int handleOutOfRange(int[] a, int idx, int[] c, int M, int v) {
    for (int j = 1; j <= M; j++) {
        if (c[j] < v) {
            c[j]++;          // occupy the new value
            a[idx] = j;      // write back the new value
            return 1;
        }
    }
    return 0;
}

/**
 * Replaces an over‑represented value with the first number whose count is
 * below `v`. The count of the original value is decreased accordingly.
 *
 * @return 1 if a replacement was performed, otherwise 0
 */
private static int handleOverrepresented(int[] a, int idx, int[] c, int M, int v) {
    for (int j = 1; j <= M; j++) {
        if (c[j] < v) {
            c[j]++;                // take the new value
            c[a[idx]]--;           // release the old value
            a[idx] = j;            // write back the new value
            return 1;
        }
    }
    return 0;
}

/**
 * Returns the smallest count among the numbers 1..M.
 */
private static int computeMinCount(int[] c, int M) {
    int min = Integer.MAX_VALUE;
    for (int i = 1; i <= M; i++) {
        min = Math.min(c[i], min);
    }
    return min;
}

