    int v = N / M;

    int changes = balanceArray(a, c, M, v);
    int min = computeMinimumCount(c, M);

    System.out.println(min + " " + changes);
    System.out.println(buildAnswerString(a));
}

/**
 * Builds the frequency array for values that are already within the range [1..M].
 */
private static int[] buildFrequencyArray(int[] a, int M) {
    int[] c = new int[M + 1];
    for (int value : a) {
        if (value <= M) {
            c[value]++;
        }
    }
    return c;
}

/**
 * Balances the input array so that every value 1..M appears at most N/M times.
 * Returns the number of modifications performed.
 */
private static int balanceArray(int[] a, int[] c, int M, int target) {
    int changes = 0;
    for (int i = 0; i < a.length; i++) {
        int current = a[i];

        if (current > M) {
            int replacement = findUnderfilledValue(c, target, M);
            if (replacement != -1) {
                c[replacement]++;
                a[i] = replacement;
                changes++;
            }
        } else if (c[current] > target) {
            int replacement = findUnderfilledValue(c, target, M);
            if (replacement != -1) {
                c[replacement]++;       // add the new value
                c[current]--;           // remove the old one
                a[i] = replacement;
                changes++;
            }
        }
    }
    return changes;
}

/**
 * Returns the first value j (1 ≤ j ≤ M) whose count is below the target,
 * or -1 if every count already meets/exceeds the target (should not happen
 * with the problem constraints).
 */
private static int findUnderfilledValue(int[] c, int target, int M) {
    for (int j = 1; j <= M; j++) {
        if (c[j] < target) {
            return j;
        }
    }
    return -1;
}

/**
 * Computes the smallest frequency among the values 1..M.
 */
private static int computeMinimumCount(int[] c, int M) {
    int min = Integer.MAX_VALUE;
    for (int i = 1; i <= M; i++) {
        min = Math.min(c[i], min);
    }
    return min;
}

/**
 * Builds the space‑separated string representation of the final array.
 */
private static String buildAnswerString(int[] a) {
    StringBuilder sb = new StringBuilder();
    for (int value : a) {
        sb.append(value).append(' ');
    }
    return sb.toString();
}

