        int v = in.nextInt();

        if (t == 1) {
            total = handleAdd(v, i, data, pending, total);
        } else if (t == 2) {
            total = handleReset(v, data, time, total, i);
        } else { // t == 3
            QueryState state = handleQuery(v, last, data, time, pending, total);
            total = state.total;
            last = state.last;
        }

        out.println(total);
    }
    out.close();
}

/*--- helper for command type 1 ------------------------------------------------*/
private static int handleAdd(int v, int index,
                             int[] data,
                             LinkedList<Point> pending,
                             int total) {
    total++;
    data[v - 1]++;                     // record the new occurrence
    pending.add(new Point(v - 1, index)); // remember when it happened
    return total;
}

/*--- helper for command type 2 ------------------------------------------------*/
private static int handleReset(int v,
                               int[] data,
                               int[] time,
                               int total,
                               int index) {
    time[v - 1] = index;               // last reset moment for this index
    total -= data[v - 1];              // all currently stored items become invisible
    data[v - 1] = 0;                   // clear the counter
    return total;
}

/*--- helper for command type 3 ------------------------------------------------*/
private static class QueryState {
    final int total;
    final int last;

    QueryState(int total, int last) {
        this.total = total;
        this.last = last;
    }
}

private static QueryState handleQuery(int v,
                                      int last,
                                      int[] data,
                                      int[] time,
                                      LinkedList<Point> pending,
                                      int total) {
    if (last < v) {
        int left = v - last;
        last = v;
        for (int j = 0; j < left; j++) {
            Point p = pending.poll();       // oldest pending insertion
            if (time[p.x] < p.y) {          // still valid (not reset after insertion)
                data[p.x]--;                // remove it from the counter
                total--;
            }
        }
    }
    return new QueryState(total, last);
}

public static void main(String[] args) throws FileNotFoundException {
    PrintWriter out = new PrintWriter(System.out);
    Scanner in = new Scanner();
    int n = in.nextInt();
    int q = in.nextInt();

    int[] data = new int[n];
    int[] time = new int[n];
    Arrays.fill(time, -1);

    LinkedList<Point> pending = new LinkedList<>();
    int[] total = new int[]{0};
    int[] last = new int[]{0};

    for (int i = 0; i < q; i++) {
        int t = in.nextInt();
        int vRaw = in.nextInt();

        if (t == 1) {
            int idx = vRaw - 1;
            handleInsert(idx, i, data, pending, total);
        } else if (t == 2) {
            int idx = vRaw - 1;
            handleReset(idx, i, data, time, total);
        } else {
            handleQuery(vRaw, i, pending, time, data, total, last);
        }

        out.println(total[0]);
    }
    out.close();
}

/** Inserts a new point for column {@code idx}. */
private static void handleInsert(int idx, int step,
                                 int[] data,
                                 LinkedList<Point> pending,
                                 int[] total) {
    total[0]++;                 // one more active element
    data[idx]++;                // count per column
    pending.add(new Point(idx, step));
}

/** Resets column {@code idx} at time {@code step}. */
private static void handleReset(int idx, int step,
                                int[] data,
                                int[] time,
                                int[] total) {
    time[idx] = step;           // remember last reset time
    total[0] -= data[idx];      // remove all active elements of this column
    data[idx] = 0;              // clear column count
}

/** Processes a query of type 3, discarding stale points up to {@code v}. */
private static void handleQuery(int v,
                                int step,
                                LinkedList<Point> pending,
                                int[] time,
                                int[] data,
                                int[] total,
                                int[] last) {
    if (last[0] < v) {
        int left = v - last[0];
        last[0] = v;
        for (int j = 0; j < left; j++) {
            Point p = pending.poll();
            // p.x is column, p.y is insertion step
            if (time[p.x] < p.y) {   // point survived any reset
                data[p.x]--;
                total[0]--;
            }
        }
    }
}

