public static void main(String[] args) throws IOException {
    FastScanner in = new FastScanner(System.in);
    PrintWriter out = new PrintWriter(System.out);
    n = in.nextInt();
    int k = in.nextInt();

    int[] ps = readPermutation(in);
    int[] fs = new int[n + 1];
    List<Integer> lens = collectCycleLengths(ps, fs);

    List<Integer> items = buildItemsFromFrequencies(fs);

    int min = solve(items, k) ? k : k + 1;
    int max = computeMax(k, lens);

    System.out.println(min + " " + max);
}

/* Reads the permutation (converts to 0‑based indices). */
private static int[] readPermutation(FastScanner in) throws IOException {
    int[] ps = new int[n];
    for (int i = 0; i < n; i++) {
        ps[i] = in.nextInt() - 1;
    }
    return ps;
}

/* Finds all cycle lengths, fills frequency array `fs`,
   and returns the list of lengths. */
private static List<Integer> collectCycleLengths(int[] ps, int[] fs) {
    boolean[] seen = new boolean[n];
    List<Integer> lens = new ArrayList<>();
    for (int i = 0; i < n; i++) {
        if (seen[i]) continue;
        int c = i;
        int len = 0;
        while (!seen[c]) {
            seen[c] = true;
            c = ps[c];
            len++;
        }
        fs[len]++;          // count cycles of this length
        lens.add(len);
    }
    return lens;
}

/* Converts the frequency array into the list of “items”
   required by the knapsack‑style solver. */
private static List<Integer> buildItemsFromFrequencies(int[] fs) {
    List<Integer> items = new ArrayList<>();
    for (int i = 1; i < fs.length; i++) {
        int freq = fs[i];
        for (int j = 1; j <= freq; j <<= 1) {
            items.add(j * i);
            freq -= j;
        }
        if (freq != 0) {
            items.add(freq * i);
        }
    }
    return items;
}

/* Computes the maximal number of positions that can be fixed. */
private static int computeMax(int k, List<Integer> lens) {
    int remaining = k;
    int max = 0;
    for (int len : lens) {
        int cnt = Math.min(remaining, len / 2);
        remaining -= cnt;
        max += 2 * cnt;
    }
    max += remaining;
    return Math.min(n, max);
}

