public void solve(int testNumber, inputClass sc, PrintWriter out) {
    int t = sc.nextInt();
    while (t-- > 0) {
        n = sc.nextInt();
        m = sc.nextInt();

        char[][] color = readGrid(sc, n, m);
        char[][] tra   = readGrid(sc, n, m);   // kept for parity with original code

        int[][] bin = new int[n * m][21];
        initFirstLevel(bin);
        buildBinaryLiftingTable(bin);

        Map<Integer, Integer> allComponents = new HashMap<>();
        Map<Integer, Integer> zeroColorComponents = new HashMap<>();
        fillComponentMaps(color, bin, allComponents, zeroColorComponents);

        out.println(allComponents.size() + " " + zeroColorComponents.size());
    }
}

/** Reads a grid of `rows` lines, each line having exactly `cols` characters. */
private char[][] readGrid(inputClass sc, int rows, int cols) {
    char[][] grid = new char[rows][cols];
    for (int i = 0; i < rows; i++) {
        grid[i] = sc.nextLine().toCharArray();
    }
    return grid;
}

/** Fills the 0‑th level of the binary‑lifting table `bin`. */
private void initFirstLevel(int[][] bin) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            bin[i * m + j][0] = next(i, j);
        }
    }
}

/** Builds the remaining 20 levels of the binary‑lifting table. */
private void buildBinaryLiftingTable(int[][] bin) {
    for (int level = 1; level < 21; level++) {
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                int prev = bin[i * m + j][level - 1];
                bin[i * m + j][level] = bin[prev][level - 1];
            }
        }
    }
}

/** Populates the two maps required for the output. */
private void fillComponentMaps(char[][] color, int[][] bin,
                               Map<Integer, Integer> all,
                               Map<Integer, Integer> zeroColor) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            int root = bin[i * m + j][20];
            all.put(root, 1);
            if (color[i][j] == '0') {
                zeroColor.put(root, 1);
            }
        }
    }
}

