private long readLong() {
    int c = nextNonSpaceChar();

    boolean negative = false;
    if (c == '-') {
        negative = true;
        c = read(); // advance past the sign
    }

    long value = readDigits(c);
    return negative ? -value : value;
}

/**
 * Skips leading whitespace characters and returns the first non‑space character.
 * Throws a RuntimeException if the underlying stream reaches EOF before any
 * non‑space character is found.
 */
private int nextNonSpaceChar() {
    int c = read();
    while (isSpaceChar(c)) {
        c = read();
        if (c == -1) {
            throw new RuntimeException();
        }
    }
    return c;
}

/**
 * Reads a contiguous sequence of decimal digits starting with {@code firstDigit},
 * builds the corresponding long value, and consumes the trailing whitespace.
 * Throws InputMismatchException if a non‑digit is encountered.
 */
private long readDigits(int firstDigit) {
    long result = 0;
    int c = firstDigit;
    while (true) {
        if (c < '0' || c > '9') {
            throw new InputMismatchException();
        }
        result = result * 10 + (c - '0');
        c = read();
        if (isSpaceChar(c)) {
            break;
        }
    }
    return result;
}

private long readLong() {
    int c = skipLeadingSpace();
    boolean negative = false;
    if (c == '-') {
        negative = true;
        c = read();
    }
    long value = parseNumber(c);
    return negative ? -value : value;
}

/** Skip whitespace characters and return the first non‑space character.
 *  Throws RuntimeException if end‑of‑stream is reached while skipping. */
private int skipLeadingSpace() {
    int c = read();
    while (isSpaceChar(c)) {
        c = read();
        if (c == -1) {
            throw new RuntimeException();
        }
    }
    return c;
}

/** Parse a sequence of digit characters starting with the supplied character.
 *  Consumes characters until a space character is encountered.
 *  Throws InputMismatchException if a non‑digit is encountered. */
private long parseNumber(int c) {
    long result = 0;
    do {
        if (c < '0' || c > '9') {
            throw new InputMismatchException();
        }
        result = result * 10 + (c - '0');
        c = read();
    } while (!isSpaceChar(c));
    return result;
}

