/*-------------------  helpers --------------------------------*/

private static void handleBZeroCase(int a, int c, StringBuilder out) {
    if (a == 0) {
        // produce c+1 copies of '1'
        for (int i = 0; i <= c; i++) {
            out.append('1');
        }
    } else {
        // produce a+1 copies of '0'
        for (int i = 0; i <= a; i++) {
            out.append('0');
        }
    }
