private static void handleBNonZeroCase(int a, int b, int c, StringBuilder out) {
    StringBuilder zeroSegment = buildZeroSegment(a);
    StringBuilder oneSegment  = buildOneSegment(c);
    StringBuilder pattern     = buildAlternatingPattern(b);

    // Insert the zero segment before the first '0' in the pattern
    pattern.insert(pattern.indexOf("0"), zeroSegment);
    // Insert the one segment before the first '1' in the pattern (after the previous insertion)
    pattern.insert(pattern.indexOf("1"), oneSegment);

    out.append(pattern);
}

private static StringBuilder buildZeroSegment(int count) {
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < count; i++) {
        sb.append('0');
    }
    return sb;
}

private static StringBuilder buildOneSegment(int count) {
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < count; i++) {
        sb.append('1');
    }
    return sb;
}

private static StringBuilder buildAlternatingPattern(int b) {
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i <= b; i++) {
        sb.append((i % 2 == 0) ? '0' : '1');
    }
    return sb;
}

public static void solve(int a, int b, int c) throws IOException {
    StringBuffer sb = new StringBuffer();

    if (b == 0) {
        if (a == 0) {
            // case: only ones, length c+1
            sb.append(buildRepeated('1', c + 1));
        } else {
            // case: only zeros, length a+1
            sb.append(buildRepeated('0', a + 1));
        }
    } else {
        // build the three parts needed for the composite string
        StringBuffer zeroPrefix = buildRepeated('0', a);
        StringBuffer oneSuffix   = buildRepeated('1', c);
        StringBuffer core        = buildAlternating(b);

        sb.append(core);
        sb.insert(sb.indexOf("0"), zeroPrefix);
        sb.insert(sb.indexOf("1"), oneSuffix);
    }

    println(sb.toString());
}

/** Returns a StringBuffer containing {@code ch} repeated {@code count} times. */
private static StringBuffer buildRepeated(char ch, int count) {
    StringBuffer buf = new StringBuffer();
    for (int i = 0; i < count; i++) {
        buf.append(ch);
    }
    return buf;
}

/** Returns a StringBuffer with an alternating 0/1 pattern of length b+1,
 *  starting with 0 at index 0. */
private static StringBuffer buildAlternating(int b) {
    StringBuffer buf = new StringBuffer();
    for (int i = 0; i <= b; i++) {
        buf.append((i % 2 == 0) ? '0' : '1');
    }
    return buf;
}

