    int n = sc.nextInt();

    int[][] parity = buildParityMatrix(n);
    char[][] board = buildCharMatrix(parity);
    printMatrix(board);
}

/**
 * Creates an n×n matrix where cells alternate between 0 and 1
 * in a checker‑board fashion, starting with 0 at (0,0).
 */
private static int[][] buildParityMatrix(int n) {
    int[][] x = new int[n][n];
    x[0][0] = 0;

    // Initialise first row
    for (int i = 1; i < n; i++) {
        x[0][i] = 1 - x[0][i - 1];
    }

    // Initialise first column
    for (int j = 1; j < n; j++) {
        x[j][0] = 1 - x[j - 1][0];
    }

    // Fill the rest of the matrix
    for (int i = 1; i < n; i++) {
        for (int j = 1; j < n; j++) {
            x[i][j] = 1 - x[i][j - 1];
        }
    }
    return x;
}

/**
 * Translates a parity matrix (0/1) into a board of characters:
 * 0 → 'W', 1 → 'B'.
 */
private static char[][] buildCharMatrix(int[][] parity) {
    int n = parity.length;
    char[][] a = new char[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            a[i][j] = (parity[i][j] == 0) ? 'W' : 'B';
        }
    }
    return a;
}

/**
 * Prints a rectangular character matrix, one row per line.
 */
private static void printMatrix(char[][] matrix) {
    for (char[] row : matrix) {
        for (char c : row) {
            System.out.print(c);
        }
        System.out.println();
    }
}

