/** Dispatches a single query to the appropriate handler. */
private static void processQuery(int l1, int r1, StringTokenizer st,
                                 SegmantTreeWithLazy segTree, int n,
                                 PrintWriter pw) {
    if (r1 < l1) {
        handleWrappedQuery(l1, r1, st, segTree, n, pw);
    } else {
        handleNormalQuery(l1, r1, st, segTree, pw);
    }
}

/** Handles queries where the interval wraps around the end of the array. */
private static void handleWrappedQuery(int l1, int r1, StringTokenizer st,
                                       SegmantTreeWithLazy segTree, int n,
                                       PrintWriter pw) {
    int l2 = 0;
    int r2 = r1;
    int newR1 = n - 1;          // expand first part to the end of the array

    if (st.hasMoreTokens()) {
        int value = Integer.parseInt(st.nextToken());
        segTree.updateRange(l1, newR1, value);
        segTree.updateRange(l2, r2, value);
    } else {
        int min = Math.min(segTree.getRange(l1, newR1),
                           segTree.getRange(l2, r2));
        pw.println(min);
    }
}

/** Handles queries that do not wrap around the array. */
private static void handleNormalQuery(int l1, int r1, StringTokenizer st,
                                      SegmantTreeWithLazy segTree,
                                      PrintWriter pw) {
    if (st.hasMoreTokens()) {
        int value = Integer.parseInt(st.nextToken());
        segTree.updateRange(l1, r1, value);
    } else {
        pw.println(segTree.getRange(l1, r1));
    }
}

