        arr[i] = Integer.parseInt(st.nextToken());
    }
    SegmantTreeWithLazy s = new SegmantTreeWithLazy(arr);
    int q = Integer.parseInt(bf.readLine());
    while (q-- > 0) {
        st = new StringTokenizer(bf.readLine());
        processQuery(st, n, s, pw);
    }
