}

/** Handles one query line – either an update or a range‑minimum query. */
private static void processQuery(StringTokenizer st, int n,
                                 SegmantTreeWithLazy segTree,
                                 PrintWriter out) {
    int l1 = Integer.parseInt(st.nextToken());
    int r1 = Integer.parseInt(st.nextToken());

    if (r1 < l1) {                         // wrap‑around case
        int l2 = 0;
        int r2 = r1;
        int r1Adjusted = n - 1;            // first interval becomes [l1 … n‑1]
        if (st.hasMoreTokens()) {
            int c = Integer.parseInt(st.nextToken());
            applyUpdate(segTree, l1, r1Adjusted, c);
            applyUpdate(segTree, l2, r2, c);
        } else {
            outputMinResult(segTree, out, l1, r1Adjusted, l2, r2);
        }
    } else {                               // normal (non‑wrapping) case
        if (st.hasMoreTokens()) {
            int c = Integer.parseInt(st.nextToken());
            applyUpdate(segTree, l1, r1, c);
        } else {
            out.println(segTree.getRange(l1, r1));
        }
    }
}

/** Performs a range update on the segment tree. */
private static void applyUpdate(SegmantTreeWithLazy segTree,
                                int left, int right, int value) {
    segTree.updateRange(left, right, value);
}

/** Prints the minimum of two disjoint ranges. */
private static void outputMinResult(SegmantTreeWithLazy segTree,
                                    PrintWriter out,
                                    int left1, int right1,
                                    int left2, int right2) {
    int min1 = segTree.getRange(left1, right1);
    int min2 = segTree.getRange(left2, right2);
    out.println(Math.min(min1, min2));
}

