        }

        List<Integer> divisors = collectCommonDivisors(s1.length(), s2.length());
        int result = countMatchingDivisors(s1, s2, divisors);
        System.out.println(result);
    }
}

/**
 * Returns true when the two strings can possibly be built from a common
 * repeating pattern. The original code rejected the pair if:
 *   – they have equal length but differ,
 *   – the shorter one is not a prefix of the longer one.
 */
private static boolean hasCommonPrefix(String a, String b) {
    int n1 = a.length();
    int n2 = b.length();

    if (n1 == n2 && !a.equals(b)) {
        return false;
    }
    if (n1 < n2 && !b.startsWith(a)) {
        return false;
    }
    if (n2 < n1 && !a.startsWith(b)) {
        return false;
    }
    return true;
}

/**
 * Finds all lengths p that divide both strings' lengths and for which the
 * complementary divisor of the longer length also divides the shorter length.
 * This reproduces the original divisor‑collection logic.
 */
private static List<Integer> collectCommonDivisors(int n1, int n2) {
    List<Integer> divisors = new ArrayList<>();

    int limit = Math.min(n1, n2);
    for (int d = 1; d <= limit; d++) {
        if (n1 % d == 0 && n2 % d == 0) {
            if (!divisors.contains(d)) {
                divisors.add(d);
            }
            // add the complementary divisor of n1 if it also divides n2
            int complement = n1 / d;
            if (n2 % complement == 0 && !divisors.contains(complement)) {
                divisors.add(complement);
            }
        }
    }
    return divisors;
}

/**
 * Counts how many divisor lengths actually generate s2 by repeating the
 * corresponding prefix of s1.
 */
private static int countMatchingDivisors(String s1, String s2, List<Integer> divisors) {
    int matches = 0;
    for (int p : divisors) {
        if (buildsFromPrefix(s1, s2, p)) {
            matches++;
        }
    }
    return matches;
}

/**
 * Returns true when repeating the prefix of s1 with length p (n2/p) times
 * yields exactly s2.
 */
private static boolean buildsFromPrefix(String s1, String s2, int p) {
    String token = s1.substring(0, p);
    int repeat = s2.length() / p;
    StringBuilder sb = new StringBuilder(repeat * p);
    for (int i = 0; i < repeat; i++) {
        sb.append(token);
    }
    return sb.toString().equals(s2);
}

