/**
 * Performs the three early‑rejection tests present in the original code.
 * Returns true if the pair of strings cannot possibly match, meaning the
 * caller should output 0.
 */
private static boolean shouldReject(String s1, String s2) {
    int n1 = s1.length();
    int n2 = s2.length();

    // identical length but different content
    if (n1 == n2 && !s1.equals(s2)) {
        return true;
    }

    // s1 is a prefix of s2?
    if (n1 <= n2 && !s2.substring(0, n1).equals(s1)) {
        return true;
    }

    // s2 is a prefix of s1?
    if (n2 <= n1 && !s1.substring(0, n2).equals(s2)) {
        return true;
    }

    return false;
}

/**
 * Returns a list containing all positive integers that divide BOTH n1 and n2.
 * The algorithm mirrors the original nested‑loop logic.
 */
private static List<Integer> commonDivisors(int n1, int n2) {
    List<Integer> divisors = new ArrayList<>();

    int limit = Math.min(n1, n2);
    for (int d = 1; d <= limit; d++) {
        if (n1 % d == 0 && n2 % d == 0) {
            if (!divisors.contains(d)) {
                divisors.add(d);
            }
            // also add the complementary divisor n1/d if it divides n2
            int complement = n1 / d;
            if (n2 % complement == 0 && !divisors.contains(complement)) {
                divisors.add(complement);
            }
        }
    }
    return divisors;
}

/**
 * Counts how many divisors from the supplied list can be used to build s2
 * by repeating the prefix of s1 of length divisor.
 */
private static int countMatchingDivisors(String s1, String s2, List<Integer> divisors) {
    int matches = 0;
    int n2 = s2.length();

    for (int p : divisors) {
        String token = s1.substring(0, p);
        int repetitions = n2 / p;

        StringBuilder builder = new StringBuilder(repetitions * p);
        for (int i = 0; i < repetitions; i++) {
            builder.append(token);
        }

        if (builder.toString().equals(s2)) {
            matches++;
        }
    }
    return matches;
}

