/**
 * Rules out each distinct letter that appears in {@code word}.
 *
 * @return the number of letters that became ruled out by this operation
 */
private static int applyDot(String word, boolean[] ruledOut) {
    int newlyRuled = 0;
    for (int i = 0; i < word.length(); i++) {
        int idx = word.charAt(i) - 'a';
        if (!ruledOut[idx]) {
            ruledOut[idx] = true;
            newlyRuled++;
        }
    }
    return newlyRuled;
}

/**
 * Keeps only the letters present in {@code word} and rules out all others.
 *
 * @return the number of letters that became ruled out by this operation
 */
private static int applyExclamation(String word, boolean[] ruledOut, boolean[] tmp) {
    // mark letters that appear in the word
    for (int i = 0; i < word.length(); i++) {
        int idx = word.charAt(i) - 'a';
        tmp[idx] = true;
    }

    int newlyRuled = 0;
    for (int j = 0; j < 26; j++) {
        if (!ruledOut[j] && !tmp[j]) {
            ruledOut[j] = true;
            newlyRuled++;
        }
    }
    return newlyRuled;
}

/**
 * Rules out the single guessed letter {@code guess}.
 *
 * @return 1 if the letter was not already ruled out, otherwise 0
 */
private static int applyQuestion(String guess, boolean[] ruledOut) {
    int idx = guess.charAt(0) - 'a';
    if (!ruledOut[idx]) {
        ruledOut[idx] = true;
        return 1;
    }
    return 0;
}

