/** Builds the array of Node where each Node.list holds the 1‑based positions
 *  of the corresponding value in the input array. */
private static Node[] buildValuePositions(int[] arr, int n) {
    Node[] dp = new Node[n + 1];
    for (int i = 1; i <= n; i++) {
        dp[i] = new Node();
    }
    for (int i = 0; i < n; i++) {
        dp[arr[i]].list.add(i + 1);   // store positions as 1‑based
    }
    return dp;
}

/** Returns the minimum gap among all values, or 0 if any value occupies every index. */
private static int calculateMinGap(Node[] dp, int n) {
    int minGap = Integer.MAX_VALUE;

    for (int i = 1; i <= n; i++) {
        if (dp[i].list.isEmpty()) {
            continue;
        }

        List<Integer> list = new ArrayList<>(dp[i].list);
        if (list.size() == n) {          // value appears in every position
            return 0;
        }

        int gap = computeGap(list, n);
        if (gap < minGap) {
            minGap = gap;
        }
    }
    return minGap;
}

/** Computes the number of “gaps” for a single value’s position list. */
private static int computeGap(List<Integer> list, int n) {
    int gap = 0;

    // Gap before the first occurrence
    if (!list.isEmpty() && list.get(0) > 1) {
        gap++;
    }

    // Gaps between consecutive occurrences
    for (int j = 0; j < list.size() - 1; j++) {
        if (list.get(j) + 1 < list.get(j + 1)) {
            gap++;
        }
    }

    // Gap after the last occurrence
    if (!list.isEmpty() && list.get(list.size() - 1) < n) {
        gap++;
    }

    return gap;
}

