/**
 * Flips the value at the given zero‑based position and updates the count of ones.
 *
 * @param arr          the array holding 0/1 values
 * @param position     zero‑based index to toggle
 * @param currentCount current number of elements equal to 1
 * @return the new count of ones after the toggle
 */
private static long toggle(Long[] arr, int position, long currentCount) {
    if (arr[position] == 1) {
        arr[position] = 0L;
        return currentCount - 1;
    } else {
        arr[position] = 1L;
        return currentCount + 1;
    }
}

