public void solve(InputReader in, PrintWriter out) {
    long n = in.nextLong();
    long k = in.nextLong();

    // 1. Trivial Yes case
    if (isTrivialYesCase(n, k)) {
        out.println("Yes");
        return;
    }

    // 2. k is not allowed to be >= n
    if (isKTooLarge(n, k)) {
        out.println("No");
        return;
    }

    // 3. Even n with k > 1 is impossible
    if (isEvenAndKGreaterThanOne(n, k)) {
        out.println("No");
        return;
    }

    // 4. Duplicate remainders detection
    if (hasDuplicateRemainders(n, k)) {
        out.println("No");
        return;
    }

    // 5. Perfect‑square shortcut
    if (isPerfectSquareWithinK(n, k)) {
        out.println("No");
        return;
    }

    // All checks passed
    out.println("Yes");
}

/** Returns true when the input satisfies the immediate “Yes” condition. */
private boolean isTrivialYesCase(long n, long k) {
    return n == 1 && k <= 2;
}

/** Returns true when k is greater than or equal to n (answer must be “No”). */
private boolean isKTooLarge(long n, long k) {
    return k >= n;
}

/** Returns true when n is even and k > 1 (answer must be “No”). */
private boolean isEvenAndKGreaterThanOne(long n, long k) {
    return (n % 2 == 0) && k > 1;
}

/**
 * Returns true if, while iterating i = 1 … min(k, MAX),
 * a remainder n % i repeats (answer must be “No”).
 */
private boolean hasDuplicateRemainders(long n, long k) {
    HashSet<Long> seen = new HashSet<>();
    long limit = Math.min(k, MAX);
    for (long i = 1; i <= limit; i++) {
        long rem = n % i;
        if (seen.contains(rem)) {
            return true;
        }
        seen.add(rem);
    }
    return false;
}

/**
 * Returns true when n is a perfect square whose root is ≤ k
 * (answer must be “No”).
 */
private boolean isPerfectSquareWithinK(long n, long k) {
    long sqrt = (long) Math.sqrt(n);
    return sqrt * sqrt == n && sqrt <= k;
}

