/* ---------- helper methods ---------- */

private boolean isTrivialYes(long n, long k) {
    return n == 1 && k <= 2;
}

/**
 * Handles the three quick‑fail conditions:
 *   • k ≥ n
 *   • n is even and k > 1
 */
private boolean isImmediateNo(long n, long k) {
    if (k >= n) {
        return true;
    }
    return n % 2 == 0 && k > 1;
}

/**
 * Returns true if some remainder n % i repeats for
 * i = 1 … min(k, MAX). The loop is unchanged; only the
 * containment logic is extracted.
 */
private boolean hasDuplicateRemainder(long n, long k) {
    HashSet<Long> seen = new HashSet<>();
    long limit = Math.min(k, MAX);
    for (long i = 1; i <= limit; i++) {
        long rem = n % i;
        if (seen.contains(rem)) {
            return true;
        }
        seen.add(rem);
    }
    return false;
}

/**
 * Checks whether n is a perfect square whose root does not
 * exceed k. If so, the answer must be “No”.
 */
private boolean isSquareWithinLimit(long n, long k) {
    long sqrt = (long) Math.sqrt(n);
    return sqrt * sqrt == n && sqrt <= k;
}

