        out.println(segments.size());
        return;
    }

    linkSegments(segments);
    TreeSet<Segment> set = createOrderedSet(segments);
    int ans = processSegments(set);
    out.println(ans);
}

/** Build the list of maximal equal‑value runs. */
private List<Segment> buildSegments(int[] a, int n) {
    List<Segment> segments = new ArrayList<>();
    for (int l = 0, r = 0; l < n; ) {
        while (r < n && a[r] == a[l]) r++;
        segments.add(new Segment(l, r, a[l], r - l));
        l = r;
    }
    return segments;
}

/** Wire each segment with its predecessor and successor. */
private void linkSegments(List<Segment> segs) {
    segs.get(0).next = segs.get(1);
    segs.get(segs.size() - 1).prev = segs.get(segs.size() - 2);
    for (int i = 1; i < segs.size() - 1; i++) {
        segs.get(i).prev = segs.get(i - 1);
        segs.get(i).next = segs.get(i + 1);
    }
}

/** Create a TreeSet that orders the segments (uses Segment.compareTo). */
private TreeSet<Segment> createOrderedSet(List<Segment> segs) {
    TreeSet<Segment> set = new TreeSet<>();
    for (Segment seg : segs) set.add(seg);
    return set;
}

/** Main processing loop – removes segments until the set empties. */
private int processSegments(TreeSet<Segment> set) {
    int ans = 0;
    while (!set.isEmpty()) {
        ans++;
        Segment seg = set.pollFirst();          // smallest segment
        boolean stop = handlePoppedSegment(seg, set);
        if (stop) break;
    }
    return ans;
}

/**
 * Handles the logic for a segment that has just been removed from the set.
 * Returns true if the algorithm should terminate immediately.
 */
private boolean handlePoppedSegment(Segment seg, TreeSet<Segment> set) {
    // isolated segment – nothing else to do
    if (seg.prev == null && seg.next == null) return true;

    // one‑sided neighbours
    if (seg.prev == null) {
        seg.next.prev = null;
        return false;
    }
    if (seg.next == null) {
        seg.prev.next = null;
        return false;
    }

    // both neighbours exist
    if (seg.prev.x != seg.next.x) {
        seg.prev.next = seg.next;
        seg.next.prev = seg.prev;
    } else {
        // neighbours have the same value → merge them
        Segment left  = seg.prev.prev;
        Segment right = seg.next.next;

        set.remove(seg.prev);
        set.remove(seg.next);

        Segment merged = new Segment(
                seg.prev.l,
                seg.next.r,
                seg.prev.x,
                seg.prev.sz + seg.next.sz
        );

        merged.prev = left;
        if (left != null) left.next = merged;

        merged.next = right;
        if (right != null) right.prev = merged;

        set.add(merged);
    }
    return false;
}

