public static void main(String[] args) {
    Scanner scan = new Scanner(System.in);
    int N = scan.nextInt();
    int M = scan.nextInt();

    int T = computeInitialT(N, M);
    if (T > N) {
        System.out.println("Impossible");
        return;
    }
    if (N == M + 1) {
        System.out.println(0);
        return;
    }

    // -------------------------------------------------
    // Unused local class kept to respect the original code
    class Node {
        int a, i;
        Node(int a, int i) {
            this.a = a;
            this.i = i;
        }
    }
    // -------------------------------------------------

    int[] a = readValues(scan, N);
    initialiseUnionFind(N);
    readAndUnionEdges(scan, M);

    Map<Integer, PriorityQueue<Integer>> componentMap = buildComponentMap(a);
    long result = computeResult(componentMap, T);
    System.out.println(result);
}

/** Computes the initial value of T from N and M (the original formula). */
private static int computeInitialT(int N, int M) {
    int F = N - M;
    return (F - 1) * 2;
}

/** Reads N integers from the scanner into an array. */
private static int[] readValues(Scanner scan, int N) {
    int[] a = new int[N];
    for (int i = 0; i < N; ++i) {
        a[i] = scan.nextInt();
    }
    return a;
}

/** Allocates and clears the union‑find structure. */
private static void initialiseUnionFind(int N) {
    uf = new int[N];
    Arrays.fill(uf, -1);
}

/** Reads M edges and unions their vertices. */
private static void readAndUnionEdges(Scanner scan, int M) {
    int edges = M;
    while (edges-- > 0) {
        int x = scan.nextInt();
        int y = scan.nextInt();
        union(x, y);
    }
}

/** Builds a map from component root to a priority queue containing all
 *  values belonging to that component. */
private static Map<Integer, PriorityQueue<Integer>> buildComponentMap(int[] values) {
    Map<Integer, PriorityQueue<Integer>> map = new HashMap<>();
    for (int i = 0; i < values.length; ++i) {
        int root = root(i);
        map.computeIfAbsent(root, k -> new PriorityQueue<>())
           .add(values[i]);
    }
    return map;
}

/** Calculates the final answer using the component map and the remaining
 *  number of selections T. */
private static long computeResult(Map<Integer, PriorityQueue<Integer>> componentMap, int T) {
    long sum = 0L;
    PriorityQueue<Integer> leftover = new PriorityQueue<>();

    for (PriorityQueue<Integer> pq : componentMap.values()) {
        // The smallest element of each component must be taken
        sum += (long) pq.poll();
        --T;
        // Remaining elements become candidates for the global pool
        while (!pq.isEmpty()) {
            leftover.add(pq.poll());
        }
    }

    while (T-- > 0) {
        sum += leftover.poll();
    }
    return sum;
}

