 * Advances {@code bufi} past the sign and guarantees that the buffer is filled.
 *
 * @return {@code true} if the number is positive, {@code false} if a leading '-' was found.
 * @throws IOException if the underlying stream cannot be read.
 */
private boolean readSign() throws IOException {
    boolean positive = true;
    if (buf[bufi] == '-') {
        ++bufi;
        if (!pumpBuf()) {
            throw new RuntimeException("IO.nextInt: Invalid int.");
        }
        positive = false;
