 * Parses consecutive digit characters, handling delimiters, overflow,
 * and invalid characters. The value is accumulated as a negative number
 * (mirroring the original algorithm) and returned.
 *
 * @return the parsed integer, stored as a negative value.
 * @throws IOException if an I/O error occurs while pumping the buffer.
 */
private int readDigits() throws IOException {
    int ret = 0;
    boolean first = true;

    while (true) {
        if (!pumpBuf()) {
            break;
        }
        if (isDelimiter(buf[bufi])) {
            if (first) {
                throw new RuntimeException("IO.nextInt: Invalid int.");
            }
            break;
        }
        first = false;

        if (buf[bufi] >= '0' && buf[bufi] <= '9') {
            // Detect overflow before multiplying.
            if (ret < -214748364) {
                throw new RuntimeException("IO.nextInt: Invalid int.");
            }
            ret *= 10;
            ret -= (int) (buf[bufi] - '0');
            // After subtraction the value must remain non‑positive.
            if (ret > 0) {
                throw new RuntimeException("IO.nextInt: Invalid int.");
            }
        } else {
            throw new RuntimeException("IO.nextInt: Invalid int.");
        }
