            throw new RuntimeException("IO.nextInt: Invalid int.");
        return false; // number is negative (sign already consumed)
    }
    return true; // no sign → positive
}

/** Reads consecutive digit characters, performing delimiter and overflow checks.
 *  The value is accumulated as a negative number to simplify the MIN_VALUE case. */
private int readDigits() throws IOException {
    boolean first = true;
    int ret = 0;

    while (true) {
        if (!pumpBuf())
            break;

        if (isDelimiter(buf[bufi])) {
            if (first)
                throw new RuntimeException("IO.nextInt: Invalid int.");
            break;
        }

        first = false;

        if (buf[bufi] >= '0' && buf[bufi] <= '9') {
            // overflow guard: before multiplying by 10 we must be > Integer.MIN_VALUE/10
            if (ret < -214748364)
                throw new RuntimeException("IO.nextInt: Invalid int.");
            ret *= 10;
            ret -= (int) (buf[bufi] - '0');
            if (ret > 0) // should stay negative while building
                throw new RuntimeException("IO.nextInt: Invalid int.");
        } else {
            throw new RuntimeException("IO.nextInt: Invalid int.");
        }

        ++bufi;
    }
    return ret;
}

/** Converts the internally‑negative representation to the final signed int. */
private int applySign(int ret, boolean positive) {
    if (positive) {
        // the only positive value that cannot be represented as a negative int is MIN_VALUE
        if (ret == -2147483648)
            throw new RuntimeException("IO.nextInt: Invalid int.");
        return -ret;
    }
    return ret; // already negative
