/**
 * Handles an optional leading minus sign, delegates digit parsing,
 * and converts the internal negative representation to the correct
 * signed integer.
 */
private int parseSignedNumber() throws IOException {
    boolean positive = true;

    if (buf[bufi] == '-') {
        ++bufi;
        if (!pumpBuf()) {
            throw new RuntimeException("IO.nextInt: Invalid int.");
        }
        positive = false;
    }

    int ret = readNumber();               // ret is stored as a negative value

    if (positive) {
        if (ret == Integer.MIN_VALUE) {   // -2147483648 cannot be negated
            throw new RuntimeException("IO.nextInt: Invalid int.");
        }
        ret = -ret;                        // make it positive
    }

    return ret;
}

/**
 * Reads a consecutive sequence of decimal digits, stops at delimiters,
 * and performs overflow detection. The number is accumulated as a
 * negative integer (to simplify the overflow check).
 */
private int readNumber() throws IOException {
    int ret = 0;
    boolean first = true;

    while (true) {
        if (!pumpBuf()) {
            break;                         // end of input
        }

        if (isDelimiter(buf[bufi])) {
            if (first) {
                throw new RuntimeException("IO.nextInt: Invalid int.");
            }
            break;                         // delimiter ends the number
        }

        first = false;
        char ch = buf[bufi];

        if (ch >= '0' && ch <= '9') {
            if (ret < -214748364) {        // overflow guard
                throw new RuntimeException("IO.nextInt: Invalid int.");
            }
            ret *= 10;
            ret -= (ch - '0');             // keep value negative
            if (ret > 0) {                 // sanity check (should never happen)
                throw new RuntimeException("IO.nextInt: Invalid int.");
            }
        } else {
            throw new RuntimeException("IO.nextInt: Invalid int.");
        }

        ++bufi;
    }

    return ret;
}

