/**
 * Reads {@code n} strings from the given scanner and returns a frequency array
 * where index {@code i} holds the total occurrences of the character {@code ('a' + i)}.
 */
private static int[] buildFrequencyArray(Scanner sc, int n) {
    int[] count = new int[26];
    for (int i = 0; i < n; i++) {
        String str = sc.next();
        for (int j = 0; j < str.length(); j++) {
            count[str.charAt(j) - 'a']++;
        }
    }
    return count;
}

/**
 * Returns {@code true} if every entry in {@code count} is divisible by {@code n},
 * i.e., each character appears the same number of times in each of the {@code n} strings.
 */
private static boolean allCountsDivisibleBy(int[] count, int n) {
    for (int i = 0; i < 26; i++) {
        if (count[i] % n != 0) {
            return false;
        }
    }
    return true;
}

