private static List<Map<Integer, Long>> buildGraph(int n, int m) throws IOException {
    List<Map<Integer, Long>> g = new ArrayList<>(n);
    for (int i = 0; i < n; ++i) {
        g.add(new HashMap<>());
    }
    for (int i = 0; i < m; ++i) {
        int u = rni() - 1;
        int v = ni() - 1;
        int w = ni();
        addOrUpdateEdge(g, u, v, w);
        addOrUpdateEdge(g, v, u, w);
    }
    return g;
}

private static void addOrUpdateEdge(List<Map<Integer, Long>> g, int from, int to, int weight) {
    Map<Integer, Long> adj = g.get(from);
    long current = adj.getOrDefault(to, LBIG);
    adj.put(to, Math.min(weight, current));
}

/* Initialise distance array, parent‑type array and priority queue */
private static void initializeDistances(long[] dist, int[] parentType, PriorityQueue<long[]> pq) {
    java.util.Arrays.fill(dist, LBIG);
    dist[0] = 0;
    pq.offer(new long[] {0, 0});
}

/* Read the k extra sources (train stations) and push them into the queue */
private static void processInitialSources(int k, int[] parentType, long[] dist,
                                          PriorityQueue<long[]> pq) throws IOException {
    for (int i = 0; i < k; ++i) {
        int s = rni() - 1;
        int y = ni();
        dist[s] = Math.min(dist[s], y);
        parentType[s] = 1;          // mark as originating from a train
        pq.offer(new long[] {s, dist[s]});
    }
}

/* Classic Dijkstra implementation on the built graph */
private static void runDijkstra(List<Map<Integer, Long>> g, long[] dist,
                                PriorityQueue<long[]> pq) {
    while (!pq.isEmpty()) {
        long[] entry = pq.poll();
        long d = entry[1];
        int v = (int) entry[0];

        if (d > dist[v]) {
            continue;               // stale entry
        }

        for (Map.Entry<Integer, Long> e : g.get(v).entrySet()) {
            int to = e.getKey();
            long w = e.getValue();
            long nd = dist[v] + w;
            if (dist[to] > nd) {
                dist[to] = nd;
                pq.offer(new long[] {to, nd});
            }
        }
    }
}

/* After Dijkstra, any edge that satisfies dist[j] == dist[i] + w makes j a train‑type vertex */
private static void markShortestTreeEdges(List<Map<Integer, Long>> g, long[] dist,
                                          int[] parentType) {
    for (int i = 0; i < g.size(); ++i) {
        for (Map.Entry<Integer, Long> e : g.get(i).entrySet()) {
            int j = e.getKey();
            long w = e.getValue();
            if (dist[j] == dist[i] + w) {
                parentType[j] = 0; // not a direct train edge any more
            }
        }
    }
}

/* Count how many vertices are still marked as train‑originated */
private static int countTrainsUsed(int[] parentType) {
    int used = 0;
    for (int v : parentType) {
        used += v;
    }
    return used;
}

