/**
 * Reads the m time‑matrices, fills {@code time} and runs Floyd‑Warshall on each.
 */
private void readTimesAndRunFloyd(int m, int n) {
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            for (int k = 0; k < n; ++k) {
                time[i][j][k] = in.nextInt();
            }
        }
        floyd(time[i], n);
    }
}

/**
 * Builds {@code dist[0]} – the best direct travel time between any two cities
 * when no swaps are used.
 */
private void initialiseBaseDist(int m, int n) {
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            int cur = INF;
            for (int k = 0; k < m; ++k) {
                cur = Math.min(cur, time[k][i][j]);
            }
            dist[0][i][j] = cur;
        }
    }
}

/**
 * Extends the distance matrix for every possible number of swaps (1 … n‑1)
 * using the recurrence:
 *   dist[u][i][j] = min( dist[u‑1][i][j],
 *                       min_k ( dist[0][i][k] + dist[u‑1][k][j] ) )
 */
private void computeDistWithSwaps(int maxK, int n) {
    for (int u = 1; u < maxK; ++u) {
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                int cur = dist[u - 1][i][j];
                for (int k = 0; k < n; ++k) {
                    cur = Math.min(cur, dist[0][i][k] + dist[u - 1][k][j]);
                }
                dist[u][i][j] = cur;
            }
        }
    }
}

/**
