 */
private void answerQueries(int r, int n) {
    for (int i = 0; i < r; ++i) {
        int from = in.nextInt() - 1;
        int to = in.nextInt() - 1;
        int swaps = Math.min(in.nextInt(), n - 1);
        out.println(dist[swaps][from][to]);
    }
}

