        int maxForward = computeMaxXor(a, false);
        int maxReverse = computeMaxXor(a, true);
        int max = Math.max(maxForward, maxReverse);

        System.out.println(max);
    }
}

/**
 * Scans the array either from left‑to‑right (reverse == false) or
 * right‑to‑left (reverse == true), maintaining a monotonic decreasing stack.
 * For every pair of adjacent values in the stack it computes the xor and
 * returns the maximum xor seen during the scan.
 */
private static int computeMaxXor(int[] a, boolean reverse) {
    Stack<Integer> st = new Stack<>();
    int max = 0;

    int start = reverse ? a.length - 1 : 0;
    int end   = reverse ? -1          : a.length;
    int step  = reverse ? -1          : 1;

    for (int i = start; i != end; i += step) {
        while (!st.isEmpty() && a[i] > st.peek()) {
            st.pop();
        }
        st.push(a[i]);

        if (st.size() >= 2) {
            int t1 = st.pop();
            int t2 = st.pop();
            max = Math.max(max, t1 ^ t2);
            st.push(t2);
            st.push(t1);
        }
    }
    return max;
}

public static void main(String[] args) throws java.lang.Exception {
    Input s = new Input(System.in);
    int t = 1;
    while (t-- > 0) {
        int n = s.nextInt();
        int a[] = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = s.nextInt();
        }

        int max = Math.max(computeMaxXor(a, true), computeMaxXor(a, false));
        System.out.println(max);
    }
}

/**
 * Computes the maximum XOR of two consecutive elements that appear on the stack
 * while scanning the array either from left‑to‑right (forward = true) or
 * right‑to‑left (forward = false).
 *
 * The algorithm mirrors the original nested‑loop logic:
 *   • Maintain a monotonic decreasing stack.
 *   • After each push, if the stack has at least two elements, evaluate the XOR
 *     of the top two and keep the maximum seen so far.
 *
 * @param arr     the input array
 * @param forward true for left‑to‑right scan, false for right‑to‑left scan
 * @return the maximum XOR found during this scan
 */
private static int computeMaxXor(int[] arr, boolean forward) {
    Stack<Integer> st = new Stack<>();
    int max = 0;
    int n = arr.length;

    if (forward) {
        for (int i = 0; i < n; i++) {
            processElement(arr[i], st);
            max = Math.max(max, evaluateTopTwo(st));
        }
    } else {
        for (int i = n - 1; i >= 0; i--) {
            processElement(arr[i], st);
            max = Math.max(max, evaluateTopTwo(st));
        }
    }
    // No need to clear the stack; it will be garbage‑collected.
    return max;
}

/**
 * Pushes the current value onto the stack after discarding any smaller values.
 *
 * @param value current array element
 * @param st    stack used for the monotonic‑decreasing property
 */
private static void processElement(int value, Stack<Integer> st) {
    while (!st.isEmpty() && value > st.peek()) {
        st.pop();
    }
    st.push(value);
}

/**
 * If the stack contains at least two elements, computes the XOR of the top two,
 * restores the stack to its original state, and returns that XOR; otherwise returns 0.
 *
 * @param st stack whose top two elements are examined
 * @return XOR of the two top elements or 0 if fewer than two elements exist
 */
private static int evaluateTopTwo(Stack<Integer> st) {
    if (st.size() < 2) {
        return 0;
    }
    int t1 = st.pop();
    int t2 = st.pop();
    int xor = t1 ^ t2;
    // Restore original order
    st.push(t2);
    st.push(t1);
    return xor;
}

