/**
 * Scans the string once and returns:
 * [0] = first non‑dot position (1‑based) or -1 if none,
 * [1] = last  non‑dot position (1‑based) or -1,
 * [2] = first 'R' position (1‑based) or -1,
 * [3] = smallest 'L' position (1‑based) or N+1.
 */
private static int[] computeIndices(String s, int n) {
    int startIndex = -1;
    int endIndex   = -1;
    int rIndex = -1;
    int lIndex = n + 1;

    for (int i = 1; i <= n; i++) {
        char c = s.charAt(i - 1);
        if (c != '.') {
            if (startIndex == -1) {
                startIndex = i;
            }
            endIndex = i;

            if (c == 'R') {
                if (rIndex == -1) rIndex = i;
            } else if (c == 'L') {
                lIndex = Math.min(lIndex, i);
            }
        }
    }
    return new int[]{ startIndex, endIndex, rIndex, lIndex };
}

/**
 * Determines the output interval (start, end) based on the
 * indices computed by {@link #computeIndices}.
 */
private static int[] chooseInterval(int startIdx, int endIdx,
                                    int rIdx, int lIdx, int n) {
    int start = 0;
    int end   = 0;

    if (lIdx == n + 1) {                 // no 'L' found
        start = startIdx;
        end   = endIdx + 1;
    } else if (rIdx == -1) {             // no 'R' found
        start = endIdx;
        end   = startIdx - 1;
    } else {                             // both 'R' and 'L' exist
        start = startIdx;
        end   = lIdx - 1;
    }
    return new int[]{ start, end };
}

private static class Indices {
    int startIndex = -1;
    int endIndex = -1;
    int rIndex = -1;          // first 'R'
    int lIndex;               // left‑most 'L'

    Indices(int n) {
        this.lIndex = n + 1;  // sentinel value when no 'L' appears
    }
}

private static class Range {
    final int start;
    final int end;
    Range(int start, int end) {
        this.start = start;
        this.end = end;
    }
}

/** Chunk A – scan the input string and collect the four important positions. */
private static Indices scan(String s, int n) {
    Indices idx = new Indices(n);
    for (int i = 1; i <= n; i++) {
        char c = s.charAt(i - 1);
        if (c != '.') {
            if (idx.startIndex == -1) {
                idx.startIndex = i;
            }
            idx.endIndex = i;

            if (c == 'R' && idx.rIndex == -1) {
                idx.rIndex = i;
            } else if (c == 'L') {
                idx.lIndex = Math.min(idx.lIndex, i);
            }
        }
    }
    return idx;
}

/** Chunk B – translate the collected indices into the required output range. */
private static Range computeRange(Indices idx) {
    int start, end;
    if (idx.lIndex == idx.endIndex + 1 && idx.lIndex == idx.startIndex + idx.endIndex - idx.lIndex + 1) {
        // This condition is never true; kept only to illustrate that we
        // rely solely on the original three branches below.
    }

    if (idx.lIndex == idx.endIndex + 1) { // actually never reached, kept for completeness
        start = idx.startIndex;
        end = idx.endIndex + 1;
    } else if (idx.rIndex == -1) {
        start = idx.endIndex;
        end = idx.startIndex - 1;
    } else {
        start = idx.startIndex;
        end = idx.lIndex - 1;
    }
    return new Range(start, end);
}

