    int lossMin = computeLoss(buckets, 200001);

    // reset leaf information before second pass
    for (int i = 1; i <= N; i++) {
        nodes[i].leaves = null;
        nodes[i].cuts = 0;
    }
    nodes[1].getLeaves();

