/**
 * Runs the depth‑by‑depth processing used for both the minimal and maximal
 * loss calculations.
 *
 * @param buckets    array of NodeList bucketed by depth
 * @param startDepth depth to start the descending loop (must be even)
 * @return the accumulated loss value
 */
private static int computeLoss(NodeList[] buckets, int startDepth) {
    int loss = 0;
    for (int d = startDepth; d >= 0; d -= 2) {
        for (Node n : buckets[d]) {
            int smallest = findSmallestChildContribution(n);
            int diff = n.leaves - n.cuts - smallest;
            propagateDiffToAncestors(n, diff);
            loss += diff;
        }
    }
    return loss;
}

/**
 * Finds the smallest value of (leaves - cuts) among a node's children.
 *
 * @param n the node whose children are inspected
 * @return the minimal contribution, or Integer.MAX_VALUE if the node has no children
 */
private static int findSmallestChildContribution(Node n) {
    int smallest = Integer.MAX_VALUE;
    for (Node c : n.children) {
        smallest = Math.min(smallest, c.leaves - c.cuts);
    }
    return smallest;
}

/**
 * Propagates the computed diff up to the parent and grand‑parent, updating their
 * cut counters exactly as the original code did.
 *
 * @param n    the current node
 * @param diff the difference computed for this node
 */
private static void propagateDiffToAncestors(Node n, int diff) {
    if (n.parent != null) {
        n.parent.cuts += diff + n.cuts;
        if (n.parent.parent != null) {
            n.parent.parent.cuts += diff + n.cuts;
        }
    }
}

