/** allocate an array of empty adjacency lists */
private static List<Integer>[] createAdjacencyList(int n) {
    @SuppressWarnings("unchecked")
    List<Integer>[] g = new List[n];
    for (int i = 0; i < n; i++) {
        g[i] = new LinkedList<>();
    }
    return g;
}

/** read the directed edges and fill `canJumpOver` for edges that point to the last element */
private static void readEdges(FastScanner in, int m, List<Integer>[] g,
                              boolean[] canJumpOver, int target) {
    for (int i = 0; i < m; i++) {
        int u = in.ni() - 1;
        int v = in.ni() - 1;
        g[u].add(v);
        if (v == target) {
            canJumpOver[u] = true;
        }
    }
}

/** core algorithm: walk the permutation from right to left and count valid swaps */
private static int computeAnswer(int[] p, List<Integer>[] g,
                                 boolean[] canJumpOver, boolean[] blockers) {
    int nBlockers = 0;
    int answer = 0;

    for (int i = p.length - 2; i >= 0; i--) {
        int node = p[i] - 1;

        if (!canJumpOver[node]) {
            // this position cannot jump over the last element → it becomes a blocker
            blockers[node] = true;
            nBlockers++;
        } else {
            int swaps = countSwapsToBlockers(node, g, blockers);
            if (swaps == nBlockers) {
                // all current blockers are reachable via a swap → count this as a good answer
                answer++;
            } else {
                // otherwise the node itself becomes a blocker
                blockers[node] = true;
                nBlockers++;
            }
        }
    }
    return answer;
}

/** count how many outgoing edges of `node` go to positions that are already blockers */
private static int countSwapsToBlockers(int node, List<Integer>[] g, boolean[] blockers) {
    int count = 0;
    for (int v : g[node]) {
        if (blockers[v]) {
            count++;
        }
    }
    return count;
}

