/**
 * Returns a fresh copy of the given character array.
 */
private static char[] copyArray(char[] src) {
    char[] dest = new char[src.length];
    System.arraycopy(src, 0, dest, 0, src.length);
    return dest;
}

/**
 * Constructs the candidate array that results from choosing rotation index {@code i}.
 *
 * The construction mirrors the original nested logic:
 *  - copy the suffix starting at position i‑1,
 *  - then either append the prefix in forward order (even length) or reverse order (odd length).
 *
 * @param c the original character array
 * @param i the 1‑based rotation index
 * @param n length of the array
 * @return the newly built candidate array
 */
private static char[] buildCandidate(char[] c, int i, int n) {
    int len = n - i + 1;               // length of the suffix part
    char[] x = new char[n];

    // copy suffix part (positions i‑1 … n‑1) to the front of x
    for (int j = i - 1; j < n; j++) {
        x[j - i + 1] = c[j];
    }

    // handle even / odd length of the suffix
    if (len % 2 == 0) {
        // even: copy the prefix (0 … i‑2) in the same order
        for (int j = 0; j < i - 1; j++) {
            x[len + j] = c[j];
        }
    } else {
        // odd: copy the prefix in reverse order
        int ind = len;
        for (int j = i - 2; j >= 0; j--) {
            x[ind++] = c[j];
        }
    }

    return x;
}

/**
 * Placeholder for the original comparison routine.
 * It returns true if {@code a} is lexicographically smaller than {@code b}.
 */
private static boolean compare(char[] a, char[] b) {
    // The original implementation is assumed to exist elsewhere.
    // Here we provide a simple lexicographic comparison to keep the code compile‑able.
    for (int i = 0; i < a.length; i++) {
        if (a[i] != b[i]) {
            return a[i] < b[i];
        }
    }
    return false; // equal arrays are not "less"
}

