    // copy suffix (c[i‑1] … c[n‑1]) to the start of result
    for (int j = pivot - 1; j < length; j++) {
        result[j - pivot + 1] = source[j];
    }

    if (len % 2 == 0) {
        // even suffix length → copy prefix in original order
        for (int j = 0; j < pivot - 1; j++) {
            result[len + j] = source[j];
        }
    } else {
        // odd suffix length → copy prefix in reverse order
        int idx = len;
        for (int j = pivot - 2; j >= 0; j--) {
            result[idx++] = source[j];
        }
    }

    return result;
}

public static void main(String[] args) throws Exception {
    BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
    PrintWriter pw = new PrintWriter(System.out);

    int t = Integer.parseInt(br.readLine());
    while (t-- > 0) {
        int n = Integer.parseInt(br.readLine());
        char[] c = br.readLine().toCharArray();

        char[] min = copyArray(c);
        int val = 1;

        for (int i = 2; i <= n; i++) {
            char[] candidate = buildCandidate(i, n, c);
            if (compare(min, candidate)) {
                min = candidate;
                val = i;
            }
        }

        pw.println(min);
        pw.println(val);
    }

    pw.flush();
    pw.close();
}

/**
 * Returns a fresh copy of the supplied character array.
 */
private static char[] copyArray(char[] source) {
    char[] copy = new char[source.length];
    System.arraycopy(source, 0, copy, 0, source.length);
    return copy;
}

/**
 * Constructs the candidate array for a given pivot {@code i}.
 *
 * The algorithm corresponds to the original nested logic that:
 *   • Takes the suffix starting at position i‑1,
 *   • Appends either the prefix in original order (even length) or reversed order (odd length).
 *
 * @param i        1‑based pivot position (2 ≤ i ≤ n)
 * @param n        total length of the original array
 * @param original the original character array
 * @return a new character array of length {@code n} representing the rotated candidate.
 */
private static char[] buildCandidate(int i, int n, char[] original) {
    int len = n - i + 1;                 // length of the suffix that moves to the front
    char[] result = new char[n];

    // Copy the suffix (positions i‑1 … n‑1) to the front of result.
    for (int j = i - 1; j < n; j++) {
        result[j - i + 1] = original[j];
    }

    if (len % 2 == 0) {
        // Even length: copy the prefix (0 … i‑2) directly after the suffix.
        for (int j = 0; j < i - 1; j++) {
            result[len + j] = original[j];
        }
    } else {
        // Odd length: copy the prefix in reverse order.
        int idx = len;
        for (int j = i - 2; j >= 0; j--) {
            result[idx++] = original[j];
        }
    }
    return result;
}

