/**
 * Chunk 1 – reads the input array, populates the frequency table
 * and collects the distinct values that actually appear.
 */
private static void readArrayAndCount(int n,
                                      Scanner in,
                                      int[] f,
                                      int[] needOnF,
                                      List<Integer> distinct) {
    for (int i = 0; i < n; i++) {
        f[i] = in.nextInt();
        needOnF[f[i]]++;
        if (!distinct.contains(f[i])) {
            distinct.add(f[i]);
        }
    }
