/**
 * Chunk 2 – sets the initial amount of tokens at position 0.
 */
private static void initializeHaveOnF(int[] haveOnF, int n) {
    haveOnF[0] = n;   // the rest are already zero
}

/**
 * Chunk 3 + 4 – core processing loop and final adjustment.
 * Returns the sum computed by the original algorithm.
 */
private static int computeSum(List<Integer> values,
                              int[] haveOnF,
                              int[] needOnF,
                              int k) {
    int sum = 0;
    int rem = haveOnF[0] - needOnF[0]; // initially n
    int ind = 1;                       // start from the second distinct value

    while (rem > 0 && ind < values.size()) {
        int current = values.get(ind);
        int previous = values.get(ind - 1);
        int take = Math.min(rem, k);

        rem -= take;
        sum += (current - previous);
        haveOnF[current] += take;
        haveOnF[previous] -= take;

        if (rem > 0) {
            sum += (current - previous);
        } else {
            rem = haveOnF[current] - needOnF[current];
            ind++;
        }
    }

    // final contribution (identical to the original code)
    sum += values.get(ind - 1) - values.get(0);
    return sum;
}

