    List<Integer> distinctValues = readAndInitialize(n, f, needonf);

    // Chunk B – initialise helper arrays and obtain the first ‘rem’
    int initialRem = prepareArrays(n, haveonf, needonf);

    // Chunk C & D – run the core algorithm and obtain the result
    int sum = computeSum(k, haveonf, needonf, distinctValues, initialRem);

    out.println(sum);
}

/**
 * Reads the n integers, fills the f array, updates needonf,
 * and returns a sorted list containing the distinct values that appear.
 */
private List<Integer> readAndInitialize(int n, int[] f, int[] needonf) {
    List<Integer> values = new ArrayList<>();
    values.add(1);                     // the sentinel value used later
    for (int i = 0; i < n; i++) {
        f[i] = in.nextInt();
        needonf[f[i]]++;
        if (!values.contains(f[i])) {
            values.add(f[i]);
        }
    }
    Collections.sort(values);
    return values;
}

/**
 * Sets the sentinel entries (frequency 0) and returns the first
 * amount of “remaining” tokens that still need to be moved.
 */
private int prepareArrays(int n, int[] haveonf, int[] needonf) {
    haveonf[0] = n;
    needonf[0] = 0;
    int fl = 0;
    return haveonf[fl] - needonf[fl];
}

/**
 * Executes the main loop that moves tokens between frequencies,
 * accumulates the distance sum, and adds the final adjustment.
 */
private int computeSum(int k,
                       int[] haveonf,
                       int[] needonf,
                       List<Integer> values,
                       int rem) {
    int sum = 0;
    int ind = 1;            // we start from the second element (index 1)
    int fl = 0;             // current frequency holder

    while (rem > 0 && ind < values.size()) {
        fl = values.get(ind);
        int take = Math.min(rem, k);
        rem -= take;

        // distance contributed by moving from previous value to current
        sum += (fl - values.get(ind - 1));

        // update have‑on‑frequency counts
        haveonf[fl] += take;
        haveonf[values.get(ind - 1)] -= take;

        if (rem > 0) {
            // still need to take more from the same segment
            sum += (fl - values.get(ind - 1));
        } else {
            // move to the next distinct value
            rem = haveonf[fl] - needonf[fl];
            ind++;
        }
    }

    // final adjustment after the loop finishes
    sum += values.get(ind - 1) - values.get(0);
    return sum;
}

