public static void solve(StringBuilder out) {
    int n = In.ni();
    long[] a = In.nl(n);

    long x = xorAll(a);

    // masks for bits that are 0 in x (rs) and 1 in x (rm)
    int[] rs = new int[64 - Long.bitCount(x)];
    int[] rm = new int[64 - rs.length];
    long ans = fillMasksAndAnswer(x, rs, rm);

    long[] b = removeBitsFromArray(a, rm);

    List<Long> bases = buildBasis(b);
    long y = maxXorFromBasis(bases);

    long h = rebuildH(y, rs);
    out.append(ans + (h << 1));
}

/* ----- extracted helpers ----- */

private static long xorAll(long[] arr) {
    long x = 0L;
    for (long v : arr) {
        x ^= v;
    }
    return x;
}

/**
 * Fills the arrays {@code rs} (positions of zero bits) and {@code rm}
 * (positions of one bits) for the value {@code x}. While doing so it also
 * constructs the partial answer {@code ans} which contains the bits of {@code x}
 * set to 1.
 */
private static long fillMasksAndAnswer(long x, int[] rs, int[] rm) {
    long ans = 0L;
    int mi = 0, si = 0;
    for (int i = 63; i >= 0; i--) {
        if (BitUtil.test(x, i)) {
            ans |= 1L << i;
            rm[mi++] = i;
        } else {
            rs[si++] = i;
        }
    }
    return ans;
}

/**
 * Returns a new array where, for every element, all bits listed in {@code rm}
 * have been cleared using {@code removeBit}.
 */
private static long[] removeBitsFromArray(long[] src, int[] rm) {
    int n = src.length;
    long[] dst = new long[n];
    for (int i = 0; i < n; i++) {
        long v = src[i];
        for (int bit : rm) {
            v = removeBit(v, bit);
        }
        dst[i] = v;
    }
    return dst;
}

/**
 * Builds a linear basis from the given array using the classic
 * Gaussian‑elimination‑over‑GF(2) method, then sorts it in descending order.
 */
private static List<Long> buildBasis(long[] arr) {
    List<Long> bases = new ArrayList<>();
    for (long e : arr) {
        for (long v : bases) {
            e = Math.min(e, e ^ v);
        }
        if (e != 0) {
            bases.add(e);
        }
    }
    Collections.sort(bases, Collections.reverseOrder());
    return bases;
}

/**
 * From a basis that is sorted in descending order, computes the maximum
 * obtainable XOR value.
 */
private static long maxXorFromBasis(List<Long> bases) {
    long y = 0L;
    for (long e : bases) {
        y = Math.max(y, y ^ e);
    }
    return y;
}

/**
 * Re‑maps the bits of {@code y} onto the original zero‑bit positions stored
 * in {@code rs} and returns the reconstructed value {@code h}.
 */
private static long rebuildH(long y, int[] rs) {
    long h = 0L;
    int len = rs.length;
    for (int i = 0; i < len; i++) {
        if (BitUtil.test(y, i)) {
            h |= 1L << rs[len - 1 - i];
        }
    }
    return h;
}

