    int[] rm = part.oneBits;

    long[] b = clearBitsInArray(a, rm);
    List<Long> basis = buildLinearBasis(b);
    long y = maxXorFromBasis(basis);
    long h = mapResultBits(y, rs);

    out.append(ans + (h << 1));
}

/*--------------------------------------------------------------
   Helper structures and functions – each isolates a logical chunk
  --------------------------------------------------------------*/

private static long xorAll(long[] arr) {
    long x = 0;
    for (long v : arr) {
        x ^= v;
    }
    return x;
}

/* Holds the partition of bit positions of a long value */
private static class PartitionResult {
    final long ans;        // bits that were set in the original value
    final int[] zeroBits;  // positions where the bit was 0
    final int[] oneBits;   // positions where the bit was 1

    PartitionResult(long ans, int[] zeroBits, int[] oneBits) {
        this.ans = ans;
        this.zeroBits = zeroBits;
        this.oneBits = oneBits;
    }
}

/* Splits the bits of x into the positions that are 0 (rs) and 1 (rm) */
private static PartitionResult partitionBits(long x) {
    int[] zeroBits = new int[64 - Long.bitCount(x)];
    int[] oneBits  = new int[Long.bitCount(x)];
    long ans = 0;
    for (int i = 63, mi = 0, zi = 0; i >= 0; i--) {
        if (BitUtil.test(x, i)) {
            ans |= 1L << i;
            oneBits[mi++] = i;
        } else {
            zeroBits[zi++] = i;
        }
    }
    return new PartitionResult(ans, zeroBits, oneBits);
}

/* Returns a new array where, for every element, all bits listed in rm are cleared */
private static long[] clearBitsInArray(long[] src, int[] rm) {
    long[] dest = new long[src.length];
    for (int i = 0; i < src.length; i++) {
        long v = src[i];
        for (int bitPos : rm) {
            v = removeBit(v, bitPos);
        }
        dest[i] = v;
    }
    return dest;
}

/* Constructs a linear basis (in decreasing order) from the values */
private static List<Long> buildLinearBasis(long[] values) {
    List<Long> basis = new ArrayList<>();
    for (long v : values) {
        for (long b : basis) {
            v = Math.min(v, v ^ b);
        }
        if (v != 0) {
            basis.add(v);
        }
    }
    basis.sort(Collections.reverseOrder());
    return basis;
}

/* From a linear basis, computes the maximal xor obtainable */
private static long maxXorFromBasis(List<Long> basis) {
    long y = 0;
    for (long b : basis) {
        y = Math.max(y, y ^ b);
    }
    return y;
}

/* Maps the bits of y onto the positions stored in rs (zero‑bit positions of x) */
private static long mapResultBits(long y, int[] rs) {
    long h = 0;
    for (int i = 0; i < rs.length; i++) {
        if (BitUtil.test(y, i)) {
            h |= 1L << rs[rs.length - 1 - i];
        }
    }
    return h;
}

