 * Returns "T" if the first player wins, otherwise "HL".
 */
private static String decideWinner(int[] sorted, int sum) {
    int n = sorted.length;
    // If the largest pile is larger than the sum of the rest, T wins immediately
    if (sorted[n - 1] * 2 > sum) {
        return "T";
    }
    // Otherwise, the parity of the total number of stones decides
    return (sum % 2 == 0) ? "HL" : "T";
}

