static int[] nextLargerElement(int[] arr, int n) {
    Stack<Integer> stack = new Stack<>();
    int[] result = new int[n];

    // The last element never has a larger element to its right
    result[n - 1] = -1;
    stack.push(n - 1);

    for (int i = n - 2; i >= 0; i--) {
        int currentValue = arr[i];

        // Chunk 1: pop smaller-or-equal elements and remember an equal‑value index
        int equalIdx = popSmallerOrEqual(stack, arr, currentValue);

        // Chunk 2: decide which index to store for position i
        result[i] = resolveResult(stack, equalIdx);

        // Chunk 3: push the current index for future iterations
        stack.push(i);
    }
    return result;
}

/**
 * Pops elements from the stack while they are less than or equal to {@code value}.
 * If an element equal to {@code value} is found, its index is remembered.
 *
 * @return the index of an equal element, or -1 if none was encountered.
 */
private static int popSmallerOrEqual(Stack<Integer> stack, int[] arr, int value) {
    int equalIdx = -1;
    while (!stack.isEmpty() && arr[stack.peek()] <= value) {
        if (arr[stack.peek()] == value) {
            equalIdx = stack.peek();
        }
        stack.pop();
    }
    return equalIdx;
}

/**
 * Determines the index to be written into the result array for the current position.
 *
 * @param stack    the stack after removing smaller-or-equal elements
 * @param equalIdx the index of an equal‑value element found while popping (or -1)
 * @return the appropriate index according to the original algorithm
 */
private static int resolveResult(Stack<Integer> stack, int equalIdx) {
    if (stack.isEmpty()) {
        return (equalIdx != -1) ? equalIdx : -1;
    } else {
        return stack.peek();
    }
}

public static int[] nextLargerElement(int[] arr, int n) {
    Stack<Integer> stack = new Stack<>();
    int[] rtrn = new int[n];
    rtrn[n - 1] = -1;
    stack.push(n - 1);

    for (int i = n - 2; i >= 0; i--) {
        int currentValue = arr[i];

        // 1️⃣ Remove elements that are not larger and remember an equal one, if any.
        int equalIdx = popWhileLessOrEqual(stack, arr, currentValue);

        // 2️⃣ Decide which index should be written to the result array.
        rtrn[i] = resolveResultIndex(stack, equalIdx);

        // 3️⃣ Push current position for future iterations.
        stack.push(i);
    }
    return rtrn;
}

/**
 * Pops indices from the stack while the corresponding array values are
 * less than or equal to {@code currentValue}. If an equal value is found,
 * its index is remembered and returned; otherwise {@code -1} is returned.
 */
private static int popWhileLessOrEqual(Stack<Integer> stack, int[] arr, int currentValue) {
    int equalIdx = -1;
    while (!stack.isEmpty() && arr[stack.peek()] <= currentValue) {
        if (arr[stack.peek()] == currentValue) {
            equalIdx = stack.peek();
        }
        stack.pop();
    }
    return equalIdx;
}

/**
 * Determines the index to store in the result array:
 * – If the stack still contains a larger element, that element’s index is used.
 * – If the stack is empty but an equal element was seen, its index is used.
 * – Otherwise {@code -1} is returned.
 */
private static int resolveResultIndex(Stack<Integer> stack, int equalIdx) {
    if (stack.isEmpty()) {
        return (equalIdx != -1) ? equalIdx : -1;
    }
    return stack.peek();
}

