/* ---------- helper methods ---------- */

private static int[] readAndSortArray(int n) throws IOException {
    int[] arr = new int[n];
    for (int i = 0; i < n; ++i) {
        arr[i] = in.readInt();
    }
    Arrays.sort(arr);
    return arr;
}

/**
 * Creates the DP table and applies the initial states that depend on the first element.
 */
private static boolean[][] createAndInitializeDp(int[] sortedValues, int k) {
    boolean[][] dp = new boolean[k + 1][k + 1];
    dp[0][0] = true;                              // empty selection

    int first = sortedValues[0];
    if (first <= k) {
        dp[first][first] = true;                  // take the first element as both total and subset sum
        dp[first][0] = true;                      // take the first element only in the total sum
    }
    return dp;
}

/**
 * Runs the classic 0/1‑knapsack style DP that populates reachable (total, subset) pairs.
 */
private static void fillDpTable(int[] values, int k, boolean[][] dp) {
    for (int i = 1; i < values.length; ++i) {
        int cur = values[i];
        if (cur > k) {
            break;                                 // larger values can never be part of a feasible total
        }
        for (int total = k - cur; total >= 0; --total) {
            for (int sub = total; sub >= 0; --sub) {
                if (dp[total][sub]) {
                    dp[total + cur][sub] = true;               // add cur to total only
                    dp[total + cur][sub + cur] = true;          // add cur to both total and subset
                }
            }
        }
    }
}

/**
 * Scans the DP row for the required total (k) and builds the output string.
 */
private static Result collectResult(boolean[][] dp, int k) {
    int count = 0;
    StringBuilder sb = new StringBuilder();
    for (int sub = 0; sub <= k; ++sub) {
        if (dp[k][sub]) {
            count++;
            sb.append(sub).append(' ');
        }
    }
    return new Result(count, sb);
}

/* ---------- tiny value object to carry the outcome ---------- */
private static final class Result {
    final int count;
    final StringBuilder builder;

    Result(int count, StringBuilder builder) {
        this.count = count;
        this.builder = builder;
    }
}

