/** Converts the input string into a 1‑based int array of digits. */
private int[] buildDigitArray(String s, int n) {
    int[] a = new int[n + 1];            // index 1 … n
    for (int i = 1; i <= n; i++) {
        a[i] = s.charAt(i - 1) - '0';
    }
    return a;
}

/** Computes the answer when k == 0 (simple base‑10 conversion). */
private long computeAnswerWhenKZero(int[] a, int n) {
    long ans = 0;
    long pow = 1;
    for (int i = n; i >= 1; i--) {
        ans = (ans + (a[i] * pow) % mod) % mod;
        pow = (pow * 10) % mod;
    }
    return ans;
}

/** Fills the auxiliary arrays `sum` and `pow` used later in the algorithm. */
private void fillSumAndPow(int n, int k, long[] sum, long[] pow) {
    pow[0] = 1;
    for (int i = 0; i <= n; i++) {
        if (i != 0) {
            sum[i] = sum[i - 1];
            pow[i] = (pow[i - 1] * 10) % mod;
        }
        int gaps = n - 2 - i;
        if (gaps >= k - 1) {
            long addition = (choose(gaps, k - 1) * pow[i]) % mod;
            sum[i] = (sum[i] + addition) % mod;
        }
    }
}

/** Computes the final answer using the pre‑filled `sum` and `pow` tables. */
private long computeAnswer(int[] a, int n, int k, long[] sum, long[] pow) {
    long ans = 0;
    for (int i = 1; i <= n; i++) {
        int r = n - i;

        if (r - 1 >= 0) {
            ans = (ans + (sum[r - 1] * a[i]) % mod) % mod;
        }
        if (i - 1 >= k) {
            long term = (pow[r] * choose(i - 1, k)) % mod;
            ans = (ans + (a[i] * term) % mod) % mod;
        }
    }
    return ans;
}

