/** Returns all divisors of {@code total} except 1. */
private Set<Integer> getDivisors(int total) {
    Set<Integer> divs = new HashSet<>();
    for (int i = 1; i * i <= total; i++) {
        if (total % i == 0) {
            divs.add(i);
            divs.add(total / i);
        }
    }
    divs.remove(1);
    return divs;
}

/** Computes the total score for a particular divisor {@code k}. */
private long computeScoreForDivisor(int k, int[] a) {
    long score = 0;
    int start = -1;
    int count = 0;
    for (int i = 0; i < a.length; i++) {
        count += a[i];
        if (count == 1 && a[i] == 1) {
            start = i;
        } else if (count == k) {
            int end = i;
            score += segmentScore(start, end, a);
            count = 0; // start a new segment
        }
    }
    return score;
}

/** Calculates the contribution of the segment [start, end] (inclusive). */
private long segmentScore(int start, int end, int[] a) {
    List<Integer> indices = new ArrayList<>();
    for (int j = start; j <= end; j++) {
        if (a[j] > 0) {
            indices.add(j);
        }
    }
    long segScore = 0;
    for (int x = 0, y = indices.size() - 1; x < y; x++, y--) {
        segScore += indices.get(y) - indices.get(x);
    }
    return segScore;
}

