/**
 * Builds the dpLeft array:
 * For each position i in s, dpLeft[i] stores the length of the longest
 * prefix of t that can be matched using characters s[0..i].
 */
private static int[] buildDpLeft(char[] s, char[] t) {
    int n = s.length;
    int m = t.length;
    int[] dpLeft = new int[n];
    int i = 0, j = 0, prev = 0;
    while (i < n && j < m) {
        if (s[i] == t[j]) {
            dpLeft[i++] = ++j;
            prev++;
        } else {
            dpLeft[i++] = prev;
        }
    }
    // If j reached m before i reaches n, the remaining positions keep the full match length.
    while (i < n) {
        dpLeft[i++] = prev;
    }
    return dpLeft;
}

/**
 * Builds the dpRight array:
 * For each position i in s (scanned from right to left), dpRight[i] stores
 * the length of the longest suffix of t that can be matched using characters
 * s[i..n‑1].
 */
private static int[] buildDpRight(char[] s, char[] t) {
    int n = s.length;
    int m = t.length;
    int[] dpRight = new int[n];
    int i = n - 1, j = m - 1, prev = 0;
    while (i >= 0 && j >= 0) {
        if (s[i] == t[j]) {
            dpRight[i--] = m - j;
            j--;
            prev++;
        } else {
            dpRight[i--] = prev;
        }
    }
    // Fill remaining positions if j went below 0.
    while (i >= 0) {
        dpRight[i--] = prev;
    }
    return dpRight;
}

