static boolean solve() {
    // Shortcut for odd number of vertices
    if (N % 2 == 1) {
        return ((N * (N - 1)) / 2 - E) % 2 != 0;
    }
    // No edges – impossible for even N
    if (E == 0) {
        return false;
    }

    // 1️⃣ Determine the parity of Taro's target condition
    boolean taroEven = isTaroEven();

    // 2️⃣ Count connected components by parity of their size
    int[] componentParity = countComponentParities(); // [evenCount, oddCount]
    int evenCount = componentParity[0];
    int oddCount  = componentParity[1];

    // 3️⃣ Apply the game‑logic decision based on the counted values
    return evaluateResult(taroEven, evenCount, oddCount);
}

/** Returns true if Taro's target parity is odd (i.e., the expression evaluates to true). */
private static boolean isTaroEven() {
    // ((N * (N - 1)) / 2 - E) % 2 != 0
    // The original name “taroEven” is kept for clarity, even though the condition checks for oddness.
    return ((N * (N - 1)) / 2 - E) % 2 != 0;
}

/**
 * Performs a BFS over the adjacency matrix {@code g} and counts how many connected
 * components have an even number of vertices and how many have an odd number.
 *
 * @return an array where result[0] = even‑size component count,
 *                result[1] = odd‑size component count.
 */
private static int[] countComponentParities() {
    boolean[] visited = new boolean[N];
    int evenCount = 0;
    int oddCount  = 0;

    for (int i = 0; i < N; ++i) {
        if (visited[i]) {
            continue;
        }

        int componentSize = bfsComponentSize(i, visited);
        if (componentSize % 2 == 0) {
            ++evenCount;
        } else {
            ++oddCount;
        }
    }
    return new int[] { evenCount, oddCount };
}

/**
 * Breadth‑first search that returns the size of the connected component
 * containing {@code start}. The {@code visited} array is updated in‑place.
 *
 * @param start   the vertex from which the BFS starts
 * @param visited array tracking already‑visited vertices
 * @return the number of vertices in this component
 */
private static int bfsComponentSize(int start, boolean[] visited) {
    int size = 1;
    visited[start] = true;

    ArrayDeque<Integer> queue = new ArrayDeque<>();
    queue.add(start);

    while (!queue.isEmpty()) {
        int v = queue.poll();
        for (int u = 0; u < N; ++u) {
            if (!visited[u] && g[v][u]) {
                ++size;
                visited[u] = true;
                queue.add(u);
            }
        }
    }
    return size;
}

/**
 * Applies the final game decision logic.
 *
 * @param taroEven   true if Taro's target parity condition is odd (as computed by {@link #isTaroEven()})
 * @param evenCount  number of connected components with even size
 * @param oddCount   number of connected components with odd size
 * @return the result of the original {@code solve()} method
 */
private static boolean evaluateResult(boolean taroEven, int evenCount, int oddCount) {
