/** Builds a TreeSet containing the integers 1 … max (inclusive). */
private static TreeSet<Integer> createAvailableSet(int max) {
    TreeSet<Integer> set = new TreeSet<>();
    for (int i = 1; i <= max; i++) {
        set.add(i);
    }
    return set;
}

/** Sorts the given list in descending order. */
private static void sortDescending(ArrayList<Integer> list) {
    Collections.sort(list, Comparator.reverseOrder());
}

/** Core algorithm that computes the required sum for one test case. */
private static long computeSum(TreeSet<Integer> available,
                               ArrayList<Integer> nlist,
                               ArrayList<Integer> mlist) {
    long sum = 0L;
    for (int idx = 0; idx < nlist.size(); idx++) {
        int needed = nlist.get(idx);
        int min = available.first();
        if (min < needed) {
            sum += mlist.get(min - 1);
            available.remove(min);
        } else {
            sum += mlist.get(needed - 1);
        }
    }
    return sum;
}

