/**
 * Converts the input string {@code s} into the {@code first} array.
 * Position 0 stays unused; positions 1..s.length() receive the digits.
 */
private int[] buildFirstArray(int x, String s) {
    int[] first = new int[x + 1];
    for (int i = 0; i < s.length(); i++) {
        if (first.length > i + 1) {
            first[i + 1] = s.charAt(i) - '0';
        }
    }
    return first;
}

/**
 * Executes the core expansion algorithm and returns the final value
 * {@code (l + r) % MOD}.
 */
private long calculateResult(int[] first, int x) {
    long l = 0;
    long r = first.length - 1;               // r starts as s.length()
    int firstPointer = (int) r;

    while (true) {
        l++;
        r--;

        if (r < 0) {
            r += MOD;
        }

        int sl = first[(int) l];

        // replicate the original nested loops
        for (int pt = 1; pt < sl && firstPointer < x; pt++) {
            for (int i = (int) l + 1;
                 firstPointer < x && i < l + 1 + r;
                 i++) {
                firstPointer++;
                first[firstPointer] = first[i];
            }
        }

        r = (sl * r) % MOD;

        if (l == x) {
            break;
        }
    }

    return (l + r) % MOD;
}

