private static HashMap<Integer, long[]> initialiseDP(int n) {
    HashMap<Integer, long[]> dp = new HashMap<>();
    dp.put(0, new long[n]);
    Arrays.fill(dp.get(0), -1L);
    return dp;
}

private static void performIteration(
        HashMap<Integer, long[]> dp,
        HashMap<Integer, long[]> next,
        long[][] v,
        long[] a,
        int n) {

    for (int mask : dp.keySet()) {
        for (int j = 0; j < n; j++) {
            int newMask = mask | (1 << j);
            if (newMask == mask) {
                continue;               // j already selected in this mask
            }

            long[] nextRow = next.computeIfAbsent(newMask, key -> {
                long[] row = new long[n];
                Arrays.fill(row, -1L);
                return row;
            });

            long best = 0L;
            long[] dpRow = dp.get(mask);
            for (int t = 0; t < n; t++) {
                if (dpRow[t] >= 0) {
                    best = Math.max(best, dpRow[t] + v[t][j]);
                }
            }
            best += a[j];
            nextRow[j] = Math.max(nextRow[j], best);
        }
    }
}

private static long computeAnswer(HashMap<Integer, long[]> dp, int n) {
    long ans = 0L;
    for (int mask : dp.keySet()) {
        long[] row = dp.get(mask);
        for (int i = 0; i < n; i++) {
            ans = Math.max(ans, row[i]);
        }
    }
    return ans;
}

