private static long[][] readTransitions(BufferedReader br, int n, int k) throws IOException {
    long[][] mat = new long[n][n];
    for (int i = 0; i < k; i++) {
        StringTokenizer st = getst(br);
        int from = nextInt(st) - 1;
        int to   = nextInt(st) - 1;
        long w   = nextInt(st);
        mat[from][to] = w;
    }
    return mat;
}

private static void initialiseDp(HashMap<Integer, long[]> dp, int n) {
    dp.put(0, new long[n]);
    Arrays.fill(dp.get(0), -1L);
}

/* runs one DP step, filling ‘next’ from ‘dp’ */
private static void runDpStep(HashMap<Integer, long[]> dp,
                              HashMap<Integer, long[]> next,
                              long[] a,
                              long[][] v,
                              int n) {
    for (int mask : dp.keySet()) {
        long[] cur = dp.get(mask);
        for (int j = 0; j < n; j++) {
            int newMask = mask | (1 << j);
            if (newMask == mask) {
                continue;               // j already chosen in this mask
            }

            // ensure a bucket exists for the new mask
            next.computeIfAbsent(newMask, key -> {
                long[] arr = new long[n];
                Arrays.fill(arr, -1L);
                return arr;
            });

            long best = 0L;
            for (int t = 0; t < n; t++) {
                if (cur[t] >= 0) {
                    best = Math.max(best, cur[t] + v[t][j]);
                }
            }
            best += a[j];

            long[] nxt = next.get(newMask);
            nxt[j] = Math.max(nxt[j], best);
        }
    }
}

