private static long computeAnswer(HashMap<Integer, long[]> dp, int n) {
    long ans = 0L;
    for (long[] arr : dp.values()) {
        for (int i = 0; i < n; i++) {
            ans = Math.max(ans, arr[i]);
        }
    }
    return ans;
}

