}

/* Performs the m DP steps */
private static void runTransitions(
        HashMap<Integer, long[]> dp,
        HashMap<Integer, long[]> next,
        long[][] v,
        long[] a,
        int n,
        int m) {

    for (int step = 0; step < m; step++) {
        for (int mask : dp.keySet()) {
            for (int j = 0; j < n; j++) {
                int newMask = mask | (1 << j);
                if (newMask == mask) continue;               // already taken

                long[] nxtRow = next.computeIfAbsent(newMask, k -> {
                    long[] arr = new long[n];
                    Arrays.fill(arr, -1L);
                    return arr;
                });

                long best = 0L;
                long[] curRow = dp.get(mask);
                for (int t = 0; t < n; t++) {
                    if (curRow[t] >= 0) {
                        best = Math.max(best, curRow[t] + v[t][j]);
                    }
                }
                best += a[j];
                nxtRow[j] = Math.max(nxtRow[j], best);
            }
        }

        // swap dp and next, then clear next for the following iteration
        HashMap<Integer, long[]> tmp = dp;
        dp = next;
        next = tmp;
        next.clear();

        if (DEBUG) {
            for (int mask : dp.keySet()) {
                debug(Integer.toString(mask, 2) + " " + Arrays.toString(dp.get(mask)));
            }
            debug("");
        }
    }

    // after loop, expose the final dp map to the caller (by reference it is already updated)
}

/* Returns the maximal value stored in any dp entry */
private static long maxAnswer(HashMap<Integer, long[]> dp, int n) {
    long ans = 0L;
    for (int mask : dp.keySet()) {
        long[] row = dp.get(mask);
        for (int i = 0; i < n; i++) {
            ans = Math.max(ans, row[i]);
        }
    }
    return ans;
}

