private HashSet<Integer> readBlockedVertices(InputReader in, int m) {
    HashSet<Integer> set = new HashSet<>();
    for (int i = 0; i < m; i++) {
        in.nextInt();          // first integer of the triple – ignored
        set.add(in.nextInt()); // middle integer – the blocked vertex
        in.nextInt();          // third integer of the triple – ignored
    }
    return set;
}

/**
 * Returns the smallest vertex id in {@code [1, n]} that is not present in {@code blocked}.
 * If every vertex is blocked, returns {@code -1} (behaviour matches the original code).
 */
private int findFirstMissingVertex(int n, Set<Integer> blocked) {
    for (int i = 1; i <= n; i++) {
        if (!blocked.contains(i)) {
            return i;
        }
    }
    return -1;
}

/**
 * Prints all ordered pairs (freeVertex, i) for every {@code i} in {@code [1, n]}
 * except when {@code i} equals {@code freeVertex}.
 */
private void printPairs(OutputWriter out, int freeVertex, int n) {
    for (int i = 1; i <= n; i++) {
        if (i != freeVertex) {
            out.println(freeVertex + " " + i);
        }
    }
}

