void solve() {
    int n = in.nextInt();
    in.nextLine();                 // consume end‑of‑line after the integer
    String s = in.nextLine();
    String t = in.nextLine();

    n *= 2;                        // total length of the two strings
    char[] ss = s.toCharArray();
    char[] tt = t.toCharArray();

    // 1️⃣ count the three column categories
    int[] columns = countColumns(ss, tt);
    int col1 = columns[0];
    int col2 = columns[1];
    int col3 = columns[2];

    // 2️⃣ decide who moves first and initialise the first score
    int[] init = initialiseResult(col3);
    int res = init[0];   // 1 → First player, 2 → Second player
    int sum1 = init[1];
    int sum2 = 0;

    // 3️⃣ run the alternating turn simulation
    int[] finalSums = simulateTurns(col1, col2, res, sum1, sum2);
    sum1 = finalSums[0];
    sum2 = finalSums[1];

    // 4️⃣ output the outcome
    if (sum1 == sum2) {
        out.println("Draw");
    } else if (sum1 > sum2) {
        out.println("First");
    } else {
        out.println("Second");
    }
}

/**
 * Counts the three possible column types:
 *   col1 – (1,0), col2 – (0,1), col3 – (1,1)
 */
private static int[] countColumns(char[] ss, char[] tt) {
    int col1 = 0, col2 = 0, col3 = 0;
    for (int i = 0; i < ss.length; i++) {
        if (ss[i] == '1' && tt[i] == '1') {
            col3++;
        } else {
            if (ss[i] == '1' && tt[i] == '0') {
                col1++;
            }
            if (tt[i] == '1' && ss[i] == '0') {
                col2++;
            }
        }
    }
    return new int[]{col1, col2, col3};
}

/**
 * Determines the starting player based on the parity of col3
 * and gives the first point if necessary.
 *
 * @return array where [0] = current player (1 or 2), [1] = sum1 after initialisation
 */
private static int[] initialiseResult(int col3) {
    if (col3 % 2 == 1) {
        // odd number of (1,1) columns → second player starts, first player gets a point
        return new int[]{2, 1};
    } else {
        // even → first player starts, no extra point
        return new int[]{1, 0};
    }
}

/**
 * Simulates the alternating turns after the initial move.
 *
 * @return array where [0] = final sum1, [1] = final sum2
 */
private static int[] simulateTurns(int col1, int col2, int res, int sum1, int sum2) {
    while (col1 != 0 || col2 != 0) {
        if (res == 1) {                 // first player's turn
            if (col1 == 0) {
                break;                  // cannot play, exit early
            }
            col1--;
            sum1++;
            res = 2;                    // switch turn
        } else {                        // second player's turn
            if (col2 == 0) {
                break;
            }
            sum2++;
            col2--;
            res = 1;
        }
    }
    // If the loop ends while it is first player's turn and there are still col2 left,
    // the second player discards one (as in the original logic).
    if (res == 1 && col2 > 0) {
        col2--;
    }

    // Remaining columns are taken by the respective players.
    sum1 += col1;
    sum2 += col2;

    return new int[]{sum1, sum2};
}

