    int[][][] maxPosition = new int[n + 1][toChange + 1][2];

    ArrayUtils.fill(minPosition, INF);
    ArrayUtils.fill(maxPosition, -INF);
    Arrays.fill(minPosition[0][0], 0);
    Arrays.fill(maxPosition[0][0], 0);

    for (int i = 1; i <= n; i++) {
        for (int j = 0; j <= toChange; j++) {
            for (int k = 0; k < 2; k++) {
                // case: we keep the current command unchanged
                applyNoChange(i, j, k, commands[i], minPosition, maxPosition);

                // case: we flip the current command (allowed only when j > 0)
                if (j > 0) {
                    applyWithChange(i, j, k, commands[i], minPosition, maxPosition);
                }
            }
        }
    }

    int answer = computeAnswer(toChange, n, minPosition, maxPosition);
    out.println(answer);
}

/**
 * Updates minPosition / maxPosition for the situation where the i‑th command
 * is taken as‑is (no change).
 */
private void applyNoChange(int i, int j, int k, char command,
                           int[][][] minPos, int[][][] maxPos) {
    if (command == 'T') {
        // turn: direction toggles, position unchanged
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j][1 - k]);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j][1 - k]);
    } else {
        // move forward in the current direction
        int delta = toward(k);
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j][k] + delta);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j][k] + delta);
    }
}

/**
 * Updates minPosition / maxPosition for the situation where we flip the
 * i‑th command (use one of the allowed changes).
 */
private void applyWithChange(int i, int j, int k, char command,
                             int[][][] minPos, int[][][] maxPos) {
    if (command == 'T') {
        // change ‘T’ into a move forward: direction stays, position moves
        int delta = toward(k);
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j - 1][k] + delta);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j - 1][k] + delta);
    } else {
        // change a move into ‘T’: direction toggles, position unchanged
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j - 1][1 - k]);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j - 1][1 - k]);
    }
}

/**
 * Computes the final answer based on the populated min/max tables.
 */
private int computeAnswer(int toChange, int n,
                          int[][][] minPos, int[][][] maxPos) {
    int best = 0;
    for (int j = toChange % 2; j <= toChange; j += 2) {
        for (int k = 0; k < 2; k++) {
            best = Math.max(best, -minPos[n][j][k]);
            best = Math.max(best, maxPos[n][j][k]);
        }
    }
    return best;
}

