/** Builds dp and its cumulative version for the first array element. */
private static void initFirstPosition(int[] a, long[][] dp, long[][] dpCum, long mod) {
    for (int last = 1; last <= 200; last++) {
        if (a[0] != -1) {
            if (a[0] == last) {
                dp[last][0] = 0;
                dp[last][1] = 1;
            } else {
                dp[last][0] = 0;
                dp[last][1] = 0;
            }
        } else {
            dp[last][0] = 0;
            dp[last][1] = 1;
        }
        dpCum[last][0] = (dpCum[last - 1][0] + dp[last][0] + mod) % mod;
        dpCum[last][1] = (dpCum[last - 1][1] + dp[last][1] + mod) % mod;
    }
}

/** Fills dpTemp for position idx based on current dp and dpCum tables. */
private static void computeDPTemp(int idx, int[] a, long[][] dp,
                                 long[][] dpCum, long[][] dpTemp, long mod) {
    for (int last = 1; last <= 200; last++) {
        if (a[idx] != -1) {
            if (a[idx] == last) {
                dpTemp[last][0] = dpCum[200][0] - dpCum[last][0] + dp[last][0] + dp[last][1];
                dpTemp[last][1] = dpCum[last - 1][0] + dpCum[last - 1][1];
            } else {
                dpTemp[last][0] = 0;
                dpTemp[last][1] = 0;
            }
        } else {
            dpTemp[last][0] = dpCum[200][0] - dpCum[last][0] + dp[last][0] + dp[last][1];
            dpTemp[last][1] = dpCum[last - 1][0] + dpCum[last - 1][1];
        }
    }
}

/** Copies dpTemp into dp, resets dpCum and rebuilds the cumulative sums. */
private static void updateDPAndCum(long[][] dp, long[][] dpTemp,
                                   long[][] dpCum, long mod) {
    // reset cumulative arrays
    for (int i = 1; i <= 200; i++) {
        dpCum[i][0] = 0;
        dpCum[i][1] = 0;
    }
    // copy temp to dp and recompute cumulative tables
    for (int last = 1; last <= 200; last++) {
        dp[last][0] = (dpTemp[last][0] + mod) % mod;
        dp[last][1] = (dpTemp[last][1] + mod) % mod;
        dpCum[last][0] = (dpCum[last - 1][0] + dpTemp[last][0] + mod) % mod;
        dpCum[last][1] = (dpCum[last - 1][1] + dpTemp[last][1] + mod) % mod;
    }
}

