    computeAllShortestPaths(n);

    // 3️⃣ Read the sequence of vertices (0‑based)
    int m = Integer.parseInt(fin.readLine());
    int[] nums = readSequence(fin, m);

    // 4️⃣ Build the final output (counter + vertex list)
    System.out.println(buildResult(nums));
}

/* -------------------------------------------------------------
   Helper: read the adjacency matrix and store it in the static  'c'
   ------------------------------------------------------------- */
private static List<List<Integer>> readAdjacency(BufferedReader fin, int n) throws IOException {
    List<List<Integer>> adjacency = new ArrayList<>();
    for (int i = 0; i < n; i++) {
        adjacency.add(new ArrayList<>());
        char[] line = fin.readLine().toCharArray();
        for (int j = 0; j < n; j++) {
            if (line[j] == '1') {
                adjacency.get(i).add(j);
            }
        }
    }
    return adjacency;
}

/* -------------------------------------------------------------
   Helper: initialise the static 'paths' list and invoke the
   existing shortestPaths(i) routine for every source vertex.
   ------------------------------------------------------------- */
private static void computeAllShortestPaths(int n) {
    paths = new ArrayList<>();
    for (int i = 0; i < n; i++) {
        shortestPaths(i);   // existing method that fills 'paths'
    }
}

/* -------------------------------------------------------------
   Helper: read the list of query vertices (convert to 0‑based)
   ------------------------------------------------------------- */
private static int[] readSequence(BufferedReader fin, int m) throws IOException {
    int[] nums = new int[m];
    StringTokenizer st = new StringTokenizer(fin.readLine());
    for (int i = 0; i < m; i++) {
        nums[i] = Integer.parseInt(st.nextToken()) - 1;
    }
    return nums;
}

/* -------------------------------------------------------------
   Helper: execute the core algorithm that decides when a vertex
   must be printed, counts the required stops and builds the
   output string.
   ------------------------------------------------------------- */
private static String buildResult(int[] nums) {
    int m = nums.length;
    StringBuilder fout = new StringBuilder();
    int counter = 0;
    int pointer = 0;               // start of the current optimal segment

    for (int i = 0; i < m; i++) {
        if (i == 0) {
            counter++;
            fout.append(nums[i] + 1).append(' ');
        } else {
            int pathCost = i - pointer;
            int minCost = (nums[pointer] == nums[i])
                    ? 0
                    : paths.get(nums[pointer]).get(nums[i]);

            if (pathCost > minCost) {
                counter++;
                fout.append(nums[i - 1] + 1).append(' ');
                pointer = i - 1;
            }
        }
    }

    // Append the final vertex and the total number of stops
    counter++;
    fout.append(nums[m - 1] + 1);
    return counter + "\n" + fout.toString();
}

public static void main(String[] args) throws IOException {
    BufferedReader fin = new BufferedReader(new InputStreamReader(System.in));

    int n = Integer.parseInt(fin.readLine());
    buildAdjacencyList(fin, n);               // <-- step 1

    computeAllShortestPaths(n);               // <-- step 2

    int m = Integer.parseInt(fin.readLine());
    int[] nums = readQuerySequence(fin, m);   // <-- step 3

    EvalResult result = evaluateSequence(nums); // <-- step 4
    System.out.println(result.counter + "\n" + result.output);
}

/* ---------- step 1: build the graph ---------- */
private static void buildAdjacencyList(BufferedReader fin, int n) throws IOException {
    c = new ArrayList<ArrayList<Integer>>();
    for (int i = 0; i < n; i++) {
        c.add(new ArrayList<Integer>());
        char[] s = fin.readLine().toCharArray();
        for (int j = 0; j < n; j++) {
            if (s[j] == '1') {
                c.get(i).add(j);
            }
        }
    }
}

/* ---------- step 2: all‑pairs shortest paths ---------- */
private static void computeAllShortestPaths(int n) {
    paths = new ArrayList<HashMap<Integer, Integer>>();
    for (int i = 0; i < n; i++) {
        shortestPaths(i);
    }
}

/* ---------- step 3: read the sequence of vertices ---------- */
private static int[] readQuerySequence(BufferedReader fin, int m) throws IOException {
    int[] nums = new int[m];
    StringTokenizer st = new StringTokenizer(fin.readLine());
    for (int i = 0; i < m; i++) {
        nums[i] = Integer.parseInt(st.nextToken()) - 1; // store 0‑based
    }
    return nums;
}

/* ---------- step 4: evaluate the sequence ---------- */
private static EvalResult evaluateSequence(int[] nums) {
    StringBuilder fout = new StringBuilder();
    int counter = 0;
    int pointer = 0;               // start of the current “valid” segment

    for (int i = 0; i < nums.length; i++) {
        int next = nums[i];
        if (i == 0) {
            counter++;
            fout.append(next + 1).append(' ');
        } else {
            int pathCost = i - pointer;
            int minCost = (nums[pointer] == next) ? 0 : paths.get(nums[pointer]).get(next);

            if (pathCost > minCost) {
                counter++;
                fout.append(nums[i - 1] + 1).append(' ');
                pointer = i - 1;
            }
        }
    }

    // always add the last vertex
    counter++;
    fout.append(nums[nums.length - 1] + 1);

    return new EvalResult(counter, fout);
}

/* tiny holder for the evaluation result */
private static class EvalResult {
    final int counter;
    final StringBuilder output;

    EvalResult(int counter, StringBuilder output) {
        this.counter = counter;
        this.output = output;
    }
}

