    if (right == -1) {
        return 0;
    }

    int bestAns = 1;
    int pairSize = 2;               // size contributed by the two outer elements

    while (left < right) {
        int maxRange = maxRangeQuery(prefixArr, left, right);
        if (maxRange >= 0) {
            bestAns = Math.max(maxRange + pairSize, bestAns);
        }

