/* ---------- helper data holder ---------- */
private static class MatchInfo {
    final String teamA;
    final String teamB;
    final int goalsA;
    final int goalsB;

    MatchInfo(String teamA, String teamB, int goalsA, int goalsB) {
        this.teamA = teamA;
        this.teamB = teamB;
        this.goalsA = goalsA;
        this.goalsB = goalsB;
    }
}

/* ---------- parse a match description ---------- */
private static MatchInfo parseMatch(String line) {
    // line format: "TeamA - TeamB : g1 g2"
    String[] parts = line.split("[- :]");
    String teamA = parts[0];
    String teamB = parts[1];
    int goalsA = Integer.parseInt(parts[2]);
    int goalsB = Integer.parseInt(parts[3]);
    return new MatchInfo(teamA, teamB, goalsA, goalsB);
}

/* ---------- update scores for a single match ---------- */
private static void applyMatchResult(List<Command> team, MatchInfo m) {
    if (m.goalsA == m.goalsB) {                     // draw
        for (Command c : team) {
            if (m.teamA.equals(c.name) || m.teamB.equals(c.name)) {
                c.scores++;
                c.goals += m.goalsA;
                c.fols  += m.goalsB;
            }
        }
    } else if (m.goalsA > m.goalsB) {               // team A wins
        for (Command c : team) {
            if (m.teamA.equals(c.name)) {
                c.scores += 3;
                c.goals  += m.goalsA;
                c.fols   += m.goalsB;
            }
            if (m.teamB.equals(c.name)) {
                c.goals += m.goalsB;
                c.fols  += m.goalsA;
            }
        }
    } else {                                        // team B wins
        for (Command c : team) {
            if (m.teamB.equals(c.name)) {
                c.scores += 3;
                c.goals  += m.goalsB;
                c.fols   += m.goalsA;
            }
            if (m.teamA.equals(c.name)) {
                c.goals += m.goalsA;
                c.fols  += m.goalsB;
            }
        }
    }
}

