/**
 * Reads *n* team names from the scanner and creates a Command object for each.
 */
private static List<Command> readTeams(Scanner in, int n) {
    List<Command> list = new ArrayList<>();
    for (int i = 0; i < n; i++) {
        list.add(new Command(in.nextLine()));
    }
    return list;
}

/**
 * Updates the two teams involved in a match described by {@code data}.
 * {@code data} layout: [team1, team2, goals1, goals2] (already split).
 */
private static void processMatch(List<Command> teams, String[] data) {
    String team1 = data[0];
    String team2 = data[1];
    int goals1 = Integer.parseInt(data[2]);
    int goals2 = Integer.parseInt(data[3]);

    if (goals1 == goals2) {                     // draw
        updateTeam(teams, team1, 1, goals1, goals2);
        updateTeam(teams, team2, 1, goals2, goals1);
    } else if (goals1 > goals2) {               // team1 wins
        updateTeam(teams, team1, 3, goals1, goals2);
        updateTeam(teams, team2, 0, goals2, goals1);
    } else {                                    // team2 wins
        updateTeam(teams, team2, 3, goals2, goals1);
        updateTeam(teams, team1, 0, goals1, goals2);
    }
}

/**
 * Applies the supplied deltas to the team identified by {@code name}.
 * If the name is not found the method does nothing (mirrors original behaviour).
 */
private static void updateTeam(List<Command> teams,
                               String name,
                               int scoreDelta,
                               int goalsForDelta,
                               int goalsAgainstDelta) {
    for (Command c : teams) {
        if (name.equals(c.name)) {
            c.scores += scoreDelta;
            c.goals  += goalsForDelta;
            c.fols   += goalsAgainstDelta;
            break; // names are unique – stop once the team is updated
        }
    }
}

/**
 * After the list is sorted, returns a {@code TreeSet} containing the names of the
 * first {@code n/2} teams (the “top half”).
 */
private static Set<String> collectTopHalfNames(List<Command> sortedTeams, int n) {
    Set<String> names = new TreeSet<>();
    for (int i = 0; i < n / 2; i++) {
        names.add(sortedTeams.get(i).name);
    }
    return names;
}

