    for (int i = 0; i < totalMatches; i++) {
        String line = in.nextLine();
        processMatch(line, team);
    }

    Collections.sort(team);
    Set<String> names = new TreeSet<>();
    for (int i = 0; i < n / 2; i++) {
        names.add(team.get(i).name);
    }

    for (String name : names) {
        System.out.println(name);
