}

/** Parses a match line and updates the team statistics accordingly. */
private static void processMatch(String line, List<Command> team) {
    // Expected format: "TeamA-TeamB X:Y"
    String[] data = line.split("[- :]");
    String home = data[0];
    String away = data[1];
    int homeGoals = Integer.parseInt(data[2]);
    int awayGoals = Integer.parseInt(data[3]);

    if (homeGoals == awayGoals) {
        applyDraw(team, home, away, homeGoals, awayGoals);
    } else if (homeGoals > awayGoals) {
        applyWinLoss(team, home, away, homeGoals, awayGoals);
    } else {
        applyWinLoss(team, away, home, awayGoals, homeGoals);
    }
}

/** Both teams drew: each gains 1 point and their goals/foils are recorded. */
private static void applyDraw(List<Command> team,
                              String teamA, String teamB,
                              int goalsA, int goalsB) {
    for (Command c : team) {
        if (teamA.equals(c.name) || teamB.equals(c.name)) {
            c.scores++;
            c.goals += (teamA.equals(c.name) ? goalsA : goalsB);
            c.fols  += (teamA.equals(c.name) ? goalsB : goalsA);
        }
    }
}

/** Winner gets 3 points; both teams receive goals/foils. */
private static void applyWinLoss(List<Command> team,
                                 String winner, String loser,
                                 int winnerGoals, int loserGoals) {
    for (Command c : team) {
        if (winner.equals(c.name)) {
            c.scores += 3;
            c.goals += winnerGoals;
            c.fols  += loserGoals;
        }
        if (loser.equals(c.name)) {
            c.goals += loserGoals;
            c.fols  += winnerGoals;
        }
    }
}

