/** Reads {@code n} integers from {@code sc} into a newly allocated array. */
private static int[] readArray(Scanner sc, int n) {
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = sc.nextInt();
    }
    return arr;
}

/** Returns the sum of all elements in {@code arr}. */
private static int sumArray(int[] arr) {
    int sum = 0;
    for (int value : arr) {
        sum += value;
    }
    return sum;
}

/** Returns {@code true} if {@code sum} is evenly divisible by {@code n}. */
private static boolean isDivisible(int sum, int n) {
    return sum % n == 0;
}

/** Counts how many elements in {@code arr} are greater than {@code threshold}. */
private static int countAboveAverage(int[] arr, int threshold) {
    Arrays.sort(arr);
    int count = 0;
    for (int value : arr) {
        if (value > threshold) {
            count++;
        }
    }
    return count;
}

public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int test = sc.nextInt();
    while (test-- > 0) {
        int n = sc.nextInt();
        int[] arr = readArray(sc, n);
        System.out.println(processCase(arr));
    }
}

/** Reads n integers from the scanner and returns them as an array. */
private static int[] readArray(Scanner sc, int n) {
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = sc.nextInt();
    }
    return arr;
}

/** Returns the answer for a single test case. */
private static int processCase(int[] arr) {
    int sum = sum(arr);
    if (sum % arr.length != 0) {
        return -1;
    }

    int target = sum / arr.length;
    Arrays.sort(arr);
    return countElementsGreaterThan(arr, target);
}

/** Calculates the sum of all elements in the array. */
private static int sum(int[] arr) {
    int total = 0;
    for (int value : arr) {
        total += value;
    }
    return total;
}

/** Counts how many elements in the *already sorted* array are strictly greater than the given threshold. */
private static int countElementsGreaterThan(int[] sortedArr, int threshold) {
    int count = 0;
    for (int value : sortedArr) {
        if (value > threshold) {
            count++;
        }
    }
    return count;
}

