}

/** Reads the binary strings and stores them as integers in {@code a}. */
private static void readInputDigits(FastScanner scan, int n) {
    for (int i = 0; i < n; i++) {
        a[i] = Integer.parseInt(scan.next(), 2);
    }
}

/** Pre‑computes, for every position and every digit (0‑9), the number of
 *  segment changes needed, or –1 if the digit cannot be produced. */
private static void fillPrecomputedDistances(int n) {
    for (int at = 0; at < n; at++) {
        for (int d = 9; d >= 0; d--) {
            boolean achievable = true;
            int dist = 0;
            for (int bit = 0; bit < 8; bit++) {
                if ((digits[d] & (1 << bit)) == 0 && (a[at] & (1 << bit)) != 0) {
                    achievable = false;               // would need to turn a lit segment off
                }
                if ((digits[d] & (1 << bit)) != 0 && (a[at] & (1 << bit)) == 0) {
                    dist++;                             // need to turn a segment on
                }
            }
            precomp[at][d] = achievable ? dist : -1;
        }
    }
}

/** Reconstructs the lexicographically largest valid number using the DP table. */
private static int[] reconstructAnswer(int n, int k) {
    int[] res = new int[n];
    int remaining = k;

    for (int at = 0; at < n; at++) {
        for (int d = 9; d >= 0; d--) {
            int dist = precomp[at][d];
            if (dist == -1) {
                continue;
            }
            if (isDigitSelectable(at, remaining, dist)) {
                res[at] = d;
                remaining -= Integer.bitCount(digits[d] ^ a[at]);
                break;
            }
        }
    }
    return res;
}

/** Returns true if digit {@code d} (whose distance is {@code dist})
 *  can be placed at position {@code at} given {@code remaining} changes. */
private static boolean isDigitSelectable(int at, int remaining, int dist) {
    if (at + 1 == a.length) {                     // last position
        return dist == remaining;
    }
    // there must be a feasible continuation from the next position
    return remaining - dist >= 0 && dp[at + 1][remaining - dist] != null
            && dp[at + 1][remaining - dist];
}

public static void main(String[] args) {
    FastScanner scan = new FastScanner();
    PrintWriter out = new PrintWriter(System.out);
    int n = scan.nextInt();
    int k = scan.nextInt();

    a = new int[n];
    for (int i = 0; i < n; i++) {
        a[i] = Integer.parseInt(scan.next(), 2);
    }

    dp = new Boolean[n][k + 1];
    precomp = new int[n][10];

    // --- extracted pre‑computation ---
    computePrecomp(a, precomp);

    if (!go(0, k)) {
        out.println(-1);
    } else {
        // --- extracted reconstruction ---
        int[] res = reconstruct(n, k, a, precomp, dp);
        for (int digit : res) {
            out.print(digit);
        }
    }

    out.close();
}

/**
 * Fills {@code precomp} with the number of segments that must be turned on
 * to change the current display {@code a[at]} into digit {@code i}.
 * If the transformation is impossible, stores -1.
 */
private static void computePrecomp(int[] a, int[][] precomp) {
    for (int at = 0; at < a.length; at++) {
        for (int i = 9; i >= 0; i--) {
            boolean achievable = true;
            int dist = 0;
            for (int bit = 0; bit < 8; bit++) {
                if ((digits[i] & (1 << bit)) == 0 && (a[at] & (1 << bit)) != 0) {
                    achievable = false;               // a has a lit segment that digit i cannot have
                }
                if ((digits[i] & (1 << bit)) != 0 && (a[at] & (1 << bit)) == 0) {
                    dist++;                             // segment must be turned on
                }
            }
            precomp[at][i] = achievable ? dist : -1;
        }
    }
}

/**
 * Reconstructs the maximal possible number (as an int array of digits)
 * that can be obtained using exactly {@code k} segment changes.
 */
private static int[] reconstruct(int n, int k, int[] a, int[][] precomp, Boolean[][] dp) {
    int[] result = new int[n];
    int left = k;

    for (int at = 0; at < n; at++) {
        for (int i = 9; i >= 0; i--) {
            int dist = precomp[at][i];
            boolean good = false;

            if (at + 1 == n) {                     // last position
                good = (dist == left);
            } else if (dist != -1 && left - dist >= 0 && dp[at + 1][left - dist] != null) {
                good = dp[at + 1][left - dist];
            }

            if (good && dist != -1) {
                result[at] = i;
                left -= Integer.bitCount(digits[i] ^ a[at]); // consume the used changes
                break;
            }
        }
    }
    return result;
}

public static void main(String[] args) {
