public void solve(int testNumber, Scanner in, PrintWriter out) {
    // Chunk 1 – read input, count positives and build the absolute‑value array
    InputData data = readInput(in);

    // Chunk 2 – BFS to find the maximal reachable number of positives
    int maxPositives = bfsMaxPositives(data.howManyPositive, data.n);

    // Chunk 3 – compute the required sum using the sorted absolute values
    int result = computeSum(data.absSorted, maxPositives);

    out.println(result);
}

/**
 * Holds the data produced by the input phase.
 */
private static class InputData {
    final int n;                 // original n
    final int howManyPositive;   // number of positive entries in the original array
    final int[] absSorted;       // sorted absolute values (ascending)
    InputData(int n, int howManyPositive, int[] absSorted) {
        this.n = n;
        this.howManyPositive = howManyPositive;
        this.absSorted = absSorted;
    }
}

/**
 * Reads the problem input, counts positive numbers and returns a sorted
 * array of absolute values.
 */
private static InputData readInput(Scanner in) {
    int n = in.nextInt();
    int size = 2 * n - 1;
    int[] abs = new int[size];
    int positiveCount = 0;
    for (int i = 0; i < size; i++) {
        int val = in.nextInt();
        if (val > 0) {
            ++positiveCount;
        }
        abs[i] = Math.abs(val);
    }
    Arrays.sort(abs); // ascending
    return new InputData(n, positiveCount, abs);
}

/**
 * Performs the BFS over possible counts of positive numbers.
 * Returns the largest count that can be reached.
 */
private static int bfsMaxPositives(int startPositives, int n) {
    int total = 2 * n - 1;
    HashSet<Integer> visited = new HashSet<>();
    LinkedList<Integer> queue = new LinkedList<>();

    visited.add(startPositives);
    queue.add(startPositives);

    int best = startPositives;
    while (!queue.isEmpty()) {
        int cur = queue.removeFirst();
        best = Math.max(best, cur);

        for (int action = 0; action <= n; action++) {
            int antiAction = n - action;
            int negatives = total - cur;
            if (antiAction <= cur && action <= negatives) {
                int next = cur - antiAction + action;
                if (visited.add(next)) {   // add returns false if already present
                    queue.add(next);
                }
            }
        }
    }
    return best;
}

/**
 * Computes the final sum: the largest `ans` absolute values are added,
 * the rest are subtracted.
 */
private static int computeSum(int[] absSorted, int ans) {
    int sum = 0;
    int len = absSorted.length;
    // the largest values are at the end of the sorted array
    for (int i = 0; i < ans; i++) {
        sum += absSorted[len - 1 - i];
    }
    for (int i = ans; i < len; i++) {
        sum -= absSorted[len - 1 - i];
    }
    return sum;
}

