private static void runFloydWarshall(long[][] res, int k) {
    for (int v = 0; v < k; v++) {
        for (int i = 0; i < k; i++) {
            for (int j = 0; j < k; j++) {
                long viaV = res[i][v] + res[v][j];
                if (viaV < res[i][j]) {
                    res[i][j] = viaV;
                }
            }
        }
    }
}

