private static int calculateMinWhenKPresent(int[] sorted, int k) {
    int n = sorted.length;
    int min = Integer.MAX_VALUE;

    for (int i = 0; i < n; i++) {
        if (sorted[i] == k) {
            if (i > (n - i - 1)) {
                int candidate = i - (n - i - 1);
                if (candidate < min) {
                    min = candidate;
                }
            } else {
                if (i == n - i - 1) {
                    min = 0;
                } else {
                    int candidate = n - i - i - 1 - 1; // exactly as original
                    if (candidate < min) {
                        min = candidate;
                    }
                }
            }
        }
    }
    return min;
