    }

    int result;
    if (n == 0) {
        result = handleZeroTurns(index, pos, direction);
    } else {
        if (inp.charAt(index) == 'T') {
            result = handlePositiveTurnsWithT(index, pos, n, direction);
        } else {
            result = handlePositiveTurnsWithoutT(index, pos, n, direction);
        }
    }

    dp[index][pos + 100][n][direction + 1] = result;
    return result;
