/* Handles the case n == 0 */
private static int handleZeroTurns(int index, int pos, int direction) {
    if (inp.charAt(index) == 'T') {
        return min(index + 1, pos, 0, -direction);
    } else {
        return min(index + 1, pos + direction, 0, direction);
    }
