/* Handles n > 0 when current character is 'T' */
private static int handlePositiveTurnsWithT(int index, int pos, int n, int direction) {
    // initial choice: take the turn (flip direction) without consuming a move
    int max = min(index + 1, pos, n, -direction);
    // try consuming i moves (1..n) and decide where to apply the turn
    for (int i = 1; i <= n; i++) {
        if (i % 2 == 0) { // even i → turn after staying on the same spot
            max = Math.max(max, min(index + 1, pos, n - i, -direction));
        } else { // odd i → turn after moving one step in current direction
            max = Math.max(max,
                    min(index + 1, pos + direction, n - i, direction));
        }
    }
    return max;
}

/* Handles n > 0 when current character is NOT 'T' */
private static int handlePositiveTurnsWithoutT(int index, int pos, int n, int direction) {
    // initial choice: move forward without turning
    int max = min(index + 1, pos + direction, n, direction);
    // try consuming i moves (1..n) and decide where to apply the turn
    for (int i = 1; i <= n; i++) {
        if (i % 2 == 0) { // even i → turn after moving forward
            max = Math.max(max,
                    min(index + 1, pos + direction, n - i, direction));
        } else { // odd i → turn after staying on the same spot
            max = Math.max(max,
                    min(index + 1, pos, n - i, -direction));
        }
    }
    return max;
}

