    Arrays.fill(maxContSum, -1L);

    // 1️⃣ read arrays and compute prefix information
    readAndPrepareSequences(sc, n);

    // 2️⃣ compute suffix maximums for every sequence
    computeSuffixMaximums(n);

    // 3️⃣ read the list of indices that will be used later
    int[] indices = readIndices(sc, m);

    // 4️⃣ find the maximum single element among the chosen sequences
    int globalMax = computeGlobalMaximum(indices);
    if (globalMax <= 0) {
        System.out.println(globalMax);
        return;
    }

    // 5️⃣ evaluate the answer using the chosen order of sequences
    long answer = evaluateAnswer(indices);

    PrintWriter pw = new PrintWriter(System.out);
    pw.println(answer);
    pw.flush();
    pw.close();
}

/**
 * Reads each sequence, fills {@code a}, and computes:
 *   • total sum per sequence ( {@code s} )
 *   • best prefix sum per sequence ( {@code maxP} )
 *   • maximum element per sequence ( {@code max2} )
 */
private static void readAndPrepareSequences(Scanner sc, int n) {
    for (int i = 0; i < n; i++) {
        int len = sc.nextInt();
        int maxElement = Integer.MIN_VALUE;
        long maxPrefix = 0L;
        long runningSum = 0L;

        a[i] = new int[len];
        for (int j = 0; j < len; j++) {
            int val = sc.nextInt();
            a[i][j] = val;

            runningSum += val;
            s[i] = runningSum;                 // total sum will end up in s[i] after the loop
            maxElement = Math.max(maxElement, val);
            maxPrefix = Math.max(maxPrefix, runningSum);
        }
        maxP[i] = maxPrefix;
        max2[i] = maxElement;
    }
}

/**
 * For every sequence computes the maximum suffix sum and stores it into {@code maxS}.
 */
private static void computeSuffixMaximums(int n) {
    maxS = new long[n];
    for (int i = 0; i < n; i++) {
        long suffixSum = 0L;
        long best = 0L;
        for (int j = a[i].length - 1; j >= 0; j--) {
            suffixSum += a[i][j];
            best = Math.max(best, suffixSum);
        }
        maxS[i] = best;
    }
}

/**
 * Reads {@code m} indices (1‑based in the input) and converts them to 0‑based.
 */
private static int[] readIndices(Scanner sc, int m) {
    int[] idx = new int[m];
    for (int i = 0; i < m; i++) {
        idx[i] = sc.nextInt() - 1;
    }
    return idx;
}

/**
 * Returns the largest element that appears in any of the chosen sequences.
 */
private static int computeGlobalMaximum(int[] indices) {
    int best = Integer.MIN_VALUE;
    for (int id : indices) {
        best = Math.max(best, max2[id]);
    }
    return best;
}

/**
 * Implements the original dynamic‑programming walk over the selected sequences
 * and returns the final answer.
 */
private static long evaluateAnswer(int[] indices) {
    long sum = 0L;
    long ans = 0L;

    for (int idx : indices) {
        // 1. best contiguous sub‑array that ends inside the current sequence
        ans = Math.max(ans, maxContSum(idx));

        // 2. best prefix of the current sequence appended to the running sum
        ans = Math.max(ans, sum + maxP[idx]);

        // 3. extend the running sum with the whole current sequence
        sum += s[idx];

        // 4. after adding the whole sequence we may keep only the best suffix
        sum = Math.max(maxS[idx], sum);

        // 5. keep the best overall value seen so far
        ans = Math.max(ans, sum);
    }
    return ans;
}

