/** Reads each array, fills the global `a` matrix and computes:
 *  – total sum per array (`sumArray`)
 *  – maximum prefix sum (`maxPrefix`)
 *  – maximum single element (`maxElement`) */
private static void readAndAnalyseArrays(Scanner sc, int n,
                                          long[] sumArray,
                                          long[] maxPrefix,
                                          int[] maxElement) {
    for (int i = 0; i < n; i++) {
        int len = sc.nextInt();
