/** Core algorithm – iterates over the chosen indices and computes the answer. */
private static long computeAnswer(int[] indices,
                                  long[] sumArray,
                                  long[] maxPrefix) {
    long sum = 0;
    long ans = 0;
    for (int idx : indices) {
        // best contiguous sub‑array inside the current array
        ans = Math.max(ans, maxContSum(idx));
