 * 3. Global maximum element among the selected indices
 * -----------------------------------------------------*/
private static int computeGlobalMaximum(int[] indices) {
    int globalMax = Integer.MIN_VALUE;
    for (int idx : indices) {
        globalMax = Math.max(globalMax, max2[idx]);
    }
    return globalMax;
}

/* -------------------------------------------------------
 * 4. Core processing loop (the former “bumpy” block)
 * -----------------------------------------------------*/
private static long processIndices(int[] indices) {
    long sum = 0L;
    long ans = 0L;

    for (int idx : indices) {
        // previous best using the helper that works on a single index
        ans = Math.max(ans, maxContSum(idx));

        // best achievable by appending the current array as a prefix
        ans = Math.max(ans, sum + maxP[idx]);

        // extend the running sum with the whole current array
        sum += s[idx];

        // after adding, we may want to keep only the best suffix
        sum = Math.max(maxS[idx], sum);

        // overall best so far
        ans = Math.max(ans, sum);
    }
    return ans;
}

