/** Returns a TreeSet containing all numbers 0..n that are not present in array a. */
private static TreeSet<Integer> computeMissingSet(int[] a, int n) {
    TreeSet<Integer> set = new TreeSet<>();
    for (int i = 0; i <= n; i++) {
        set.add(i);
    }
    for (int value : a) {
        set.remove(value);
    }
    return set;
}

/** Handles the case when the smallest missing value equals n.
 *  Finds the first index j where a[j] != j, sets a[j] = n,
 *  and records the (1‑based) position in the answer list. */
private static void handleSpecialCase(int[] a, List<Integer> ans) {
    for (int j = 0; j < a.length; j++) {
        if (a[j] != j) {
            a[j] = a.length;           // a.length == n
            ans.add(j + 1);            // store 1‑based index
            break;
        }
    }
}

/** Handles the normal case where the smallest missing value is < n.
 *  Assigns that value to its own position and records the position. */
private static void handleNormalCase(int[] a, List<Integer> ans,
                                     TreeSet<Integer> missing) {
    int idx = missing.first();          // smallest missing value (< n)
    a[idx] = idx;
    ans.add(idx + 1);                   // store 1‑based index
}

