        TreeSet<Integer> missing = buildMissingSet(a, n, in);

        int cnt = 0;
        while (cnt < 2 * n) {
            applyStep(a, missing, ans);
            // recompute missing set after the step (exactly as original)
            missing = buildMissingSet(a, n, null);
