/**
 * Builds a TreeSet containing all numbers 0..n that are not present in {@code a}.
 * If {@code reader} is non‑null, the method also reads the array values from it.
 */
private static TreeSet<Integer> buildMissingSet(int[] a, int n, InputReader reader) {
    TreeSet<Integer> set = new TreeSet<>();
    for (int v = 0; v <= n; v++) {
        set.add(v);
    }
    if (reader != null) {
        for (int j = 0; j < n; j++) {
            a[j] = reader.nextInt();
            set.remove(a[j]);
        }
    } else {
        for (int j = 0; j < n; j++) {
            set.remove(a[j]);
        }
    }
    return set;
}

/**
 * Executes one iteration of the original while‑loop logic.
 * It mutates {@code a} and records the performed operation in {@code ans}.
 */
private static void applyStep(int[] a, TreeSet<Integer> missing, List<Integer> ans) {
    int firstMissing = missing.first();
    if (firstMissing == a.length) { // missing value is n
        for (int j = 0; j < a.length; j++) {
            if (a[j] != j) {
                a[j] = a.length;          // set to n
                ans.add(j + 1);           // store 1‑based index
                break;
            }
        }
    } else {
        a[firstMissing] = firstMissing;
        ans.add(firstMissing + 1);
    }
}

