private static class SearchContext {
    int i;      // current index in txt
    int j;      // current index in pat
    int count;  // number of matches found
}

/**
 * Counts how many times {@code pat} occurs in {@code txt} using the KMP algorithm.
 */
public static int KMPSearch(String txt, String pat) {
    int m = pat.length();
    int n = txt.length();
    int[] lps = new int[m];
    PrefixTable(pat, m, lps);               // builds the LPS table

    SearchContext ctx = new SearchContext(); // i, j, count start at 0

    while (ctx.i < n) {
        if (charsMatch(txt, pat, ctx.i, ctx.j)) {
            advanceOnMatch(ctx);
        }

        if (ctx.j == m) {
            handleFullMatch(ctx, lps, m);
        } else if (ctx.i < n && !charsMatch(txt, pat, ctx.i, ctx.j)) {
            handleMismatch(ctx, lps);
        }
    }
    return ctx.count;
}

/* -------------------------------------------------------------------- */
/* Helper methods – each encapsulates one logical chunk of the algorithm */
/* -------------------------------------------------------------------- */

private static boolean charsMatch(String txt, String pat, int i, int j) {
    return pat.charAt(j) == txt.charAt(i);
}

/** Advance both indexes when the current characters are equal. */
private static void advanceOnMatch(SearchContext ctx) {
    ctx.j++;
    ctx.i++;
}

/** A full pattern has been found: count it and reset j via the LPS table. */
private static void handleFullMatch(SearchContext ctx, int[] lps, int m) {
    ctx.count++;
    ctx.j = lps[m - 1];   // continue searching for overlapping matches
}

/**
 * Resolve a mismatch:
 *   – if we have a previously matched prefix, fall back using the LPS table
 *   – otherwise move forward in the text.
 */
private static void handleMismatch(SearchContext ctx, int[] lps) {
    if (ctx.j != 0) {
        ctx.j = lps[ctx.j - 1];
    } else {
        ctx.i = ctx.i + 1;
    }
}

public static int KMPSearch(String txt, String pat) {
    int m = pat.length();
    int n = txt.length();
    int[] lps = new int[m];
    int j = 0;
    int count = 0;

    PrefixTable(pat, m, lps);

    int i = 0;
    while (i < n) {
        // Chunk A – character comparison
        if (charactersMatch(txt, pat, i, j)) {
            i++;
            j++;

            // Chunk B – full pattern found
            if (isFullMatch(j, m)) {
                count++;
                j = nextJOnFullMatch(lps, j);
            }
            continue; // continue to next iteration, reduces nesting
        }

        // Chunk C – mismatch handling
        int newJ = nextJOnMismatch(lps, j);
        if (newJ != -1) {
            j = newJ;               // slide pattern using LPS
        } else {
            i++;                    // advance text pointer, j stays 0
            j = 0;
        }
    }
    return count;
}

/* ----- extracted helper methods ----- */

/**
 * Returns true if the characters at the current indices of txt and pat match.
 */
private static boolean charactersMatch(String txt, String pat, int i, int j) {
    return pat.charAt(j) == txt.charAt(i);
}

/**
 * Returns true when the pattern index j has reached the pattern length m,
 * i.e., a full match has been found.
 */
private static boolean isFullMatch(int j, int m) {
    return j == m;
}

/**
 * After a complete match, the next value of j is the value stored in the LPS
 * table at position j‑1.
 */
private static int nextJOnFullMatch(int[] lps, int j) {
    return lps[j - 1];
}

/**
 * Handles a mismatch.
 * • If j != 0, returns the new j (lps[j‑1]) so the pattern slides left.
 * • If j == 0, returns -1 to signal that the text index must be advanced.
 */
private static int nextJOnMismatch(int[] lps, int j) {
    if (j != 0) {
        return lps[j - 1];
    }
    return -1; // special flag meaning “advance i”
}

