/**
 * Returns the index (0‑based) of the smallest element in the array.
 */
private int indexOfMinElement(int[] arr)
{
    int min = Integer.MAX_VALUE;
    int minIdx = 0;

    for (int i = 0; i < arr.length; ++i) {
        if (arr[i] < min) {
            min = arr[i];
            minIdx = i;
        }
    }
    return minIdx;
}

/**
 * Returns the start index (0‑based) of the length‑k sub‑array whose sum is minimal.
 * Assumes k > 0 and k <= arr.length.
 */
private int startIndexOfMinSumWindow(int[] arr, int k)
{
    int currentSum = 0;
    // sum of the first window
    for (int i = 0; i < k; ++i) {
        currentSum += arr[i];
    }
    int minSum = currentSum;
    int minIdx = 0;

    // slide the window across the array
    for (int i = 1; i <= arr.length - k; ++i) {
        currentSum = (currentSum - arr[i - 1]) + arr[i + k - 1];
        if (currentSum < minSum) {
            minSum = currentSum;
            minIdx = i;
        }
    }
    return minIdx;
}

