/** Initialise global arrays and adjacency list, and fill depth information. */
private static void buildTree(int n) {
    depths = new int[n];
    pre    = new int[n];
    post   = new int[n];
    g      = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        g[i] = new ArrayList<>();
    }
    for (int i = 1; i < n; i++) {
        int parent = input.nextInt() - 1;
        depths[i] = depths[parent] + 1;
        g[parent].add(i);
    }
}

/** Execute all queries. */
private static void processQueries(int n, PrintWriter out) throws IOException {
    int q = input.nextInt();
    IT it = new IT(n);

    for (int i = 0; i < q; i++) {
        int type = input.nextInt();
        if (type == 1) {
            handleUpdate(it);
        } else {
            handleQuery(it, out);
        }
    }
}

/** Process a type‑1 query: range update on subtree of node x. */
private static void handleUpdate(IT it) throws IOException {
    int x = input.nextInt() - 1;
    int v = input.nextInt();
    int k = input.nextInt();
    it.add(pre[x], post[x], v, k, depths[x]);
}

/** Process a type‑2 query: retrieve the current value for node x. */
private static void handleQuery(IT it, PrintWriter out) throws IOException {
    int x = input.nextInt() - 1;
    int original = x;
    int idx = pre[x];

    long value = it.getVal(idx);
    long slope = it.getSlope(idx);
    long result = (value - depths[original] * slope) % mod;
    if (result < 0) result += mod;
    out.println(result);
}

