/** Allocate the global arrays/lists for a tree of size n. */
private static void allocateStructures(int n) {
    depths = new int[n];
    pre = new int[n];
    post = new int[n];
    g = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        g[i] = new ArrayList<Integer>();
    }
}

/** Build the adjacency list and depth array from the parent list. */
private static void readTree(int n) {
    for (int i = 1; i < n; i++) {
        int p = input.nextInt() - 1;          // parent index (0‑based)
        depths[i] = depths[p] + 1;            // depth of node i
        g[p].add(i);                          // add child to parent list
    }
}

/** Iterate over all queries and delegate to the proper handler. */
private static void processQueries(int q, IT it, PrintWriter out) {
    for (int i = 0; i < q; i++) {
        int type = input.nextInt();
        if (type == 1) {
            handleUpdate(it);
        } else {
            handleQuery(it, out);
        }
    }
}

/** Process a type‑1 query: range update on a subtree. */
private static void handleUpdate(IT it) {
    int x = input.nextInt() - 1;
    int v = input.nextInt();
    int k = input.nextInt();

    it.add(pre[x], post[x], v, k, depths[x]);
}

/** Process a type‑2 query: point query on a node. */
private static void handleQuery(IT it, PrintWriter out) {
    int x = input.nextInt() - 1;
    int original = x;          // keep original index for depth lookup
    x = pre[x];                // map to preorder index

    long v = it.getVal(x);
    long s = it.getSlope(x);

    long res = (v - depths[original] * s) % mod;
    if (res < 0) res += mod;
    out.println(res);
}

