}

private static void readTreeEdges(int n) {
    for (int i = 1; i < n; i++) {
        int p = input.nextInt() - 1;          // parent index (0‑based)
        depths[i] = depths[p] + 1;            // compute depth while reading
        g[p].add(i);                          // adjacency list
    }
}

/* depth‑first search that fills pre‑ and post‑order numbers */
private static void dfs(int v) {
    pre[v] = cnt++;
    for (int to : g[v]) {
        dfs(to);
    }
    post[v] = cnt - 1;
}

/* process a type‑1 query (range update) */
private static void handleUpdate(int x, int v, int k, IT it) {
    it.add(pre[x], post[x], v, k, depths[x]);
}

/* process a type‑2 query (point query) */
private static void handleQuery(int x, IT it, PrintWriter out) {
    int original = x;          // keep original vertex index
    int idx = pre[x];          // map to Euler order position
    long val = it.getVal(idx);
    long slope = it.getSlope(idx);
    long res = (val - depths[original] * slope) % mod;
    if (res < 0) {
        res += mod;
    }
    out.println(res);
}

