/** Counts '0', '1', '2' in the given string. */
private static int[] countDigits(String s) {
    int zeros = 0, ones = 0, twos = 0;
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == '0') zeros++;
        else if (c == '1') ones++;
        else twos++;
    }
    return new int[]{zeros, ones, twos};
}

/** First pass – create missing zeros by converting surplus '1' or '2'. */
private static void fillZeros(char[] a, int[] deficit) {
    // deficit[0] = needZero, deficit[1] = needTwo (t1), deficit[2] = needOne (o1)
    if (deficit[0] <= 0) return;

    for (int i = 0; i < a.length && deficit[0] > 0; i++) {
        if (a[i] == '2' && deficit[1] < 0) {
            a[i] = '0';
            deficit[0]--;
            deficit[1]++;          // we removed a surplus two
        } else if (a[i] == '1' && deficit[2] < 0) {
            a[i] = '0';
            deficit[0]--;
            deficit[2]++;          // we removed a surplus one
        }
    }
}

/** Second pass – create missing twos by converting surplus '0' or '1'. */
private static void fillTwos(char[] a, int[] deficit) {
    // deficit[1] = needTwo, deficit[0] = needZero, deficit[2] = needOne
    if (deficit[1] <= 0) return;

    for (int i = a.length - 1; i >= 0 && deficit[1] > 0; i--) {
        if (a[i] == '1' && deficit[2] < 0) {
            a[i] = '2';
            deficit[1]--;
            deficit[2]++;          // we removed a surplus one
        } else if (a[i] == '0' && deficit[0] < 0) {
            a[i] = '2';
            deficit[1]--;
            deficit[0]++;          // we removed a surplus zero
        }
    }
}

/** Third pass – create missing ones by converting surplus '0' or '2'. */
private static void fillOnes(char[] a, int[] deficit) {
    // deficit[2] = needOne, deficit[0] = needZero, deficit[1] = needTwo
    if (deficit[2] <= 0) return;

    // left‑to‑right: turn surplus '2' into '1'
    for (int i = 0; i < a.length && deficit[2] > 0; i++) {
        if (a[i] == '2' && deficit[1] < 0) {
            a[i] = '1';
            deficit[2]--;
            deficit[1]++;          // we removed a surplus two
        }
    }

    // right‑to‑left: turn surplus '0' into '1'
    for (int i = a.length - 1; i >= 0 && deficit[2] > 0; i--) {
        if (a[i] == '0' && deficit[0] < 0) {
            a[i] = '1';
            deficit[2]--;
            deficit[0]++;          // we removed a surplus zero
        }
    }
}

/** Builds the final string from the character array. */
private static StringBuilder buildResult(char[] a) {
    StringBuilder sb = new StringBuilder(a.length);
    for (char c : a) sb.append(c);
    return sb;
}

public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    PrintWriter out = new PrintWriter(System.out);
    int n = sc.nextInt();
    String s = sc.nextLine();                     // original reading order preserved
    int zeros = 0, ones = 0, twos = 0;

    // count existing digits
    for (int i = 0; i < n; i++) {
        char c = s.charAt(i);
        if (c == '0')
            zeros++;
        else if (c == '1')
            ones++;
        else
            twos++;
    }

    char[] a = s.toCharArray();
    int needEach = n / 3;
    int[] deficit = new int[3];                   // 0: zeros, 1: ones, 2: twos
    deficit[0] = needEach - zeros;
    deficit[1] = needEach - ones;
    deficit[2] = needEach - twos;

    if (deficit[0] > 0) {
        adjustZeros(a, n, deficit);
    }
    if (deficit[2] > 0) {
        adjustTwos(a, n, deficit);
    }
    if (deficit[1] > 0) {
        adjustOnes(a, n, deficit);
    }

    out.println(buildResult(a, n));
    out.flush();
}

/**
 * Convert surplus ‘1’ or ‘2’ into ‘0’ while we still need more zeros.
 */
private static void adjustZeros(char[] a, int n, int[] deficit) {
    for (int i = 0; i < n && deficit[0] > 0; i++) {
        if (a[i] == '2' && deficit[2] < 0) {
            a[i] = '0';
            deficit[0]--;
            deficit[2]++;
        } else if (a[i] == '1' && deficit[1] < 0) {
            a[i] = '0';
            deficit[0]--;
            deficit[1]++;
        }
    }
}

/**
 * Convert surplus ‘0’ or ‘1’ into ‘2’ while we still need more twos.
 */
private static void adjustTwos(char[] a, int n, int[] deficit) {
    for (int i = n - 1; i >= 0 && deficit[2] > 0; i--) {
        if (a[i] == '1' && deficit[1] < 0) {
            a[i] = '2';
            deficit[2]--;
            deficit[1]++;
        } else if (a[i] == '0' && deficit[0] < 0) {
            a[i] = '2';
            deficit[2]--;
            deficit[0]++;
        }
    }
}

/**
 * Convert surplus ‘0’ or ‘2’ into ‘1’ while we still need more ones.
 * First a forward pass (using excess twos), then a backward pass (using excess zeros).
 */
private static void adjustOnes(char[] a, int n, int[] deficit) {
    // forward pass – replace excess ‘2’ with ‘1’
    for (int i = 0; i < n && deficit[1] > 0; i++) {
        if (a[i] == '2' && deficit[2] < 0) {
            a[i] = '1';
            deficit[1]--;
            deficit[2]++;
        }
    }
    // backward pass – replace excess ‘0’ with ‘1’
    for (int i = n - 1; i >= 0 && deficit[1] > 0; i--) {
        if (a[i] == '0' && deficit[0] < 0) {
            a[i] = '1';
            deficit[1]--;
            deficit[0]++;
        }
    }
}

/**
 * Build the final string from the character array.
 */
private static String buildResult(char[] a, int n) {
    StringBuilder sb = new StringBuilder(n);
    for (int i = 0; i < n; i++) {
        sb.append(a[i]);
    }
    return sb.toString();
}

