public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int N = sc.nextInt();
    String S = sc.next();

    List<Node> firstHalfNodes = generateFirstHalfNodes(S, N);
    Map<String, Map<String, Long>> secondHalfMap = buildSecondHalfMap(S, N);
    long ans = countMatches(firstHalfNodes, secondHalfMap);

    System.out.println(ans);
}

/**
 * Generates all (s1, s2) pairs for the first N characters of the string.
 * s1 – characters kept in original order,
 * s2 – characters omitted, collected in reverse order.
 */
private static List<Node> generateFirstHalfNodes(String S, int N) {
    List<Node> list = new ArrayList<>();
    int total = 1 << N;               // 2^N subsets
    for (int mask = 0; mask < total; mask++) {
        StringBuilder s1 = new StringBuilder();
        StringBuilder s2 = new StringBuilder();
        for (int j = 0; j < N; j++) {
            if ((mask & (1 << j)) != 0) {
                s1.append(S.substring(j, j + 1));
            } else {
                // prepend to keep reverse order
                s2.insert(0, S.substring(j, j + 1));
            }
        }
        list.add(new Node(s1.toString(), s2.toString()));
    }
    return list;
}

/**
 * Builds the map that for each s1 (formed from the second half of the string)
 * records how many times each corresponding s2 appears.
 */
private static Map<String, Map<String, Long>> buildSecondHalfMap(String S, int N) {
    Map<String, Map<String, Long>> map = new HashMap<>();
    int total = 1 << N;               // 2^N subsets
    int offset = N;                   // start of the second half

    for (int mask = 0; mask < total; mask++) {
        StringBuilder s1 = new StringBuilder();
        StringBuilder s2 = new StringBuilder();

        for (int j = 0; j < N; j++) {
            int idx = j + offset;
            if ((mask & (1 << j)) != 0) {
                s1.append(S.substring(idx, idx + 1));
            } else {
                s2.insert(0, S.substring(idx, idx + 1));
            }
        }

        String key1 = s1.toString();
        String key2 = s2.toString();

        map.computeIfAbsent(key1, k -> new HashMap<>())
           .merge(key2, 1L, Long::sum);
    }

    return map;
}

/**
 * Counts how many (s1, s2) pairs from the first half match a reversed pair
 * stored in the second‑half map.
 */
private static long countMatches(List<Node> nodes,
                                 Map<String, Map<String, Long>> map) {
    long ans = 0L;
    for (Node node : nodes) {
        String s1 = node.a;   // from first half (kept characters)
        String s2 = node.b;   // from first half (removed characters, reversed)

        Map<String, Long> inner = map.get(s2);
        if (inner != null) {
            Long cnt = inner.get(s1);
            if (cnt != null) {
                ans += cnt;
            }
        }
    }
    return ans;
}

