/** Reads the permutation and colour arrays (1‑based). */
private static void readArrays(BufferedReader br, int n, int[] arr, int[] colors)
        throws IOException {
    StringTokenizer st1 = new StringTokenizer(br.readLine());
    StringTokenizer st2 = new StringTokenizer(br.readLine());
    for (int i = 1; i <= n; i++) {
        arr[i] = Integer.parseInt(st1.nextToken());
        colors[i] = Integer.parseInt(st2.nextToken());
    }
}

/** Returns all cycles of the permutation defined by arr (1‑based indexing). */
private static List<List<Integer>> buildCycles(int[] arr, int n) {
    List<List<Integer>> cycles = new ArrayList<>();
    boolean[] seen = new boolean[n + 1];

    for (int i = 1; i <= n; i++) {
        if (seen[i]) continue;

        List<Integer> cycle = new ArrayList<>();
        int cur = i;
        do {
            cycle.add(cur);
            seen[cur] = true;
            cur = arr[cur];
        } while (cur != i);
        cycles.add(cycle);
    }
    return cycles;
}

/** Finds the smallest divisor over all cycles that satisfies the colour condition. */
private static int computeMinAnswer(List<List<Integer>> cycles, int[] colors) {
    int minAns = Integer.MAX_VALUE;

    for (List<Integer> cycle : cycles) {
        List<Integer> divs = divisors(cycle.size()); // assumed to exist elsewhere
        for (int d : divs) {
            if (hasValidShift(cycle, colors, d)) {
                minAns = Math.min(minAns, d);
                break; // smallest divisor for this cycle found
            }
        }
    }
    return minAns;
}

/** Returns true if there exists a rotation start such that every d‑th element
 *  of the cycle has the same colour. */
private static boolean hasValidShift(List<Integer> cycle, int[] colors, int d) {
    int sz = cycle.size();
    for (int start = 0; start < d; start++) {
        int expectedColour = colors[cycle.get(start)];
        boolean ok = true;
        for (int offset = 0; offset < sz; offset += d) {
            int idx = (start + offset) % sz;
            if (colors[cycle.get(idx)] != expectedColour) {
                ok = false;
                break;
            }
        }
        if (ok) {
            return true;
        }
    }
    return false;
}

public static void main(String[] args) throws IOException {
    BufferedReader f = new BufferedReader(new InputStreamReader(System.in));
    PrintWriter out = new PrintWriter(new OutputStreamWriter(System.out));
    int t = Integer.parseInt(f.readLine());
    while (t-- > 0) {
        int n = Integer.parseInt(f.readLine());
        int[] arr = new int[n + 1];
        int[] colors = new int[n + 1];
        StringTokenizer st1 = new StringTokenizer(f.readLine());
        StringTokenizer st2 = new StringTokenizer(f.readLine());
        for (int i = 1; i <= n; i++) {
            arr[i] = Integer.parseInt(st1.nextToken());
            colors[i] = Integer.parseInt(st2.nextToken());
        }

        List<List<Integer>> cycles = findCycles(arr, n);
        int minAns = Integer.MAX_VALUE;

        for (List<Integer> cycle : cycles) {
            int bestDiv = minimalDivisorForCycle(cycle, colors);
            minAns = Math.min(minAns, bestDiv);
        }

        out.println(minAns);
    }
    out.close();
}

/** Detects all cycles of the permutation `arr` (1‑based). */
private static List<List<Integer>> findCycles(int[] arr, int n) {
    List<List<Integer>> cycles = new ArrayList<>();
    boolean[] seen = new boolean[n + 1];

    for (int i = 1; i <= n; i++) {
        if (seen[i]) {
            continue;
        }
        List<Integer> cycle = new ArrayList<>();
        int cur = i;
        cycle.add(cur);
        cur = arr[cur];
        while (cur != i) {
            cycle.add(cur);
            seen[cur] = true;
            cur = arr[cur];
        }
        cycles.add(cycle);
    }
    return cycles;
}

/** Returns the smallest divisor `d` of the cycle length for which all
 *  vertices spaced `d` apart have the same colour. */
private static int minimalDivisorForCycle(List<Integer> cycle, int[] colors) {
    List<Integer> divisors = divisors(cycle.size());   // assumed existing helper
    for (int d : divisors) {
        if (hasUniformColourForDivisor(cycle, d, colors)) {
            return d;          // the first (smallest) suitable divisor
        }
    }
    // Should never reach here because divisor = cycle.size() always works
    return cycle.size();
}

/** Checks whether for a given divisor `d` the colours repeat uniformly
 *  around the cycle. */
private static boolean hasUniformColourForDivisor(List<Integer> cycle, int d, int[] colors) {
    int len = cycle.size();
    for (int start = 0; start < d; start++) {
        int expectedColour = colors[cycle.get(start)];
        boolean ok = true;
        for (int pos = start; pos < len; pos += d) {
            if (colors[cycle.get(pos)] != expectedColour) {
                ok = false;
                break;
            }
        }
        if (ok) {
            return true;
        }
    }
    return false;
}

