public void solve(int testNumber, inputClass sc, PrintWriter out) {
    int n = sc.nextInt();
    StringBuilder s = new StringBuilder(sc.nextLine());
    boolean[] used = new boolean[n];

    int nb = processKnownPairs(s, n, used);
    if (nb == -1) {
        out.println("IMPOSSIBLE");
        return;
    }

    int toAdd = countUnusedLetters(used, n);
    if (toAdd > nb) {
        out.println("IMPOSSIBLE");
        return;
    }

    fillRemainingPairs(s, n, nb, toAdd, used);
    out.println(s);
}

/** 
 * Handles the first half of the string:
 *  – matches already known characters,
 *  – counts pairs of both‑side ‘?’ (nb),
 *  – fills the {@code used} array.
 * Returns {@code -1} if the palindrome cannot be formed.
 */
private int processKnownPairs(StringBuilder s, int n, boolean[] used) {
    int nb = 0;
    int len = s.length();
    int half = len / 2 + (len % 2 == 0 ? 0 : 1);

    for (int i = 0; i < half; i++) {
        char left = s.charAt(i);
        char right = s.charAt(len - 1 - i);

        if (left == '?' && right == '?') {
            nb++;
            continue;
        }

        // exactly one side is '?'
        if (left == '?' ^ right == '?') {
            if (left == '?') {
                s.setCharAt(i, right);
                left = right;
            } else {
                s.setCharAt(len - 1 - i, left);
                right = left;
            }
        }

        // mismatch after the above substitution
        if (left != right) {
            return -1;                 // impossible
        }

        used[left - 'a'] = true;      // mark the letter as already present
    }
    return nb;
}

/** Counts how many letters from {@code 0 … n‑1} are still unused. */
private int countUnusedLetters(boolean[] used, int n) {
    int cnt = 0;
    for (int i = 0; i < n; i++) {
        if (!used[i]) cnt++;
    }
    return cnt;
}

/** Fills the remaining ‘?’ pairs with either ‘a’ or the smallest unused letters. */
private void fillRemainingPairs(StringBuilder s, int n, int nb, int toAdd, boolean[] used) {
    int len = s.length();
    int half = len / 2 + (len % 2 == 0 ? 0 : 1);
    int nxt = firstUnusedLetter(used, n);

    for (int i = 0; i < half; i++) {
        if (s.charAt(i) != '?') continue;

        if (nb > toAdd) {                     // we have spare “both‑?'’ pairs
            s.setCharAt(i, 'a');
            s.setCharAt(len - 1 - i, 'a');
            nb--;
        } else {
            // use the next still‑unused letter
            while (nxt < n && used[nxt]) nxt++;
            char c = (char) (nxt + 'a');
            s.setCharAt(i, c);
            s.setCharAt(len - 1 - i, c);
            used[nxt] = true;                // now this letter is used
            nxt++;
        }
    }
}

/** Finds the smallest index of an unused letter (0‑based). Returns {@code n} if none exist. */
private int firstUnusedLetter(boolean[] used, int n) {
    for (int i = 0; i < n; i++) {
        if (!used[i]) return i;
    }
    return n;
}

