/**
 * Performs the multi‑source BFS that was previously nested inside {@code work}.
 * The method extracts the level‑by‑level iteration and the neighbour handling
 * into dedicated helpers so that each block of logic is small and self‑contained.
 */
private Set<Integer> bfsCollectEdges(ArrayList<int[]>[] graph,
                                     Set<Integer> sources,
                                     int maxDist,
                                     int nodeCount) {
    Set<Integer> cutEdges = new HashSet<>();
    int[] visitedBy = new int[nodeCount];
    Arrays.fill(visitedBy, -1);
    LinkedList<int[]> queue = new LinkedList<>();

    // initialise the queue with all source vertices
    for (int src : sources) {
        visitedBy[src] = src;
        queue.add(new int[]{src, src, 0}); // {currentNode, rootSource, distanceFromRoot}
    }

    while (!queue.isEmpty()) {
        int levelSize = queue.size();
        for (int i = 0; i < levelSize; i++) {
            int[] entry = queue.poll();
            processQueueEntry(entry, graph, visitedBy, maxDist, queue, cutEdges);
        }
    }
    return cutEdges;
}

/**
 * Handles one element taken from the BFS queue. The inner neighbour loop
 * is delegated to {@link #handleNeighbour(int, int[], int, int, int[], int, LinkedList, Set)}.
 */
private void processQueueEntry(int[] entry,
                               ArrayList<int[]>[] graph,
                               int[] visitedBy,
                               int maxDist,
                               LinkedList<int[]> queue,
                               Set<Integer> cutEdges) {
    int node = entry[0];
    int root = entry[1];
    int dist = entry[2];

    for (int[] edge : graph[node]) {
        handleNeighbour(edge, root, dist, visitedBy, maxDist, queue, cutEdges);
    }
}

/**
 * Encapsulates the decision logic for a single neighbour of the current node.
 */
private void handleNeighbour(int[] edgeInfo,
                             int root,
                             int dist,
                             int[] visitedBy,
                             int maxDist,
                             LinkedList<int[]> queue,
                             Set<Integer> cutEdges) {
    int neighbour = edgeInfo[0];
    int edgeId   = edgeInfo[1];

    if (visitedBy[neighbour] == root) {
        // already visited from the same source – nothing to do
        return;
    }
    if (visitedBy[neighbour] != -1) {
        // visited from a different source -> the edge is a cut edge
        cutEdges.add(edgeId);
        return;
    }
    if (dist == maxDist) {
        // we have reached the maximum permitted distance from the source
        cutEdges.add(edgeId);
    } else {
        visitedBy[neighbour] = root;
        queue.add(new int[]{neighbour, root, dist + 1});
    }
}

