/* ---------- helper methods ---------- */

private HashSet<Integer> readSpecialNodes(int count) {
    HashSet<Integer> set = new HashSet<>();
    for (int i = 0; i < count; i++) {
        set.add(in.nextInt() - 1);               // store 0‑based indices
    }
