}

@SuppressWarnings("unchecked")
private ArrayList<int[]>[] createEmptyGraph(int n) {
    ArrayList<int[]>[] g = (ArrayList<int[]>[]) new ArrayList[n];
    for (int i = 0; i < n; i++) {
        g[i] = new ArrayList<>();
    }
    return g;
}

private void readEdgesAndBuildGraph(ArrayList<int[]>[] graph, int edgeCount) {
    for (int i = 0; i < edgeCount; i++) {
        int a = in.nextInt() - 1;
        int b = in.nextInt() - 1;
        int edgeId = i + 1;                      // original 1‑based edge identifier
        graph[a].add(new int[] { b, edgeId });
        graph[b].add(new int[] { a, edgeId });
    }
}

private HashSet<Integer> bfsCollectEdges(ArrayList<int[]>[] graph,
                                          HashSet<Integer> sources,
                                          int maxDepth) {
    HashSet<Integer> collected = new HashSet<>();
    int n = graph.length;
    int[] visitedRoot = new int[n];
    Arrays.fill(visitedRoot, -1);
    LinkedList<int[]> queue = new LinkedList<>();

    initializeBfsQueue(sources, visitedRoot, queue);

    while (!queue.isEmpty()) {
        int levelSize = queue.size();
        for (int i = 0; i < levelSize; i++) {
            int[] current = queue.poll();               // {node, root, distance}
            processNode(current, graph, visitedRoot, maxDepth, collected, queue);
        }
    }
    return collected;
}

private void initializeBfsQueue(HashSet<Integer> sources,
                                 int[] visitedRoot,
                                 LinkedList<int[]> queue) {
    for (int node : sources) {
        visitedRoot[node] = node;
        queue.add(new int[] { node, node, 0 });
    }
}

private void processNode(int[] entry,
                         ArrayList<int[]>[] graph,
                         int[] visitedRoot,
                         int maxDepth,
                         HashSet<Integer> collected,
                         LinkedList<int[]> queue) {
    int node = entry[0];
    int root = entry[1];
    int dist = entry[2];

    for (int[] edge : graph[node]) {
        int neighbour = edge[0];
        int edgeId   = edge[1];

        if (visitedRoot[neighbour] == root) {
            continue;                        // already reached from the same source
        }
        if (visitedRoot[neighbour] != -1) {   // reached from a different source
            collected.add(edgeId);
        } else {
            if (dist == maxDepth) {
                collected.add(edgeId);
            } else {
                visitedRoot[neighbour] = root;
                queue.add(new int[] { neighbour, root, dist + 1 });
            }
        }
    }
}

