public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    String n = sc.next();

    if (startsWithOne(n)) {
        System.out.println(powerOfNine(n.length() - 1));
        return;
    }

    long bestWithDecrease = maxProductByDecreasingSomeDigit(n);
    long productAllDigits = productOfDigits(n);

    System.out.println(Math.max(productAllDigits, bestWithDecrease));
}

/* ----- helper methods ----- */

private static boolean startsWithOne(String s) {
    return s.charAt(0) == '1';
}

/** Returns 9 to the power of exp (i.e., 9ⁿ). */
private static long powerOfNine(int exp) {
    long result = 1L;
    for (int i = 0; i < exp; i++) {
        result *= 9L;
    }
    return result;
}

/** Product of every digit in the given numeric string. */
private static long productOfDigits(String s) {
    long prod = 1L;
    for (int i = 0; i < s.length(); i++) {
        prod *= digitValue(s.charAt(i));
    }
    return prod;
}

/** Returns the maximal product obtainable by decreasing one digit
 *  (or none) and turning all following digits into 9.
 */
private static long maxProductByDecreasingSomeDigit(String n) {
    long best = 0L;
    int len = n.length();

    for (int i = 0; i < len; i++) {
        char cur = n.charAt(i);
        if (cur == '0') {
            continue;                 // cannot decrease a zero
        }

        long prefixProduct = productOfPrefix(n, i);
        long decreasedDigit = digitValue(cur) - 1;
        long suffixProduct = powerOfNine(len - i - 1);

        long candidate = prefixProduct * decreasedDigit * suffixProduct;
        best = Math.max(best, candidate);
    }
    return best;
}

/** Product of digits in the prefix [0, exclusiveEnd). */
private static long productOfPrefix(String s, int exclusiveEnd) {
    long prod = 1L;
    for (int i = 0; i < exclusiveEnd; i++) {
        prod *= digitValue(s.charAt(i));
    }
    return prod;
}

/** Converts a digit character ('0'‑'9') to its integer value. */
private static int digitValue(char c) {
    return c - '0';
}

