 * prefix. Performs a binary search on the max‑prefix array to locate the
 * first position with a larger maximum, trims the stack accordingly, and
 * computes dp[i] based on that position.
 */
private void handleDecreasingCase(int i, int[] a, int[] dp, int[] max, Stack<Integer> stack) {
    int left = -1;
    int right = i - 1;

    // binary search for the smallest index r such that max[r] > a[i]
