/** 
 * Binary‑searches the first index {@code r} (0 ≤ r < i) such that
 * {@code max[r] > value}. Returns {@code i‑1} when no such index exists.
 */
private int findFirstGreater(int[] max, int i, int value) {
    int l = -1;
    int r = i - 1;
    while (r - l > 1) {
        int m = (l + r) >>> 1;               // unsigned right shift = divide by 2
        if (max[m] > value) {
            r = m;
        } else {
            l = m;
        }
    }
    return r;
}

/** Pops elements from the stack while the top index exceeds {@code bound}. */
private void pruneStack(Stack<Integer> stack, int bound) {
    while (stack.peek() > bound) {
        stack.pop();
    }
}

