    if (n > 1) arr[1] = false;
    return arr;
}

private static void applySieve(boolean[] arr) {
    int limit = (int) Math.sqrt(arr.length);
    for (int i = 2; i <= limit; i++) {
        if (arr[i]) {
            for (int j = i * i; j < arr.length; j += i) {
                arr[j] = false;
            }
        }
    }
}

private static List<Integer> collectPrimes(boolean[] arr) {
    List<Integer> list = new ArrayList<>();
    for (int i = 0; i < arr.length; i++) {
        if (arr[i]) {
            list.add(i);
        }
    }
    return list;
}

