private static long computeAnswer(int n, int x, int pos) {
    final long MOD = 1_000_000_007L;
    long larger = n - x;      // numbers greater than x
    long smaller = x - 1;     // numbers smaller than x

    // 1️⃣ binary‑search‑like simulation
    SearchResult sr = runBinarySearch(n, pos, larger, smaller, MOD);

    // 2️⃣ multiply the remaining values (factorial of smaller+larger)
    return multiplyRemaining(sr.ans, sr.larger + sr.smaller, MOD);
