/**
 * Simulates the binary‑search process described in the original code.
 * It updates the answer while consuming “larger” or “smaller” values.
 */
private static SearchResult runBinarySearch(int n, int pos,
                                            long larger, long smaller,
                                            long mod) {
    long ans = 1;
    int lo = 0;
    int hi = n;

    while (lo < hi) {
        int mid = (lo + hi) / 2;
        if (mid > pos) {
            hi = mid;
            ans = (ans * larger) % mod;
            larger--;
        } else if (mid < pos) {
            lo = mid + 1;
            ans = (ans * smaller) % mod;
            smaller--;
        } else { // mid == pos
            lo = mid + 1;
            if (lo == n - 1) {
                ans = (ans * larger) % mod;
                larger--;
                break;
            }
        }
    }
    return new SearchResult(ans, larger, smaller);
}

/**
 * Multiplies {@code current} by 1 … {@code upTo} (inclusive) modulo {@code mod}.
 */
private static long multiplyRemaining(long current, long upTo, long mod) {
    for (long i = 1; i <= upTo; i++) {
        current = (current * i) % mod;
    }
    return current;
}

