 * the count of numbers larger than x and the count of numbers smaller than x.
 */
private static SearchResult performBinarySearch(int n, int x, int pos, long mod) {
    long ans = 1L;
    long larger = n - x;   // numbers > x
    long smaller = x - 1;  // numbers < x

