    long sum = 0;
    for (int col = 0; col < trees.length; col++) {
        sum += print[col] = trees[col].query();
    }
    return sum;
}

/**
 * Slides a window of size {@code windowSize} down the rows,
 * updating the segment trees incrementally.
 * Returns {@code true} if any window yields a total ≤ {@code limit},
 * and leaves {@code print} with the values of the successful window.
 */
private static boolean slideWindowAndCheck(
        SegmentTree[] trees, long[][] a, int windowSize, long limit, long[] print) {

    int n = a.length;
    int m = trees.length;

    for (int i = 0, j = windowSize; j < n; i++, j++) {
        // remove the row that slides out of the window
        for (int col = 0; col < m; col++) {
            trees[col].update_point(i + 1, 0L);
        }
        // add the new row that slides into the window
        for (int col = 0; col < m; col++) {
            trees[col].update_point(j + 1, a[j][col]);
        }

        long curr = computePrintAndSum(trees, print);
        if (curr <= limit) {
            return true;            // successful window found
        }
    }
    return false;                   // no window satisfied the condition
}

public static void main(String[] args) throws Exception {
    Scanner sc = new Scanner();
    PrintWriter out = new PrintWriter(System.out);

    int n = sc.nextInt(), m = sc.nextInt(), k = sc.nextInt();

    long[][] a = new long[n][m];
    for (int i = 0; i < n; i++)
        for (int j = 0; j < m; j++)
            a[i][j] = sc.nextLong();

    int start = 1, end = n;
    long[] ans = new long[m];

    while (start <= end) {
        int mid = start + (end - start) / 2;

        // 1️⃣ build empty segment trees
        SegmentTree[] trees = createSegmentTrees(m, n);

        // 2️⃣ fill with the first 'mid' rows and evaluate the first window
        long[] currentPrint = queryAllTrees(trees, a, mid, m);
        long currentSum = sumArray(currentPrint);
        boolean can = currentSum <= k;
        if (can) ans = currentPrint.clone();

        // 3️⃣ slide the window if the first window was not feasible
        if (!can) {
            long[] slidePrint = new long[m];
            can = slideWindow(trees, a, n, m, mid, k, slidePrint);
            if (can) ans = slidePrint.clone();
        }

        // binary‑search direction
        if (can) {
            start = mid + 1;
        } else {
            end = mid - 1;
        }
    }

    for (long x : ans) out.print(x + " ");
    out.flush();
    out.close();
}

/* ---------- helper methods introduced by the refactoring ---------- */

private static SegmentTree[] createSegmentTrees(int m, int n) {
    SegmentTree[] trees = new SegmentTree[m];
    for (int i = 0; i < m; i++) {
        trees[i] = new SegmentTree(n);
    }
    return trees;
}

/**
 * Inserts the first {@code rows} of {@code a} into the segment trees
 * and returns the array containing each tree's query result.
 */
private static long[] queryAllTrees(SegmentTree[] trees, long[][] a, int rows, int m) {
    // populate the trees with the first 'rows' rows
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < m; j++) {
            trees[j].update_point(i + 1, a[i][j]);
        }
    }
    // collect the query results
    long[] print = new long[m];
    for (int l = 0; l < m; l++) {
        print[l] = trees[l].query();
    }
    return print;
}

/**
 * Slides a fixed‑size window of {@code mid} rows over the remaining rows.
 * Updates {@code bestPrint} with the query results of the first feasible window.
 *
 * @return {@code true} if a feasible window (sum ≤ k) is found.
 */
private static boolean slideWindow(SegmentTree[] trees, long[][] a, int n, int m,
                                   int mid, long k, long[] bestPrint) {
    for (int i = 0, j = mid; j < n; i++, j++) {
        // remove the row that leaves the window
        for (int l = 0; l < m; l++) {
            trees[l].update_point(i + 1, 0L);
        }
        // add the new row that enters the window
        for (int l = 0; l < m; l++) {
            trees[l].update_point(j + 1, a[j][l]);
        }
        // recompute queries and total sum
        long currentSum = 0;
        for (int l = 0; l < m; l++) {
            bestPrint[l] = trees[l].query();
            currentSum += bestPrint[l];
        }
        if (currentSum <= k) {
            return true;
        }
    }
    return false;
}

/** Simple utility to sum the elements of a long array. */
private static long sumArray(long[] arr) {
    long s = 0;
    for (long v : arr) s += v;
    return s;
}

