/* ---------- helper methods ---------- */

private static Node[] readNodes(SC scan, int n) {
    Node[] a = new Node[n];
    for (int i = 0; i < n; i++) {
        a[i] = new Node(i);
    }
    for (int i = 0; i < n; i++) {
        a[i].p = scan.nextInt();
    }
    for (int i = 0; i < n; i++) {
        a[i].c = scan.nextInt();
    }
    return a;
}

private static long[] computeAnswers(Node[] nodes, int k) {
    // sort by p
    Arrays.sort(nodes, new byP());

    // priority queue ordered by c
    PriorityQueue<Node> pq = new PriorityQueue<>(new byC());
    for (Node node : nodes) {
        pq.add(node);
    }

    long[] ans = new long[nodes.length];
    for (Node cur : nodes) {
        long sum = cur.c + accumulateKSmallest(cur, pq, k);
        ans[cur.i] = sum;
    }
    return ans;
}

/**
 * Takes up to {@code k} nodes from {@code pq} whose {@code p} value is
 * strictly smaller than {@code current.p}.  Their {@code c} values are summed
 * and the taken nodes are temporarily removed from the queue.
 * Nodes with {@code p >= current.p} are discarded permanently – this matches
 * the original algorithm's behaviour.
 */
private static long accumulateKSmallest(Node current,
                                        PriorityQueue<Node> pq,
                                        int k) {
    long sum = 0L;
    Stack<Node> temp = new Stack<>();
    int taken = 0;

    while (taken < k && !pq.isEmpty()) {
        Node top = pq.peek();

        // Guard clause – discard nodes that are not eligible
        if (top.p >= current.p) {
            pq.poll();          // permanently remove
            continue;           // do not count this iteration
        }

        // Eligible node: add its contribution and remember it for later restoration
        sum += top.c;
        temp.push(pq.poll());
        taken++;
    }

    // Restore the nodes we temporarily removed
    while (!temp.isEmpty()) {
        pq.add(temp.pop());
    }
    return sum;
}

