}

/** Returns true iff the given undirected graph satisfies the “K” conditions. */
private static boolean isKGraph(int[][] g) {
    int n = g.length;

    // ----- step 1: find a suitable root -----
    visited = new boolean[n];
    isRoot = new boolean[n];
    int root = dfsFindRoot(0, -1, g, 0);
    if (root == -1) {
        return false;                     // guard clause
    }

    // ----- step 2: validate each root candidate -----
    visited = new boolean[n];
    for (int i = 0; i < n; i++) {
        if (isRoot[i] && dfsFromRoot(i, -1, g) == -2) {
            return false;                 // guard clause
        }
    }

    // ----- step 3: ensure the graph is connected -----
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            return false;                 // guard clause
        }
    }

    // all checks passed
    return true;
}

