/* ---------- 1. Input reading ---------- */
private void readInput() throws IOException {
    fs = new FastScannerq(new InputStreamReader(System.in));
    n = fs.nextInt();
    m = fs.nextInt();
    k = fs.nextInt();

    capitals = new int[k];
    for (int i = 0; i < k; i++) {
        capitals[i] = fs.nextInt() - 1;
    }

    graph = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        graph[i] = new ArrayList<>();
    }

    for (int i = 0; i < m; i++) {
        int q = fs.nextInt() - 1;
        int to = fs.nextInt() - 1;
        graph[q].add(to);
        graph[to].add(q);
    }
}

/* ---------- 2. Map / used initialisation ---------- */
private void initialiseMaps() {
    map = new HashMap<>(k);
    used = new boolean[n];

    for (int i = 0; i < k; i++) {
        int cap = capitals[i];
        used[cap] = true;
        ArrayList<Integer> list = new ArrayList<>();
        list.add(cap);
        map.put(cap, list);
    }
}

/* ---------- 3. DFS from each capital ---------- */
private void runDfsFromCapitals() {
    for (int i = 0; i < k; i++) {
        dfsCapital(capitals[i]);
    }
}

/* ---------- 4. Find index of the largest component ---------- */
private int indexOfLargestComponent() {
    int maxSize = 0;
    int idx = 0;
    for (int i = 0; i < k; i++) {
        int size = map.get(capitals[i]).size();
        if (size > maxSize) {
            maxSize = size;
            idx = i;
        }
    }
    return idx;
}

/* ---------- 5. Merge all non‑capital vertices into the largest component ---------- */
private void mergeRemainingVertices(int largestIdx) {
    ArrayList<Integer> largestList = map.get(capitals[largestIdx]);
    for (int v = 0; v < n; v++) {
        if (!used[v]) {
            largestList.add(v);
        }
    }
    map.put(capitals[largestIdx], largestList);
}

/* ---------- 6. Compute per‑component scores ---------- */
private int[] computeComponentScores() {
    int[] sum = new int[k];
    for (int i = 0; i < k; i++) {
        ArrayList<Integer> component = map.get(capitals[i]);
        int sz = component.size();

        // Number of possible edges inside the component
        sum[i] = (int) (sz * ((double) (sz - 1) / 2));

        // Subtract the edges that already exist in the original graph
        int existingEdges = 0;
        for (int v : component) {
            existingEdges += graph[v].size();
        }
        sum[i] -= existingEdges / 2;
    }
    return sum;
}

/* ---------- 7. Aggregate and output ---------- */
private void printResult(int[] sum) {
    int total = 0;
    for (int s : sum) {
        total += s;
    }
    System.out.println(total);
}

