public int nextInt() {
    int b = skipToDigitOrMinus();

    // If we reached EOF, behave like the original implementation (return 0)
    if (b == -1) {
        return 0;
    }

    boolean minus = false;
    if (b == '-') {
        minus = true;
        b = readByte();          // advance to the first digit after the sign
    }

    return readNumber(b, minus);
}

/**
 * Skips any non‑digit and non‑minus bytes.
 * Returns the first relevant byte (digit, '-', or -1 on EOF).
 */
private int skipToDigitOrMinus() {
    int b;
    while ((b = readByte()) != -1) {
        if ((b >= '0' && b <= '9') || b == '-') {
            return b;
        }
    }
    return -1;   // EOF
}

/**
 * Reads consecutive digit bytes starting with {@code b},
 * assembles the integer value and applies the sign.
 */
private int readNumber(int b, boolean minus) {
    int num = 0;
    while (b != -1) {
        if (b >= '0' && b <= '9') {
            // num = num * 10 + (b - '0'); using bit‑shift for speed
            num = (num << 3) + (num << 1) + (b - '0');
        } else {
            break;
        }
        b = readByte();
    }
    return minus ? -num : num;
}

