public static void main(String[] args) {
    FastReader fr = new FastReader();
    PrintWriter out = createWriter();

    char[] str = fr.nextLine().toCharArray();
    final int MOD = 1_000_000_007;

    long result = computeResult(str, MOD);
    out.println(result);
    out.flush();
}

/*---------------------- helper methods ----------------------*/

private static PrintWriter createWriter() {
    if (FROM_FILE) {
        try {
            return new PrintWriter(new FileWriter("output.txt"));
        } catch (IOException ignored) {
            // fall back to standard output if file creation fails
        }
    }
    return new PrintWriter(new OutputStreamWriter(System.out));
}

/**
 * Calculates the required value for the given character array.
 */
private static long computeResult(char[] str, int mod) {
    if (str == null || str.length == 0) {
        return 0L;                     // guard clause – nothing to process
    }

    int n = str.length;
    int i = advanceWhile(str, 0, 'b'); // skip leading 'b's
    int aPower = 1;
    long res = 0L;

    while (i < n) {
        // find the end of the consecutive 'a' block starting at i
        int j = i + 1;
        while (j < n && str[j] == 'a') {
            j++;
        }
        if (j == n) {
            break;                     // guard clause – no following 'b' block
        }

        int aCount = j - i;
        aPower = updateAPower(aPower, aCount, mod);

        // first 'b' is at position j, count all consecutive 'b's starting there
        int firstB = j;
        int afterBs = advanceWhile(str, firstB + 1, 'b');
        int bCount = afterBs - firstB;

        res = (res + bCount * ((long) aPower - 1)) % mod;

        i = afterBs; // continue from the character after the processed 'b' block
    }

    return res;
}

/**
 * Advances the index while the character at that position equals {@code target}.
 * Returns the first index that does **not** contain {@code target} (or {@code arr.length}
 * if the end of the array is reached).
 */
private static int advanceWhile(char[] arr, int startIdx, char target) {
    int idx = startIdx;
    while (idx < arr.length && arr[idx] == target) {
        idx++;
    }
    return idx;
}

/**
 * Multiplies {@code current} by 2ⁿ (mod {@code mod}) where {@code n = times}.
 */
private static int updateAPower(int current, int times, int mod) {
