/**
 * Core algorithm that computes the required result.
 * The implementation is identical to the original, only the
 * “multiply‑by‑2” part has been extracted to a helper method.
 */
private static long evaluate(char[] str) {
    final int MOD = 1_000_000_007;
    int n = str.length;

    int i = 0;
    int aPower = 1;
    long res = 0L;

    // skip leading 'b's
    while (i < n && str[i] == 'b') {
        i++;
    }

    while (i < n) {
        int j = i + 1;
        while (j < n && str[j] == 'a') {
            j++;
        }
        if (j == n) {
            break;
        }

        int aCnt = j - i;
        aPower = multiplyPowerOfTwo(aPower, aCnt, MOD);

        int k = j + 1;
        while (k < n && str[k] == 'b') {
            k++;
        }
        int bCnt = k - j;

        res = (res + bCnt * ((long) aPower - 1)) % MOD;
        i = k;
    }

    return res;
}

/**
 * Multiplies {@code value} by 2 exactly {@code times} times,
 * applying the modulus at each step. This replaces the original
 * inner for‑loop to keep the main algorithm clearer.
 */
private static int multiplyPowerOfTwo(int value, int times, int mod) {
    int result = value;
    for (int p = 0; p < times; p++) {
        result = (int) ((result * 2L) % mod);
    }
    return result;
}

