/**
 * Returns an array {@code [left, right]} where
 * {@code left} is the greatest column index whose distance from the
 * current row is < L and {@code right} is the greatest column index
 * whose distance from the current row is ≤ R.
 */
private long[] computeLeftRight(long dx, long low, long high, long L, long R) {
    long left  = (long) Math.sqrt(low);
    long right = (long) Math.sqrt(high);

    while (left > 0 && left * left + dx * dx >= L * L) left--;
    while (left * left + dx * dx < L * L) left++;
    left--;

    while (right > 0 && right * right + dx * dx >= R * R) right--;
    while (right * right + dx * dx <= R * R) right++;
    right--;

    return new long[]{left, right};
}

