 * for the current dx. The bounds are already clamped to the interval [0, m].
 */
private int[] computeBounds(long dx, long low, long high,
                            long L, long R, int m) {
    long left = (long) Math.sqrt(low);
    long right = (long) Math.sqrt(high);

    // adjust left so that left^2 + dx^2  is just below L^2
    while (left > 0 && left * left + dx * dx >= L * L) {
        left--;
    }
    while (left * left + dx * dx < L * L) {
        left++;
    }
    left--;

    // adjust right so that right^2 + dx^2  is just below R^2
    while (right > 0 && right * right + dx * dx >= R * R) {
        right--;
    }
    while (right * right + dx * dx <= R * R) {
        right++;
    }
    right--;

    if (left < 0) {
        left = 0;
    }
    if (right > m) {
        right = m;
    }
    return new int[]{(int) left, (int) right};
}

