private long contribute(int dx, int left, int right, int n, int m) {
    long cntR = right - getCount(dx, right);
    long cntL = left - getCount(dx, left);
    long cnt = (cntR - cntL) % modulo;
    if (cnt < 0) {
        cnt += modulo;
    }

    long sumR = right * (long) (right + 1) / 2 - getSum(dx, right);
    long sumL = left * (long) (left + 1) / 2 - getSum(dx, left);
    long sum = sumR - sumL;

    sum = (cnt * (m + 1) % modulo - sum) % modulo;
    if (sum < 0) {
        sum += modulo;
    }

    long contribution = (2 * sum % modulo) * (n - dx + 1) % modulo;
    return contribution;
}

private static class Bounds {
    long left;
    long right;

    Bounds(long left, long right) {
        this.left = left;
        this.right = right;
    }
