/** Guard‑clause version of the original solve method. */
public void solve(int testNumber, FastScanner in, PrintWriter out) {
    init();
    int n = in.nextInt();
    int m = in.nextInt();
    long L = in.nextInt();
    long R = in.nextInt();
    modulo = in.nextInt();

    long result = 0;

    for (long dx = 1; dx <= n; dx++) {
        Bounds b = computeBounds(dx, L, R, m);
        if (b == null) {
            continue;                     // no valid y‑range for this dx
        }

        long cnt = countInInterval(dx, b.left, b.right);
        cnt = mod(cnt);

        long sum = sumInInterval(dx, b.left, b.right, cnt, m);
        // contribution of this dx
        long contribution = (2L * sum % modulo) * (n - dx + 1) % modulo;
        result = (result + contribution) % modulo;
    }

    if (L <= 1) {
        result += (n + 1L) * m + n * (m + 1L);
    }

    out.println(result % modulo);
}

/** Computes the feasible y‑interval [left+1, right] for a given dx. */
private Bounds computeBounds(long dx, long L, long R, int m) {
    long low  = L * L - dx * dx;
    long high = R * R - dx * dx;

    if (low < 0) low = 0;
    if (high < 0) return null;                     // interval empty → skip

    long left  = (long) Math.sqrt(low);
    long right = (long) Math.sqrt(high);

    while (left > 0 && left * left + dx * dx >= L * L) left--;
    while (left * left + dx * dx < L * L) left++;
    left--;                                         // make it exclusive

    while (right > 0 && right * right + dx * dx >= R * R) right--;
    while (right * right + dx * dx <= R * R) right++;
    right--;                                        // make it exclusive

    if (left < 0) left = 0;
    if (right > m) right = m;
    if (left >= right) return null;                // empty after clipping

    return new Bounds(left, right);
}

/** Number of lattice points with x = dx and y in (left, right]. */
private long countInInterval(long dx, long left, long right) {
    long cntR = right - getCount((int) dx, (int) right);
    long cntL = left  - getCount((int) dx, (int) left);
    return cntR - cntL;
}

/** Sum of (m+1 - y) over the same interval, transformed as in the original. */
private long sumInInterval(long dx, long left, long right, long cnt, int m) {
    long sumR = right * (right + 1) / 2 - getSum((int) dx, (int) right);
    long sumL = left  * (left  + 1) / 2 - getSum((int) dx, (int) left);
    long sum  = sumR - sumL;

    sum = (cnt * (m + 1) % modulo) - sum;
    return mod(sum);
}

/** Normalises a value to the range [0, modulo). */
private long mod(long x) {
    x %= modulo;
    if (x < 0) x += modulo;
    return x;
}

