private long parseNumber(int firstDigit) {
    long n = 0;
    int b = firstDigit;

    while (true) {
        if (isDigit(b)) {
            n = n * 10 + (b - '0');
        } else if (b == -1 || !isPrintableChar(b)) {
            return n;                     // end of token
        } else {
            throw new NumberFormatException();
        }
        b = readByte();
    }
}

