        return cnt == times ? 1 : 0;
    }
    if (digitDP[pos][cnt][f] != -1) {
        return digitDP[pos][cnt][f];
    }

    int res = 0;
    int limit = getLimit(pos, f);

    for (int dgt = 0; dgt <= limit; ++dgt) {
        if (canTakeDigit(dgt, cnt)) {
            int newCnt = updatedCount(dgt, cnt);
            int newFlag = updatedFlag(f, dgt, limit);
            res += call(pos + 1, newCnt, newFlag);
        }
    }

    digitDP[pos][cnt][f] = res;
    return res;
}

/** Returns the maximum digit allowed at the current position. */
private static int getLimit(int pos, int f) {
    return f == 0 ? number.charAt(pos) - '0' : 9;
}

/** Checks whether taking the digit keeps the count within the allowed limit. */
private static boolean canTakeDigit(int dgt, int cnt) {
    return (dgt == digit ? cnt + 1 : cnt) <= times;
}

/** Computes the updated count of the special digit after choosing `dgt`. */
private static int updatedCount(int dgt, int cnt) {
    return dgt == digit ? cnt + 1 : cnt;
}

/** Computes the next “tight” flag (`f`) for the recursive call. */
private static int updatedFlag(int f, int dgt, int limit) {
    return (f == 0 && dgt < limit) ? 1 : f;
}

public static int call(int pos, int cnt, int f) {
    // Guard clause 1: impossible to reach the required count
    if (cnt > times) {
        return 0;
    }

    // Guard clause 2: reached the end of the number string
    if (pos == number.length()) {
        return cnt == times ? 1 : 0;
    }

    // Guard clause 3: memoised result already available
    if (digitDP[pos][cnt][f] != -1) {
        return digitDP[pos][cnt][f];
    }

    // Core recursion (extracted)
    int res = computeRecursive(pos, cnt, f);
    digitDP[pos][cnt][f] = res;
    return res;
}

/**
 * Performs the digit‑DP transition for the current state.
 * The method is deliberately small: it only computes the limit,
 * iterates over possible digits, checks the count constraint,
 * updates the tight flag and recurses.
 */
private static int computeRecursive(int pos, int cnt, int f) {
    int res = 0;
    int limit = (f == 0) ? number.charAt(pos) - '0' : 9;

    for (int dgt = 0; dgt <= limit; ++dgt) {
        int newCnt = (dgt == digit) ? cnt + 1 : cnt;
        if (newCnt <= times) {
            int newFlag = (f == 0 && dgt < limit) ? 1 : f;
            res += call(pos + 1, newCnt, newFlag);
        }
    }
    return res;
}

