public long nextLong() {
    ensureCurrentCharInitialized();

    boolean negative = skipNonDigitsAndDetectSign();
    checkEOF();

    long value = readDigits();
    return negative ? -value : value;
}

/** Ensure that the current character is read at least once. */
private void ensureCurrentCharInitialized() {
    if (c == NULL_CHAR) {
        c = nextChar();
    }
}

/**
 * Skips any characters that are not part of a numeric literal.
 * Detects a leading minus sign and returns whether the result should be negative.
 */
private boolean skipNonDigitsAndDetectSign() {
    boolean negative = false;
    while (!EOF_FLAG && (c < '0' || c > '9')) {
        if (c == '-') {
            negative = true;
        }
        c = nextChar();
    }
    return negative;
}

/** Reads consecutive digit characters and builds the corresponding long value. */
private long readDigits() {
    long result = 0;
    while (c >= '0' && c <= '9') {
        // result = result * 10 + (c - '0');
        result = (result << 3) + (result << 1) + (c - '0');
        c = nextChar();
    }
    return result;
}

