        ans[i] = max;
        int cur = p[i];

        tryUnion(cur, cur + 1, alive, uft, n);
        tryUnion(cur, cur - 1, alive, uft, n);

        max = Math.max(max, uft.sum(cur));
        alive[cur] = true;
    }
}

