private static void tryUnion(int idx, int neighbor, boolean[] alive,
                             UnionFindTree uft, int n) {
    if (neighbor < 1 || neighbor > n) return;          // out of range
    if (!alive[neighbor]) return;                     // not yet alive
    uft.union(idx, neighbor);
}

