}

/**
 * Creates the {@code sum} array expected by {@link UnionFindTree}.
 * The original code stored {@code a[i]} at {@code sum[i+1]}.
 */
private static long[] buildSumArray(int[] a) {
    int n = a.length;
    long[] sum = new long[n + 1];
    for (int i = 0; i < n; i++) {
        sum[i + 1] = a[i];
    }
    return sum;
}

/**
 * Performs the reverse‑iteration algorithm that computes the answer
 * for each position. Guard clauses keep the flow straight‑forward.
 */
private static long[] computeAnswers(int[] p, UnionFindTree uft, boolean[] alive) {
    int n = p.length;
    long[] ans = new long[n];
    long max = 0;

    for (int i = n - 1; i >= 0; i--) {
        ans[i] = max;

        int idx = p[i];
        int right = idx + 1;
        int left = idx - 1;

        if (right <= n && alive[right]) {
            uft.union(idx, right);
        }
        if (left >= 1 && alive[left]) {
            uft.union(idx, left);
        }

        max = Math.max(max, uft.sum(idx));
        alive[idx] = true;
    }
    return ans;
}

