private long rec(int l1, int r1, int l2, int r2, int len) {
    // ---- guard clauses ----------------------------------------------------
    if (len == 0) return 0;
    if (l1 > r1 || l2 > r2) return 0;
    if (r1 - l1 + 1 == len) return r2 - l2 + 1;
    if (r2 - l2 + 1 == len) return r1 - l1 + 1;

    int center = (len / 2) + 1;

    // ---- distinct logical paths -----------------------------------------
    if (bothInLeftHalf(r1, r2, center))
        return rec(l1, r1, l2, r2, len / 2);

    if (bothInRightHalf(l1, l2, center))
        return rec(l1 - center, r1 - center, l2 - center, r2 - center, len / 2);

    if (leftHalfRightHalf(r1, l2, center))
        return rec(l1, r1, l2 - center, r2 - center, len / 2);

    if (rightHalfLeftHalf(r2, l1, center))
        return rec(l1 - center, r1 - center, l2, r2, len / 2);

    if (coversCenter(l1, r1, center) && coversCenter(l2, r2, center))
        return handleBothCoverCenter(l1, r1, l2, r2, center, len);

    if (coversCenter(l1, r1, center))
        return handleFirstCoversCenter(l1, r1, l2, r2, center, len);

    if (coversCenter(l2, r2, center))
        return rec(l2, r2, l1, r1, len);   // symmetric case, keep original call

    throw new AssertionError("!");
}

// -------------------------------------------------------------------------
// Helper predicates
private boolean bothInLeftHalf(int r1, int r2, int center) {
    return r1 < center && r2 < center;
}
private boolean bothInRightHalf(int l1, int l2, int center) {
    return l1 > center && l2 > center;
}
private boolean leftHalfRightHalf(int r1, int l2, int center) {
    return r1 < center && l2 > center;
}
private boolean rightHalfLeftHalf(int r2, int l1, int center) {
    return r2 < center && l1 > center;
}
private boolean coversCenter(int l, int r, int center) {
    return l <= center && r >= center;
}

// -------------------------------------------------------------------------
// Branch that both intervals span the centre
private long handleBothCoverCenter(int l1, int r1, int l2, int r2, int center, int len) {
    long max;
    // decide which side of the first interval can contribute more
    if (center - l1 >= r1 - center) {
        max = rec(l1, center - 1, l2, r2, len);
    } else {
        max = rec(center + 1, r1, l2, r2, len);
    }
    // overlapping part of the two intervals
    int le = Math.max(l1, l2);
    int ri = Math.min(r1, r2);
    max = Math.max(max, ri - le + 1);
    return max;
}

// -------------------------------------------------------------------------
// Branch that only the first interval spans the centre
private long handleFirstCoversCenter(int l1, int r1, int l2, int r2, int center, int len) {
    long left  = rec(l1, center - 1, l2, r2, len);
    long right = rec(center + 1, r1, l2, r2, len);
    return Math.max(left, right);
}

