/* ---------------------------------------------------------- */

private static final class SignInfo {
    final boolean negative;
    final int firstChar;

    SignInfo(boolean negative, int firstChar) {
        this.negative = negative;
        this.firstChar = firstChar;
    }
}

/**
 * Reads an optional leading '-' and returns whether the number is negative
 * together with the first character after the sign.
 */
private SignInfo readSignAndFirstChar() {
    int ch = rB();
    boolean negative = false;
    if (ch == '-') {
        negative = true;
        ch = rB();
    }
    return new SignInfo(negative, ch);
}

/**
 * Accumulates digits starting with {@code currentDigit} into a long value.
 * The method stops when the next character is either EOF or a character
 * that is not part of a numeric token (as defined by {@code iPC}).
 * It throws NumberFormatException for any illegal non‑digit character.
 */
private long parseNumber(long accumulator, int currentDigit) {
    long result = accumulator;
    int ch = currentDigit;

    while (true) {
        // ch is guaranteed to be a digit when the loop iterates
        result = result * 10 + (ch - '0');

        int next = rB();
        if (next == -1 || !iPC(next)) {
            // End of the token – return the accumulated value
            return result;
        }
        if (!isDigit(next)) {
            // Non‑digit but still considered part of a number → malformed
            throw new NumberFormatException();
        }
        ch = next; // continue with the next digit
    }
}

/** Utility: digit test */
private boolean isDigit(int c) {
    return '0' <= c && c <= '9';
}

