public static long getClosestK(long[] a, long x) {
    int low = 0;
    int high = a.length - 1;

    while (low <= high) {
        int mid = (low + high) / 2;

        // Guard clauses – each handles a distinct logical path
        if (mid == 0) {
            return handleMidZero(a, x);
        }

        if (mid == a.length - 1) {
            return a[a.length - 1];
        }

        if (a[mid] == x || a[mid + 1] == x) {
            return x;
        }

        if (a[mid] < x && a[mid + 1] > x) {
            return handleBetween(a, mid, x);
        }

        // Normal binary‑search progress
        if (a[mid] < x) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }

    // The original method threw this when the array was empty
    throw new IllegalArgumentException("The array cannot be empty");
}

/** Handles the situation where the midpoint is the first element. */
private static long handleMidZero(long[] a, long x) {
    if (a.length == 1) {
        return a[0];
    }
    return Math.min(Math.abs(a[0] - x), Math.abs(a[1] - x)) + x;
}

/** Handles the situation where x lies between a[mid] and a[mid+1]. */
private static long handleBetween(long[] a, int mid, long x) {
    return Math.min(Math.abs(a[mid] - x), Math.abs(a[mid + 1] - x)) + x;
}

