    // base case
    if (idx == n) {
        return 0;
    }
    // memoised result?
    if (memo[last][phase][idx] != -1) {
        return memo[last][phase][idx];
    }

    long ans;
    switch (phase) {
        case 0:
            ans = computePhase0(last, idx);
            break;
        case 1:
            ans = computePhase1(last, idx);
            break;
        case 2:
            ans = computePhase2(last, idx);
            break;
        case 3:
            ans = computePhase3(last, idx);
            break;
        default:
            throw new IllegalStateException("Unexpected phase: " + phase);
    }

    // store and return
    return memo[last][phase][idx] = ans;
}

