    for (int i = 0; i <= k; i++) {
        mat[k + 1 + i][i] = 1;
    }
    return mat;
}

/* Fill the combinatorial part of the matrix */
private void populateMatrix(long[][] mat, int k) {
    for (int c = 0; c <= k; c++) {
        for (int r = 0; r <= c; r++) {
            mat[r][k + 1 + c] = mul(ncr(c, r), pow[c - r], M);
            mat[k + 1 + r][k + 1 + c] = ncr(c, r);
        }
    }
}

/* Replicate column (2k+1) into column (2k+2) as in the original code */
private void copyLastColumn(long[][] mat, int k) {
    for (int i = 0; i <= 2 * k + 1; i++) {
        mat[i][2 * k + 2] = mat[i][2 * k + 1];
    }
}

/* Exponentiate the matrix using the existing pow routine */
private long[][] raiseMatrix(long[][] mat, long exponent) {
    return pow(mat, exponent);
}

/* Build the initial vector (arr) */
private long[] buildInitialVector(int k, long[] powArr) {
    int sz = computeSize(k);
    long[] vec = new long[sz];
    for (int i = 0; i <= k; i++) {
        vec[i] = 1;
    }
    for (int i = k + 1; i <= 2 * k + 1; i++) {
        vec[i] = powArr[i - k];
    }
    vec[sz - 1] = 1;
    vec[sz - 1] = add(vec[sz - 1], powArr[k + 1], M);
    return vec;
}

/* Final dot‑product to obtain the answer */
private long calculateAnswer(long[] vec, long[][] mat, int size) {
    long ans = 0;
    for (int i = 0; i < size; i++) {
        ans = add(ans, mul(vec[i], mat[i][size - 1], M), M);
    }
    return ans;
}

void solve() {
    long n = nl();
    int k = ni();

    // Guard clause for the trivial case
    if (n == 1) {
        pw.println("1");
        return;
    }

    precompute(k + 2);
    int sz = 2 * k + 3;                     // size of the matrix / vector
    long[][] matrix = buildMatrix(k, sz);
    matrix = pow(matrix, n - 2);            // matrix exponentiation

    long[] vector = buildInitialVector(k, sz);
    long answer = computeAnswer(vector, matrix, sz);

    pw.println(answer);
}

/** Constructs the transition matrix used in the solution. */
private long[][] buildMatrix(int k, int sz) {
    long[][] m = new long[sz][sz];

    // Part 1: set the lower‑left diagonal to 1
    for (int i = 0; i <= k; i++) {
        m[k + 1 + i][i] = 1;
    }

    // Part 2: fill combinatorial coefficients
    for (int c = 0; c <= k; c++) {
        for (int r = 0; r <= c; r++) {
            m[r][k + 1 + c] = mul(ncr(c, r), pow[c - r], M);
            m[k + 1 + r][k + 1 + c] = ncr(c, r);
        }
    }

    // Part 3: copy the last-but-one column to the last column
    for (int i = 0; i <= 2 * k + 1; i++) {
        m[i][2 * k + 2] = m[i][2 * k + 1];
    }

    // Part 4: set the bottom‑right cell to 1 (absorbing state)
    m[sz - 1][sz - 1] = 1;

    return m;
}

/** Builds the initial vector that will be multiplied with the powered matrix. */
private long[] buildInitialVector(int k, int sz) {
    long[] v = new long[sz];

    // First k+1 entries are 1
    for (int i = 0; i <= k; i++) {
        v[i] = 1;
    }

    // Next k+1 entries are powers of the base (pow[])
    for (int i = k + 1; i <= 2 * k + 1; i++) {
        v[i] = pow[i - k];
    }

    // Final entry: 1 plus an extra term
    v[sz - 1] = 1;
    v[sz - 1] = add(v[sz - 1], pow[k + 1], M);

    return v;
}

/** Computes the final answer by contracting the vector with the last column of the matrix. */
private long computeAnswer(long[] vector, long[][] matrix, int sz) {
    long ans = 0;
    for (int i = 0; i < sz; i++) {
        ans = add(ans, mul(vector[i], matrix[i][sz - 1], M), M);
    }
    return ans;
}

