/** Fills both the backing array and the list with the next `size` integers. */
private static void readDeck(FastReader in, int size, List<Integer> list, int[] backing) {
    for (int i = 0; i < size; i++) {
        backing[i] = in.nextInt();
        list.add(backing[i]);
    }
}

/** Simulates the card game and returns the outcome. */
private static Result playGame(List<Integer> l1, List<Integer> l2) {
    int rounds = 0;
    boolean cycle = false;

    Set<List<Integer>> seenL1 = new HashSet<>();
    Set<List<Integer>> seenL2 = new HashSet<>();
    seenL1.add(l1);
    seenL2.add(l2);

    while (!l1.isEmpty() && !l2.isEmpty()) {
        int card1 = l1.remove(0);
        int card2 = l2.remove(0);

        if (card1 > card2) {
            l1.add(card2);
            l1.add(card1);
        } else {
            l2.add(card1);
            l2.add(card2);
        }
        rounds++;

        // Guard clause – stop if a deck became empty after the round.
        if (l1.isEmpty() || l2.isEmpty()) {
            break;
        }

        // Detect a previously seen configuration (cycle).
        if (seenL1.contains(l1) && seenL2.contains(l2)) {
            cycle = true;
            break;
        }
        seenL1.add(l1);
        seenL2.add(l2);
    }

    int winner = l2.isEmpty() ? 1 : 2;
    return new Result(rounds, winner, cycle);
}

/** Simple DTO to transport the outcome of the simulation. */
private static class Result {
    final int rounds;
    final int winner;   // 1 if player 1 wins, 2 otherwise
    final boolean cycle;

    Result(int rounds, int winner, boolean cycle) {
        this.rounds = rounds;
        this.winner = winner;
        this.cycle = cycle;
    }
}

