        return p.x;
    }

    // Guard clause: p.y is the unique match
    if (matchesOnly(p.y, x, y, p.x)) {
        return p.y;
    }

    // No single common value found
    return -1;
}

/**
 * Returns true if {@code candidate} equals exactly one of {@code first} or {@code second},
 * and {@code other} does not equal the remaining one.
 * This replaces the repeated four‑branch conditional logic.
 */
private boolean matchesOnly(int candidate, int first, int second, int other) {
    return (candidate == first && other != second) ||
           (candidate == second && other != first);
}

