/* Adjust the sliding window to the requested query bounds.
   The method updates the global state (`nowAns`, frequency array, etc.)
   and returns the new left/right positions via the query object. */
private static void adjustWindow(Query qy, int currentL, int currentR) {
    // move left pointer
    while (currentL < qy.l) {
        remove(currentL - 1);
        currentL++;
    }
    while (currentL > qy.l) {
        currentL--;
        add(currentL - 1);
    }

    // move right pointer
    while (currentR < qy.r) {
        add(++currentR);
    }
    while (currentR > qy.r) {
        remove(currentR--);
    }

    // store the new positions back into the query object so the caller sees them
    qy.l = currentL;
    qy.r = currentR;
}

