/**
 * Returns the transformed string according to the problem rules,
 * or {@code null} if no suitable even digit exists.
 */
private static String buildResult(String s) {
    int len = s.length();
    char lastChar = s.charAt(len - 1);
    int lastDigit = lastChar - '0';

    int rightmostEvenGreaterIdx = -1;

    for (int i = 0; i < len - 1; i++) {
        int current = s.charAt(i) - '0';
        if (current % 2 != 0) {
            continue; // not an even digit, ignore
        }

        if (current < lastDigit) {
            // First even digit smaller than the last digit – optimal swap.
            return swap(s, i, lastChar);
        }

        // current > lastDigit
        rightmostEvenGreaterIdx = i; // keep the farthest such index
    }

    // No smaller even digit found; use the right‑most even digit greater than last,
    // if one exists.
    if (rightmostEvenGreaterIdx != -1) {
        return swap(s, rightmostEvenGreaterIdx, lastChar);
    }

    // No suitable even digit anywhere.
    return null;
}

/**
 * Creates a new string where the character at {@code idx} is replaced
 * by {@code lastChar}, and the original character at {@code idx}
 * is moved to the position just before the original last character.
 */
private static String swap(String s, int idx, char lastChar) {
    int len = s.length();
    char displacedChar = s.charAt(idx);

    // Build: prefix + lastChar + middle + displacedChar
    StringBuilder sb = new StringBuilder(len);
    sb.append(s, 0, idx);               // part before idx
    sb.append(lastChar);                // new char at idx
    sb.append(s, idx + 1, len - 1);     // middle part (excluding original last char)
    sb.append(displacedChar);           // original idx char moves to end
    return sb.toString();
}

void solve() throws IOException {
