    if (n == 0) {
        ob.println(0);
        return;
    }

    // 1‑based character array for easier translation of the original code
    char[] s = new char[n + 1];
    for (int i = 1; i <= n; i++) {
        s[i] = inp[i - 1];
    }

    int[] dp = new int[n + 1];
    initFirstPositions(s, dp, n);

    for (int i = 4; i <= n; i++) {
        dp[i] = computeDPAt(i, s, dp);
