/* ---------- helper methods ---------- */

private boolean isDivisibleBy3(char c) {
    return (c - '0') % 3 == 0;
}

/** Initialise dp[1], dp[2] and dp[3] exactly as the original implementation. */
private void initFirstPositions(char[] s, int[] dp, int n) {
    // dp[1]
    dp[1] = isDivisibleBy3(s[1]) ? 1 : 0;

    // dp[2] – only if the string has at least two characters
    if (n >= 2) {
        int mod = isDivisibleBy3(s[2]) ? 1 : 0;
        dp[2] = isDivisibleBy3(s[2]) ? dp[1] + 1 : 0;
        dp[2] = isDivisibleBy3(s[1]) ? Math.max(dp[2], 1 + mod) : dp[2];
        dp[2] = ((s[1] - '0') + (s[2] - '0')) % 3 == 0 ? Math.max(dp[2], 1) : dp[2];
    }

    // dp[3] – only if the string has at least three characters
    if (n >= 3) {
        int mod = isDivisibleBy3(s[3]) ? 1 : 0;
        dp[3] = isDivisibleBy3(s[3]) ? dp[2] + 1 : 0;
        dp[3] = isDivisibleBy3(s[2]) ? Math.max(dp[3], dp[2] + mod) : dp[3];
        dp[3] = isDivisibleBy3(s[1]) ? Math.max(dp[3], dp[1] + mod) : dp[3];
        dp[3] = ((s[2] - '0') + (s[3] - '0')) % 3 == 0 ? Math.max(dp[3], dp[1] + 1) : dp[3];
        dp[3] = ((s[1] - '0') + (s[2] - '0') + (s[3] - '0')) % 3 == 0
                ? Math.max(dp[3], 1)
                : dp[3];
    }
}

/** Computes dp[i] for i >= 4 following the original DP transition rules. */
private int computeDPAt(int i, char[] s, int[] dp) {
    int z = s[i] - '0';
    int y = s[i - 1] - '0';
    int x = s[i - 2] - '0';

    int bestPrev = Math.max(dp[i - 1], Math.max(dp[i - 2], dp[i - 3]));
    int cur = (z % 3 == 0) ? bestPrev + 1 : bestPrev;

    if (y % 3 == 0 || (y + z) % 3 == 0) {
        cur = Math.max(cur, Math.max(dp[i - 2] + 1, dp[i - 3] + 1));
    }
    if (x % 3 == 0 || (x + y + z) % 3 == 0) {
        cur = Math.max(cur, dp[i - 3] + 1);
    }
    if (x + y % 3 == 0) {                     // kept exactly as in the original code
        int mod = (z % 3 == 0) ? 1 : 0;
        cur = Math.max(cur, dp[i - 3] + 1 + mod);
    }
    return cur;
}

