/**
 * Returns true if arrays {@code original} and {@code shuffled} can be made identical
 * by swapping at most one mismatched pair.
 */
private static boolean canBeEqualWithAtMostOneSwap(int[] original, int[] shuffled) {
    int n = original.length;

    // 1. sort a copy of the shuffled array
    int[] sorted = Arrays.copyOf(shuffled, n);
    Arrays.sort(sorted);

    // 2. map each (original[i], sorted[i]) pair to its index
    TreeMap<Triple, Integer> indexMap = buildTripleIndexMap(original, sorted);

    boolean[] swapped = new boolean[n];
    int swapCount = 0;

    for (int i = 0; i < n; i++) {
        // guard: already handled or already equal → nothing to do
        if (swapped[i] || original[i] == sorted[i]) {
            continue;
        }

        // look for the complementary pair (sorted[i], original[i])
        Triple needed = new Triple(sorted[i], original[i]);
        Integer partnerIdx = indexMap.get(needed);
        if (partnerIdx == null) {
            return false;               // no matching element → impossible
        }

        if (!swapped[partnerIdx]) {
            swapped[partnerIdx] = true;
            swapCount++;

            // guard: more than one swap required → impossible
            if (swapCount > 1) {
                return false;
            }
        }
    }

    // If we reach here, at most one swap was needed and it was possible
    return true;
}

/**
 * Builds a TreeMap that maps a (valueFromOriginal, valueFromSorted) pair
 * to its index in the arrays.
 */
private static TreeMap<Triple, Integer> buildTripleIndexMap(int[] original, int[] sorted) {
    TreeMap<Triple, Integer> map = new TreeMap<>();
    for (int i = 0; i < original.length; i++) {
        map.put(new Triple(original[i], sorted[i]), i);
    }
    return map;
}

