    Arrays.sort(b);

    boolean canBeFixed = canSwapAtMostOne(N, a, b);
    System.out.println(canBeFixed ? "YES" : "NO");
}

/** Returns true if the two arrays differ in at most one swappable pair. */
private static boolean canSwapAtMostOne(int n, int[] a, int[] b) {
    TreeMap<Triple, Integer> map = buildIndexMap(n, a, b);
    boolean[] isSwapped = new boolean[n];
    int swapCount = 0;

    for (int i = 0; i < n; i++) {
        // guard clauses – skip already processed positions or equal elements
        if (isSwapped[i] || a[i] == b[i]) {
            continue;
        }

        Integer occ = map.get(new Triple(b[i], a[i]));
        // no reverse pair found → impossible
        if (occ == null) {
            return false;
        }

        // reverse pair already used in another swap → impossible
        if (isSwapped[occ]) {
            continue;
        }

        // perform the swap
        isSwapped[occ] = true;
        swapCount++;

        // more than one swap required → not allowed
        if (swapCount > 1) {
            return false;
        }
    }
    return true;
}

/** Builds a map from (original value, shuffled value) to its index. */
private static TreeMap<Triple, Integer> buildIndexMap(int n, int[] a, int[] b) {
    TreeMap<Triple, Integer> map = new TreeMap<>();
    for (int i = 0; i < n; i++) {
        Triple key = new Triple(a[i], b[i]);
        map.put(key, i);
    }
    return map;
}

