    boolean possible = canBeEqualWithAtMostOneSwap(a, b, indexMap);

    System.out.println(possible ? "YES" : "NO");
}

/**
 * Builds a map from (original value, sorted value) → its position in the original array.
 */
private static TreeMap<Triple, Integer> buildIndexMap(int[] original, int[] sorted) {
    TreeMap<Triple, Integer> map = new TreeMap<>();
    for (int i = 0; i < original.length; i++) {
        Triple key = new Triple(original[i], sorted[i]);
        map.put(key, i);
    }
    return map;
}

/**
 * Determines whether the two arrays can become identical by performing
 * at most one pairwise swap. The method returns {@code true} if this is possible.
 */
private static boolean canBeEqualWithAtMostOneSwap(int[] a, int[] b,
                                                   TreeMap<Triple, Integer> map) {
    int swaps = 0;
    boolean[] swapped = new boolean[a.length];
    boolean failed = false;

    for (int i = 0; i < a.length && !failed; i++) {
        // guard‑clauses: skip already processed positions or equal elements
        if (swapped[i] || a[i] == b[i]) {
            continue;
        }

        Integer partnerIdx = map.get(new Triple(b[i], a[i]));
        if (partnerIdx == null) {
            // no counterpart exists → impossible
            failed = true;
            break;
        }

        if (swapped[partnerIdx]) {
            // counterpart already used in another swap
            continue;
        }

        swapped[partnerIdx] = true;
        swaps++;

        // more than one swap is not allowed
        if (swaps > 1) {
            failed = true;
        }
    }

    return !failed && swaps <= 1;
}

