/**
 * Returns true if, with the given tolerance {@code mid}, each element of {@code s}
 * can be covered by the moving intervals defined by {@code p}.
 */
private static boolean canMatch(long[] p, long[] s, long mid) {
    int i = 0, j = 0;
    int n = p.length, m = s.length;

    while (i < n && j < m) {
        long toright = computeRightmostReach(p[i], s[j], mid);
        // advance j while the current s[j] is within reach
        while (j < m && s[j] <= toright) {
            j++;
        }
        i++;
    }
    return j == m;
}

/**
 * Computes the farthest position to the right that the i‑th person can reach
 * while still being able to cover the j‑th shop, according to the problem rules.
 * Returns 0 when the shop cannot be covered.
 */
private static long computeRightmostReach(long person, long shop, long mid) {
    if (person <= shop) {
        // shop is to the right: simply move forward by mid
        return person + mid;
    }
    long distance = person - shop;
    if (distance > mid) {
        // shop is too far on the left to be covered
        return 0L;
    }
    // shop is to the left but reachable; optimal strategy described in original code
    long remain = mid - distance;
    long option1 = mid - 2L * distance;                // go left first, then right
    long option2 = remain / 2L;                        // split remaining time equally
    return person + Math.max(option1, option2);
}

