public static void main(String[] args) throws IOException {
    BufferedReader in = new BufferedReader(new InputStreamReader(System.in));
    StringTokenizer tk = new StringTokenizer(in.readLine());

    int n = Integer.parseInt(tk.nextToken());
    int m = Integer.parseInt(tk.nextToken());

    long[] p = new long[n];
    tk = new StringTokenizer(in.readLine());
    for (int i = 0; i < n; i++) {
        p[i] = Long.parseLong(tk.nextToken());
    }

    long[] s = new long[m];
    tk = new StringTokenizer(in.readLine());
    for (int i = 0; i < m; i++) {
        s[i] = Long.parseLong(tk.nextToken());
    }

    long left = 0;
    long right = (long) 1e11;
    long answer = -1;

    while (left <= right) {
        long mid = (left + right) >>> 1; // same as (left+right)/2 but avoids overflow
        if (canMatch(p, s, mid)) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    System.out.println(answer);
}

/**
 * Checks whether all elements of {@code s} can be matched using the
 * tolerance {@code mid} against the positions {@code p}.
 *
 * @return {@code true} if the whole {@code s} array can be covered, {@code false} otherwise
 */
private static boolean canMatch(long[] p, long[] s, long mid) {
    int i = 0, j = 0;
    int n = p.length, m = s.length;

    while (i < n && j < m) {
        long toright;
        if (p[i] <= s[j]) {
            toright = p[i] + mid;
        } else if (p[i] - s[j] <= mid) {
            long diff = p[i] - s[j];
            toright = p[i] + Math.max(mid - 2 * diff, (mid - diff) / 2);
        } else {
            // Cannot reach s[j] from p[i] with the current mid
            return false;
        }

        while (j < m && s[j] <= toright) {
            j++;
        }
        i++;
    }

    // All elements of s were covered iff j reached the end of s
    return j == m;
}

