    while (left <= right) {
        long mid = (left + right) / 2;
        if (canCoverAll(p, s, mid)) {
            answer = mid;
            right = mid - 1;               // try to find a smaller feasible value
        } else {
            left = mid + 1;                // need a larger value
        }
    }

    System.out.println(answer);
}

/** Reads a line containing {@code size} long numbers. */
private static long[] readLongArray(BufferedReader in, int size) throws IOException {
    long[] arr = new long[size];
    StringTokenizer tk = new StringTokenizer(in.readLine());
    for (int i = 0; i < size; i++) {
        arr[i] = parseLong(tk.nextToken());
    }
    return arr;
}

/**
 * Returns {@code true} iff all elements of {@code s} can be covered
 * using the current {@code mid} value.
 *
 * The logic mirrors the original inner loop but uses guard clauses
 * to short‑circuit when a particular {@code p[i]} cannot reach the
 * next uncovered {@code s[j]}.
 */
private static boolean canCoverAll(long[] p, long[] s, long mid) {
    int i = 0, j = 0;
    int n = p.length;
    int m = s.length;

    while (i < n && j < m) {
        long toright;

        // Guard clause: p[i] is left of or equal to s[j]
        if (p[i] <= s[j]) {
            toright = p[i] + mid;
        }
        // Guard clause: p[i] is right of s[j] but within distance {@code mid}
        else if (p[i] - s[j] <= mid) {
            long diff = p[i] - s[j];
            long option1 = mid - 2 * diff;
            long option2 = (mid - diff) / 2;
            toright = p[i] + Math.max(option1, option2);
        }
        // Nothing can be done with this p[i] – fail early
        else {
            return false;
        }

        // Skip all s[j] that are already covered by the current toright
        while (j < m && s[j] <= toright) {
            j++;
        }
        i++;
    }

    // Success iff every s[j] has been covered
    return j == m;
}

