 * Guard‑clauses skip work when the source cell is zero.
 */
private void updateTransitions(int l, int r, int m, int cd) {
    long dpVal = dp[l * M1 + r * M2 + m];
    if (dpVal != 0L) {
        // transitions that use digits smaller than the current digit
        for (int d = 0; d < cd; d++) {
            int idx = (l + 1) * M1
                    + nextRest[(l + 1) * R1 + r * R2 + d] * M2
                    + nextInd[(m << 4) | d];
