        }
    }

    long cdpVal = cdp[l * M1 + r * M2 + m];
    if (cdpVal != 0L) {
        // transition that uses the current digit itself
        int idx = (l + 1) * M1
                + nextRest[(l + 1) * R1 + r * R2 + cd] * M2
                + nextInd[(m << 4) | cd];
