/**
 * Updates the DP tables for a single digit position {@code l}
 * with the current digit value {@code cd}.
 */
private void processDigitPosition(int l, int cd) {
    for (int r = 0; r < LCM; r++) {
        for (int m = 0; m < MAXM; m++) {

            long dpVal = dp[l * M1 + r * M2 + m];
            if (dpVal != 0L) {
                // propagate states for digits smaller than the current digit
                for (int d = 0; d < cd; d++) {
                    int newR = nextRest[(l + 1) * R1 + r * R2 + d];
                    int newM = nextInd[(m << 4) | d];
                    cdp[(l + 1) * M1 + newR * M2 + newM] += dpVal;
                }
            }

            long cdpVal = cdp[l * M1 + r * M2 + m];
            if (cdpVal != 0L) {
                // propagate the exact current digit
                int newR = nextRest[(l + 1) * R1 + r * R2 + cd];
                int newM = nextInd[(m << 4) | cd];
                cdp[(l + 1) * M1 + newR * M2 + newM] += cdpVal;
            }
        }
    }
}

/**
 * Computes the final answer after all digit positions have been processed.
 */
private long sumResults(int len) {
    long ret = 0L;
    for (int r = 0; r < LCM; r++) {
        for (int m = 0; m < MAXM; m++) {
            if (m == 0 || r % lcm[m] == 0) {
                ret += cdp[len * M1 + r * M2 + m];
            }
        }
    }
    return ret;
