    // Guard clauses for characters that do not affect the score
    if (c == '.' || c == 'k' || c == 'K') {
        return;
    }

    int pieceValue = pieceWeight(c);
    if (Character.isUpperCase(c)) {
        w += pieceValue;        // white piece
    } else {
        b += pieceValue;        // black piece
    }
}

/**
 * Returns the material value of a chess piece, ignoring colour.
 * Queen = 9, Rook = 5, Bishop = 3, Knight = 3, Pawn = 1.
 * Unknown characters yield 0.
 */
private static int pieceWeight(char piece) {
    switch (Character.toUpperCase(piece)) {
        case 'Q': return 9;
        case 'R': return 5;
        case 'B':
        case 'N': return 3;
        case 'P': return 1;
        default:  return 0;
    }
}

