/**
 * Chooses the appropriate value (normal or power) based on {@code usePower},
 * then updates the running maximum and the expression that produced it.
 *
 * @param usePower   true if the power variant must be used
 * @param normalVal the value computed with the logarithmic formula
 * @param powerVal  the value computed with the exponential formula
 * @param candidate the string representation of the current expression
 * @param maxHolder a single‑element array holding the current maximum
 * @param expHolder a single‑element array holding the expression for the maximum
 */
private static void evaluateBlock(boolean usePower,
                                  double normalVal,
                                  double powerVal,
                                  String candidate,
                                  double[] maxHolder,
                                  String[] expHolder) {
    double value = usePower ? powerVal : normalVal;
    if (value > maxHolder[0]) {
        maxHolder[0] = value;
        expHolder[0] = candidate;
    }
}

