 * @param delta  current Δ values for each element
 * @param pq     priority queue ordered by Δ
 * @param curHave number of elements already taken (starts at N)
 * @return the final sum of squares
 */
private static long upgradeUntilTarget(long result, int[] cur, long[] delta,
                                       PriorityQueue<Integer> pq, int curHave) {
