/* Helper: greedy loop that increases elements until we have K parts */
private static long performGreedyIncrease(
        long[] values,
        int[] cur,
        long[] delta,
        int targetCount,
        long currentRes,
        int currentHave,
        PriorityQueue<Integer> pq) {

    long res = currentRes;
