/**
 * Performs the incremental loop until the number of taken elements reaches K.
 *
 * @param targetK   desired total count (K)
 * @param pq        priority queue ordered by delta
 * @param delta     mutable array of current deltas
 * @param cur       mutable array of current multiplicities
 * @param curRes    current result (sum of squares)
 * @return the updated result after the loop finishes
 */
private static long increaseResultUntilK(int targetK,
                                         PriorityQueue<Integer> pq,
                                         long[] delta,
                                         int[] cur,
                                         long curRes) {
    int curHave = N; // initially we have N elements (each taken once)

    while (curHave < targetK) {
        int id = pq.poll();
        curRes += delta[id];

        if (debug) {
