public static long nextLong() {
    // Guard clause: no more input
    if (!hasNext()) throw new NoSuchElementException();

    int b = readByte();
    boolean minus = false;

    // Guard clause: optional leading minus sign
    if (b == '-') {
        minus = true;
        b = readByte();
    }

    // Guard clause: first non‑sign character must be a digit
    if (!isDigit(b)) throw new NumberFormatException();

    // Delegate the digit‑parsing loop
    long magnitude = readNumber(b);

    // Apply sign
    return minus ? -magnitude : magnitude;
}

/** Reads successive digit bytes starting with {@code firstByte}
 *  and returns the accumulated numeric value.
 *  Terminates when a non‑printable character or EOF is encountered.
 *  Throws {@link NumberFormatException} for any invalid (non‑digit printable) byte.
 */
private static long readNumber(int firstByte) {
    long n = 0;
    int b = firstByte;

    while (true) {
        if (isDigit(b)) {
            n = n * 10 + (b - '0');
        } else if (b == -1 || !isPrintableChar(b)) {
            // End of number reached
            return n;
        } else {
            // Printable but not a digit -> malformed number
            throw new NumberFormatException();
        }
        b = readByte();
    }
}

/** Predicate that tells whether a byte represents an ASCII digit. */
private static boolean isDigit(int c) {
    return '0' <= c && c <= '9';
}

public static long nextLong() {
    if (!hasNext())
        throw new NoSuchElementException();     // guard clause

    // Determine sign and obtain first non‑sign byte
    SignInfo signInfo = readSignAndFirstByte();

    // The first meaningful byte must be a digit
    if (!isDigit(signInfo.firstByte))
        throw new NumberFormatException();       // guard clause

    long magnitude = parseDigits(signInfo.firstByte);
    return signInfo.isNegative ? -magnitude : magnitude;
}

/**
 * Holds the sign information and the first byte after the optional sign.
 */
private static class SignInfo {
    final boolean isNegative;
    final int firstByte;

    SignInfo(boolean isNegative, int firstByte) {
        this.isNegative = isNegative;
        this.firstByte = firstByte;
    }
}

/** Reads an optional leading '-' and returns sign + first byte. */
private static SignInfo readSignAndFirstByte() {
    int b = readByte();
    boolean negative = false;

    if (b == '-') {
        negative = true;
        b = readByte();
    }
    return new SignInfo(negative, b);
}

/** Returns true if the character code represents a decimal digit. */
private static boolean isDigit(int c) {
    return c >= '0' && c <= '9';
}

/**
 * Parses the digit sequence starting with {@code firstByte}.
 * Stops when end‑of‑stream or a non‑printable character is reached.
 * Throws NumberFormatException for any other unexpected character.
 */
private static long parseDigits(int firstByte) {
    long value = 0;
    int b = firstByte;

    while (true) {
        if (isDigit(b)) {
            value = value * 10 + (b - '0');
        } else if (b == -1 || !isPrintableChar(b)) {
            return value;                         // termination condition
        } else {
            throw new NumberFormatException();   // illegal character
        }
        b = readByte();
    }
}

