    int t = sc.nextInt();
    while (t-- > 0) {
        long aOrig = sc.nextLong();
        long sOrig = sc.nextLong();

        // 1️⃣ build the subtraction string (s1)
        String diffStr = buildDifferenceString(aOrig, sOrig);
        diffStr = diffStr.isEmpty() ? "0" : diffStr;

        // 2️⃣ try to interpret it as a number
        long diffVal = safeParseLong(diffStr);
        if (diffVal == -1) {
            System.out.println(-1);
            continue;
        }

        // 3️⃣ build the addition string (s2) from diffVal and the original a
        String sumStr = buildSumString(diffVal, aOrig);
        sumStr = sumStr.isEmpty() ? "0" : sumStr;

        // 4️⃣ validate the reconstruction
        long sumVal = safeParseLong(sumStr);
        if (sumVal == sOrig) {
            System.out.println(diffVal);
        } else {
            System.out.println(-1);
        }
    }
}

/** Returns the digit‑wise subtraction string described in the original code. */
private static String buildDifferenceString(long a, long s) {
    StringBuilder sb = new StringBuilder();
    while (s > 0 || a > 0) {
        long digitS = s % 10;
        long digitA = a % 10;
        if (digitS >= digitA) {
            sb.append(digitS - digitA);
            s /= 10;
            a /= 10;
        } else {
            // need to borrow from the next decimal place of s
            long twoDigitsS = s % 100;
            sb.append(twoDigitsS - digitA);
            s /= 100;
            a /= 10;
        }
    }
    // sb currently holds the result reversed
    return sb.reverse().toString();
}

/** Returns the digit‑wise addition string of diff and a (original a). */
private static String buildSumString(long diff, long a) {
    StringBuilder sb = new StringBuilder();
    while (diff > 0 || a > 0) {
        long digitDiff = diff % 10;
        long digitA = a % 10;
        sb.append(digitDiff + digitA);
        diff /= 10;
        a /= 10;
    }
    // sb currently holds the result reversed
    return sb.reverse().toString();
}

/** Parses a string to long; returns -1 if parsing fails. */
private static long safeParseLong(String s) {
    try {
        return Long.parseLong(s);
    } catch (NumberFormatException e) {
        return -1;
    }
}

