// ------------------------------------------------------------
// 1️⃣ Parse input, build the undirected weighted graph (adjList)
private static InputData readInput(Scanner sc) {
    V = sc.nextInt();                 // number of vertices
    int E = sc.nextInt();             // number of edges
    int n = sc.nextInt();             // number of start vertices
    m = V;                            // original code kept this assignment
    int k = sc.nextInt();             // required matching size

    int[] start = new int[n];
    for (int i = 0; i < n; i++) {
        start[i] = sc.nextInt() - 1;  // convert to 0‑based
    }

    adjList = new ArrayList[V];
    for (int i = 0; i < V; i++) {
        adjList[i] = new ArrayList<>();
    }

    for (int i = 0; i < E; i++) {
        int u = sc.nextInt() - 1;
        int v = sc.nextInt() - 1;
        int t = sc.nextInt();
        adjList[u].add(new Edge(v, t));
        adjList[v].add(new Edge(u, t));
    }

    return new InputData(start, k);
}

// ------------------------------------------------------------
// 2️⃣ Run Dijkstra from each start vertex and collect distances
private static int[][] computeAllDistances(int[] start) {
    int n = start.length;
    int[][] dist = new int[n][V];
    for (int i = 0; i < n; i++) {
        dist[i] = dijkstra(start[i]); // dijkstra returns int[V]
    }
    return dist;
}

// ------------------------------------------------------------
// 3️⃣ Binary search the smallest “mid” for which a matching ≥ k exists
private static int binarySearchMinimumMid(InputData data, int[][] dist) {
    int lo = 0, hi = (int) 2e6;
    int ans = -1;

    while (lo <= hi) {
        int mid = (lo + hi) / 2;

        buildBipartiteGraph(dist, mid);      // creates adjList2 used by hopcroftKarp
        if (hopcroftKarp() >= data.k) {      // enough matches → try smaller mid
            ans = mid;
            hi = mid - 1;
        } else {                             // not enough → need larger mid
            lo = mid + 1;
        }
    }
    return ans;
}

// ------------------------------------------------------------
// Helper: construct the bipartite graph (left side = start indices, right side = vertices)
// Only edges whose distance ≤ limit are kept.
private static void buildBipartiteGraph(int[][] dist, int limit) {
    int n = dist.length; // number of start vertices
    adjList2 = new ArrayList[n + 1]; // 1‑based indexing as in the original code
    for (int i = 1; i <= n; i++) {
        adjList2[i] = new ArrayList<>();
        for (int v = 1; v <= V; v++) {
            if (dist[i - 1][v - 1] <= limit) {
                adjList2[i].add(v);
            }
        }
    }
}

private static class InputData {
    int V, E, n, m, k;
    int[] start;
}

/** Reads the whole input, initialises the global adjacency list and returns the parsed data. */
private static InputData readInput(Scanner sc) throws IOException {
    InputData data = new InputData();
    data.V = sc.nextInt();
    data.E = sc.nextInt();
    data.n = sc.nextInt();
    data.m = data.V;
    data.k = sc.nextInt();

    data.start = new int[data.n];
    for (int i = 0; i < data.n; i++) {
        data.start[i] = sc.nextInt() - 1;
    }

    adjList = new ArrayList[data.V];
    for (int i = 0; i < data.V; i++) {
        adjList[i] = new ArrayList<>();
    }
    int edges = data.E;
    while (edges-- > 0) {
        int u = sc.nextInt() - 1;
        int v = sc.nextInt() - 1;
        int t = sc.nextInt();
        adjList[u].add(new Edge(v, t));
        adjList[v].add(new Edge(u, t));
    }
    return data;
}

/** Runs Dijkstra for every start vertex and returns the distance matrix. */
private static int[][] computeAllDistances(int[] start) {
    int[][] dist = new int[start.length][V];
    for (int i = 0; i < start.length; i++) {
        dist[i] = dijkstra(start[i]);
    }
    return dist;
}

/** Builds the bipartite adjacency list (adjList2) for a given time limit. */
private static void buildBipartiteGraph(int[][] dist, int limit) {
    adjList2 = new ArrayList[n + 1];
    for (int i = 1; i <= n; i++) {
        adjList2[i] = new ArrayList<>();
        for (int v = 1; v <= V; v++) {
            if (dist[i - 1][v - 1] <= limit) {
                adjList2[i].add(v);
            }
        }
    }
}

/** Binary‑searches the smallest time such that at least k matchings exist. */
private static int searchMinimumTime(int k, int[] start, int[][] dist) {
    int ans = -1;
    int lo = 0;
    int hi = (int) 2e6;

    while (lo <= hi) {
        int mid = (lo + hi) / 2;

        buildBipartiteGraph(dist, mid);

        if (hopcroftKarp() >= k) {
            ans = mid;
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return ans;
}

