/* ---------- binary search on answer ---------- */
private static int findMinimumTime() {
    int answer = -1;
    int lo = 0;
    int hi = (int) 2e6;   // upper bound from original solution

    while (lo <= hi) {
        int mid = (lo + hi) / 2;

        buildBipartiteGraph(mid);

        if (hopcroftKarp() >= k) {
            answer = mid;
            hi = mid - 1;          // try to find a smaller feasible time
        } else {
            lo = mid + 1;          // need a larger time limit
        }
    }
    return answer;
}

/* ---------- helper for each binary‑search step ---------- */
private static void buildBipartiteGraph(int timeLimit) {
    adjList2 = new ArrayList[n + 1];
    for (int i = 1; i <= n; i++) {
        List<Integer> reachable = new ArrayList<>();
        for (int v = 1; v <= V; v++) {
            if (dist[i - 1][v - 1] <= timeLimit) {
                reachable.add(v);
            }
        }
        adjList2[i] = new ArrayList<>(reachable);
    }
}

