public final long nextLong() {
    if (!hasNext()) {
        throw new java.util.NoSuchElementException();
    }

    long n = 0;
    try {
        byte b = readByte();

        // sign handling – guard clause
        if (b == '-') {
            n = readNegativeNumber(n);
            return n;
        }

        // first character must be a digit
        validateFirstByte(b);

        // positive number parsing
        n = readPositiveNumber(n, b);
        return n;
    } catch (java.util.NoSuchElementException e) {
        // Preserve original behaviour: return whatever has been accumulated.
        return n;
    }
}

/** Parses the rest of a negative number. Assumes the leading '-' has already been read. */
private long readNegativeNumber(long n) {
    byte b;
    while (isNumber(b = readByte())) {
        // original logic used '0' - b to build a negative value
        n = n * 10 + ('0' - b);
    }
    return n;
}

/** Parses a positive number. `firstDigit` is guaranteed to be a digit. */
private long readPositiveNumber(long n, byte firstDigit) {
    byte b = firstDigit;
    do {
        n = n * 10 + (b - '0');
        b = readByte();
    } while (isNumber(b));
    return n;
}

/** Ensures the first byte after a possible sign is a digit. */
private void validateFirstByte(byte b) {
    if (!isNumber(b)) {
        throw new NumberFormatException();
    }
}

