/** Simple value object to carry the result of a single move. */
private static final class MoveResult {
    final long steps;
    final long x;
    final long y;

    MoveResult(long steps, long x, long y) {
        this.steps = steps;
        this.x = x;
        this.y = y;
    }
}

/**
 * Computes the effect of moving from (x, y) by the vector (dx, dy) inside a
 * board of size n × m. Returns the number of steps actually performed and the
 * new position. The method uses guard clauses to handle trivial cases early.
 */
private static MoveResult handleMove(long dx, long dy,
                                     long x, long y,
                                     long n, long m) {
    // Guard clause: no movement at all.
    if (dx == 0 && dy == 0) {
        return new MoveResult(0, x, y);
    }

    long stepx = 0;
    long stepy = 0;

    // Maximum possible steps in the x‑direction.
    if (dx < 0) {
        long cells = x - 1;
        stepx = cells / (-dx);
    } else if (dx > 0) {
        long cells = n - x;
        stepx = cells / dx;
    }

    // Maximum possible steps in the y‑direction.
    if (dy < 0) {
        long cells = y - 1;
        stepy = cells / (-dy);
    } else if (dy > 0) {
        long cells = m - y;
        stepy = cells / dy;
    }

    // Pure vertical movement.
    if (dx == 0 && dy != 0) {
        long steps = stepy;
        long newY = y + steps * dy;
        return new MoveResult(steps, x, newY);
    }

    // Pure horizontal movement.
    if (dy == 0 && dx != 0) {
        long steps = stepx;
        long newX = x + steps * dx;
        return new MoveResult(steps, newX, y);
    }

    // Diagonal movement – the limiting direction decides the number of steps.
    if (stepx > stepy) {
        long steps = stepy;
        long newX = x + steps * dx;
        long newY = y + steps * dy;
        return new MoveResult(steps, newX, newY);
    } else if (stepx < stepy) {
        long steps = stepx;
        long newX = x + steps * dx;
        long newY = y + steps * dy;
        return new MoveResult(steps, newX, newY);
    } else { // stepx == stepy
        long steps = stepx; // same as stepy
        long newX = x + steps * dx;
        long newY = y + steps * dy;
        return new MoveResult(steps, newX, newY);
    }
}

public static void main(String[] args) {
    Charset charset = Charset.forName("ascii");
    FastIO rd = new FastIO(System.in, System.out, charset);

    long n = rd.readLong();
    long m = rd.readLong();

    long x = rd.readLong();
    long y = rd.readLong();

    int k = rd.readInt();
    State state = new State(x, y, 0L);

    while (k-- > 0) {
        long dx = rd.readLong();
        long dy = rd.readLong();
        applyMove(state, dx, dy, n, m);
    }

    System.out.println(state.steps);
}

/** Holds the mutable simulation state. */
private static class State {
    long x;
    long y;
    long steps;

    State(long x, long y, long steps) {
        this.x = x;
        this.y = y;
        this.steps = steps;
    }
}

/**
 * Updates {@code state} with the movement described by {@code dx}/{@code dy}
 * while respecting the board limits {@code n} (width) and {@code m} (height).
 *
 * The method uses guard clauses to handle the special cases first,
 * then applies the generic diagonal movement logic.
 */
private static void applyMove(State state, long dx, long dy, long n, long m) {
    // Guard: no movement at all.
    if (dx == 0 && dy == 0) {
        return;
    }

    // Compute how far we could travel in each axis before hitting a border.
    long stepx = (dx == 0) ? Long.MAX_VALUE : maxSteps(dx, state.x, n);
    long stepy = (dy == 0) ? Long.MAX_VALUE : maxSteps(dy, state.y, m);

    // Guard: pure vertical movement.
    if (dx == 0) {
        state.steps += stepy;
        state.y += stepy * dy;
        return;
    }

    // Guard: pure horizontal movement.
    if (dy == 0) {
        state.steps += stepx;
        state.x += stepx * dx;
        return;
    }

    // General diagonal case – move the minimum of the two limits.
    long stepsToTake = Math.min(stepx, stepy);
    state.steps += stepsToTake;
    state.x += stepsToTake * dx;
    state.y += stepsToTake * dy;
}

/**
 * Returns the maximum whole‑number of steps that can be taken in the direction
 * {@code delta} before the coordinate {@code pos} would leave the interval
 * [1, {@code limit}].
 *
 * {@code delta} is non‑zero.
 */
private static long maxSteps(long delta, long pos, long limit) {
    if (delta > 0) {
        long cells = limit - pos; // cells to the far border
        return cells / delta;
    } else { // delta < 0
        long cells = pos - 1; // cells to the near border
        return cells / (-delta);
    }
}

