public void solve(int testNumber, InputReader in, OutputWriter out) {
    int k = in.readInt();
    char[] str = in.readString().toCharArray();

    boolean[] flag = new boolean[str.length];
    int distinct = markFirstOccurrences(str, flag);

    // Guard clause: not enough distinct letters
    if (distinct < k) {
        out.printLine("NO");
        return;
    }

    trimToKDistinct(str, flag, distinct, k);
    out.print("YES");
    printResult(flag, str, out);
}

/**
 * Marks the first occurrence of each character in {@code str}.
 * {@code flag[i]} becomes true only for the left‑most position of a character.
 * Returns the number of distinct characters found.
 */
private int markFirstOccurrences(char[] str, boolean[] flag) {
    boolean[] seen = new boolean[26];
    int distinct = 0;
    for (int i = 0; i < str.length; i++) {
        int idx = str[i] - 'a';
        if (!seen[idx]) {
            seen[idx] = true;
            flag[i] = true;
            distinct++;
        }
    }
    return distinct;
}

/**
 * Turns off {@code flag} entries from right to left until exactly {@code k}
 * distinct characters remain marked.
 */
private void trimToKDistinct(char[] str, boolean[] flag, int distinct, int k) {
    for (int i = str.length - 1; i >= 0 && distinct > k; i--) {
        if (flag[i]) {
            flag[i] = false;
            distinct--;
        }
    }
}

/**
 * Writes the answer: a newline after every kept character, then the character itself.
 */
private void printResult(boolean[] flag, char[] str, OutputWriter out) {
    for (int i = 0; i < str.length; i++) {
        if (flag[i]) {
            out.printLine();
        }
        out.print(str[i]);
    }
}

