public int upperFirstBound(ArrayList<Integer> a, Integer x) {
    int size = a.size();
    if (size == 0) {
        return 0;
    }

    // Guard‑clauses for the trivial boundaries
    if (a.get(0) > x) {
        return 0;
    }
    if (a.get(size - 1) <= x) {
        return size;
    }

    // Delegates the binary‑search part
    return findUpperBound(a, x, 0, size - 1);
}

/** Binary‑search that returns the first index whose element is greater than x. */
private int findUpperBound(ArrayList<Integer> a, int x, int left, int right) {
    int mid = -1;
    while (left <= right) {
        mid = (left + right) >>> 1; // unsigned right shift avoids overflow

        if (isUpperBoundAtMid(a, mid, x)) {
            // Exact match where the next element is greater than x
            return (a.get(mid) == x) ? mid + 1 : mid;
        }

        // Guard‑clauses for moving the search window
        if (a.get(mid) <= x) {
            left = mid + 1;
        } else if (mid > 0 && a.get(mid - 1) <= x) {
            return mid; // First element greater than x
        } else {
            right = mid - 1;
        }
    }
    // When the loop finishes without an early return, left is the insertion point
    return left;
}

/**
 * Determines whether the current mid position already satisfies the “upper bound”
 * condition: either the element at mid equals x and the next element is greater,
 * or the element at mid is greater than x while the previous element is ≤ x.
 */
private boolean isUpperBoundAtMid(ArrayList<Integer> a, int mid, int x) {
    int current = a.get(mid);
    if (current == x) {
        // Need to be sure that mid+1 exists; caller guarantees this case.
        return a.get(mid + 1) > x;
    }
    // current > x && previous ≤ x
    return current > x && mid > 0 && a.get(mid - 1) <= x;
}

