/* ----- extracted helpers for the four distinct paths ----- */

private long computeForLast(int ind, int curIndent) {
    // branch: 'f' && lastFor(ind)
    return dp(ind + 1, curIndent + 1);
}

private long computeForNotLast(int ind, int curIndent) {
    // branch: 'f' && !lastFor(ind)
    return dp(ind, curIndent - 1) + dp(ind + 1, curIndent + 1);
}

private long computeSLast(int ind, int curIndent) {
    // branch: 's' && lastFor(ind)
    return dp(ind + 1, curIndent);
}

private long computeSNotLast(int ind, int curIndent) {
    // branch: 's' && !lastFor(ind)
    return dp(ind + 1, curIndent) + dp(ind, curIndent - 1);
}

long dp(int ind, int curIndent) {
    // Guard clauses – fast exits
    if (ind == n) return 1;
    if (curIndent < 0) return 0;
    if (memo[ind][curIndent] != -1) return memo[ind][curIndent];

    long ans;
    if (a[ind] == 'f') {
        ans = computeFor(ind, curIndent);
    } else { // a[ind] == 's'
        ans = computeStatement(ind, curIndent);
    }

    return memo[ind][curIndent] = ans % mod;
}

private long computeFor(int ind, int curIndent) {
    // 'f' and it is the last for‑statement of the block
    if (lastFor(ind)) {
        return dp(ind + 1, curIndent + 1);
    }
    // 'f' but not the last for‑statement
    long res = dp(ind, curIndent - 1);
    res += dp(ind + 1, curIndent + 1);
    return res;
}

private long computeStatement(int ind, int curIndent) {
    // 's' and it follows a last for‑statement
    if (lastFor(ind)) {
        return dp(ind + 1, curIndent);
    }
    // 's' but not after a last for‑statement
    long res = dp(ind + 1, curIndent);
    res += dp(ind, curIndent - 1);
    return res;
}

