private static int solve(int aR, int bR, int total) {
    // Guard clause: final step – no more moves
    if (total == 2 * n - 1) {
        return 0;
    }

    // Guard clause: already computed
    if (dp[aR][bR][total] != -oo) {
        return dp[aR][bR][total];
    }

    // Translate indexes to board coordinates
    int ax = total - aR;
    int ay = aR;
    int bx = total - bR;
    int by = bR;

    // Compute best score for the next step
    int ans = maxNextScore(aR, bR, total, ax, ay, bx, by);

    // Add the values of the current cells
    ans += a[ax][ay] + a[bx][by];

    // If both walkers are on the same cell, subtract the duplicate addition
    if (ax == bx && ay == by) {
        ans -= a[ax][by];
    }

    // Memoise and return
    dp[aR][bR][total] = ans;
    return ans;
}

/**
 * Returns the maximal score obtainable from the four possible moves
 * from the current positions. If none of the moves is legal, returns 0.
 */
private static int maxNextScore(int aR, int bR, int total,
                                int ax, int ay, int bx, int by) {
    int best = -oo;

    // Move both walkers downwards (right in the original grid)
    if (ax + 1 < n && bx + 1 < n) {
        best = Math.max(best, solve(aR, bR, total + 1));
    }
    // Move first walker down, second walker right
    if (ax + 1 < n && by + 1 < n) {
        best = Math.max(best, solve(aR, bR + 1, total + 1));
    }
    // Move first walker right, second walker down
    if (ay + 1 < n && bx + 1 < n) {
        best = Math.max(best, solve(aR + 1, bR, total + 1));
    }
    // Move both walkers rightwards
    if (ay + 1 < n && by + 1 < n) {
        best = Math.max(best, solve(aR + 1, bR + 1, total + 1));
    }

    return best == -oo ? 0 : best;
}

private static int solve(int aR, int bR, int total) {
    // Guard clause for the terminal state
    if (total == 2 * n - 1) {
        return 0;
    }

    // Return cached result if already computed
    if (dp[aR][bR][total] != -oo) {
        return dp[aR][bR][total];
    }

    // Current coordinates for the two walkers
    int ax = total - aR;
    int ay = aR;
    int bx = total - bR;
    int by = bR;

    // Evaluate all feasible next moves
    int ans = maxNext(aR, bR, total, ax, ay, bx, by);

    // If no move was possible, treat as 0; otherwise add the cell values
    ans = (ans == -oo) ? 0 : ans;
    ans += cellSum(ax, ay, bx, by);

    // Memoise and return
    dp[aR][bR][total] = ans;
    return ans;
}

/**
 * Returns the best value obtainable by moving to the next step.
 * Each conditional represents a distinct movement combination for the two walkers.
 */
private static int maxNext(int aR, int bR, int total,
                           int ax, int ay, int bx, int by) {
    int best = -oo;

    // both move right
    if (ax + 1 < n && bx + 1 < n) {
        best = Math.max(best, solve(aR, bR, total + 1));
    }
    // a moves right, b moves down
    if (ax + 1 < n && by + 1 < n) {
        best = Math.max(best, solve(aR, bR + 1, total + 1));
    }
    // a moves down, b moves right
    if (ay + 1 < n && bx + 1 < n) {
        best = Math.max(best, solve(aR + 1, bR, total + 1));
    }
    // both move down
    if (ay + 1 < n && by + 1 < n) {
        best = Math.max(best, solve(aR + 1, bR + 1, total + 1));
    }

    return best;
}

/**
 * Calculates the sum contributed by the current cells.
 * If both walkers are on the same cell, that cell's value must be counted only once.
 */
private static int cellSum(int ax, int ay, int bx, int by) {
    int sum = a[ax][ay] + a[bx][by];
    if (ax == bx && ay == by) {
        sum -= a[ax][by];   // remove double‑counted value
    }
    return sum;
}

