/**
 * Executes the O(n log n) longest‑increasing‑subsequence algorithm used in
 * the original program and returns the number of positions that were
 * filled (the length of the LIS).
 */
private static int computeLisResult(int[] data) {
    int n = data.length;
    int[] dp = new int[n + 1];
    Arrays.fill(dp, 987654321);
    dp[0] = data[0];

    for (int i = 1; i < n; i++) {
        int pos = findInsertPosition(dp, data[i], n);
        dp[pos] = Math.min(data[i], dp[pos]);
    }

    return countFilled(dp);
}

/**
 * Binary‑searches {@code dp} to find the smallest index {@code lo} such that
 * {@code dp[lo] >= value}. The method returns the index where {@code value}
 * should be placed (or updated). Guard clauses keep the flow flat.
 */
private static int findInsertPosition(int[] dp, int value, int limit) {
    int lo = 0, hi = limit;
    while (hi > lo + 1) {
        int mid = (hi + lo) / 2;
        if (dp[mid] > value) {
            hi = mid;
        } else {
            lo = mid;
        }
    }
    // If the element at lo is smaller than the value, the correct slot is lo+1.
    if (dp[lo] < value) {
        lo++;
    }
    // Ensure we never write past the array (guard clause).
    return (lo <= limit) ? lo : limit;
}

/**
 * Counts how many entries in {@code dp} are different from the sentinel value.
 */
private static int countFilled(int[] dp) {
    int count = 1; // dp[0] is always filled
    for (int i = 1; i < dp.length; i++) {
        if (dp[i] != 987654321) {
            count++;
        }
    }
    return count;
}

