    }
    return arr;
}

/** Returns the length of the longest increasing subsequence for {@code data}. */
private static int computeLisLength(int[] data) {
    final int INF = 987654321;
    int n = data.length;

    int[] dp = new int[n + 1];
    Arrays.fill(dp, INF);
    dp[0] = data[0];                 // first element always starts a subsequence

    for (int i = 1; i < n; i++) {
        int lo = 0, hi = n;
        // binary search for the greatest index whose dp value ≤ data[i]
        while (hi > lo + 1) {
            int mid = (hi + lo) / 2;
            if (dp[mid] > data[i]) {
                hi = mid;
            } else {
                lo = mid;
            }
        }
        if (dp[lo] < data[i]) {
            lo++;
        }
        if (lo <= n) {
            dp[lo] = Math.min(data[i], dp[lo]);
        }
    }

    int res = 1; // at least one element forms an increasing subsequence
    for (int i = 1; i <= n; i++) {
        if (dp[i] != INF) {
            res++;
        }
    }
    return res;
}

