/** Moves the left pointer from its current position to target, updating the structure. */
private static int moveLeft(int current, int target, int[] data) {
    while (current < target) {
        remove(data[current]);
        current++;
    }
    while (current > target) {
        current--;
        add(data[current]);
    }
    return current;
}

/** Moves the right pointer from its current position to target, updating the structure. */
private static int moveRight(int current, int target, int[] data) {
    while (current < target) {
        current++;
        add(data[current]);
    }
    while (current > target) {
        remove(data[current]);
        current--;
    }
    return current;
}

