/**
 * Moves the current window [left, right] to the target interval [targetLeft, targetRight].
 * The method updates the static fields {@code left}, {@code right}, and {@code res}
 * using the existing {@code add} and {@code remove} helpers.
 *
 * @param targetLeft  desired left index (inclusive)
 * @param targetRight desired right index (inclusive)
 * @param data        the array of values being processed
 * @param curLeft     current left pointer (will be updated)
 * @param curRight    current right pointer (will be updated)
 */
private static void adjustWindow(int targetLeft, int targetRight, int[] data,
                                 int curLeft, int curRight) {
    // Move left pointer forward
    while (left < targetLeft) {
        remove(data[left]);
        left++;
    }
    // Move left pointer backward
    while (left > targetLeft) {
        left--;
        add(data[left]);
    }
    // Expand right pointer
    while (right < targetRight) {
        right++;
        add(data[right]);
    }
    // Shrink right pointer
    while (right > targetRight) {
        remove(data[right]);
        right--;
    }
}

