/**
 * Moves the sliding window so that it exactly covers the interval [targetLeft, targetRight].
 * The method updates the mutable {@code window} array (window[0] = left, window[1] = right)
 * and relies on the existing {@code add} and {@code remove} methods to maintain {@code res}.
 */
private static void adjustWindow(int targetLeft, int targetRight, int[] data, int[] window) {
    int left = window[0];
    int right = window[1];

    while (left < targetLeft) {
        remove(data[left]);
        left++;
    }
    while (left > targetLeft) {
        left--;
        add(data[left]);
    }
    while (right < targetRight) {
        right++;
        add(data[right]);
    }
    while (right > targetRight) {
        remove(data[right]);
        right--;
    }

    window[0] = left;
    window[1] = right;
}

