/** Section A – create the base lists and fill indices 1 and 2. */
private static ArrayList<ArrayList<Integer>> initShortLists() {
    ArrayList<ArrayList<Integer>> shorts = new ArrayList<>(9);
    for (int i = 0; i <= 8; i++) {
        shorts.add(new ArrayList<Integer>());
    }
    // index 1: single‑digit numbers 0‑9
    for (int i = 0; i <= 9; i++) {
        shorts.get(1).add(i);
    }
    // index 2: two‑digit palindromes 00, 11, …, 99
    for (int i = 0; i <= 9; i++) {
        shorts.get(2).add(10 * i + i);
    }
    return shorts;
}

/** Section B – generate palindromes of length 3 … 7. */
private static void extendPalindromes(ArrayList<ArrayList<Integer>> shorts) {
    int mult = 11;   // multiplier for the outer digit
    int tens = 1;    // 10^(length‑2)

    for (int len = 3; len < 8; len++) {
        tens *= 10;          // shift left for the next length
        mult = (mult - 1) * 10 + 1;   // update 11 → 101 → 1001 → …

        for (int outer = 0; outer <= 9; outer++) {
            for (int inner : shorts.get(len - 2)) {
                // Build number: outer * mult + inner * 10
                shorts.get(len).add(outer * mult + inner * 10);
            }
        }
    }
}

/** Section C – gather all generated numbers whose last digit is not zero. */
private static ArrayList<Integer> collectPalindromes(ArrayList<ArrayList<Integer>> shorts) {
    ArrayList<Integer> pals = new ArrayList<>();
    for (int len = 1; len < 8; len++) {
        for (int value : shorts.get(len)) {
            if (value % 10 == 0) {
                continue;               // guard clause – skip numbers ending in 0
            }
            pals.add(value);
        }
    }
    return pals;
}

