    TreeSet<int[]> set = new TreeSet<>(new Comparator<int[]>() {
        @Override
        public int compare(int[] a, int[] b) {
            if (a[1] != b[1])
                return b[1] - a[1];
            return b[0] - a[0];
        }
    });

