    for (int i = 0; i < n; i++) {
        arr[i] = sc.nextInt();
    }

    // build the first window [0 … k‑1]
    populateInitialWindow(arr, k, occ, set);

    // slide the window; i points to the rightmost index of the current window
    for (int i = k - 1; i < n; i++) {
        cleanSet(set);
        printCurrent(set, pw);

        // element that will enter the window in the next iteration
        if (i + 1 < n) {
            addElement(arr[i + 1], occ, set);
        }

        // element that leaves the current window
        int outgoing = arr[i - k + 1];
        removeElement(outgoing, occ, set);
    }

    pw.flush();
    pw.close();
}

/**
 * Fills {@code occ} and {@code set} with the frequencies of the first {@code k}
 * elements of {@code arr}.
 */
private static void populateInitialWindow(int[] arr, int k,
                                          Map<Integer, Integer> occ,
                                          TreeSet<int[]> set) {
    for (int i = 0; i < k; i++) {
        int x = arr[i];
        occ.put(x, occ.getOrDefault(x, 0) + 1);
    }
    for (Map.Entry<Integer, Integer> e : occ.entrySet()) {
        set.add(new int[]{e.getKey(), e.getValue()});
    }
}

/**
 * Removes from {@code set} every entry whose count is larger than 1.
 */
private static void cleanSet(TreeSet<int[]> set) {
    while (!set.isEmpty() && set.first()[1] > 1) {
        set.pollFirst();
    }
}

/**
 * Prints the current answer: the biggest value that appears exactly once,
 * or “Nothing” if none exists.
 */
private static void printCurrent(TreeSet<int[]> set, PrintWriter pw) {
    if (set.isEmpty()) {
        pw.println("Nothing");
    } else {
        pw.println(set.first()[0]);
    }
}

/**
 * Increments the frequency of {@code x} in {@code occ} and updates {@code set}
 * accordingly.
 */
private static void addElement(int x,
                               Map<Integer, Integer> occ,
                               TreeSet<int[]> set) {
    int oldCount = occ.getOrDefault(x, 0);
    if (oldCount > 0) {
        // remove the old entry from the set
        set.remove(new int[]{x, oldCount});
    }
    int newCount = oldCount + 1;
    occ.put(x, newCount);
    set.add(new int[]{x, newCount});
}

/**
 * Decrements the frequency of {@code x} in {@code occ} and updates {@code set}
 * accordingly. If the frequency drops to zero the key is removed from {@code occ}.
 */
private static void removeElement(int x,
                                  Map<Integer, Integer> occ,
                                  TreeSet<int[]> set) {
    Integer countObj = occ.get(x);
    if (countObj == null) {
        return; // element not present – nothing to do
    }
    int count = countObj;
    // remove the current entry from the set
    set.remove(new int[]{x, count});

    if (count == 1) {
        occ.remove(x);
    } else {
        int newCount = count - 1;
        occ.put(x, newCount);
        set.add(new int[]{x, newCount});
    }
}

