public int compare(node n1, node n2) {
    // Primary comparison on the numeric value
    if (n1.val < n2.val) {
        return -1;
    }
    if (n1.val > n2.val) {
        return 1;
    }

    // Values are equal – defer to type‑based comparison
    return compareWhenValuesEqual(n1, n2);
}

private int compareWhenValuesEqual(node n1, node n2) {
    // If types are identical, the nodes are considered equal
    if (n1.type == n2.type) {
        return 0;
    }

    // Ordering rule: -1 < 0 < any other type
    if (n1.type == -1) {
        return -1;
    }
    if (n2.type == -1) {
        return 1;
    }
    if (n1.type == 0) {
        return -1;
    }
    if (n2.type == 0) {
        return 1;
    }

    // Types differ but are neither -1 nor 0 – treat as equal for ordering purposes
    return 0;
}

public int compare(node n1, node n2) {
    // Guard clause: compare primary values first
    int valueComparison = Integer.compare(n1.val, n2.val);
    if (valueComparison != 0) {
        return valueComparison;
    }

    // Values are equal – fall back to type comparison
    return compareType(n1.type, n2.type);
}

