/**
 * Adds the appropriate replacement digits for a given character to the target list.
 * The mapping follows the original problem's specification:
 *   4 → 2,2,3
 *   8 → 2,2,2,7
 *   6 → 3,5
 *   9 → 3,3,2,7
 *   0,1 → (no digits)
 *   otherwise → numeric value of the character
 *
 * @param digit the character representing the original digit
 * @param target the list to receive the replacement digits
 */
private static void addReplacementDigits(char digit, List<Integer> target) {
    switch (digit) {
        case '4':
            target.add(2);
            target.add(2);
            target.add(3);
            break;
        case '8':
            target.add(2);
            target.add(2);
            target.add(2);
            target.add(7);
