/** Reads a deck: first the size, then that many integers. */
private static List<Integer> readCards(Scanner in) {
    int size = in.nextInt();
    List<Integer> deck = new ArrayList<>(size);
    for (int i = 0; i < size; i++) {
        deck.add(in.nextInt());
    }
    return deck;
}

/**
 * Checks whether the game has finished.
 * Prints the appropriate result and returns true if the loop should stop.
 */
private static boolean isGameOver(List<Integer> s1, List<Integer> s2, int count) {
    if (s2.isEmpty()) {
        System.out.println(count + " 1");
        return true;
    }
    if (s1.isEmpty()) {
        System.out.println(count + " 2");
        return true;
    }
    return false;
}

/** Executes one round according to the original comparison rules. */
private static void playRound(List<Integer> s1, List<Integer> s2) {
    int top1 = s1.get(0);
    int top2 = s2.get(0);

    if (top1 == top2) {
        s1.add(top1);
        s1.remove(0);
        s2.add(top2);
        s2.remove(0);
    } else if (top1 > top2) {
        s1.add(top2);
        s1.add(top1);
        s1.remove(0);
        s2.remove(0);
    } else { // top1 < top2
        s2.add(top1);
        s2.add(top2);
        s2.remove(0);
        s1.remove(0);
    }
}

