private static void processTestCase(Reader sc, PrintWriter out) throws IOException {
    int n = sc.nextInt();

    // initial bounds (large enough to be overwritten)
    int xMin = -(int) 1e5;   // lower bound for x (x0)
    int xMax =  (int) 1e5;   // upper bound for x (x1)
    int yMin = -(int) 1e5;   // lower bound for y (y0)
    int yMax =  (int) 1e5;   // upper bound for y (y1)

    int[] dir = new int[4]; // direction flags for the current point
    for (int i = 0; i < n; i++) {
        int x = sc.nextInt();
        int y = sc.nextInt();
        for (int j = 0; j < 4; j++) {
            dir[j] = sc.nextInt();
        }

        // tighten the feasible region according to the flags
        if (dir[0] == 0) xMin = Math.max(xMin, x); // cannot go left
        if (dir[1] == 0) yMax = Math.min(yMax, y); // cannot go up
        if (dir[2] == 0) xMax = Math.min(xMax, x); // cannot go right
        if (dir[3] == 0) yMin = Math.max(yMin, y); // cannot go down
    }

    // Guard clause – impossible region
    if (xMax < xMin || yMax < yMin) {
        out.println(0);
        return;
    }

    // Feasible point exists; any point inside works, we output (xMin, yMin)
    out.println("1 " + xMin + " " + yMin);
}

