/*--- helper methods ---------------------------------------------------*/

private void ensureHasNext() {
    if (!hasNext()) {
        throw new NoSuchElementException();
    }
}

/**
 * Holds the sign information and the numeric value already parsed from
 * the first character.
 */
private static final class SignAndValue {
    final boolean negative;
    final long   value;
    SignAndValue(boolean negative, long value) {
        this.negative = negative;
        this.value = value;
    }
}

/**
 * Interprets the first character of the token.
 * - '-'  -> negative number, value starts at 0
 * - digit -> positive number, value = digit
 * - otherwise -> NumberFormatException
 */
private SignAndValue parseFirstChar(long ch) {
    if (ch == '-') {
        return new SignAndValue(true, 0L);
    }
    if (!isDigit(ch)) {
        throw new NumberFormatException();
    }
    return new SignAndValue(false, ch - '0');
}

/**
 * Consumes the remaining characters, building the final long value.
 * Stops when EOF (-1) or a non‑printable character is encountered.
 */
private long readRemaining(long current, boolean negative) {
    while (true) {
        int b = readByte();

        if (isDigit(b)) {
            current = current * 10 + (b - '0');
        } else if (b == -1 || !isPrintableChar(b)) {
            return negative ? -current : current;
        } else {
            // Any other printable character terminates the token
            // but is not valid for a number.
            throw new NoSuchElementException();
        }
    }
}

/** Simple digit predicate used by several helpers. */
private boolean isDigit(int c) {
    return '0' <= c && c <= '9';
}

private static class ParseResult {
    final long value;
    final boolean minus;

    ParseResult(long value, boolean minus) {
        this.value = value;
        this.minus = minus;
    }
}

/** Parses the first byte of the token and determines sign and initial digit. */
private ParseResult parseFirstByte() {
    long b = readByte();

    if (b == '-') {
        // negative sign, value starts at 0
        return new ParseResult(0L, true);
    }

    if (b < '0' || b > '9') {
        throw new NumberFormatException();
    }

    // positive number, first digit already read
    return new ParseResult(b - '0', false);
}

/** Reads the remaining digits of a long token. */
private long readRemainingDigits(long current) {
    while (true) {
        int b = readByte();

        if (b >= '0' && b <= '9') {
            current = current * 10 + (b - '0');
        } else if (b == -1 || !isPrintableChar(b)) {
            // end of token
            return current;
        } else {
            // unexpected character inside number
            throw new NoSuchElementException();
        }
    }
}

/** Returns the next long from the input, preserving the original semantics. */
public long nextLong() {
    if (!hasNext()) {
        throw new NoSuchElementException();
    }

    ParseResult first = parseFirstByte();
    long value = readRemainingDigits(first.value);
    return first.minus ? -value : value;
}

