        sb[j] = new StringBuilder();
    }

    // Counters for each builder
    long[] cnt = new long[10];

    // The characters that belong to the cycle "codeforces"
    char[] letters = {'c', 'o', 'd', 'e', 'f', 'o', 'r', 'c', 'e', 's'};

    int i = 0;
    while (product(cnt) < k) {
        int idx = i % 10;
        appendChar(idx, sb, cnt, letters);
        i++;
    }

    // Concatenate the builders in order and print
    StringBuilder result = new StringBuilder();
    for (StringBuilder b : sb) {
        result.append(b);
    }
    pw.println(result);
    pw.close();
}

/**
 * Appends the character belonging to {@code idx} to the corresponding
 * StringBuilder and increments its counter.
 */
private static void appendChar(int idx, StringBuilder[] builders, long[] counters, char[] letters) {
    builders[idx].append(letters[idx]);
    counters[idx]++;
}

/**
 * Returns the product of all counters.  The initial product is 0 because
 * all counters start at 0, matching the original termination condition.
 */
private static long product(long[] counters) {
    long prod = 1;
    for (long v : counters) {
        prod *= v;
    }
    return prod;
}

public static void main(String[] args) throws IOException, InterruptedException {
    Scanner sc = new Scanner(System.in);
    long k = sc.nextLong();

    // Characters that correspond to each position 0‑9
    char[] chars = {'c', 'o', 'd', 'e', 'f', 'o', 'r', 'c', 'e', 's'};

    // One StringBuilder per position
    StringBuilder[] builders = {
        new StringBuilder(), new StringBuilder(), new StringBuilder(),
        new StringBuilder(), new StringBuilder(), new StringBuilder(),
        new StringBuilder(), new StringBuilder(), new StringBuilder(),
        new StringBuilder()
    };

    // Counters for each builder
    long[] counts = new long[10];

    int i = 0;
    while (productLessThanK(counts, k)) {
        int idx = i % 10;
        builders[idx].append(chars[idx]);
        counts[idx]++;          // increment the appropriate counter
        i++;
    }

    // Preserve original concatenation order
    pw.println(
        builders[0] + "" + builders[1] + "" + builders[2] + "" +
        builders[3] + "" + builders[4] + "" + builders[5] + "" +
        builders[6] + "" + builders[7] + "" + builders[8] + "" +
        builders[9]
    );
    pw.close();
}

/**
 * Returns true while the product of all counters is strictly less than k.
 * The computation stops early as soon as the product meets or exceeds k
 * to avoid unnecessary overflow work.
 */
private static boolean productLessThanK(long[] counts, long k) {
    long product = 1;
    for (long c : counts) {
        product *= c;
        if (product >= k) {
            return false;
        }
    }
    return product < k;
}

