int query(int n, int[] T, int[][] P, int[] L, int u, int v) {
    // 1️⃣ make sure u is the deeper (or equal) node
    int[] swapped = ensureDeeperNode(u, v, L);
    u = swapped[0];
    v = swapped[1];

    // 2️⃣ highest power of two we need for binary lifting
    int log = maxLog(L[u]);

    // 3️⃣ lift u up so both nodes are on the same depth
    u = liftNodeToDepth(u, v, L, P, log);

    // 4️⃣ if after lifting they coincide, we have found the LCA
    if (u == v) {
        return u;
    }

    // 5️⃣ lift both nodes together until their ancestors diverge
    u = liftTogetherUntilAncestorDiffers(u, v, P, log);

    // 6️⃣ the parent of the diverging node is stored in T
    return T[u];
}

/** Swaps u and v when v is deeper, returns the possibly swapped pair. */
private int[] ensureDeeperNode(int u, int v, int[] L) {
    if (L[u] < L[v]) {
        return new int[]{v, u};
    }
    return new int[]{u, v};
}

/** Returns ⌊log₂(depth)⌋ – the greatest exponent such that (1 << exponent) ≤ depth. */
private int maxLog(int depth) {
    int log = 0;
    while ((1 << (log + 1)) <= depth) {
        log++;
    }
    return log;
}

/** Moves node u up until it reaches the same depth as node v. */
private int liftNodeToDepth(int u, int v, int[] L, int[][] P, int log) {
    for (int i = log; i >= 0; i--) {
        if (L[u] - (1 << i) >= L[v]) {
            u = P[u][i];
        }
    }
    return u;
}

/** Lifts both nodes together until their 2^i‑ancestors differ. Returns the (now equal) ancestor of u. */
private int liftTogetherUntilAncestorDiffers(int u, int v, int[][] P, int log) {
    for (int i = log; i >= 0; i--) {
        if (P[u][i] != -1 && P[u][i] != P[v][i]) {
            u = P[u][i];
            v = P[v][i];
        }
    }
    return u;
}

