    int thisDiff = this.goal - this.miss;
    int otherDiff = c.goal - c.miss;
    // Higher goal difference ranks before lower → reverse order
    return Integer.compare(otherDiff, thisDiff);
}

private int compareGoals(Country c) {
    // More goals rank before fewer goals → reverse order
    return Integer.compare(c.goal, this.goal);
}

private int compareNames(Country c) {
    // Lexicographical order (already matches original logic)
    return this.name.compareTo(c.name);
}

