public static long getCount(int pos, int count, int isTight, long[][][] dp, String no) {
    // Guard clauses – early exits for base cases and memoised results
    if (count > 3) {
        return 0;
    }
    if (pos == no.length()) {
        return 1;
    }
    if (dp[pos][count][isTight] != -1) {
        return dp[pos][count][isTight];
    }

    long ans = 0;
    int upperBound = computeUpperBound(pos, isTight, no);

    for (int digit = 0; digit <= upperBound; digit++) {
        int flag = (digit != 0) ? 1 : 0;
        int nextTight = computeNextTight(isTight, digit, upperBound);
        ans += getCount(pos + 1, count + flag, nextTight, dp, no);
    }

    dp[pos][count][isTight] = ans;
    return ans;
}

/**
 * Returns the maximal digit that can be placed at {@code pos}.
 * When the current prefix is already tight we must not exceed the
 * corresponding digit in {@code no}; otherwise we can use 9.
 */
private static int computeUpperBound(int pos, int isTight, String no) {
    if (isTight == 1) {
        return no.charAt(pos) - '0';
    }
    return 9;
}

/**
 * Determines whether the next recursive call remains tight.
 * It stays tight only if the current call is tight and we choose
 * the maximal allowed digit.
 */
private static int computeNextTight(int isTight, int digit, int upperBound) {
    if (isTight == 1 && digit == upperBound) {
        return 1;
    }
    return 0;
}

public static long getCount(int pos, int count, int isTight, long[][][] dp, String no) {
    // Guard clauses – early exits for simple cases
    if (count > 3) {
        return 0;
    }
    if (pos == no.length()) {
        return 1;
    }
    if (dp[pos][count][isTight] != -1) {
        return dp[pos][count][isTight];
    }

    long ans = 0;
    int upperBound = computeUpperBound(isTight, pos, no);

    for (int digit = 0; digit <= upperBound; digit++) {
        ans += accumulateForDigit(pos, count, isTight, digit, upperBound, dp, no);
    }

    return dp[pos][count][isTight] = ans;
}

/** Returns the maximum digit allowed at the current position. */
private static int computeUpperBound(int isTight, int pos, String no) {
    return (isTight == 1) ? (no.charAt(pos) - '0') : 9;
}

/** Performs the recursive step for a single digit choice. */
private static long accumulateForDigit(int pos, int count, int isTight,
                                      int digit, int upperBound,
                                      long[][][] dp, String no) {
    int flag = (digit != 0) ? 1 : 0;
    int nextTight = (isTight == 1 && digit == upperBound) ? 1 : 0;
    return getCount(pos + 1, count + flag, nextTight, dp, no);
