    // Guard clause for impossible case
    if (impossible(n, k)) {
        return "No such line.";
    }

    List<Integer> alive = initAlive(n);
    long left = k;
    StringBuilder ret = new StringBuilder();

    for (int len = 1; len <= n; len++) {
        // 1️⃣ Find the smallest character that makes the remaining rank ≤ left
        char chosen = findCharForLen(s, alive, len, left);
        ret.append(chosen);

        // 2️⃣ Build the list of positions that stay alive after fixing this character
        List<Integer> next = collectNext(s, alive, len, chosen);

        // 3️⃣ How many strings are skipped by all characters smaller than ‘chosen’?
        long skipped = add(s, alive, len, (char) (chosen - 1));
        left -= skipped;

        // Guard clause – the answer is completely built
        if (left <= next.size()) {
            return ret;
        }
        left -= next.size();

        // 4️⃣ Continue with the narrowed set of alive positions
        alive = next;
    }
    return null;
}

/* ----- extracted helpers ------------------------------------------------- */

private List<Integer> initAlive(int n) {
    List<Integer> list = new ArrayList<>(n);
    for (int i = 0; i < n; i++) {
        list.add(i);
    }
    return list;
}

/** Binary‑search the character for the current length that reaches the rank `left`. */
private char findCharForLen(String s, List<Integer> alive, int len, long left) {
    char lo = (char) ('a' - 1);
    char hi = 'z';
    while (lo + 1 < hi) {
        int mid = (lo + hi) / 2;
        long cnt = add(s, alive, len, (char) mid);
        if (cnt < left) {
            lo = (char) mid;
        } else {
            hi = (char) mid;
        }
    }
    return hi;               // the smallest character that reaches or exceeds `left`
}

/** Collect positions that stay alive when the character at `len`‑th place is `c`. */
private List<Integer> collectNext(String s, List<Integer> alive, int len, char c) {
    List<Integer> next = new ArrayList<>();
    int n = s.length();
    for (int pos : alive) {
        if (pos + len <= n && s.charAt(pos + len - 1) == c) {
            next.add(pos);
        }
    }
    return next;
}

