private static void initialiseBoundaries(int[] a, int n) {
    a[0] = -(int) 2e9;
    a[n + 1] = -a[0];
}

/** Reads the n input numbers and initialises l[i] and r[i] to 1. */
private static void readSequence(int[] a, int[] l, int[] r, int n) throws IOException {
    for (int i = 1; i <= n; i++) {
        a[i] = nextInt();
        l[i] = 1;
        r[i] = 1;
    }
    // the extra cells are never used in the algorithm but keeping them zeroed
    // makes the later loops easier to read
    l[0] = r[0] = l[n + 1] = r[n + 1] = 0;
}

/** l[i] = length of the longest increasing prefix ending at i. */
private static void computeLeftLengths(int[] a, int[] l, int n) {
    for (int i = 1; i <= n; i++) {
        if (a[i] > a[i - 1]) {
            l[i] = l[i - 1] + 1;
        }
    }
}

/** r[i] = length of the longest increasing suffix starting at i. */
private static void computeRightLengths(int[] a, int[] r, int n) {
    for (int i = n; i >= 1; i--) {
        if (a[i + 1] > a[i]) {
            r[i] = r[i + 1] + 1;
        }
    }
}

/** Evaluates all candidates for the answer and returns the maximum length. */
private static int computeMaximumLength(int[] a, int[] l, int[] r, int n) {
    int max = 1;   // at least one element can always be taken

    // 1) Remove the element a[i] and concatenate the left and right runs
    for (int i = 1; i <= n; i++) {
        // case a[i] fits strictly between its neighbours
        if (a[i] > a[i - 1] && a[i] < a[i + 1]) {
            int candidate = l[i - 1] + r[i + 1] + 1;
            if (candidate > max) {
                max = candidate;
            }
            continue;   // guard clause – the other condition cannot improve this i
        }

        // case we can delete a[i] because the gap between neighbours is > 1
        if (a[i + 1] > a[i - 1] + 1) {
            int candidate = l[i - 1] + r[i + 1] + 1;
            if (candidate > max) {
                max = candidate;
            }
        }
    }

    // 2) Extend a left run by changing the element just after it
    for (int i = 2; i <= n; i++) {
        int candidate = l[i - 1] + 1;
        if (candidate > max) {
            max = candidate;
        }
    }

    // 3) Extend a right run by changing the element just before it
    for (int i = 1; i <= n - 1; i++) {
        int candidate = r[i + 1] + 1;
        if (candidate > max) {
            max = candidate;
        }
    }

    return max;
}

