            a = lift[a][i];
            b = lift[b][i];
        }
    }

    // The parent of 'a' (or 'b') is the lowest common ancestor
    return ps[a];
}

/**
 * Returns the greatest integer k such that 2^k <= n.
 */
private static int highestPowerOfTwo(int n) {
    int log = 0;
    while ((1 << (log + 1)) <= n) {
        log++;
    }
    return log;
}

/**
 * Moves {@code node} upwards in the binary‑lifting table until it reaches {@code targetDepth}.
 */
private static int liftNodeToDepth(int node, int targetDepth, int[][] lift, int[] depths) {
    int log = highestPowerOfTwo(depths[node]);
    for (int i = log; i >= 0; i--) {
        if (depths[node] - (1 << i) >= targetDepth) {
            node = lift[node][i];
        }
    }
    return node;
}

static int lca(int a, int b, int[][] lift, int[] depths, int[] ps) {
    // Guard clause: make sure 'a' is the deeper (or equal) node.
    int[] ordered = ensureDeeperFirst(a, b, depths);
    a = ordered[0];
    b = ordered[1];

    int log = maxLog(depths[a]);

    // Lift 'a' up until both nodes are on the same depth.
    a = liftNodeByDepthDifference(a, depths[a] - depths[b], lift, log);
    if (a == b) {
        return a; // Guard clause – LCA found after depth alignment.
    }

    // Lift both nodes together while their ancestors differ.
    int[] lifted = liftUntilParentsDiffer(a, b, lift, log);
    a = lifted[0]; // 'b' is no longer needed after this point.

    return ps[a];
}

/** Swaps the two node indices if `a` is shallower than `b`. Returns an array {a, b}. */
private static int[] ensureDeeperFirst(int a, int b, int[] depths) {
    if (depths[a] < depths[b]) {
        int tmp = a;
        a = b;
        b = tmp;
    }
    return new int[]{a, b};
}

/** Returns the largest integer `log` such that (1 << log) ≤ `depth`. */
private static int maxLog(int depth) {
    int log = 0;
    while ((1 << (log + 1)) <= depth) {
        log++;
    }
    return log;
}

/** Lifts `node` upward by `diff` levels using the binary‑lifting table. */
private static int liftNodeByDepthDifference(int node, int diff, int[][] lift, int maxLog) {
    for (int i = maxLog; i >= 0; i--) {
        if ((diff & (1 << i)) != 0) {
            node = lift[node][i];
        }
    }
    return node;
}

/** Simultaneously lifts `a` and `b` while their ancestors at the same power differ. */
private static int[] liftUntilParentsDiffer(int a, int b, int[][] lift, int maxLog) {
    for (int i = maxLog; i >= 0; i--) {
        if (lift[a][i] != -1 && lift[a][i] != lift[b][i]) {
            a = lift[a][i];
            b = lift[b][i];
        }
    }
    return new int[]{a, b};
}

