            end[i]    = new int[] { p - t, w, p };
        }
    }
}

/** Sorts `origin` using the same ordering rules as the original comparator. */
private static void sortOrigin(int[][] origin) {
    Arrays.sort(origin, (a, b) -> {
        int sumA = a[1] + a[2];
        int sumB = b[1] + b[2];
        if (sumA != sumB) {
            return Integer.compare(sumA, sumB);
        }
        int diffA = a[1] - a[2];
        int diffB = b[1] - b[2];
        return Integer.compare(diffA, diffB);
    });
}

/** Sorts `end` using the same ordering rules as the original comparator. */
private static void sortEnd(int[][] end) {
    Arrays.sort(end, (a, b) -> {
        if (a[0] != b[0]) {
            return Integer.compare(a[0], b[0]);
        }
        int diffA = a[1] - a[2];
        int diffB = b[1] - b[2];
        return Integer.compare(diffA, diffB);
    });
}

/** Re‑orders the sorted `end` data back to the original input order. */
private static int[][] mapToOriginalOrder(int[][] origin, int[][] end) {
    int n = origin.length;
    int[][] result = new int[n][2];
    for (int i = 0; i < n; i++) {
        int originalIndex = origin[i][0];
        result[originalIndex] = new int[] { end[i][1], end[i][2] };
    }
    return result;
}

