/**
 * Consumes consecutive non‑digit bytes and returns the last non‑numeric
 * byte encountered (or NOT_SET if none were found before a digit).
 */
private int readSignByte() throws IOException {
    int signByte = NOT_SET;
    while (!isDigit(buff[buffPtr])) {
        signByte = buff[buffPtr];
        advancePointer();
    }
    return signByte;
}

/**
 * Moves the buffer pointer forward, updating the underlying buffer
 * when necessary and checking for EOF after the move.
 */
private void advancePointer() throws IOException {
    buffPtr++;
    if (buffPtr >= buff.length) {
        updateBuff();
    }
    ensureNotEOF();
}

