private static void soln() {
    int n = nextInt();
    char[] arr = nextLine().toCharArray();

    int maxLength = 0;      // longest run of characters outside '(' … ')'
    int currentLen = 0;     // length of the run we are currently scanning
    int words = 0;          // number of runs that appear inside parentheses
    boolean insideParen = false;   // true while we are between '(' and ')'

    for (int i = 0; i < n; i++) {
        char c = arr[i];

        // ----- '_' ends the current run ----------------------------------
        if (c == '_') {
            if (insideParen) {
                words = countWordIfInside(words, currentLen);
            } else {
                maxLength = updateMaxLength(maxLength, currentLen);
            }
            currentLen = 0;
            continue;                     // guard clause – next iteration
        }

        // ----- '(' starts a parenthesised region -------------------------
        if (c == '(') {
            // the run that just ended is outside parentheses
            maxLength = updateMaxLength(maxLength, currentLen);
            currentLen = 0;
            insideParen = true;
            continue;
        }

        // ----- ')' ends a parenthesised region ---------------------------
        if (c == ')') {
            // the run that just ended is inside parentheses
            words = countWordIfInside(words, currentLen);
            currentLen = 0;
            insideParen = false;
            continue;
        }

        // ----- regular character – extend the current run ----------------
        currentLen++;
    }

    // Handle possible trailing run after the loop
    maxLength = updateMaxLength(maxLength, currentLen);

    pw.println(maxLength + " " + words);
}

/** Returns the larger of the two lengths. */
private static int updateMaxLength(int currentMax, int candidate) {
    return (candidate > currentMax) ? candidate : currentMax;
}

/** Increments the word counter when a non‑empty run finishes inside parentheses. */
private static int countWordIfInside(int words, int length) {
    return (length > 0) ? words + 1 : words;
}

