/**
 * Core algorithm: starting from the first element of the permutation,
 * keep two candidate strings {@code hand1} and {@code hand2}. For each
 * subsequent entry we try to replace them with larger strings.
 * Returns {@code true} if the process can finish without both hands
 * becoming {@code null}.
 */
private boolean isPossible(String[][] name, int[] pmt, int n) {
    String hand1 = name[pmt[0]][0];
    String hand2 = name[pmt[0]][1];

    for (int i = 1; i < n; i++) {
        String candidate1 = null;
        String candidate2 = null;

        // try to upgrade the first hand
        if (name[pmt[i]][0].compareTo(hand1) > 0 ||
            name[pmt[i]][0].compareTo(hand2) > 0) {
            candidate1 = name[pmt[i]][0];
        }

        // try to upgrade the second hand
        if (name[pmt[i]][1].compareTo(hand1) > 0 ||
            name[pmt[i]][1].compareTo(hand2) > 0) {
            candidate2 = name[pmt[i]][1];
        }

        // move to next state
        hand1 = candidate1;
        hand2 = candidate2;

        // guard‑clauses for early termination / normalization
        if (hand1 == null && hand2 == null) {
            return false;                     // NO
        }
        if (hand1 != null && hand2 == null) {
            hand2 = hand1;                     // duplicate the only non‑null hand
        } else if (hand1 == null && hand2 != null) {
            hand1 = hand2;
        }
    }
    return true; // YES
}

public void solve() {
    // read number of entries
    String ip = sc.nextLine();
    String[] tok = ip.split("[ ]+");
    int n = lineToInt(tok[0]);

    final int N_MAX = 100000;
    String[][] name = new String[N_MAX][2];
    int[] pmt = new int[N_MAX];

    // read names
    for (int i = 0; i < n; i++) {
        ip = sc.nextLine();
        tok = ip.split("[ ]+");
        name[i][0] = tok[0];
        name[i][1] = tok[1];
    }

    // read permutation (1‑based in input, convert to 0‑based)
    ip = sc.nextLine();
    tok = ip.split("[ ]+");
    for (int i = 0; i < n; i++) {
        pmt[i] = lineToInt(tok[i]) - 1;
    }

    // initialise hands with the first selected pair
    String[] hands = new String[] {
        name[pmt[0]][0],
        name[pmt[0]][1]
    };

    // process remaining pairs
    for (int i = 1; i < n; i++) {
        if (!updateHands(i, pmt, name, hands)) {
            out.print("NO");
            out.flush();
            return;
        }
    }

    out.print("YES");
    out.flush();
}

/**
 * Updates the current pair of hands based on the i‑th entry.
 *
 * @param idx   index in the permutation array (must be ≥ 1)
 * @param pmt   permutation array (0‑based)
 * @param name  matrix of name pairs
 * @param hands mutable two‑element array holding the current hands;
 *              on return it contains the updated pair.
 * @return {@code true} if at least one hand remains, {@code false}
 *         if both candidates are {@code null} (meaning the answer is NO).
 */
private boolean updateHands(int idx, int[] pmt, String[][] name, String[] hands) {
    String candidate0 = name[pmt[idx]][0];
    String candidate1 = name[pmt[idx]][1];

    String newHand0 = null;
    String newHand1 = null;

    // guard clauses – select a candidate only if it is greater than either current hand
    if (candidate0.compareTo(hands[0]) > 0 || candidate0.compareTo(hands[1]) > 0) {
        newHand0 = candidate0;
    }
    if (candidate1.compareTo(hands[0]) > 0 || candidate1.compareTo(hands[1]) > 0) {
        newHand1 = candidate1;
    }

    hands[0] = newHand0;
    hands[1] = newHand1;

    // both null → impossible situation
    if (hands[0] == null && hands[1] == null) {
        return false; // guard clause, caller will output "NO"
    }

    // normalise: if one side is null, copy the non‑null value
    if (hands[0] == null) {
        hands[0] = hands[1];
    } else if (hands[1] == null) {
        hands[1] = hands[0];
    }

    return true;
}

