/** Finds all pairs of vertices that are currently in different components in
 *  *both* Union‑Find structures, unions them, and returns the list of added edges. */
private static List<int[]> collectNewEdges(int n, int[] parent1, int[] parent2) {
    List<int[]> result = new ArrayList<>(n * n);
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            // Guard clause – skip if already connected in either graph
            if (find(parent1, i) == find(parent1, j) ||
