public int nextInt() {
    // Guard clause – fail fast if there is no next token
    ensureHasNext();

    // Read the first byte and skip any leading whitespace
    int c = skipSpaces(readByte());

    // Handle optional sign
    boolean minus = isMinus(c);
    if (minus) {
        c = readByte(); // advance past the '-'
    }

    // Parse the unsigned integer part
    int result = readUnsignedInt(c);

    // Apply sign if necessary
    return minus ? -result : result;
}

// -------------------------------------------------------------------
// Helper methods – each encapsulates a single responsibility
// -------------------------------------------------------------------
private void ensureHasNext() {
    if (!hasNext()) {
        throw new NoSuchElementException();
    }
}

private int skipSpaces(int c) {
    while (isSpaceChar(c)) {
        c = readByte();
    }
    return c;
}

private boolean isMinus(int c) {
    return c == '-';
}

/**
 * Reads consecutive digit characters starting with {@code c},
 * builds the integer value and stops when a space character is encountered.
 * Throws {@link InputMismatchException} if a non‑digit is found.
 */
private int readUnsignedInt(int c) {
    int res = 0;
    while (true) {
        if (c < '0' || c > '9') {
            throw new InputMismatchException();
        }
        res = res * 10 + (c - '0');
        c = readByte();
        if (isSpaceChar(c)) {
            break;
        }
    }
    return res;
}

