public int calc(boolean cur, int bit) {
    int res = 0;
    for (int j = 0; j < n; j++) {
        String v = vars[j];
        Exp e = all.get(v);

        // Guard clause: handle constant bit strings early
        if (e.x != null) {
            value[j] = e.x[bit] == '1';
            continue;
        }

        // Evaluate the expression defined by e
        boolean result = evaluate(e, cur);

        if (result) {
            res++;
        }
        value[e.id] = result;
    }
    return res;
}

/**
 * Computes the Boolean result of the expression described by {@code e}
 * using the current input bit {@code cur}.
 */
private boolean evaluate(Exp e, boolean cur) {
    boolean v1 = operandValue(e.v1, cur);
    boolean v2 = operandValue(e.v2, cur);

    switch (e.op) {
        case 1: // AND
            return v1 && v2;
        case 2: // OR
            return v1 || v2;
        case 3: // XOR
            return v1 ^ v2;
        default:
            // Preserve original behaviour (treated as false)
            return false;
    }
}

/**
 * Resolves the Boolean value of a variable reference.
 * If the reference starts with '?' it represents the current input bit,
 * otherwise it looks up the previously computed value.
 */
private boolean operandValue(String var, boolean cur) {
    if (var.charAt(0) == '?') {
        return cur;
    }
    return value[all.get(var).id];
}

