/** Returns true if the character's alphabetical index (a=1, b=2, …) does not exceed k. */
private boolean isCharValid(char ch) {
    int value = ch - 'a' + 1;
    return value <= k;
}

/** Returns true if the two characters are a wildcard pair or are exactly equal. */
private boolean isMatchOrWildcard(char left, char right) {
    return left == '?' || right == '?' || left == right;
