boolean valid() {
    int i = 0;
    int j = a.length - 1;
    while (i <= j) {
        // Guard: characters must be within the allowed range
        if (!isWithinLimit(a[i]) || !isWithinLimit(a[j])) {
            return false;
        }

        // Guard: the mirrored pair must match or contain a wildcard
        if (!areMirroredCharsAcceptable(a[i], a[j])) {
            return false;
        }

        // Both checks passed – advance towards the centre
        i++;
        j--;
    }
    return true;
}

/** Returns true if the character’s alphabetic rank (a→1, b→2, …) does not exceed k. */
private boolean isWithinLimit(char ch) {
    int rank = ch - 'a' + 1;
    return rank <= k;
}

/**
 * Returns true when the two characters are compatible for a palindrome:
 * – either side is a wildcard '?'  OR
 * – the characters are identical.
 */
private boolean areMirroredCharsAcceptable(char left, char right) {
    return left == '?' || right == '?' || left == right;
}

