    return arr;
}

/** Sorts the index array so that indices appear in ascending order of left[i]. */
private static void sortByLeft(Integer[] indices, final int[] left) {
    Arrays.sort(indices, (a, b) -> Integer.compare(left[a], left[b]));
}

/** Sorts the index array so that indices appear in ascending order of right[i]. */
private static void sortByRight(Integer[] indices, final int[] right) {
    Arrays.sort(indices, (a, b) -> Integer.compare(right[a], right[b]));
}

/**
 * Core algorithm – walks the intervals sorted by left border,
 * maintains a map of the cheapest cost for each duration that has already ended,
 * and tries to combine the current interval with a previously‑ended one
 * to reach the required total length.
 *
 * @return the minimal combined cost, or {@code Integer.MAX_VALUE} if impossible.
 */
private static int findMinimumCost(
        int[] left, int[] right, int[] cost,
        Integer[] byLeft, Integer[] byRight,
        int requiredLength) {

    TreeMap<Integer, Integer> bestCostByDuration = new TreeMap<>();
    int rightPtr = 0;                     // index in byRight that we have already processed
    int bestTotalCost = Integer.MAX_VALUE;

    for (int idx : byLeft) {
        int curLeft = left[idx];

        // Move right‑pointer forward while intervals end before the current left border
        while (right[byRight[rightPtr]] < curLeft) {
            int finishedIdx = byRight[rightPtr++];
            int duration = right[finishedIdx] - left[finishedIdx] + 1;
            int c = cost[finishedIdx];

            // keep the cheapest cost for this exact duration
            bestCostByDuration.merge(duration, c, Math::min);
        }

        int curDuration = right[idx] - left[idx] + 1;
        Integer complementCost = bestCostByDuration.get(requiredLength - curDuration);

        if (complementCost != null) {
            int total = complementCost + cost[idx];
            if (total < bestTotalCost) {
                bestTotalCost = total;
            }
        }
    }

    return bestTotalCost;
}

