private static class InputData {
    final int[] left;
    final int[] right;
    final int[] cost;
    final int req;

    InputData(int[] left, int[] right, int[] cost, int req) {
        this.left = left;
        this.right = right;
        this.cost = cost;
        this.req = req;
    }
}

/*--------------- step 1: read all data ----------------*/
private static InputData readInput(BufferedReader reader) throws IOException {
    StringTokenizer st = new StringTokenizer(reader.readLine());
    int n = Integer.parseInt(st.nextToken());
    int req = Integer.parseInt(st.nextToken());

    int[] left = new int[n];
    int[] right = new int[n];
    int[] cost = new int[n];

    for (int i = 0; i < n; i++) {
        st = new StringTokenizer(reader.readLine());
        left[i] = Integer.parseInt(st.nextToken());
        right[i] = Integer.parseInt(st.nextToken());
        cost[i] = Integer.parseInt(st.nextToken());
    }
    return new InputData(left, right, cost, req);
}

/*--------------- step 2: core algorithm ----------------*/
private static int computeMinimumCost(int[] left, int[] right, int[] cost, int req) {
    Integer[] byLeft = buildIndexArray(left.length);
    Integer[] byRight = buildIndexArray(right.length);

    sortByLeft(byLeft, left);
    sortByRight(byRight, right);

    TreeMap<Integer, Integer> minCostByDuration = new TreeMap<>();
    int nextRightIdx = 0;
    int best = Integer.MAX_VALUE;

    for (int idx : byLeft) {
        int currentLeft = left[idx];

        // remove intervals that end before the current left border
        nextRightIdx = evictExpiredIntervals(
                minCostByDuration, left, right, cost, byRight, nextRightIdx, currentLeft);

        // try to complement the current interval
        int needed = req - (right[idx] - left[idx] + 1);
        Integer complementCost = minCostByDuration.get(needed);
        if (complementCost != null) {
            int candidate = complementCost + cost[idx];
            if (candidate < best) {
                best = candidate;
            }
        }
    }
    return best == Integer.MAX_VALUE ? -1 : best;
}

/*--------------- step 3: utility methods ----------------*/
private static Integer[] buildIndexArray(int size) {
    Integer[] arr = new Integer[size];
    for (int i = 0; i < size; i++) {
        arr[i] = i;
    }
    return arr;
}

private static void sortByLeft(Integer[] indices, int[] left) {
    Arrays.sort(indices, (a, b) -> Integer.compare(left[a], left[b]));
}

private static void sortByRight(Integer[] indices, int[] right) {
    Arrays.sort(indices, (a, b) -> Integer.compare(right[a], right[b]));
}

/*--------------- step 4: guard‑clause style helper ----------------*/
private static int evictExpiredIntervals(
        TreeMap<Integer, Integer> map,
        int[] left, int[] right, int[] cost,
        Integer[] byRight, int startIdx, int currentLeft) {

    int i = startIdx;
    while (i < byRight.length && right[byRight[i]] < currentLeft) {
        int idx = byRight[i];
        int duration = right[idx] - left[idx] + 1;
        int c = cost[idx];
        map.merge(duration, c, Math::min); // keep the cheaper cost for this duration
        i++;
    }
    return i;
}

