public void solve(int testNumber, Scanner in, PrintWriter out) {
    String me = in.nextLine();
    int n = Integer.parseInt(in.nextLine());
    HashMap<String, Integer> points = new HashMap<>();

    for (int i = 0; i < n; ++i) {
        Action action = parseAction(in.nextLine());

        ensurePlayer(points, action.first);
        ensurePlayer(points, action.second);

        if (!involvesMe(action.first, action.second, me)) {
            continue;               // guard clause – skip lines unrelated to me
        }

        addPoints(points, action.first, action.delta);
        addPoints(points, action.second, action.delta);
    }

    ArrayList<Person> people = new ArrayList<>();
    for (String name : points.keySet()) {
        if (!name.equals(me)) {
            people.add(new Person(name, points.get(name)));
        }
    }
    Collections.sort(people);
    for (Person person : people) {
        out.println(person.name);
    }
}

/* ----------- helper methods and tiny data holder ----------- */

private static class Action {
    final String first;
    final String second;
    final int delta;

    Action(String first, String second, int delta) {
        this.first = first;
        this.second = second;
        this.delta = delta;
    }
}

/** Parses a raw input line into its participants and the points to award. */
private Action parseAction(String line) {
    String[] tokens = line.split(" ");

    String first = tokens[0];
    // the second name is the token before the last one (the last token is something like "p.")
    String second = tokens[tokens.length - 2];
    // strip the trailing punctuation (e.g., "Bob:" -> "Bob")
    second = second.substring(0, second.length() - 2);

    char actionChar = tokens[1].charAt(0);
    int delta;
    switch (actionChar) {
        case 'p': delta = 15; break;
        case 'c': delta = 10; break;
        case 'l': delta = 5;  break;
        default:  delta = 0;  // defensive – should never happen with valid input
    }
    return new Action(first, second, delta);
}

/** Ensures that the map contains an entry for the given player. */
private void ensurePlayer(Map<String, Integer> points, String name) {
    points.putIfAbsent(name, 0);
}

/** Returns true if either participant is the player identified by *me*. */
private boolean involvesMe(String first, String second, String me) {
    return first.equals(me) || second.equals(me);
}

/** Adds *delta* points to the given player in the map. */
private void addPoints(Map<String, Integer> points, String name, int delta) {
    points.put(name, points.get(name) + delta);
}

