/* ---------- helper methods ---------- */

private static long[] readArray(FastReader in, int size) {
    long[] a = new long[size];
    for (int i = 0; i < size; i++) {
        a[i] = in.nextLong();
    }
    return a;
}

private static long[] buildPrefixSum(long[] k) {
    long[] psum = new long[k.length];
    psum[0] = k[0];
    for (int i = 1; i < k.length; i++) {
        psum[i] = psum[i - 1] + k[i];
    }
    return psum;
}

/**
 * Updates the first {@code it} elements using the prefix sums.
 */
private static void applyFrontUpdates(long[] arr, long[] psum, int mod, int it) {
    for (int i = 0; i < it; i++) {
        arr[i] = ((arr[i] % mod) + (psum[i] % mod)) % mod;
    }
}

/**
 * Updates the last {@code it} elements using the suffix view of the prefix sums.
 */
private static void applyRearUpdates(long[] arr, long[] psum, int mod,
                                    int n, int m, int it) {
    for (int i = 0; i < it; i++) {
        int revIdx = n - 1 - i;                     // index from the right side
        int offset = m - 1 - i - 1;                 // (m‑1‑i‑1) in the original code
        long sub = (offset < 0) ? 0 : psum[offset];
        long addition = (psum[m - 1] - sub) % mod;
        arr[revIdx] = ((arr[revIdx] % mod) + addition) % mod;
    }
}

/**
 * Handles the remaining middle positions.
 * The logic differs when {@code it == m}; we treat that case up‑front
 * (guard clause) and otherwise use the sliding window defined by {@code id}.
 */
private static void applyMiddleUpdates(long[] arr, long[] psum, int mod,
                                       int n, int m, int steps, int it) {
    // Guard clause: when it equals m the whole middle region receives the same addition.
    if (it == m) {
        long addition = psum[m - 1] % mod;
        for (int i = n - it - 1; i >= it; i--) {
            arr[i] = ((arr[i] % mod) + addition) % mod;
        }
        return;
    }

    // General case – sliding window using id.
    int id = m - 2;                     // start index for the window
    for (int i = n - it - 1; i >= it; i--) {
        long windowSum = (psum[id] - psum[id - steps]) % mod;
        arr[i] = ((arr[i] % mod) + windowSum) % mod;
        id--;
    }
}

