/** builds prefix sums: psum[i] = Σ_{j=0..i} k[j] */
private static long[] computePrefixSum(long[] k) {
    long[] psum = new long[k.length];
    if (k.length == 0) {
        return psum;
    }
    psum[0] = k[0];
    for (int i = 1; i < k.length; i++) {
        psum[i] = psum[i - 1] + k[i];
    }
    return psum;
}

/** first part: update the first 'limit' elements */
private static void addPrefixSumToFirstElements(long[] arr, long[] psum,
                                                int limit, int mod) {
    for (int i = 0; i < limit; i++) {
        arr[i] = (arr[i] % mod + psum[i] % mod) % mod;
    }
}

/** second part: update the last 'limit' elements */
private static void addPrefixSumToLastElements(long[] arr, long[] psum,
                                               int limit, int n, int mod) {
    for (int i = 0; i < limit; i++) {
        int idx = n - 1 - i;
        long sub = (limit - i - 2 < 0) ? 0 : psum[limit - i - 2];
        long add = (psum[psum.length - 1] - sub) % mod;
        arr[idx] = (arr[idx] % mod + add) % mod;
    }
}

/** third part: update the middle range */
private static void addMiddleElements(long[] arr, long[] psum,
                                      int n, int m, int steps,
                                      int it, int mod) {
    // Guard clause for the special case where the whole pattern fits exactly
    if (it == m) {
        long add = psum[m - 1] % mod;
        for (int i = n - it - 1; i >= it; i--) {
            arr[i] = (arr[i] % mod + add) % mod;
        }
        return;
    }

    int id = m - 2;
    for (int i = n - it - 1; i >= it; i--) {
        long add = (psum[id] - psum[id - steps]) % mod;
        arr[i] = (arr[i] % mod + add) % mod;
        id--;
    }
}

