    int m = k.length;
    long[] psum = new long[m];
    psum[0] = k[0];
    for (int i = 1; i < m; i++) {
        psum[i] = psum[i - 1] + k[i];
    }
    return psum;
}

/* first “it” positions */
private static void applyFrontUpdates(long[] arr, long[] psum, int it, int c) {
    for (int i = 0; i < it; i++) {
        arr[i] = (arr[i] % c + psum[i] % c) % c;
    }
}

/* last “it” positions */
private static void applyBackUpdates(long[] arr, long[] psum,
                                     int n, int m, int it, int c) {
    for (int i = 0; i < it; i++) {
        int idx          = n - 1 - i;               // position in arr
        int psumIdx      = m - 2 - i;               // index used in psum
        long leftSum = (psumIdx >= 0) ? psum[psumIdx] : 0L;
        long add = (psum[m - 1] - leftSum) % c;
        arr[idx] = (arr[idx] % c + add) % c;
    }
}

/* middle segment */
private static void applyMiddleUpdates(long[] arr, long[] psum,
                                       int n, int m, int steps,
                                       int it, int c) {
    int id = m - 2;                                 // start index for psum
    for (int i = n - it - 1; i >= it; i--) {
        if (it == m) {
            arr[i] = (arr[i] % c + psum[m - 1] % c) % c;
        } else {
            long diff = (psum[id] - psum[id - steps]) % c;
            arr[i] = (arr[i] % c + diff) % c;
            id--;
        }
    }
}

