        menuplan[a - 1] = sc.nextInt();
    }

    // initialise day 0
    initializeFirstDay(pasta, menuplan[0]);

    // process remaining days
    for (int i = 1; i < n; i++) {
        processDay(i, pasta, menuplan);
    }

    // compute and output result
    int pattern = computePattern(pasta, n - 1);
    System.out.println(pattern);
}

/**
 * Sets the values for day 0 according to the first menu plan entry.
 */
private static void initializeFirstDay(int[][] pasta, int plan) {
    if (plan == 0) {
        pasta[0][1] = 1;
        pasta[0][3] = 1;
        pasta[0][5] = 1;
        return;
    }
    if (plan == 1) {
        pasta[0][1] = 1;
        return;
    }
    if (plan == 2) {
        pasta[0][3] = 1;
        return;
    }
    // plan == 3
    pasta[0][5] = 1;
}

/**
 * Updates row {@code day} of {@code pasta} based on the menu plan for that day.
 * Each branch is isolated with a guard‑clause (early return) to avoid deep nesting.
 */
private static void processDay(int day, int[][] pasta, int[] menuplan) {
    int prev = day - 1;
    int plan = menuplan[day];
    final int MOD = 10000;

    if (plan == 0) {
        pasta[day][0] = pasta[prev][1] % MOD;
        pasta[day][2] = pasta[prev][3] % MOD;
        pasta[day][4] = pasta[prev][5] % MOD;
        pasta[day][1] = (pasta[prev][2] + pasta[prev][3] + pasta[prev][4] + pasta[prev][5]) % MOD;
        pasta[day][3] = (pasta[prev][0] + pasta[prev][1] + pasta[prev][4] + pasta[prev][5]) % MOD;
        pasta[day][5] = (pasta[prev][0] + pasta[prev][1] + pasta[prev][2] + pasta[prev][3]) % MOD;
        return;
    }

    if (plan == 1) {
        pasta[day][0] = pasta[prev][1] % MOD;
        pasta[day][1] = (pasta[prev][2] + pasta[prev][3] + pasta[prev][4] + pasta[prev][5]) % MOD;
        return;
    }

    if (plan == 2) {
        pasta[day][2] = pasta[prev][3] % MOD;
        pasta[day][3] = (pasta[prev][0] + pasta[prev][1] + pasta[prev][4] + pasta[prev][5]) % MOD;
        return;
    }

    // plan == 3
    pasta[day][4] = pasta[prev][5] % MOD;
    pasta[day][5] = (pasta[prev][0] + pasta[prev][1] + pasta[prev][2] + pasta[prev][3]) % MOD;
}

/**
 * Sums the six values of the last processed row and returns the result modulo 10000.
 */
private static int computePattern(int[][] pasta, int lastIndex) {
    int sum = 0;
    for (int i = 0; i < 6; i++) {
        sum += pasta[lastIndex][i];
    }
    return sum % 10000;
}

