public static void main(String[] args) throws IOException {
    try (Scanner sc = new Scanner(System.in)) {
        int N = sc.nextInt();
        int K = sc.nextInt();

        int[] as = new int[N];
        for (int i = 0; i < N; i++) {
            as[i] = sc.nextInt();
        }

        int[] imos = new int[N + 1];
        for (int step = 0; step < K; step++) {
            Arrays.fill(imos, 0);

            // guard clause – stop early when every element already covers the whole array
            if (allElementsAtLeast(as, N)) {
                break;
            }

            applyPropagation(as, imos);
        }

        printArray(as);
    }
}

/**
 * Returns true if every element in {@code arr} is greater than or equal to {@code threshold}.
 */
private static boolean allElementsAtLeast(int[] arr, int threshold) {
    for (int value : arr) {
        if (value < threshold) {
            return false;
        }
    }
    return true;
}

/**
 * Executes one “infection” step:
 *   – builds the difference array {@code imos},
 *   – transforms it into a prefix‑sum,
 *   – writes the result back into {@code as}.
 */
private static void applyPropagation(int[] as, int[] imos) {
    int N = as.length;
    for (int i = 0; i < N; i++) {
        int lower = Math.max(0, i - as[i]);
        int upper = Math.min(N - 1, i + as[i]);

        imos[lower] += 1;
        imos[upper + 1] -= 1;
    }

    // prefix sum over the difference array
    for (int i = 0; i < N; i++) {
        imos[i + 1] += imos[i];
    }

    // copy back to the original array
    for (int i = 0; i < N; i++) {
        as[i] = imos[i];
    }
}

