/* ---------- Step 2: sliding‑window logic ---------- */
private static Window findBestWindow(int[] a, int n, int k) {
    int left = 0, right = 0;
    int zeroCount = 0;
    int bestLen = 0, bestStart = -1, bestEnd = -1;

    while (left < n && right < n) {
        // expand window while we have room for more zeros
        while (right < n && zeroCount < k) {
            if (a[right] == 0) zeroCount++;
            right++;
        }
        // skip trailing ones – they belong to the current window
        while (right < n && a[right] == 1) {
            right++;
        }

        // guard clause: update the best window if this one is longer
        if (right - left > bestLen) {
            bestLen = right - left;
            bestStart = left;
            bestEnd = right;
        }

        // shrink window from the left
        if (a[left] == 0) zeroCount--;
        left++;
    }

    // guarantee non‑negative length (handles empty input)
    if (bestLen < 0) bestLen = 0;
    return new Window(bestStart, bestEnd, bestLen);
}

/* ---------- Step 3: build answer array ---------- */
private static int[] buildAnswer(int[] original, Window w) {
    int[] ans = Arrays.copyOf(original, original.length);
    for (int i = w.start; i < w.end; i++) {
        ans[i] = 1;
    }
    return ans;
}

