    }
}

static class Result {
    int maxLen;
    int[] answer;
}

private static Result findLongestSegment(int[] a, int n, int k) {
    // Guard clause for empty array
    if (n == 0) {
        Result empty = new Result();
        empty.maxLen = 0;
        empty.answer = new int[0];
        return empty;
    }

    int s = 0, t = 0, count = 0;
    int max = 0, maxs = -1, maxt = -1;

    while (s < n && t < n) {
        // Expand window while we can still turn zeros into ones
        while (t < n && count < k) {
            if (a[t] == 0) {
                ++count;
            }
            ++t;
        }
        // Skip already‑good ones after the window limit is hit
        while (t < n && a[t] == 1) {
            ++t;
        }
        // Record the best window seen so far
        if (max < t - s) {
            max = t - s;
            maxs = s;
            maxt = t;
        }
        // Shrink window from the left
        if (a[s] == 0) {
            --count;
        }
        ++s;
    }

    // Build the answer array: flip the selected segment to 1s
    int[] ans = Arrays.copyOf(a, n);
    for (int i = maxs; i < maxt; i++) {
        ans[i] = 1;
    }

    Result r = new Result();
    r.maxLen = max;
    r.answer = ans;
    return r;
}

