private static void decideAndPrintTopology(int n, int[] indeg) {
    int countDegree1 = 0;
    int countDegree2 = 0;
    int hasStarCenter = 0;

    for (int i = 1; i <= n; i++) {
        if (indeg[i] == 1) {
            countDegree1++;
        } else if (indeg[i] == 2) {
            countDegree2++;
        } else if (indeg[i] == n - 1) {
            hasStarCenter = 1;
        }
    }

    // Guard‑clauses – each returns early when its condition is satisfied
    if (isBusTopology(n, countDegree1, countDegree2)) {
        System.out.println("bus topology");
        return;
    }
    if (isRingTopology(n, countDegree2)) {
        System.out.println("ring topology");
        return;
    }
    if (isStarTopology(n, hasStarCenter, countDegree1)) {
        System.out.println("star topology");
        return;
    }
    System.out.println("unknown topology");
}

