private static boolean isBusTopology(int n, int cntDeg1, int cntDeg2) {
    return cntDeg1 == 2 && cntDeg2 == n - 2;
}

private static boolean isRingTopology(int n, int cntDeg2) {
    return cntDeg2 == n;
}

private static boolean isStarTopology(int n, int hasCenter, int cntDeg1) {
    return hasCenter == 1 && cntDeg1 == n - 1;
}

