/**
 * Returns a max‑priority queue that orders indices by the corresponding
 * values in {@code values}.  The queue never contains duplicate indices.
 */
private static Queue<Integer> createMaxPriorityQueue(final long[] values) {
    Queue<Integer> pq = new PriorityQueue<>((i1, i2) -> {
        if (values[i1] < values[i2]) return 1;
        if (values[i1] > values[i2]) return -1;
        return i2 - i1;               // deterministic tie‑break
    });
    for (int i = 0; i < values.length; i++) {
        pq.add(i);
    }
    return pq;
