                                        int n, int m, long p) {
    Queue<Integer> prow = createMaxPriorityQueue(row);
    Queue<Integer> pcol = createMaxPriorityQueue(col);

    long[] ansr = new long[k + 1];
    long[] ansc = new long[k + 1];

    for (int i = 1; i <= k; i++) {
        int rr = prow.poll();           // row with current max sum
        int cc = pcol.poll();           // column with current max sum

        long valr = row[rr];
        long valc = col[cc];

        ansr[i] = ansr[i - 1] + valr;
        ansc[i] = ansc[i - 1] + valc;

        // decrease the selected row/column for the next iteration
        row[rr] -= m * p;
        col[cc] -= n * p;

        prow.add(rr);
        pcol.add(cc);
    }

    return new long[][]{ansr, ansc};
}

