private static long computeMaximum(long[] ansr, long[] ansc,
                                   int k, long p) {
    long max = Long.MIN_VALUE;
    for (int i = 0; i <= k; i++) {
        long current = ansr[i] + ansc[k - i] - p * (long) i * (long) (k - i);
        if (current > max) {
            max = current;
        }
    }
    return max;
}

