/* ---------- helper methods ---------- */

private long[][] readAndTransformGrid(int n, int m, int minDiff,
                                      int rows, int cols) throws IOException {
    long[][] grid = new long[rows][cols];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            int value = nextInt();
            int r = i + j;
            int c = i - j - minDiff;
            grid[r][c] = value;
        }
    }
    return grid;
}

private void build2DPrefixSum(long[][] f) {
    int rows = f.length;
    int cols = f[0].length;

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            if (i > 0) {
                f[i][j] += f[i - 1][j];
            }
            if (j > 0) {
                f[i][j] += f[i][j - 1];
            }
            if (i > 0 && j > 0) {
                f[i][j] -= f[i - 1][j - 1];
            }
        }
    }
}

private void buildDiagonalPrefixes(long[][] f,
                                   long[][] mainDiag,
                                   long[][] secDiag) {
    int rows = f.length;
    int cols = f[0].length;

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            mainDiag[i][j] = secDiag[i][j] = f[i][j];

            if (i > 0 && j > 0) {
                mainDiag[i][j] += mainDiag[i - 1][j - 1];
            }
            if (i > 0 && j < cols - 1) {
                secDiag[i][j] += secDiag[i - 1][j + 1];
            }
        }
    }
}

/* holder for the best answer */
private static class Best {
    long value = Long.MIN_VALUE;
