/* search the centre that maximises the required sum */
private Best findBestCenter(int n, int m, int k, int minDiff,
                            long[][] mainDiag, long[][] secDiag) {
    Best best = new Best();

    for (int i = k - 1; i <= n - k; i++) {
        for (int j = k - 1; j <= m - k; j++) {
            int x = i + j;
            int y = i - j - minDiff;

            long cur = get(mainDiag, x + k - 1, y + k - 1)
                     - get(mainDiag, x - k - 1, y - k - 1);

            cur -= get(secDiag, x + k - 1, y - k)
                 - get(secDiag, x - k - 1, y + k);

            if (cur > best.value) {
                best.value = cur;
                best.x = i;
                best.y = j;
            }
        }
    }
    return best;
}

void solve() throws IOException {
    int n = nextInt();
