/* ------------------------------------------------------------------ */
/*  1. Build 2‑D prefix sum over the transformed coordinates            */
/* ------------------------------------------------------------------ */
private static long[][] buildPrefixSum(int n, int m, int rows, int cols, int minDiff)
        throws IOException {
    long[][] f = new long[rows][cols];

    // place original values into transformed matrix
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            int r = i + j;
            int c = i - j - minDiff;
            f[r][c] = nextInt();
        }
    }

    // compute classic 2‑D prefix sum in‑place
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            if (i > 0) f[i][j] += f[i - 1][j];
            if (j > 0) f[i][j] += f[i][j - 1];
            if (i > 0 && j > 0) f[i][j] -= f[i - 1][j - 1];
        }
    }
    return f;
}

/* ------------------------------------------------------------------ */
/*  2. Build prefix sums along the two diagonal directions            */
/* ------------------------------------------------------------------ */
private static void buildDiagonalPrefixes(long[][] f,
                                           long[][] mainDiag,
                                           long[][] secDiag,
                                           int rows, int cols) {
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            mainDiag[i][j] = secDiag[i][j] = f[i][j];

            // main diagonal (↘)
            if (i > 0 && j > 0) {
                mainDiag[i][j] += mainDiag[i - 1][j - 1];
            }
            // secondary diagonal (↙)
            if (i > 0 && j < cols - 1) {
                secDiag[i][j] += secDiag[i - 1][j + 1];
            }
        }
    }
}

/* ------------------------------------------------------------------ */
/*  3. Scan every possible centre, compute the diamond sum and keep   */
/*     the maximum.                                                   */
/* ------------------------------------------------------------------ */
private static Result findBestCenter(int k,
                                     int n, int m,
                                     int minDiff,
                                     long[][] mainDiag,
                                     long[][] secDiag) {
    long bestSum = Long.MIN_VALUE;
    int bestRow = -1;
    int bestCol = -1;

    for (int i = k - 1; i <= n - k; i++) {
        for (int j = k - 1; j <= m - k; j++) {

            int x = i + j;
            int y = i - j - minDiff;

            long cur = get(mainDiag, x + k - 1, y + k - 1)
                     - get(mainDiag, x - k - 1, y - k - 1);

            cur -= get(secDiag, x + k - 1, y - k)
                 - get(secDiag, x - k - 1, y + k);

            if (cur > bestSum) {
                bestSum = cur;
                bestRow = i;
                bestCol = j;
