    a[0] = '(';
    a[n - 1] = ')';

    // 3️⃣ replace every '?' with '(' or ')' according to the remaining quota
    fillQuestionMarks(a, n);

    // 4️⃣ verify that the completed string is a correct parenthesis sequence
    if (!isBalanced(a)) {
        out.println(":(");
    } else {
        out.print(a);
    }

