/**
 * Returns true if the initial quick checks pass:
 * - length must be even,
 * - first character cannot be ')',
 * - last character cannot be '('.
 */
private static boolean isPotentiallyValid(int n, char[] a) {
    return !(n % 2 == 1 || a[0] == ')' || a[n - 1] == '(');
}

/**
 * Fills every '?' in the array.
 * The first half of the string must contain exactly n/2 '('.
 * After accounting for the already fixed '(' we insert the remaining '('
 * left‑to‑right, turning the rest of the '?' into ')'.
 */
private static void fillQuestionMarks(char[] a, int n) {
    int opensNeeded = n / 2;                // total '(' required
    for (int i = 0; i < n; i++) {
        if (a[i] == '(') {
            opensNeeded--;                  // already placed '(' reduce the need
        }
    }
    for (int i = 0; i < n; i++) {
        if (a[i] == '?') {
            if (opensNeeded > 0) {
                a[i] = '(';
                opensNeeded--;
            } else {
                a[i] = ')';
            }
        }
    }
}

/**
 * Checks whether the character array represents a valid parenthesis sequence.
 * Mirrors the original algorithm where a balance counter is increased for '('
 * and decreased for ')', but rejects the string as soon as an invalid state is
 * encountered (guard clause).
 */
private static boolean isBalanced(char[] a) {
    int balance = 0;
    int len = a.length;

    for (int i = 0; i < len; i++) {
        if (a[i] == '(') {
            balance++;
        } else { // ')'
            // Invalid if we would drop below zero **unless** we're at the very last
            // position with exactly one open bracket left (the original special case).
            if ((balance == 1 && i == len - 1) || balance > 1) {
                balance--;
            } else {
                return false; // guard clause – early exit on failure
            }
        }
    }
    return balance == 0;
}

