static long dp(int i, int isequal, int nonzeros) {
    // Guard clauses – early exits
    if (nonzeros > 3) return 0;
    if (i == 19) return 1;
    if (memo[i][isequal][nonzeros] != -1) return memo[i][isequal][nonzeros];

    long cnt = 0;
    int digit = n[i];

    for (int j = 0; j < 10; j++) {
        cnt += nextContribution(i, isequal, nonzeros, j, digit);
    }

    return memo[i][isequal][nonzeros] = cnt;
}

/**
 * Computes the contribution of choosing digit {@code j} at position {@code i}.
 * Returns 0 when the choice would exceed the bound defined by {@code digit}
 * while {@code isequal == 1}.
 */
private static long nextContribution(int i, int isequal, int nonzeros, int j, int digit) {
    int nextNonZeros = (j == 0) ? nonzeros : nonzeros + 1;

    if (isequal == 1) {
        if (j == digit) {
            // Still equal to the prefix of n
            return dp(i + 1, 1, nextNonZeros);
        }
        if (j < digit) {
            // Became strictly less than the prefix of n
            return dp(i + 1, 0, nextNonZeros);
        }
        // j > digit would make the number larger than n → no contribution
        return 0;
    }

    // isequal == 0 → already less than n, any digit is allowed
    return dp(i + 1, 0, nextNonZeros);
}

static long dp(int i, int isequal, int nonzeros) {
    // Guard clauses – fast‑path exits
    if (nonzeros > 3) return 0;
    if (i == 19) return 1;
    if (memo[i][isequal][nonzeros] != -1) return memo[i][isequal][nonzeros];

    long cnt = 0;
    int digit = n[i];

    for (int j = 0; j < 10; j++) {
        cnt += contribution(i, isequal, nonzeros, digit, j);
    }

    return memo[i][isequal][nonzeros] = cnt;
}

/**
 * Returns the contribution of choosing digit {@code j} at position {@code i}.
 * Handles the three logical branches that existed in the original method.
 */
private static long contribution(int i, int isequal, int nonzeros, int digit, int j) {
    int newNonzeros = (j == 0) ? nonzeros : nonzeros + 1;

    if (isequal == 1) {
        if (j == digit) {
            // stays equal to the prefix of n
            return dp(i + 1, 1, newNonzeros);
        }
        if (j < digit) {
            // becomes smaller than n, no longer equal
            return dp(i + 1, 0, newNonzeros);
        }
        // j > digit → invalid branch, contributes nothing
        return 0;
    }

    // isequal == 0: already smaller than n, stay smaller
    return dp(i + 1, 0, newNonzeros);
}

