/** Returns true if the pair satisfies the “better” condition w.r.t. current minima. */
private static boolean isValid(Pair p, int mina, int minb) {
    return p.a > mina && p.b < minb;
}

/** Updates mina/minb when the previous element forces a new minimum. */
private static void updateMinIfNeeded(Pair previous, int[] mins) {
    // mins[0] = mina, mins[1] = minb
    if (previous.b > mins[1]) {
        mins[0] = previous.a;
        mins[1] = previous.b;
    }
}

/** Counts how many pairs are “better” than the current minima while scanning the array. */
private static int countValidPairs(Pair[] arr) {
    if (arr.length == 0) {
        return 0;
    }

    int[] mins = new int[] { arr[0].a, arr[0].b }; // mins[0]=mina, mins[1]=minb
    int count = 0;
    int i = 1;

    while (i < arr.length) {
        // Skip over elements that share the same 'a' as the previous one,
        // but still evaluate each of them against the current minima.
        while (i < arr.length && arr[i].a == arr[i - 1].a) {
            if (isValid(arr[i], mins[0], mins[1])) {
                count++;
            }
            i++;
        }

        // If we have reached the end after the inner loop, break out.
        if (i >= arr.length) {
            break;
        }

        // Possibly tighten the minima using the element just before the current one.
        updateMinIfNeeded(arr[i - 1], mins);

        // Evaluate the current element.
        if (isValid(arr[i], mins[0], mins[1])) {
            count++;
        }
        i++;
    }

    return count;
}

