/**
 * Counts how many pairs (a,b) satisfy
 *   a > minASeenSoFar  &&  b < minBSeenSoFar
 * while iterating over the array that is already sorted by {@code Pair}'s natural order.
 */
private static int countDominatingPairs(Pair[] arr) {
    // Guard clause – nothing to count.
    if (arr == null || arr.length == 0) {
        return 0;
    }

    int minA = arr[0].a;
    int minB = arr[0].b;
    int count = 0;
    int i = 1;

    while (i < arr.length) {
        // Skip over consecutive elements that share the same 'a' value.
        while (i < arr.length && arr[i].a == arr[i - 1].a) {
            i++;
        }
        if (i >= arr.length) {
            break; // guard: no further elements.
        }

        // Guard clause – check the current pair against the best seen so far.
        if (arr[i].a > minA && arr[i].b < minB) {
            count++;
        }

        // Update the reference minima using the previous element, mirroring the original logic.
        if (arr[i - 1].b > minB) {
            minA = arr[i - 1].a;
            minB = arr[i - 1].b;
        }

        i++;
    }

    return count;
}

