public void solve(InputReader in, PrintWriter out) {
    int n = in.nextInt();
    int totalTime = in.nextInt();

    Pair[] problems = new Pair[n];
    for (int i = 0; i < n; i++) {
        int a = in.nextInt();
        int t = in.nextInt();
        problems[i] = new Pair(a, t, i + 1);
    }
    Arrays.sort(problems);

    int low = 0, high = n, best = 0;
    List<Integer> bestAns = new ArrayList<>();

    while (low <= high) {
        int mid = low + (high - low) / 2;
        List<Integer> candidate = trySolve(mid, totalTime, problems);

        if (candidate.size() >= mid) {
            best = mid;
            bestAns = candidate;
            low = mid + 1;        // try to find a larger feasible set
        } else {
            high = mid - 1;       // mid is too large, search lower
        }
    }

    out.println(best);
    out.println(bestAns.size());
    for (int idx : bestAns) {
        out.print(idx + " ");
    }
    out.println();
}

/**
 * Attempts to select up to {@code need} problems whose difficulty
 * {@code a} is at least {@code need} and whose total time does not exceed
 * {@code availableTime}. Returns the list of chosen problem indices
 * (may be smaller than {@code need} if impossible).
 */
private List<Integer> trySolve(int need, int availableTime, Pair[] sorted) {
    List<Integer> selected = new ArrayList<>();
    int timeLeft = availableTime;

    for (Pair p : sorted) {
        if (selected.size() == need) {
            break;
        }
        if (p.a >= need && timeLeft >= p.t) {
            timeLeft -= p.t;
            selected.add(p.index);
        }
    }
    return selected;
}

