/**
 * Determines the value of tree[i] based on previously computed entries.
 * Guard clauses return early when a true condition is found.
 */
private static boolean computeTreeAt(int i, boolean[] tree) {
    // If the previous position is losing, current is winning
    if (!tree[i - 1]) {
        return true;
    }
    // If two steps back exists and is losing, current is winning
    if (i >= 2 && !tree[i - 2]) {
        return true;
    }
    // If K steps back exists and is losing, current is winning
    if (i >= K && !tree[i - K]) {
        return true;
    }
    // No winning move found
    return false;
}

/**
