private static int[][] computeSuffixArray(String s) {
    int n = s.length();
    char[] chars = s.toCharArray();

    Entry[] entries = initEntries(n);
    int[][] rankTable = initRanks(chars, n);

    int level = 1;
    for (int skip = 1; skip < n; level++, skip <<= 1) {
        populateEntries(entries, rankTable, level - 1, skip, n);
        Arrays.sort(entries);
        writeNewRanks(rankTable, entries, level, n);
    }

    return Arrays.copyOf(rankTable, level);
}

/* ---------- helper methods ---------- */

private static Entry[] initEntries(int n) {
    Entry[] arr = new Entry[n];
    for (int i = 0; i < n; i++) {
        arr[i] = new Entry();
    }
    return arr;
}

private static int[][] initRanks(char[] chars, int n) {
    int[][] p = new int[MAXLG][n];
    for (int i = 0; i < n; i++) {
        p[0][i] = (int) chars[i];
    }
    return p;
}

private static void populateEntries(Entry[] entries, int[][] rankTable,
                                    int prevLevel, int skip, int n) {
    for (int i = 0; i < n; i++) {
        entries[i].nr[0] = rankTable[prevLevel][i];
        entries[i].nr[1] = (i + skip < n) ? rankTable[prevLevel][i + skip] : -1000;
        entries[i].p = i;
    }
}

private static void writeNewRanks(int[][] rankTable, Entry[] entries,
                                  int level, int n) {
    for (int i = 0; i < n; i++) {
        rankTable[level][entries[i].p] = computeRank(entries, rankTable, i, level);
    }
}

/* returns the rank for entries[i] using the previously written rank */
private static int computeRank(Entry[] entries, int[][] rankTable,
                               int i, int level) {
    if (i == 0) {
        return 0;
    }
    boolean sameAsPrev = entries[i].nr[0] == entries[i - 1].nr[0]
                      && entries[i].nr[1] == entries[i - 1].nr[1];
    return sameAsPrev ? rankTable[level][entries[i - 1].p] : i;
}

