public void solve(int testNumber, InputReader in, PrintWriter out) {
    int n = in.nextInt();
    char[] commands = in.next().toCharArray();

    FastSegmentTree<EEditor.S> st = new FastSegmentTree<>(n, EEditor.S::new);
    int cursor = 0;

    List<Integer> answer = new ArrayList<>();
    for (char cmd : commands) {
        // 1. move cursor
        if (cmd == L) {
            cursor = moveCursorLeft(cursor);
        } else if (cmd == R) {
            cursor = moveCursorRight(cursor);
        }

        // 2. apply the command to the segment tree
        applyUpdate(cmd, cursor, st);

        // 3. obtain current result
        answer.add(computeCurrentAnswer(st, n));
    }
    out.println();
    out.println(Util.join(answer));
}

/** Moves cursor one step left, never below zero. */
private int moveCursorLeft(int cursor) {
    int newPos = cursor - 1;
    return newPos < 0 ? 0 : newPos;
}

/** Moves cursor one step right. */
private int moveCursorRight(int cursor) {
    return cursor + 1;
}

/** Updates the segment tree according to the command at the given cursor. */
private void applyUpdate(char cmd, int cursor, FastSegmentTree<EEditor.S> st) {
    if (cmd == PLUS) {
        st.value.init(1);
        st.update(cursor);
    } else if (cmd == MINUS) {
        st.value.init(-1);
        st.update(cursor);
    } else if (cmd != L && cmd != R) { // any other character besides L/R
        st.value.init(0);
        st.update(cursor);
    }
}

/** Queries the whole segment tree and returns the required answer for the current state. */
private int computeCurrentAnswer(FastSegmentTree<EEditor.S> st, int n) {
    st.query(0, n);
    if (st.value.sum[0] != 0 || st.value.min[0] < 0) {
        return -1;
    }
    return st.value.max[0];
}

