/**
 * Counts how many of the lowest {@code bits} positions differ between {@code mask}
 * and {@code x}. A position differs when the corresponding bits are not equal.
 */
private int countBitMismatches(int mask, int x, int bits) {
    int mismatches = 0;
    for (int j = 0; j < bits; j++) {
        boolean maskBitSet = ((1 << j) & mask) != 0;
        boolean xBitSet    = ((1 << j) & x) != 0;
        if (maskBitSet != xBitSet) {
            mismatches++;
        }
    }
    return mismatches;
}

public void solve(InputReader in, OutputWriter out) {
