    int m = in.readInt();
    int k = in.readInt();

    int[] A = readArray(in, m);
    int x = in.readInt();

    int f = 0;
    for (int value : A) {
        if (isWithinK(value, x, n, k)) {
            f++;
        }
    }

    pout.println(f);
    pout.close();
}

/** Reads an integer array of the given length from the InputReader. */
private int[] readArray(InputReader in, int length) {
    int[] arr = new int[length];
    for (int i = 0; i < length; i++) {
        arr[i] = in.readInt();
    }
    return arr;
}

/**
 * Returns true if the number of differing bits between {@code a} and {@code x}
 * among the lowest {@code n} bits does not exceed {@code k}.
 * Uses a guard clause to abort early when the limit is exceeded.
 */
private boolean isWithinK(int a, int x, int n, int k) {
    int diff = a ^ x;                     // bits that differ
    int mask = (1 << n) - 1;              // keep only the first n bits
    diff &= mask;

    // Guard clause: stop as soon as we know the count is too large
    int bits = Integer.bitCount(diff);
    return bits <= k;
}

