public void solve(int testNumber, Scanner in, PrintWriter out) {
    long days = in.nextInt();
    long entries = in.nextInt();

    LinkedHashMap<Long, Long> dayToHeight = new LinkedHashMap<>();
    for (int i = 0; i < entries; i++) {
        long day = in.nextInt();
        long height = in.nextInt();
        dayToHeight.put(day, height);
    }

    List<Interval> intervals = buildIntervals(dayToHeight);

    // --------------------------------------------------------------------
    // 1️⃣  Single recorded day – answer can be computed directly.
    // --------------------------------------------------------------------
    if (intervals.isEmpty()) {
        long onlyDay = dayToHeight.keySet().iterator().next();
        long h = dayToHeight.get(onlyDay);
        long answer = Math.max(h + onlyDay - 1, h + days - onlyDay);
        out.print(answer);
        return;
    }

    // --------------------------------------------------------------------
    // 2️⃣  Height contributed by the parts before the first record
    //      and after the last record.
    // --------------------------------------------------------------------
    long maxHeight = computeBoundaryMaxHeight(intervals, dayToHeight, days);

    // --------------------------------------------------------------------
    // 3️⃣  Process every interior interval; abort if impossible.
    // --------------------------------------------------------------------
    maxHeight = evaluateIntervals(intervals, dayToHeight, maxHeight, out);
    if (maxHeight == Long.MIN_VALUE) {          // “IMPOSSIBLE” already printed
        return;
    }

    out.print(maxHeight);
}

/**
 * Turns the ordered map of (day → height) into a list of consecutive
 * intervals [prevDay, currDay] that contain at least one day between them.
 */
private static List<Interval> buildIntervals(LinkedHashMap<Long, Long> map) {
    List<Interval> intervals = new ArrayList<>();
    Iterator<Map.Entry<Long, Long>> it = map.entrySet().iterator();

    long prevDay = it.next().getKey();          // map is never empty here
    while (it.hasNext()) {
        long currDay = it.next().getKey();
        intervals.add(new Interval(prevDay, currDay));
        prevDay = currDay;
    }
    return intervals;
}

/**
 * Calculates the maximal height that can be reached before the first
 * recorded day (if it is not day 1) and after the last recorded day
 * (if it is not the final day).
 */
private static long computeBoundaryMaxHeight(List<Interval> intervals,
                                              LinkedHashMap<Long, Long> map,
                                              long totalDays) {
    long maxHeight = -1;

    // before the first known day
    Interval first = intervals.get(0);
    if (first.start != 1) {
        maxHeight = map.get(first.start) + (first.start - 1);
    }

    // after the last known day
    Interval last = intervals.get(intervals.size() - 1);
    if (last.end != totalDays) {
        long candidate = map.get(last.end) + (totalDays - last.end);
        maxHeight = Math.max(maxHeight, candidate);
    }

    return maxHeight;
}

/**
 * Verifies each interior interval can be traversed with a slope of at most 1,
 * updates the global maximum height and aborts with “IMPOSSIBLE” if any
 * interval violates the constraint.
 *
 * @return the updated maximum height, or {@code Long.MIN_VALUE} if impossible.
 */
private static long evaluateIntervals(List<Interval> intervals,
                                      LinkedHashMap<Long, Long> map,
                                      long currentMax,
                                      PrintWriter out) {
    long maxHeight = currentMax;

    for (Interval interval : intervals) {
        long startHeight = map.get(interval.start);
        long endHeight   = map.get(interval.end);

        long diff  = Math.abs(startHeight - endHeight);
        long slots = interval.end - interval.start - 1;   // days between the two known points

        // If the required change is larger than the number of days available,
        // the sequence cannot be constructed.
        if (diff > slots + 1) {
            out.println("IMPOSSIBLE");
            return Long.MIN_VALUE;
        }

        // Fill the remaining slots to obtain the highest possible peak.
        while (diff < slots) {
            diff++;
            slots--;
        }

        long possiblePeak = Math.min(startHeight, endHeight) + diff;
        maxHeight = Math.max(maxHeight, possiblePeak);
    }
    return maxHeight;
}

public void solve(int testNumber, Scanner in, PrintWriter out) {
    long days = in.nextInt();
    int entries = in.nextInt();

    LinkedHashMap<Long, Long> dayToHeightMap = buildDayHeightMap(in, entries);
    List<Interval> intervals = buildIntervals(dayToHeightMap);

    // Guard clause – only one known day → answer can be computed directly
    if (intervals.isEmpty()) {
        long onlyDay = dayToHeightMap.keySet().iterator().next();
        long height = dayToHeightMap.get(onlyDay);
        long answer = Math.max(height + onlyDay - 1, height + days - onlyDay);
        out.print(answer);
        return;
    }

    long maxHeight = maxHeightFromBoundaries(intervals, dayToHeightMap, days);

    Long interiorMax = processIntervals(intervals, dayToHeightMap, out);
    if (interiorMax == null) {               // IMPOSSIBLE was already printed
        return;
    }
    maxHeight = Math.max(maxHeight, interiorMax);

    out.print(maxHeight);
}

/* ---------- helper methods ---------- */

private LinkedHashMap<Long, Long> buildDayHeightMap(Scanner in, int entries) {
    LinkedHashMap<Long, Long> map = new LinkedHashMap<>();
    for (int i = 0; i < entries; i++) {
        long day = in.nextInt();
        long height = in.nextInt();
        map.put(day, height);
    }
    return map;
}

private List<Interval> buildIntervals(LinkedHashMap<Long, Long> dayToHeightMap) {
    List<Interval> intervals = new ArrayList<>();
    Iterator<Map.Entry<Long, Long>> it = dayToHeightMap.entrySet().iterator();

    long prevDay = it.next().getKey();               // first known day
    while (it.hasNext()) {
        long currDay = it.next().getKey();
        intervals.add(new Interval(prevDay, currDay));
        prevDay = currDay;
    }
    return intervals;
}

/**
 * Computes the maximal possible height that can be achieved at the very
 * beginning (day 1) or at the very end (day {@code days}) of the whole
 * period, using the first and last known days.
 */
private long maxHeightFromBoundaries(List<Interval> intervals,
                                     LinkedHashMap<Long, Long> map,
                                     long days) {
    long max = -1;

    // left side (day 1 … first known day)
    if (intervals.get(0).start != 1) {
        long firstDay = intervals.get(0).start;
        max = map.get(firstDay) + (firstDay - 1);
    }

    // right side (last known day … day {@code days})
    long lastDay = intervals.get(intervals.size() - 1).end;
    if (lastDay != days) {
        max = Math.max(max, map.get(lastDay) + (days - lastDay));
    }

    return max;
}

/**
 * Validates each interior interval.
 * If an interval cannot be satisfied, prints "IMPOSSIBLE" and returns {@code null}.
 * Otherwise returns the maximal height that can be achieved inside those intervals.
 */
private Long processIntervals(List<Interval> intervals,
                              LinkedHashMap<Long, Long> map,
                              PrintWriter out) {
    long maxInside = -1;

    for (Interval interval : intervals) {
        long heightStart = map.get(interval.start);
        long heightEnd = map.get(interval.end);

        long diff = Math.abs(heightStart - heightEnd);
        long slots = interval.end - interval.start - 1;

        // Guard clause – impossible configuration
        if (diff > slots + 1) {
            out.println("IMPOSSIBLE");
            return null;
        }

        // Fill remaining slots with the smallest possible increase
        while (diff < slots) {
            diff++;
            slots--;
        }

        long candidate = Math.min(heightStart, heightEnd) + diff;
        maxInside = Math.max(maxInside, candidate);
    }
    return maxInside;
}

