public long nextLong() {
    // 1. Guard clause – no more tokens
    ensureHasNext();

    // 2. Parse optional sign and obtain first non‑sign byte
    SignInfo signInfo = parseSign();

    // 3. First character must be a digit
    ensureDigit(signInfo.firstByte);

    // 4. Accumulate the numeric value
    return readNumber(0L, signInfo.isNegative, signInfo.firstByte);
}

/* ---------- helper methods ---------- */

private void ensureHasNext() {
    if (!hasNext()) {
        throw new NoSuchElementException();
    }
}

/* Holds the sign flag and the first byte after the optional '-' */
private static final class SignInfo {
    final boolean isNegative;
    final int firstByte;
    SignInfo(boolean isNegative, int firstByte) {
        this.isNegative = isNegative;
        this.firstByte = firstByte;
    }
}

/** Parses an optional leading '-' and returns the sign together with the next byte. */
private SignInfo parseSign() {
    int b = readByte();
    boolean negative = false;
    if (b == '-') {
        negative = true;
        b = readByte();
    }
    return new SignInfo(negative, b);
}

/** Validates that the supplied byte is a decimal digit, otherwise throws. */
private void ensureDigit(int b) {
    if (b < '0' || b > '9') {
        throw new NumberFormatException();
    }
}

/**
 * Reads consecutive digit characters, building the numeric value.
 * Terminates when a non‑digit, EOF (‑1) or a non‑printable character is encountered.
 * Returns the constructed long, applying the sign if necessary.
 */
private long readNumber(long current, boolean negative, int b) {
    while (true) {
        if (b >= '0' && b <= '9') {
            current = current * 10 + (b - '0');
        } else if (b == -1 || !isPrintableChar(b)) {
            return negative ? -current : current;
        } else {
            throw new NumberFormatException();
        }
        b = readByte();
    }
}

