void solve() throws IOException {
    int k = nextInt();
    char[] s = next().toCharArray();

    int[] freq = buildInitialFrequencies(s, k);
    SegmentTree[] segmentTrees = buildSegmentTrees(freq);
    applyUpdates(segmentTrees);
    String answer = buildResult(s, k, segmentTrees);

    writer.print(answer);
}

/* ---------- helper methods ---------- */
private int[] buildInitialFrequencies(char[] s, int k) {
    int[] freq = new int[26];
    for (char c : s) {
        freq[c - 'a'] += k;
    }
    return freq;
}

private SegmentTree[] buildSegmentTrees(int[] freq) {
    SegmentTree[] trees = new SegmentTree[26];
    for (int i = 0; i < 26; i++) {
        trees[i] = new SegmentTree(freq[i]);
    }
    return trees;
}

private void applyUpdates(SegmentTree[] trees) throws IOException {
    int q = nextInt();
    for (int i = 0; i < q; i++) {
        int x = nextInt();
        char c = next().charAt(0);
        int zeroPos = trees[c - 'a'].getZeroPos(x);
        trees[c - 'a'].increment(zeroPos);
    }
}

private String buildResult(char[] s, int k, SegmentTree[] trees) {
    int[] freq = new int[26];               // reused as a counter per character
    StringBuilder sb = new StringBuilder();

    for (int rep = 0; rep < k; rep++) {
        for (char c : s) {
            int idx = c - 'a';
            int occurrence = freq[idx];
            SegmentTree st = trees[idx];

            // guard clause – print only when the leaf is still zero
            if (st.a[occurrence + st.q] == 0) {
                sb.append(c);
            }
            freq[idx]++;                     // advance to next occurrence of this char
        }
    }
    return sb.toString();
}

/* ---------- SegmentTree ---------- */
static class SegmentTree {
    final int q;          // size of the underlying complete binary tree
    final int[] a;        // stored counts for each node

    SegmentTree(int n) {
        int size = 1;
        while (size <= n) {
            size <<= 1;
        }
        this.q = size;
        this.a = new int[2 * q];
    }

    /** Increments the value at position i (0‑based) and all its ancestors. */
    void increment(int i) {
        for (i += q; i > 0; i >>= 1) {
            a[i]++;
        }
    }

    /** Returns the position of the k‑th zero in the original array (1‑based). */
    int getZeroPos(int k) {
        return getZeroPos(k, 1, 0, q);
    }

    private int getZeroPos(int k, int seg, int l, int r) {
        if (r - l == 1) {
            return l;
        }
        int mid = (l + r) >> 1;
        int zerosInLeft = mid - l - a[seg << 1];
        if (zerosInLeft >= k) {
            return getZeroPos(k, seg << 1, l, mid);
        } else {
            return getZeroPos(k - zerosInLeft, (seg << 1) + 1, mid, r);
        }
    }
}

