public int lowerBound(ArrayList<Integer> a, int x) {
    int size = a.size();

    // Guard clauses – handle trivial cases up‑front
    if (size == 0 || a.get(0) >= x) {
        return -1;
    }
    if (a.get(size - 1) < x) {
        return size - 1;
    }

    int left = 0;
    int right = size - 1;
    int mid = -1;                         // retained for final return compatibility

    while (left <= right) {
        mid = (left + right) >>> 1;       // unsigned right shift avoids overflow

        if (isExactMatchWithPrevLess(a, mid, x)) {
            return mid - 1;
        }

        if (a.get(mid) >= x) {
            right = mid - 1;              // everything at mid and to the right is too large
        } else if (isMidLessAndNextGE(a, mid, x)) {
            return mid;                   // a[mid] < x && a[mid+1] ≥ x → lower bound found
        } else {
            left = mid + 1;               // a[mid] < x && a[mid+1] < x
        }
    }

    // When the loop exits, `right` is the greatest index whose value is < x.
    // Returning `mid` (the last computed midpoint) matches the original behaviour,
    // but `right` conveys the intent more clearly.
    return right;
}

// ---------------------------------------------------------------------
// Helper predicates – each expresses a single logical condition
// ---------------------------------------------------------------------
private boolean isExactMatchWithPrevLess(ArrayList<Integer> a, int mid, int x) {
    return a.get(mid) == x && mid > 0 && a.get(mid - 1) < x;
}

private boolean isMidLessAndNextGE(ArrayList<Integer> a, int mid, int x) {
    return a.get(mid) < x
            && mid + 1 < a.size()
            && a.get(mid + 1) >= x;
}

