private int[] findIntersection(int[] pminx, int[] pmaxx, int[] pminy, int[] pmaxy,
                               int[] sminx, int[] smaxx, int[] sminy, int[] smaxy,
                               int n) {
    // 1️⃣  Only suffix (all but first rectangle)
    if (sminx[1] <= smaxx[1] && sminy[1] <= smaxy[1]) {
        return new int[]{sminx[1], sminy[1]};
    }

    // 2️⃣  Only prefix (all but last rectangle)
    if (pminx[n - 2] <= pmaxx[n - 2] && pminy[n - 2] <= pmaxy[n - 2]) {
        return new int[]{pminx[n - 2], pminy[n - 2]};
    }

    // 3️⃣  Remove one rectangle in the middle
    for (int i = 1; i <= n - 2; ++i) {
        int minX = Math.max(sminx[i + 1], pminx[i - 1]);
        int maxX = Math.min(smaxx[i + 1], pmaxx[i - 1]);
        int minY = Math.max(sminy[i + 1], pminy[i - 1]);
        int maxY = Math.min(smaxy[i + 1], pmaxy[i - 1]);

        if (minX <= maxX && minY <= maxY) {
            return new int[]{minX, minY};
        }
    }

    // No feasible point
    return null;
}

