public long saorihayami() {
    // Guard: no input available
    if (!hayamisaori()) {
        throw new NoSuchElementException();
    }

    // Read the first character and handle an optional leading '-'
    boolean negative = false;
    int ch = SaoriHayami();
    if (ch == '-') {
        negative = true;
        ch = SaoriHayami();
    }

    // Guard: the first non‑sign character must be a digit
    if (!isDigit(ch)) {
        throw new NumberFormatException();
    }

    // Accumulate the number starting with the already‑read digit
    long value = readNumber(ch);
    return negative ? -value : value;
}

/** Returns true if the supplied character code represents a decimal digit. */
private boolean isDigit(int c) {
    return '0' <= c && c <= '9';
}

/**
 * Reads subsequent characters, builds the long value and stops when the
 * stream ends (c == -1) or when a non‑numeric separator is encountered
 * (hayami_saori(c) == false).  Any other non‑digit character causes a
 * NumberFormatException, matching the original logic.
 */
private long readNumber(int firstDigit) {
    long result = 0;
    int ch = firstDigit;

    while (true) {
        // At this point ch is guaranteed to be a digit
        result = result * 10 + (ch - '0');

        // Fetch the next character
        ch = SaoriHayami();

        if (isDigit(ch)) {
            // Continue accumulating digits
            continue;
        }

        // End of numeric token: either EOF (-1) or a legal separator
        if (ch == -1 || !hayami_saori(ch)) {
            return result;
        }

        // Any other character is illegal in the numeric token
        throw new NumberFormatException();
    }
}

