/*----------------------------------------------------------*/
/* Helper methods – each does one well‑defined job           */
/*----------------------------------------------------------*/
private void setupIO() {
    br = new BufferedReader(new InputStreamReader(System.in));
    pw = new PrintWriter(new OutputStreamWriter(System.out));
}

/* Reads the first n pairs of strings into the `input` array */
private void readRawEntries() throws IOException {
    for (int i = 0; i < n; i++) {
        TEntry e = new TEntry();
        e.s1 = nextToken();
        e.s2 = nextToken();
        input[i] = e;
    }
}

/* Builds the `entries` array according to the permutation list */
private void buildPermutation() throws IOException {
    for (int i = 0; i < n; i++) {
        int idx = nextInt() - 1;          // convert to 0‑based index
        entries[i] = input[idx];
    }
}

/* Returns the smaller string of the first entry – the starting point */
private String initialLastString() {
    String first = entries[0].s1;
    String second = entries[0].s2;
    return (second.compareTo(first) < 0) ? second : first;
}

/* Core algorithm – checks if we can pick a strictly increasing string */
private boolean isPossibleSequence() {
    String lastStr = initialLastString();

    for (int i = 1; i < n; i++) {
        String candidate = null;

        // consider s1
        if (entries[i].s1.compareTo(lastStr) > 0) {
            candidate = entries[i].s1;
        }

        // consider s2 – keep the smaller viable choice
        if (entries[i].s2.compareTo(lastStr) > 0) {
            if (candidate == null || entries[i].s2.compareTo(candidate) < 0) {
                candidate = entries[i].s2;
            }
        }

        // Guard clause: no string larger than lastStr → impossible
        if (candidate == null) {
            return false;
        }

        lastStr = candidate; // advance to the chosen string
    }
    return true;
}

