/**
 * Creates the rail adjacency matrix and initializes it with INF,
 * setting the diagonal to 0.
 */
private static int[][] createRailMatrix(int n) {
    int[][] matrix = new int[n][n];
    for (int i = 0; i < n; i++) {
        Arrays.fill(matrix[i], INF);
        matrix[i][i] = 0;
    }
    return matrix;
}

/**
 * Reads the m rail edges and fills the symmetric adjacency matrix.
 */
private static void readRailEdges(int[][] distRail, int m) {
    for (int i = 0; i < m; i++) {
        int a = sc.nextInt() - 1;
        int b = sc.nextInt() - 1;
        distRail[a][b] = 1;
        distRail[b][a] = 1;
    }
}

/**
 * Constructs the road adjacency matrix: a road exists iff there is
 * no direct rail edge. Distances are set to 1 for roads and INF
 * otherwise (except the diagonal, which stays 0 by default).
 */
private static int[][] buildRoadMatrix(int[][] distRail, int INF) {
    int n = distRail.length;
    int[][] distRoad = new int[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i == j) {
                continue;
            }
            if (distRail[i][j] == INF) {
                distRoad[i][j] = 1;          // no rail → road
            } else if (distRail[i][j] == 1) {
                distRoad[i][j] = INF;        // direct rail → no road
            }
        }
    }
    return distRoad;
}

