/* Creates a rail distance matrix filled with INF and zero on the diagonal */
private static int[][] createRailMatrix(int n) {
    int[][] matrix = new int[n][n];
    for (int i = 0; i < n; i++) {
        Arrays.fill(matrix[i], INF);
        matrix[i][i] = 0;
    }
    return matrix;
}

/* Reads the m rail edges and stores them with distance 1 */
private static void fillRailEdges(int[][] distRail, int m) {
    for (int i = 0; i < m; i++) {
        int a = sc.nextInt() - 1;
        int b = sc.nextInt() - 1;
        distRail[a][b] = 1;
        distRail[b][a] = 1;
    }
}

/* Builds the road distance matrix: 1 where there is no rail, INF where a rail exists */
private static int[][] buildRoadMatrix(int[][] distRail, int n) {
    int[][] distRoad = new int[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i == j) {
                continue;
            }
            if (distRail[i][j] == INF) {
                distRoad[i][j] = 1;
            } else if (distRail[i][j] == 1) {
                distRoad[i][j] = INF;
            }
        }
    }
    return distRoad;
}

