private static void printResult(int[][] distRail, int[][] distRoad, int n) {
    if (distRail[0][n - 1] == 1 && distRoad[0][n - 1] < INF) {
        out.println(distRoad[0][n - 1]);
        return;
    }
    if (distRoad[0][n - 1] == 1 && distRail[0][n - 1] < INF) {
        out.println(distRail[0][n - 1]);
        return;
    }
    out.println(-1);
}

