/* Reads a single token from the scanner and converts it to a Cell.
   Expected format: a letter a‑h followed by a digit 1‑8 (e.g., "c3").
*/
private static Cell readCell(Scanner scanner) {
    if (!scanner.hasNext()) {
        throw new IllegalArgumentException("Expected cell coordinate");
    }
    String token = scanner.next();
    int letter = "abcdefgh".indexOf(token.charAt(0)) + 1;   // column (1‑8)
    int digit  = Character.getNumericValue(token.charAt(1)); // row (1‑8)
    return new Cell(letter, digit);
}

/* Computes the sequence of moves needed to go from start to end.
   Each move is expressed as a string containing any of the
   directions: R (right), L (left), U (up), D (down). */
private static List<String> computeSteps(Cell start, Cell end) {
    // Guard clause: start already equals end – no steps required.
    if (start.letter == end.letter && start.digit == end.digit) {
        return Collections.emptyList();
    }

    List<String> steps = new ArrayList<>();
    // Work on mutable copies so the original cells stay unchanged.
    int curLetter = start.letter;
    int curDigit  = start.digit;

    while (curLetter != end.letter || curDigit != end.digit) {
        StringBuilder move = new StringBuilder();

        if (end.letter - curLetter > 0) {
            move.append('R');
            curLetter++;
        } else if (end.letter - curLetter < 0) {
            move.append('L');
            curLetter--;
        }

        if (end.digit - curDigit > 0) {
            move.append('U');
            curDigit++;
        } else if (end.digit - curDigit < 0) {
            move.append('D');
            curDigit--;
        }

        steps.add(move.toString());
    }
    return steps;
}

