static long solve(int l, int r, int lc, int rc) throws Exception {
    // Guard clauses – handle trivial / cached cases up‑front
    if (l > r) {
        return 1L;
    }
    if (l == r) {
        System.out.println(l);
        throw new Exception("Impossible");
    }
    if (dp[l][r][lc][rc] != -1) {
        return dp[l][r][lc][rc];
    }

    long result = 0L;
    int curr = arr[l];

    for (int i = 0; i <= 1; i++) {
        // contribution when the left colour differs from lc
        result = (result + contributionIfLeftDiff(l, r, lc, rc, i, curr)) % mod;

        // contribution when the right side satisfies its condition
        result = (result + contributionIfRightValid(l, r, lc, rc, i, curr)) % mod;
    }

    dp[l][r][lc][rc] = result;
    return result;
}

/** Returns the product for the branch `if (i != lc)`; 0 if the condition fails. */
private static long contributionIfLeftDiff(int l, int r, int lc, int rc,
                                           int i, int curr) throws Exception {
    if (i == lc) {
        return 0L;
    }
    long left  = solve(l + 1, curr - 1, i, 2);
    long right = solve(curr + 1, r, 2, rc);
    return (left * right) % mod;
}

/** Returns the product for the branch `if ((curr+1<=r) || i!=rc)`; 0 if the condition fails. */
private static long contributionIfRightValid(int l, int r, int lc, int rc,
                                             int i, int curr) throws Exception {
    if ((curr + 1 > r) && i == rc) {
        return 0L;
    }
    long left  = solve(l + 1, curr - 1, 2, i);
    long right = solve(curr + 1, r, i, rc);
    return (left * right) % mod;
}

