public void solve(int testNumber, InputReader in, PrintWriter out) {
    long x1 = in.ni(), y1 = in.ni(), x2 = in.ni(), y2 = in.ni();
    long n = in.ni();
    char[] cmd = in.next().toCharArray();

    final long INF = (long) 2e18;
    long low = 0, high = INF;
    int iterations = 100;                 // enough for convergence with long range

    while (iterations-- > 0) {
        long mid = (low + high) / 2;
        if (canReachIn(mid, n, cmd, x1, y1, x2, y2)) {
            high = mid;
        } else {
            low = mid;
        }
    }

    if (high == INF) {
        out.println(-1);
        return;                           // guard clause – end early
    }
    out.println(high);
}

/**
 * Returns true if the target (x2, y2) can be reached in at most {@code steps}
 * using the given command pattern.
 */
private static boolean canReachIn(long steps, long n, char[] cmd,
                                  long xStart, long yStart,
                                  long xTarget, long yTarget) {
    long[] pos = simulatePosition(steps, n, cmd, xStart, yStart);
    long distance = Math.abs(pos[0] - xTarget) + Math.abs(pos[1] - yTarget);
    return distance <= steps;
}

/**
 * Simulates the robot position after distributing {@code steps} over the
 * command sequence {@code cmd}. The distribution follows the original logic:
 * each command receives {@code steps / n} moves, and the first {@code steps % n}
 * commands receive one extra move.
 *
 * @return a two‑element array: {@code [x, y]}.
 */
private static long[] simulatePosition(long steps, long n, char[] cmd,
                                       long xStart, long yStart) {
    long x = xStart;
    long y = yStart;
    long base = steps / n;
    long extra = steps % n;

    for (int i = 0; i < n; i++) {
        long moves = base + (i < extra ? 1 : 0);
        switch (cmd[i]) {
            case 'U' -> y += moves;
            case 'D' -> y -= moves;
            case 'L' -> x -= moves;
            default  -> x += moves;   // 'R'
        }
    }
    return new long[] {x, y};
}

