public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);

    // 1️⃣ read basic sizes
    int n = sc.nextInt();
    int m = sc.nextInt();
    int k = sc.nextInt();

    // 2️⃣ initialise containers
    int[] cs = new int[k];
    Integer[] bucket = new Integer[k + 1];
    initialiseBucket(bucket);
    Node[] graph = createGraph(n);

    // 3️⃣ read special vertices
    readSpecialVertices(sc, k, cs, graph);

    // 4️⃣ read edges and count them
    int edgeCount = readEdges(sc, m, graph);

    // 5️⃣ run BFS from every special vertex
    runAllBFS(graph, cs);

    // 6️⃣ fill bucket[0] with vertices that have no key
    fillBucketForUnassigned(graph, bucket);

    // 7️⃣ compute final answer
    long answer = computeAnswer(bucket, k, edgeCount);
    System.out.println(answer);
}

/* ---------- helper methods ---------- */

private static void initialiseBucket(Integer[] bucket) {
    for (int i = 0; i < bucket.length; i++) {
        bucket[i] = 0;
    }
}

private static Node[] createGraph(int n) {
    Node[] graph = new Node[n];
    for (int i = 0; i < n; i++) {
        graph[i] = new Node();
    }
    return graph;
}

/* reads the k special vertices, stores them in cs[] (0‑based) and
   sets graph[vertex].key to the order in which they appear (1‑based) */
private static void readSpecialVertices(Scanner sc, int k, int[] cs, Node[] graph) {
    for (int i = 1; i <= k; i++) {
        int c = sc.nextInt();          // 1‑based input
        cs[i - 1] = c - 1;              // store 0‑based index
        graph[c - 1].key = i;           // mark the node with its order
    }
}

/* reads the m undirected edges, updates adjacency lists and returns
   the total number of edges (the original code stored it in “num”) */
private static int readEdges(Scanner sc, int m, Node[] graph) {
    int edgeCount = 0;
    for (int i = 0; i < m; i++) {
        int u = sc.nextInt();
        int v = sc.nextInt();
        graph[u - 1].next.add(v - 1);
        graph[v - 1].next.add(u - 1);
        edgeCount++;
    }
    return edgeCount;
}

/* runs BFS for every special vertex */
private static void runAllBFS(Node[] graph, int[] cs) {
    if (cs == null || cs.length == 0) {
        return;                     // guard clause – nothing to process
    }
    for (int start : cs) {
        BFS(graph, start, graph[start].next);
    }
}

/* counts vertices whose key is still 0 and puts the count into bucket[0] */
private static void fillBucketForUnassigned(Node[] graph, Integer[] bucket) {
    int zeroKeyCount = 0;
    for (Node node : graph) {
        if (node.key == 0) {
            zeroKeyCount++;
        }
    }
    bucket[0] = zeroKeyCount;
}

/* performs the remaining bucket manipulation and computes the final result */
private static long computeAnswer(Integer[] bucket, int k, int edgeCount) {
    int e = bucket[0];
    bucket[0] = 0;

    Arrays.sort(bucket);                     // ascending
    bucket[k] = bucket[k] + e;                // move the “zero‑key” vertices to the last bucket

    long answer = 0;
    for (int i = k; i > 0; i--) {
        long cnt = bucket[i];
        answer += cnt * (cnt - 1) / 2;        // nC2 for bucket i
    }
    return answer - edgeCount;
}

public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int n = sc.nextInt();
    int m = sc.nextInt();
    int k = sc.nextInt();

    int[] specialNodes = readSpecialNodes(sc, k);
    Node[] graph = createGraph(n);
    int edgeCount = readEdges(sc, m, graph);
    Integer[] bucket = initBucket(k);

    assignSpecialKeys(specialNodes, graph);
    bfsFromAllSpecialNodes(specialNodes, graph);
    fillBucketForUnmarkedNodes(graph, bucket);

    long answer = computeAnswer(bucket, k, edgeCount);
    System.out.println(answer);
}

/* ---------- helper methods ---------- */

private static int[] readSpecialNodes(Scanner sc, int k) {
    int[] cs = new int[k];
    for (int i = 0; i < k; i++) {
        int c = sc.nextInt();          // 1‑based index from input
        cs[i] = c - 1;                  // store as 0‑based
    }
    return cs;
}

private static Node[] createGraph(int n) {
    Node[] graph = new Node[n];
    for (int i = 0; i < n; i++) {
        graph[i] = new Node();
    }
    return graph;
}

/* reads the edges, populates adjacency lists and returns the total number of edges */
private static int readEdges(Scanner sc, int m, Node[] graph) {
    int edgeCount = 0;
    for (int i = 0; i < m; i++) {
        int u = sc.nextInt() - 1;   // convert to 0‑based
        int v = sc.nextInt() - 1;
        graph[u].next.add(v);
        graph[v].next.add(u);
        edgeCount++;
    }
    return edgeCount;
}

/* bucket[0..k] are initialised to zero */
private static Integer[] initBucket(int k) {
    Integer[] bucket = new Integer[k + 1];
    for (int i = 0; i <= k; i++) {
        bucket[i] = 0;
    }
    return bucket;
}

/* stores the order (1‑based) of each special node inside the corresponding Node */
private static void assignSpecialKeys(int[] specialNodes, Node[] graph) {
    for (int i = 0; i < specialNodes.length; i++) {
        graph[specialNodes[i]].key = i + 1;
    }
}

/* runs the existing BFS routine for every special node */
private static void bfsFromAllSpecialNodes(int[] specialNodes, Node[] graph) {
    for (int nodeIdx : specialNodes) {
        BFS(graph, nodeIdx, graph[nodeIdx].next);
    }
}

/* counts vertices that were never visited by any BFS (key == 0) */
private static void fillBucketForUnmarkedNodes(Node[] graph, Integer[] bucket) {
    for (Node node : graph) {
        if (node.key == 0) {
            bucket[0] = bucket[0] + 1;
        }
    }
}

/* final aggregation identical to the original algorithm */
private static long computeAnswer(Integer[] bucket, int k, int edgeCount) {
    int isolated = bucket[0];
    bucket[0] = 0;

    Arrays.sort(bucket);                     // ascending
    bucket[k] = bucket[k] + isolated;        // put isolated vertices into the last bucket

    long answer = 0;
    for (int i = k; i > 0; i--) {
        answer += (long) bucket[i] * (bucket[i] - 1) / 2;
    }
    return answer - edgeCount;
}

