private static int[] computeEvenPrefix(int[] a) {
    int n = a.length;
    int[] even = new int[n];
    for (int i = 0; i < n; i++) {
        even[i] = (a[i] % 2 == 0 ? 1 : 0) + (i > 0 ? even[i - 1] : 0);
    }
    return even;
}

private static void fillDP(long[][] dp, int[] a, int[] even, int b, int n) {
    for (int i = 1; i <= b; i++) {
        for (int j = 2; j < n; j++) {
            propagateBest(dp, i, j);
            updateCellIfPossible(dp, i, j, a, even);
        }
    }
}

/* propagate the best of the three neighbouring states */
private static void propagateBest(long[][] dp, int i, int j) {
    dp[i][j] = Math.max(dp[i][j], Math.max(dp[i - 1][j], dp[i][j - 1]));
}

/* guard‑clause style update of dp[i][j] */
private static void updateCellIfPossible(long[][] dp, int i, int j,
                                         int[] a, int[] even) {
    if (!isEvenIndex(j)) {
        return;                                 // guard clause
    }
    if (!hasHalfEvens(j, even)) {
        return;                                 // guard clause
    }

    int cost = Math.abs(a[j] - a[j - 1]);
    if (i < cost) {
        return;                                 // guard clause
    }

    dp[i][j] = Math.max(dp[i][j], 1 + dp[i - cost][j - 1]);
}

/* predicate helpers */
private static boolean isEvenIndex(int j) {
    return (j & 1) == 0; // same as j % 2 == 0 but faster
}

private static boolean hasHalfEvens(int j, int[] even) {
    return even[j - 1] == j / 2;
}

public static void main(String[] args) throws IOException {
    int n = in.nextInt();
    int b = in.nextInt();
    int[] a = new int[n];
    for (int i = 0; i < n; i++) {
        a[i] = in.nextInt();
    }

    int[] even = computeEvenPrefix(a);

    long[][] dp = new long[b + 1][n + 1];
    for (int i = 1; i <= b; i++) {
        for (int j = 2; j < n; j++) {
            updateDpCell(dp, i, j, a, even);
        }
    }

    System.out.println(dp[b][n - 1]);
}

/**
 * Builds a prefix‑sum array where even[i] = number of even elements in a[0..i].
 */
private static int[] computeEvenPrefix(int[] a) {
    int n = a.length;
    int[] even = new int[n];
    for (int i = 0; i < n; i++) {
        even[i] = (a[i] % 2 == 0 ? 1 : 0) + (i > 0 ? even[i - 1] : 0);
    }
    return even;
}

/**
 * Updates dp[i][j] according to the original nested logic.
 * Guard clauses replace deep nesting for clarity.
 */
private static void updateDpCell(long[][] dp, int i, int j, int[] a, int[] even) {
    // propagate the best value from the top or left neighbour
    dp[i][j] = Math.max(dp[i][j], Math.max(dp[i - 1][j], dp[i][j - 1]));

    // guard: only even indices are considered
    if (j % 2 != 0) {
        return;
    }
    // guard: we need exactly half of the first j elements to be even
    if (even[j - 1] != j / 2) {
        return;
    }

    int diff = Math.abs(a[j] - a[j - 1]);
    // guard: not enough budget to cover the difference
    if (i < diff) {
        return;
    }

    dp[i][j] = Math.max(dp[i][j], 1 + dp[i - diff][j - 1]);
}

