/** Returns the substring that starts at the k‑th vowel from the end of {@code line},
 *  or {@code null} if the line contains fewer than k vowels. */
private static String suffixFromKthVowel(String line, int k) {
    int vowelCount = 0;
    for (int pos = line.length() - 1; pos >= 0; pos--) {
        if (isVowel(line.charAt(pos))) {
            vowelCount++;
            if (vowelCount == k) {
                return line.substring(pos);
            }
        }
    }
    return null; // not enough vowels
}

/** Determines the rhyme scheme from the four suffixes.
 *  Returns "aaaa", "abba", "aabb", "abab" or "NO". */
private static String decideScheme(String[] ends) {
    // the set tells us how many distinct suffixes exist
    java.util.TreeSet<String> distinct = new java.util.TreeSet<>();
    for (String s : ends) {
        distinct.add(s);
    }

    int distinctCount = distinct.size();
    if (distinctCount == 1) {
        return "aaaa";
    }
    if (distinctCount == 2) {
        if (ends[0].equals(ends[3]) && ends[1].equals(ends[2])) {
            return "abba";
        }
        if (ends[0].equals(ends[1]) && ends[2].equals(ends[3])) {
            return "aabb";
        }
        if (ends[0].equals(ends[2]) && ends[1].equals(ends[3])) {
            return "abab";
        }
    }
    return "NO";
}

