/**
 * Determines whether the triple (i, j, i ^ j) satisfies all required conditions:
 *   1. The XOR value is within the range [0, n].
 *   2. The XOR value has not been marked as visited.
 *   3. The domain‑specific {@code check} predicate holds.
 *
 * @param i   first index
 * @param j   second index
 * @param n   upper bound for the XOR value
 * @param vis visitation array
 * @return true if the triple can be counted, false otherwise
 */
private boolean isCandidate(int i, int j, int n, int[] vis) {
    int xor = i ^ j;
    return xor <= n && vis[xor] == 0 && check(i, j, xor);
}

