 * Checks whether the difference array {@code b} fulfills the problem constraints.
 *
 * <p>The original loop contained a complex conditional that mixed three concerns:
 * <ul>
 *   <li>detecting a negative element,
 *   <li>ensuring at most one positive block with a constant value,
 *   <li>tracking the interval of that block.</li>
 * </ul>
 * All of that logic is now isolated in this method, returning {@code true}
 * when the input is valid (i.e., when the original code would print "YES").
 *
 * @param b the array of differences (target - source)
 * @return {@code true} if the transformation is possible, {@code false} otherwise
 */
private static boolean isTransformationPossible(int[] b) {
    int l = -1;   // left bound of the positive block (1‑based index as in original code)
    int r = -1;   // right bound of the positive block
    int k = -1;   // value of the positive elements inside the block

    for (int i = 0; i < b.length; i++) {
        int val = b[i];

        // 1️⃣ Any negative value makes the whole test fail immediately.
        if (val < 0) {
            return false;
        }

        // 2️⃣ Positive values start (or continue) the single allowed block.
        if (val > 0) {
            // a) we already closed a block (r != -1) → second block → invalid
            // b) we are inside a block but the value differs from the first one → invalid
            if ((l != -1 && r != -1) || (l != -1 && val != k)) {
                return false;
            }
            // first positive element → remember its position and value
            if (l == -1) {
                l = i + 1;   // original code used 1‑based index
                k = val;
            }
        } else { // val == 0
            // zeros after the start of a block extend the block's right bound
            if (l != -1) {
                r = i;
            }
        }
    }

    // The original implementation set r = n when a block started but never closed.
    // This side‑effect does not influence the final answer, but we keep it for parity.
    if (l != -1 && r == -1) {
        r = b.length;
    }

    return true;   // no rule was violated
}

