public static int find(int n, int[] a) {
    sort(a);
    int res = 0;
    boolean[] found = new boolean[n + 1];
    int last = 1;

    for (int i = 0; i < n; i++) {
        int cur = a[i];

        if (isDistinctInRange(cur, n, found)) {
            markFound(cur, found);
        } else {
            if (isTooSmall(cur, last)) {
                return -1;
            }
            res++;
            markFound(last, found);
        }

        last = nextMissing(last, found, n);
    }

    return res;
}

/* Predicate: value is between 1 and n and has not been recorded yet */
private static boolean isDistinctInRange(int value, int n, boolean[] found) {
    return value >= 1 && value <= n && !found[value];
}

/* Predicate: value cannot replace the current missing smallest element */
private static boolean isTooSmall(int value, int last) {
    return value <= 2 * last;
}

/* Record that a value is present */
private static void markFound(int value, boolean[] found) {
    found[value] = true;
}

/* Advance `last` to the next index that is still missing */
private static int nextMissing(int start, boolean[] found, int n) {
    int candidate = start;
    while (candidate <= n && found[candidate]) {
        candidate++;
    }
    return candidate;
}

