/**
 * Returns the number of additional segments that must be turned on to transform
 * {@code current} into the representation of {@code digit}. Returns -1 if the
 * transformation is impossible (a segment that is on in {@code current} would
 * need to be turned off).
 */
private static int calculateCost(char[] current, int digit, char[][] DIGITS) {
    int flips = 0;
    for (int pos = 0; pos < 7; pos++) {
        char target = DIGITS[digit][pos];
        char present = current[pos];
        if (target == '0' && present == '1') {
            return -1;                     // impossible: would need to turn off a segment
        }
        if (target == '1' && present == '0') {
            ++flips;                       // need to turn this segment on
        }
    }
    return flips;
}

/**
 * Checks whether digit {@code d} can be placed at position {@code idx}
 * given the remaining number of turns {@code remainingK}.
 */
private static boolean canPlaceDigit(int idx, int d, int remainingK,
                                     boolean[][] dp, int[][] cost) {
    int needed = cost[idx][d];
    return needed != -1
            && needed <= remainingK
            && dp[idx + 1][remainingK - needed];
}

