/**
 * Checks that the three cells directly above (i,j) exist.
 */
private static boolean hasUpperNeighbour(int i, int j, int m) {
    return i - 1 >= 0 && j - 1 >= 0 && j + 1 < m;
}

/**
 * Returns true if the current cell equals the three cells directly above it.
 */
private static boolean upperThreeEqual(char[][] a, int i, int j) {
    char val = a[i][j];
    return val == a[i - 1][j - 1] && val == a[i - 1][j] && val == a[i - 1][j + 1];
}

/**
 * Determines whether the pattern can be extended upward by ‘num’ rows.
 */
private static boolean canExtend(long num, int i, char[][] a, int j) {
    return i - 2 * num >= 0 && a[i - 2 * num][j] == a[i][j];
}

/**
 * Computes the DP value for cell (i,j) according to the original logic.
 */
private static long computeDp(int i, int j, char[][] a, long[][] dp) {
    long num = Math.min(dp[i - 1][j - 1],
            Math.min(dp[i - 1][j], dp[i - 1][j + 1]));

    if (upperThreeEqual(a, i, j)) {
        if (canExtend(num, i, a, j)) {
            return num + 1;
        }
        return num;
    }
    return 1;
}

