/**
 * Returns true if a cross‑shaped pattern of '#' characters fits starting
 * at (row, col) and the required cells are all '#'.
 *
 * The pattern consists of:
 *   (col, row)       – already examined by the caller
 *   (col, row+1)     – right of the start
 *   (col, row+2)     – two steps right
 *   (col-1, row+1)   – one up from the middle
 *   (col+1, row+1)   – one down from the middle
 *
 * Bounds are checked to avoid ArrayIndexOutOfBoundsException.
 */
private static boolean isCrossPattern(char[][] board, int row, int col, int size) {
    // ensure indices stay inside the board
    if (row + 2 >= size) return false;          // need two cells to the right
    if (col - 1 < 0) return false;              // need one cell up
    if (col + 1 >= size) return false;          // need one cell down

    // check that all required positions contain '#'
    return board[col][row + 1] == '#'
        && board[col][row + 2] == '#'
        && board[col - 1][row + 1] == '#'
        && board[col + 1][row + 1] == '#';
}

