/**
 * Updates the DP table for the transition from position i with digit j.
 */
private void addTransitions(int i, int j, int[] memo, long[][] ans) {
    int combined = memo[i + 1] + j;
    int half = combined / 2;
    ans[i + 1][half] += ans[i][j];
    if ((combined & 1) == 1) {               // odd sum → also possible upper half
        ans[i + 1][half + 1] += ans[i][j];
    }
}

/**
 * Determines whether two consecutive digits satisfy the original complex condition.
 * The condition is true when the current digit is either the exact average
 * (for even sum) or the ceiling of the average (for odd sum) of the two digits.
 */
private boolean isValidTransition(int prev, int curr) {
    int sum = prev + curr;
    int avg = sum / 2;
    if ((sum & 1) == 0) {                     // even sum
        return avg == curr;                  // equivalent to prev == curr
    } else {                                  // odd sum
        return avg + 1 == curr;
    }
}

