/**
 * Assigns the three distinct colors {1,2,3} to the vertices a, b, c.
 * If none of them is colored yet, they receive 1, 2 and 3 respectively.
 * If exactly one vertex already has a color, the other two receive the
 * remaining colors in ascending order, preserving the original evaluation
 * order (a → b → c).
 */
private static void assignColors(int[] color, int a, int b, int c) {
    // Case: all three vertices are uncolored
    if (color[a] == 0 && color[b] == 0 && color[c] == 0) {
        color[a] = 1;
        color[b] = 2;
        color[c] = 3;
        return;
    }

    // Determine which vertex is already colored, following the original order
    int preVertex;
    int preColor;
    if (color[a] != 0) {
        preVertex = a;
        preColor = color[a];
    } else if (color[b] != 0) {
        preVertex = b;
        preColor = color[b];
    } else {
        preVertex = c;
        preColor = color[c];
    }

    // Find the two colors that are still free (the numbers 1..3 except preColor)
    int[] missing = new int[2];
    int idx = 0;
    for (int col = 1; col <= 3; col++) {
        if (col != preColor) {
            missing[idx++] = col;
        }
    }

    // Assign the missing colors to the other two vertices in order a, b, c
    int assignIdx = 0;
    if (a != preVertex) {
        color[a] = missing[assignIdx++];
    }
    if (b != preVertex) {
        color[b] = missing[assignIdx++];
    }
    if (c != preVertex) {
        color[c] = missing[assignIdx];
    }
}

