/** Returns the distance according to the original complex conditional. */
private static int computeDistance(int n, int x1, int y1, int x2, int y2) {
    if (isSameVerticalBorder(x1, x2, n)) {
        return Math.abs(y1 - y2);
    } else if (isSameHorizontalBorder(y1, y2, n)) {
        return Math.abs(x1 - x2);
    } else if (x1 == 0 && y2 == n) {
        return n - y1 + x2;
    } else if (y1 == n && x2 == n) {
        return n - x1 + n - y2;
    } else if (x1 == 0 && y2 == 0) {
        return y1 + x2;
    } else if (y1 == 0 && x2 == n) {
        return n - x1 + y2;
    } else if (x1 == 0) {
        return Math.min(n - y1 + n + n - y2, y1 + n + y2);
    } else {
        return Math.min(n - x1 + n + n - x2, x1 + n + x2);
    }
}

/** True when both points lie on the same vertical border of the board. */
private static boolean isSameVerticalBorder(int x1, int x2, int n) {
    return x1 == x2 && (x1 == 0 || x1 == n);
}

/** True when both points lie on the same horizontal border of the board. */
private static boolean isSameHorizontalBorder(int y1, int y2, int n) {
    return y1 == y2 && (y1 == 0 || y1 == n);
}

