static void f(boolean[][] visited, char[][] graph, int m, int n,
              int i, int j, char ch, point[][] parent) {
    visited[i][j] = true;

    // explore the four orthogonal neighbours
    if (exploreNeighbor(visited, graph, m, n, i, j, ch, parent, i + 1, j)) return;
    if (exploreNeighbor(visited, graph, m, n, i, j, ch, parent, i - 1, j)) return;
    if (exploreNeighbor(visited, graph, m, n, i, j, ch, parent, i, j + 1)) return;
    if (exploreNeighbor(visited, graph, m, n, i, j, ch, parent, i, j - 1)) return;
}

/**
 * Attempts to move from (i,j) to (newI,newJ).
 *
 * @return true if a cycle has been detected (i.e., the global flag {@code a}
 *         has been set to 1), causing the caller to abort further processing.
 */
private static boolean exploreNeighbor(boolean[][] visited, char[][] graph,
                                       int m, int n, int i, int j, char ch,
                                       point[][] parent, int newI, int newJ) {
    if (!issafe(visited, graph, m, n, newI, newJ, ch)) {
        return false;
    }

    // neighbour already visited – check whether it is not the direct parent
    if (visited[newI][newJ]) {
        if (!(parent[i][j].x == newI && parent[i][j].y == newJ)) {
            a = 1;                     // cycle found
            return true;               // propagate the early exit
        }
        return false;                  // visited but is the parent → nothing to do
    }

    // first time we reach this cell
    parent[newI][newJ] = new point(i, j);
    f(visited, graph, m, n, newI, newJ, ch, parent);
    return a == 1;                     // propagate if a was set deeper in recursion
}

