public static int[] palindromeRadius(String s) {
    int n = s.length();
    int[] rad = new int[n];
    for (int i = 0, j = 0; i < n; ) {
        while (canExpand(s, i, j, n)) {
            j++;
        }
        rad[i] = j - i - 1;
        for (int bi = i++; shouldCopyRadius(i, j, rad, bi); i++) {
            rad[i] = Math.min(rad[bi] + bi - i, rad[bi + bi - i]);
        }
    }
    return rad;
}

/** Determines whether the current centre `i` can be expanded to include position `j`. */
private static boolean canExpand(String s, int i, int j, int n) {
    int mirror = i + i - j;                // index reflected across the centre `i`
    return j < n && mirror >= 0 && s.charAt(j) == s.charAt(mirror);
}

/** Determines whether the radius at position `i` can be copied from a previously computed value. */
private static boolean shouldCopyRadius(int i, int j, int[] rad, int bi) {
    return i < j && rad[bi + bi - i] != rad[bi] + bi - i;
}

