public void solve(int testNumber, Scanner in, PrintWriter out) {
    int n = in.nextInt();
    ModInt[][] dp = new ModInt[n + 1][64];
    ModInt[] tmp = new ModInt[64];
    ModInt res = new ModInt(0);

    // initialise dp[3]
    for (int i = 0; i < 64; i++) {
        dp[3][i] = isAllowedState(i) ? new ModInt(1) : new ModInt(0);
    }

    // dynamic programming
    for (int i = 3; i < n; i++) {
        Arrays.fill(tmp, new ModInt(0));
        for (int j = 0; j < 64; j++) {
            for (int k = 0; k < 4; k++) {
                if (isForbiddenTransition(j, k)) {
                    continue;
                }
                int next = (j * 4 + k) % 64;
                tmp[next] = tmp[next].add(dp[i][j]);
            }
        }

        for (int j = 0; j < 64; j++) {
            dp[i + 1][j] = isAllowedState(j) ? tmp[j] : new ModInt(0);
        }
    }

    // sum up the answer
    for (int i = 0; i < 64; i++) {
        res = res.add(dp[n][i]);
    }

    out.println(res.getVal());
}

/** Returns true if the transition from state j using digit k must be skipped. */
private boolean isForbiddenTransition(int j, int k) {
    return ((j / 4 == 2) || (j / 16 == 0 && j % 4 == 2)) && k == 1;
}

/** Returns true if the state j is allowed (i.e., not one of the forbidden states 6, 9, 33). */
private boolean isAllowedState(int j) {
    return j != 33 && j != 6 && j != 9;
}

