static int getAns(Candy[] candies, int t, int x) {
		Queue<Candy> q2 = new LinkedList<Candy>();
		PriorityQueue<Candy> q = new PriorityQueue<>();
		for (Candy c : candies) q.add(c);

		int ans = 0;
		while (true) {
			Candy max = null;
			q2.clear();
			while (!q.isEmpty() && q.peek().h <= x) {
				if (q.peek().t != t && (max == null || q.peek().m > max.m)) {
					max = q.peek();
				}
				q2.add(q.poll());
			}
			if (q2.size() == 0 || max == null) break;
			while (!q2.isEmpty()) {
				if (q2.peek() != max) q.add(q2.peek());
				q2.poll();
			}
			x += max.m;
			t = max.t;
			ans++;
		}
		return ans;
	}

