/**
 * Tries to read a date of the form "dd-mm-yyyy" starting at position {@code i}
 * in {@code input}. Returns a {@link Date} object when the substring is a
 * syntactically correct date and falls within the allowed range,
 * otherwise returns {@code null}.
 */
private static Date parseDateAt(char[] input, int i, int[] days) {
    // day: two digits
    if (!Character.isDigit(input[i]) || !Character.isDigit(input[i + 1])) {
        return null;
    }
    int day = Character.getNumericValue(input[i]) * 10
            + Character.getNumericValue(input[i + 1]);

    // first separator
    if (input[i + 2] != '-') {
        return null;
    }

    // month: two digits
    if (!Character.isDigit(input[i + 3]) || !Character.isDigit(input[i + 4])) {
        return null;
    }
    int month = Character.getNumericValue(input[i + 3]) * 10
              + Character.getNumericValue(input[i + 4]);

    // month range check
    if (month < 1 || month > 12) {
        return null;
    }
    // day range check according to month
    if (day < 1 || day > days[month - 1]) {
        return null;
    }

    // second separator
    if (input[i + 5] != '-') {
        return null;
    }

    // year: four digits
    if (!Character.isDigit(input[i + 6]) || !Character.isDigit(input[i + 7])
            || !Character.isDigit(input[i + 8]) || !Character.isDigit(input[i + 9])) {
        return null;
    }
    int year = Character.getNumericValue(input[i + 6]) * 1000
            + Character.getNumericValue(input[i + 7]) * 100
            + Character.getNumericValue(input[i + 8]) * 10
            + Character.getNumericValue(input[i + 9]);

    // allowed year range
    if (year < 2013 || year > 2015) {
        return null;
    }

    return new Date(day, month, year);
}

/** Formats a {@link Date} as "dd-mm-yyyy" with leading zeros. */
private static String format(Date d) {
    String day = (d.day < 10 ? "0" : "") + d.day;
    String month = (d.month < 10 ? "0" : "") + d.month;
    return day + "-" + month + "-" + d.year;
}

