/**
 * Determines whether the current window of S starting at {@code i} constitutes a
 * match for W.
 *
 * <p>The match is valid when:
 * <ul>
 *   <li>the rolling hash of the window equals the hash of W,</li>
 *   <li>the window does not overlap with a previously counted match (i >= end), and</li>
 *   <li>the actual sub‑arrays are equal (to protect against hash collisions).</li>
 * </ul>
 *
 * @param S    the source array
 * @param i    start index of the current window in S
 * @param W    the pattern array
 * @param hash current rolling hash of the window in S
 * @param want pre‑computed hash of W
 * @param M    length of W
 * @param end  index right after the last accepted match
 * @return true if the window is a genuine, non‑overlapping match
 */
private static boolean isValidMatch(int[] S, int i, int[] W,
                                   long hash, long want, int M, int end) {
    return hash == want && i >= end && checkSubarrayEqual(S, i, W, 0, M);
}

