/** Builds the reversed substring of {@code s} that ends after the k‑th vowel
 *  (counting from the end). If fewer than k vowels are present, returns null. */
private String buildReversedFragmentUntilKVowels(String s, int k) {
    StringBuilder sb = new StringBuilder();
    int vowelCount = 0;
    for (int i = s.length() - 1; i >= 0; i--) {
        char ch = s.charAt(i);
        sb.append(ch);
        if (vowels.contains(ch)) {
            vowelCount++;
            if (vowelCount == k) {
                return sb.toString();   // exactly k vowels reached
            }
        }
    }
    // Fewer than k vowels found
    return null;
}

