            int unhappy = peopleInCurr - happy;

            if (happy < 0 || unhappy < 0 || (peopleInCurr + happiness[curr]) % 2 != 0) {
                return new CUncleBogdanAndCountryHappiness.pair(0, 0, false);
            }

            int happyBelow = 0;
            int unHappyBelow = 0;
            for (Integer child : children) {
                if (par != child) {
                    CUncleBogdanAndCountryHappiness.pair p = dfs(people, happiness, child, tree, curr, peopleInSubtree);
                    if (p.happy > happy || !p.okBelow) {
