/* K == 2 : area of the smallest axis‑aligned rectangle that encloses any two points */
private static long minAreaForTwoPoints(int n, long[] x, long[] y) {
    long best = Long.MAX_VALUE;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            long x1 = Math.min(x[i], x[j]);
            long x2 = Math.max(x[i], x[j]);
            long y1 = Math.min(y[i], y[j]);
            long y2 = Math.max(y[i], y[j]);
            long area = (x2 - x1) * (y2 - y1);
            best = Math.min(best, area);
        }
    }
    return best;
}

