		for(int i = 0; i < m; i++, x ^= 1) {
			long time = i == 0 ? ts[i] - 1 : ts[i] - ts[i-1];
			time *= d;
			int front = 0, tail = 0, right = (int) Math.min(n, time+1);
			int left = -right+1;
			for(int j = 0; j <= Math.min(n-1, time); j++) {
				while(tail > front && dp[x^1][dq[tail-1]] <= dp[x^1][j]) tail--;
				dq[tail++] = j;
