    	for(int i = 0;i<n;i++){
    		String str = in.next();
    		arr[i]  = str.toCharArray();
    	}
    	cord start = new cord();
    	cord end = new cord();
    	start.x = in.nextInt() - 1;
    	start.y = in.nextInt() - 1;
    	end.x = in.nextInt() -1;
    	end.y = in.nextInt() -1;
    	int[] dx = {1,-1,0,0};
    	int[] dy = {0,0,1,-1};
    	Queue<cord> que = new LinkedList<>();
    	arr[start.x][start.y] = 'X';
    	que.add(start);
    	int flag = 1;
    	while(!que.isEmpty()){
    		cord temp = que.poll();
    		for(int i = 0;i<4;i++){
    			int r  = temp.x + dx[i];
    			int c = temp.y + dy[i];
    			if(r == end.x && c == end.y && arr[r][c] == 'X'){
    				flag = 0;
    				break;
    			}
    			if(r >= 0 && r< n && c>=0 && c<m && arr[r][c] == '.'){
    				arr[r][c] = 'X';
    				cord xo = new cord();
    				xo.x = r;
    				xo.y = c;
    				que.add(xo);
    			}
    		}
    	}
    	if(flag == 0)
    		System.out.println("YES");
    	else
    		System.out.println("NO");

    }

