static int check(int l,int a,int b,int c){
	if(l==0){
		return 0;
	}
    if(l<0||(l>0&&l<a&&l<b&&l<c)){
		return -1;
	}
	int left=Math.max(check(l-a,a,b,c),Math.max(check(l-b,a,b,c),check(l-c,a,b,c))+1);
	return left;

}

int bs(int low, int high, int lq, int rq) {
		int start = low;
		int end = high;
		while(low <= high) {
			int mid = low+(high-low)/2;
			if(buckets[mid].next > rq) high = mid-1;
			else low = mid+1;
		}
		if(start <= high && high <= end && lq <= buckets[high].next && buckets[high].next <= rq) return buckets[high].delta;
		return 0;
	}

