public static int restaurant(int a , int b , int c) {
		int ans = 0;
		if(a>0) {
			a--; ans++;
		}
		if(b>0) {
			b--; ans++;
		}
		if(c>0) {
			c--; ans++;
		}
		int highest = Math.max(a,Math.max(c, b));

		if(a==highest) {
			if(a>0&&b>0)
			{ a--; b--; ans++; }
			if(a>0&&c>0)
			{ a--; c--; ans++; }
			if(c>0&&b>0)
			{ c--; b--; ans++; }
		}

		if(b==highest) {
			if(c>0&&b>0)
			{ c--; b--; ans++; }
			if(a>0&&b>0)
			{ a--; b--; ans++; }
			if(c>0&&a>0)
			{ c--; a--; ans++; }
		}

		if(c==highest) {
			if(c>0&&b>0)
			{ c--; b--; ans++; }
			if(a>0&&c>0)
			{ a--; c--; ans++; }
			if(a>0&&b>0)
			{ a--; b--; ans++; }
		}

		if(a>0&&b>0&&c>0) {
			a--; b--; c--; ans++;
		}
		return ans;

	}

int solve() {
        int n = in.nextInt();
        int[] count = new int[n];
        long secondGroup = 0;
        for (int i = 0; i < n; i++) {
            count[i] = in.nextInt();
            secondGroup += count[i];
        }

        int x = in.nextInt();
        int y = in.nextInt();

        int firstGroup = 0;
        int k = 0;
        while (firstGroup < x) {
            firstGroup += count[k];
            secondGroup -= count[k];
            if (secondGroup < x) {
                return 0;
            }            
            k++;
        }

        while (secondGroup > y) {
            firstGroup += count[k];
            secondGroup -= count[k];
            if (firstGroup > y) {
                return 0;
            }
            k++;
        }
        if (firstGroup < x || firstGroup > y || secondGroup < x || secondGroup > y || k == n) {
            return 0;
        }
        return k + 1;
    }

