private static void update(int root, int rl, int rr, int idx) 
    {
        if(idx < rl || idx > rr)
            return;
        if(rl == rr)
        {
            tree[root] = idx;
            return;
        }

        int rm = rl + rr >> 1;
        update(2*root+1, rl, rm, idx);
        update(2*root+2, rm+1, rr, idx);

        if(tree[2*root+1] != -1 && (tree[2*root+2] == -1 || order[tree[2*root+1]][1] <= order[tree[2*root+2]][1]))
            tree[root] = tree[2*root+1];
        else
            tree[root] = tree[2*root+2];

    }

