/**
 * Returns true if the character represents a single digit that is
 * divisible by 4 (i.e., '0', '4' or '8').
 */
private static boolean isSingleDigitDivisibleBy4(char c) {
    return c == '0' || c == '4' || c == '8';
}

/**
 * Returns true if the two‑digit number formed by the high‑order digit
 * {@code high} and the low‑order digit {@code low} is divisible by 4.
 */
private static boolean isTwoDigitNumberDivisibleBy4(char high, char low) {
    int value = (high - '0') * 10 + (low - '0');
    return value % 4 == 0;
}

