/*--- helper methods ------------------------------------------------------*/

private static boolean tryFace(int[] cube, int face,
                               int[] requiredBefore,
                               int[] requiredAfter) {
    // pre‑condition: the two faces that must already be solved
    if (!allFacesDone(cube, requiredBefore)) {
        return false;
    }

    // rotate once, check condition
    rotateFace(cube, face);
    if (allFacesDone(cube, requiredAfter)) {
        return true;
    }

    // rotate two more times (total three), check condition again
    rotateFace(cube, face);
    rotateFace(cube, face);
    if (allFacesDone(cube, requiredAfter)) {
        return true;
    }

    // rotate back to the original orientation (fourth rotation)
    rotateFace(cube, face);
    return false;
}

private static boolean allFacesDone(int[] cube, int[] faces) {
    for (int f : faces) {
        if (!facedone(cube, f)) {
            return false;
        }
    }
    return true;
}

private static void rotateFace(int[] cube, int face) {
    switch (face) {
        case 1: rotateface1(cube); break;
        case 2: rotateface2(cube); break;
        case 4: rotateface4(cube); break;
        default:
            throw new IllegalArgumentException("Unsupported face: " + face);
    }
}

