    if (!isDivisibleBy(y, x)) {
        out.println(0);
        return;
    }

    long withoutGCD = y / x;

    // guard: the only possible pair is (1,1) and x itself lies in [l, r]
    if (isSingleFactorInRange(withoutGCD, x, l, r)) {
        out.println(1);
        return;
    }

    long lb = Math.max((long) Math.ceil((double) l / x), 1L);
    long ub = Math.max(r / x, 1L);
    long res = 0;

    for (long i = lb; i <= ub && i * i < withoutGCD; i++) {
        if (isValidDivisorPair(i, withoutGCD, ub)) {
            res += 2;
        }
    }

    out.println(res);
}

/** Returns true if y is divisible by x. */
private boolean isDivisibleBy(long y, long x) {
    return y % x == 0;
}

/** Returns true when withoutGCD == 1 and the sole possible number x lies inside [l, r]. */
private boolean isSingleFactorInRange(long withoutGCD, long x, long l, long r) {
    return withoutGCD == 1 && x >= l && x <= r;
}

/**
 * Checks the three‑part condition used inside the loop:
 *   1) i divides withoutGCD,
 *   2) the complementary divisor is not larger than the upper bound,
 *   3) the two divisors are coprime.
 */
private boolean isValidDivisorPair(long i, long withoutGCD, long ub) {
    if (withoutGCD % i != 0) {
        return false;
    }
    long counterpart = withoutGCD / i;
    return counterpart <= ub && gcd(i, counterpart) == 1;
}

/** Existing GCD helper (presumed to be defined elsewhere). */
private long gcd(long a, long b) {
    while (b != 0) {
        long tmp = a % b;
        a = b;
        b = tmp;
    }
    return Math.abs(a);
}

