public static void main(String[] args) {
    FastScanner fi = new FastScanner();
    String si = fi.next();
    int n = si.length();
    char[] s = si.toCharArray();
    int[][] dp = new int[n][n];
    int[] cnt = new int[n + 1];

    /* ---- handle substrings of length 1 and 2 ---- */
    for (int l = 0; l < n; l++) {
        for (int r = l; r < n; r++) {
            if (l == r) {
                dp[l][r] = 1;                     // was dp[l][r]++
            } else if (l == r - 1) {
                dp[l][r] = computeDpForAdjacent(l, r, s, dp);
            }
            cnt[dp[l][r]]++;
        }
    }

    /* ---- handle substrings of length ≥ 3 ---- */
    for (int l = n - 2; l >= 0; l--) {
        for (int r = l + 2; r < n; r++) {
            dp[l][r] = computeDpForEqualEnds(l, r, s, dp, n);
            cnt[dp[l][r]]++;
        }
    }

    /* ---- build the answer ---- */
    int[] ans = new int[n + 1];
    int totalSum = 0;
    for (int i = 1; i <= n; i++) {
        totalSum += cnt[i];
    }
    for (int i = 1; i <= n; i++) {
        ans[i] = totalSum;
        totalSum -= cnt[i];
        if (ans[i] < 0) {
            ans[i] = 0;
        }
        System.out.print(ans[i] + " ");
    }
}

/*--- helper methods that encapsulate the complex conditionals ---*/
private static int computeDpForAdjacent(int l, int r, char[] s, int[][] dp) {
    // l and r are consecutive indices
    if (s[l] != s[r]) {
        return 0;
    }
    int m = middleIndex(l, r);
    return (m >= 0) ? dp[l][m] + 1 : 0;
}

private static int computeDpForEqualEnds(int l, int r, char[] s, int[][] dp, int n) {
    // substrings where the first and last characters are equal
    if (s[l] != s[r]) {
        return 0;
    }
    int m = middleIndex(l, r);
    boolean middleOk = m >= 0
            && r >= 1
            && l < n - 1
            && l <= r - 2
            && dp[l + 1][r - 1] != 0;
    return middleOk ? dp[l][m] + 1 : 0;
}

private static int middleIndex(int l, int r) {
    // original expression: (int)Math.ceil((l+r)/2.0) - 1
    return (int) Math.ceil((l + r) / 2.0) - 1;
}

