private static long computeNeighbourContribution(int i, int j) {
    long S = 1;
    int[] neighbourComp = new int[4]; // 0: up, 1: left, 2: down, 3: right

    // up
    if (i > 0) {
        neighbourComp[0] = matrComp[i - 1][j];
        if (neighbourComp[0] != -1) {
            S += matrSqare[neighbourComp[0]];
            S %= 10;
        }
    }

