    if (j > 0) {
        neighbourComp[1] = matrComp[i][j - 1];
        if (neighbourComp[1] != -1 && neighbourComp[1] != neighbourComp[0]) {
            S += matrSqare[neighbourComp[1]];
            S %= 10;
        }
    }

    // down
    if (i < n - 1) {
        neighbourComp[2] = matrComp[i + 1][j];
        if (neighbourComp[2] != -1
                && neighbourComp[2] != neighbourComp[0]
                && neighbourComp[2] != neighbourComp[1]) {
            S += matrSqare[neighbourComp[2]];
            S %= 10;
        }
    }

