/** Computes the final answer for a single test case. */
private static int computeAnswer(int[][] matrix, int m, int n) {
    int[] colMax = columnMaximums(matrix);
    int minOfColMax = minValue(colMax);

    // Guard clause: when m ≤ n‑1 the answer is just the min of column maxima
    if (m <= n - 1) {
        return minOfColMax;
    }

    int secondLargest = maxSecondLargestInRows(matrix);
    return Math.min(secondLargest, minOfColMax);
}

/** Returns an array containing the maximum value of each column. */
private static int[] columnMaximums(int[][] matrix) {
    int cols = matrix[0].length;
    int[] max = new int[cols];
    for (int[] row : matrix) {
        for (int j = 0; j < cols; j++) {
            if (row[j] > max[j]) {
                max[j] = row[j];
            }
        }
    }
    return max;
}

/** Returns the smallest element of the given array. */
private static int minValue(int[] arr) {
    int min = arr[0];
    for (int i = 1; i < arr.length; i++) {
        if (arr[i] < min) {
            min = arr[i];
        }
    }
    return min;
}

/** Finds the largest among the second‑largest elements of each row. */
private static int maxSecondLargestInRows(int[][] matrix) {
    int best = Integer.MIN_VALUE;
    for (int[] row : matrix) {
        Arrays.sort(row);
        int second = row[row.length - 2]; // assumes n ≥ 2, same as original logic
        if (second > best) {
            best = second;
        }
    }
    return best;
}

