 * @param buildings array of original building heights
 * @return the total additional height needed
 */
private static long computeAddedCost(int mask, int[] buildings) {
    int currentMax = 0;
    long add = 0;
    for (int i = 0; i < buildings.length; i++) {
        if ((mask & (1 << i)) != 0) {
            add += Math.max(0, currentMax - buildings[i] + 1);
            currentMax = Math.max(currentMax + 1, buildings[i]);
        } else {
            currentMax = Math.max(currentMax, buildings[i]);
        }
    }
