private static void processTestCase(int[] nums) {
    int n = nums.length;
    for (int pre = 1; pre <= n; pre++) {
        int target = sumFirst(nums, pre);
        int initialCount = pre - 1;
        Integer result = tryPartition(nums, pre, target, initialCount);
        if (result != null) {
            System.out.println(result);
            return; // success – stop processing this test case
        }
    }
}

/**
 * Returns the sum of the first {@code length} elements of {@code a}.
 */
private static int sumFirst(int[] a, int length) {
    int sum = 0;
    for (int i = 0; i < length; i++) {
        sum += a[i];
    }
    return sum;
}

/**
 * Attempts to partition the array starting at {@code start} into consecutive
 * windows each summing to {@code target}. {@code count} holds the number of
 * elements processed so far. If the partition succeeds, the final count is
 * returned; otherwise {@code null} is returned.
 */
private static Integer tryPartition(int[] a, int start, int target, int count) {
    int i = start;
    while (i < a.length) {
        int windowSum = 0;
        // accumulate until we reach or exceed the target
        while (i < a.length && windowSum < target) {
            windowSum += a[i];
            count++;
            i++;
        }
        // guard clause – the window does not match the required sum
        if (windowSum != target) {
            return null;
        }
        // the last increment of count belongs to the next window,
        // so we compensate as in the original algorithm
        count--;
    }
    return count;
}

