public static int dfs(int start, int prev) {
    int color = colors[start - 1];

    Deque<Integer> stack = new ArrayDeque<>();
    stack.push(start);

    Set<Integer> visited = new HashSet<>();
    visited.add(start);

    while (!stack.isEmpty()) {
        int node = stack.pop();
        for (int neighbor : tree.get(node - 1)) {
            // Guard: ignore the edge we came from
            if (neighbor == prev) {
                continue;
            }
            // Guard: different colour – abort search
            if (!hasSameColor(neighbor, color)) {
                return -1;
            }
            // Guard: already visited – nothing to do
            if (visited.add(neighbor)) { // add returns true only if not present
                stack.push(neighbor);
            }
        }
    }
    return color;
}

