/**
 * Returns the maximum number of 3‑coins that are needed for any value in {@code A}
 * when at most {@code ones} 1‑coins and {@code twos} 2‑coins may be used.
 */
private static int computeRequiredThrees(int[] values, int ones, int twos) {
    int maxThrees = 0;
    for (int a : values) {
        int needed = minimalThreeCoins(a, ones, twos);
        maxThrees = Math.max(maxThrees, needed);
    }
    return maxThrees;
}

/**
 * Finds the smallest possible count of 3‑coins that, together with up to {@code ones}
 * 1‑coins and {@code twos} 2‑coins, composes the amount {@code a}.
 * Returns {@code INF} if the amount cannot be formed.
 */
private static int minimalThreeCoins(int a, int ones, int twos) {
    int minThree = INF;

    for (int i = 0; i <= ones; i++) {
        for (int j = 0; j <= twos; j++) {
            int remainder = a - i - 2 * j;

            // guard clauses – skip impossible or non‑divisible remainders
            if (remainder < 0) {
                continue;
            }
            if (remainder % 3 != 0) {
                continue;
            }

            minThree = Math.min(minThree, remainder / 3);
        }
    }
    return minThree;
}

