    }

    long[][] dp = new long[n + 1][n + 1];
    initDp(dp, n);
    fillDp(dp, n);
    long best = computeBest(dp, n);
    out.println(best);
}

/* initialise dp with “infinite” values */
private void initDp(long[][] dp, int n) {
    for (int i = 0; i <= n; i++) {
        Arrays.fill(dp[i], Long.MAX_VALUE);
    }
}

/* fill the dynamic‑programming table */
private void fillDp(long[][] dp, int n) {
    for (int len = 2; len < n - 1; len++) {
        for (int i = 0; i < n; i++) {
            for (int mid = 1; mid < len; mid++) {
                long cur = computeCost(i, len, mid, n, dp);
                dp[i][len] = Math.min(dp[i][len], cur);
            }
        }
    }
}

/* compute the cost for a particular (i, len, mid) triple */
private long computeCost(int i, int len, int mid, int n, long[][] dp) {
    int end = (i + len) % n;
    int m = (i + mid) % n;
    long cur = (long) (i + 1) * (end + 1) * (m + 1);

    // guard‑clause style: add sub‑problems only when they exist
    cur += (mid > 1) ? dp[i][mid] : 0;
    cur += (len - mid > 1) ? dp[m][len - mid] : 0;

    return cur;
}

/* compute the final answer from the filled dp table */
private long computeBest(long[][] dp, int n) {
    long best = dp[1][n - 2] + 2L * n;

    for (int len = 2; len < n - 1; len++) {
        long candidate = dp[0][len] + dp[len][n - len];
        best = Math.min(best, candidate);
    }
    return best;
}

public void solve(int testNumber, FastScanner in, PrintWriter out) {
    int n = in.ni();
    if (n == 3) {
        out.println(6);
        return;
    }

    long[][] dp = new long[n + 1][n + 1];
    for (int i = 0; i <= n; i++) {
        Arrays.fill(dp[i], Long.MAX_VALUE);
    }

    // fill dp for all possible segment lengths
    for (int len = 2; len < n - 1; len++) {
        for (int i = 0; i < n; i++) {
            int end = (i + len) % n;
            dp[i][len] = computeBestForSegment(i, end, len, dp);
        }
    }

    long best = dp[1][n - 2] + 2L * n;
    for (int len = 2; len < n - 1; len++) {
        best = Math.min(best, dp[0][len] + dp[len][n - len]);
    }
    out.println(best);
}

/**
 * Computes the minimal cost for a fixed segment (i … end) of length {@code len}.
 * The heavy work – iterating over possible middle points – is isolated here.
 */
private static long computeBestForSegment(int i, int end, int len, long[][] dp) {
    long min = Long.MAX_VALUE;
    for (int mid = 1; mid < len; mid++) {
        int m = (i + mid) % n;               // actual vertex index of the middle point
        long cur = triangleCost(i, end, m);  // base triangle cost

        // add sub‑problems only when they contain at least two vertices
        if (mid > 1) {
            cur += dp[i][mid];
        }
        if (len - mid > 1) {
            cur += dp[m][len - mid];
        }
        min = Math.min(min, cur);
    }
    return min;
}

/**
 * Returns the cost of the triangle formed by vertices (i, end, m)
 * using 1‑based indexing as required by the original formula.
 */
private static long triangleCost(int i, int end, int m) {
    return (long) (i + 1) * (end + 1) * (m + 1);
}

