/**
 * Searches the sub‑matrix that starts just after (startRow,startCol)
 * and returns the position of the smallest element together with its value.
 */
private static MinInfo findMinInTail(int startRow, int startCol,
                                     int[][] table, int[] numberColumn) {
    int minRow = startRow;
    int minCol = startCol;
    int minValue = table[startRow][startCol];

    for (int i = startRow; i < table.length; i++) {
        int colStart = (i == startRow) ? startCol + 1 : 0;
        for (int j = colStart; j < numberColumn[i]; j++) {
            int cur = table[i][j];
            if (cur < minValue) {
                minValue = cur;
                minRow = i;
                minCol = j;
            }
        }
    }
    return new MinInfo(minRow, minCol, minValue);
}

/** Swaps two elements of the matrix. */
private static void swap(int[][] table, int r1, int c1, int r2, int c2) {
    int tmp = table[r1][c1];
    table[r1][c1] = table[r2][c2];
    table[r2][c2] = tmp;
}

