/**
 * Returns {@code true} if the substring s[l..r] brings the walk back to the origin.
 * The method isolates the inner most loop and the switch, flattening the call‑site.
 */
private static boolean isZeroDisplacement(String s, int l, int r) {
    int dx = 0;
    int dy = 0;

    for (int i = l; i <= r; i++) {
        char c = s.charAt(i);
        switch (c) {
            case 'U': dy++; break;
            case 'D': dy--; break;
            case 'L': dx++; break;
            case 'R': dx--; break;
            default:   // no‑op for unexpected characters
        }
    }

    // Guard clause – return early when the displacement is not zero
    return dx == 0 && dy == 0;
