/**
 * Returns true if the substring s[left..right] has net displacement (0,0)
 * after applying the moves: U/D change dy, L/R change dx.
 */
private boolean isZeroDisplacement(String s, int left, int right) {
    int dx = 0;
    int dy = 0;
    for (int i = left; i <= right; i++) {
        char c = s.charAt(i);
        if (c == 'U') {
            dy++;
        } else if (c == 'D') {
            dy--;
        } else if (c == 'L') {
            dx++;
        } else if (c == 'R') {
            dx--;
        }
    }
    return dx == 0 && dy == 0;
}

