            int n = A.length;
            long[][] C = new long[n][n];
            for(int i = 0;i < n;i++){
                long[] sum = new long[n];
                for(int k = 0;k < n;k++){
                    for(int j = 0;j < n;j++){
                        sum[j] += A[i][k] * A[k][j];
                        if(sum[j] >= BIG) sum[j] -= BIG;
                    }
                }
                for(int j = 0;j < n;j++){
                    C[i][j] = (sum[j] % MOD);
                }
            }
            return C;
        }

