/**
 * Returns a list containing all elements of the sorted array except the
 * elements at the two specified indices.
 */
private static List<Integer> remainingElements(int[] sorted, int idx1, int idx2) {
    List<Integer> result = new ArrayList<>(sorted.length - 2);
    for (int k = 0; k < sorted.length; k++) {
        if (k != idx1 && k != idx2) {
            result.add(sorted[k]);
        }
    }
    return result;
}

/**
 * Given a sorted list with even length, computes the sum of differences
 * between each consecutive pair: (list[1]-list[0]) + (list[3]-list[2]) + ...
 */
private static long pairDifferenceSum(List<Integer> list) {
    long sum = 0L;
    for (int i = 0; i < list.size() - 1; i += 2) {
        sum += list.get(i + 1) - list.get(i);
    }
    return sum;
}

