/**
 * Returns the distance (index of 'S' minus index of 'G') for a given row.
 * If either character is missing the method returns the difference using
 * the last seen positions (original code behaved the same).
 */
private int computeDistance(String row, int length) {
    int gPos = -1;
    int sPos = -1;

    for (int k = 0; k < length; k++) {
        char ch = row.charAt(k);
        if (ch == 'G') {
            gPos = k;
        } else if (ch == 'S') {
            sPos = k;
        }

        // Guard clause – stop scanning once both positions are known
        if (gPos != -1 && sPos != -1) {
            break;
        }
    }
    return sPos - gPos;
}

