        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                if (s.charAt(i - 1) == t.charAt(j - 1)) {
                    updateMatch(c, i, j, dyn);
                } else {
                    updateMismatch(c, i, j, dyn);
                }
                propagateBest(c, i, j, dyn);
            }
        }
    }

    int solution = 0;
    for (int c = 1; c <= k; c++) {
        solution = max(solution, dyn[0][c][n][m], dyn[1][c][n][m]);
    }
    out.println(solution);
}

/**
 * Handles the case where the current characters of the two strings are equal.
 * Updates the “matched” DP layer (dyn[1]).
 */
private static void updateMatch(int c, int i, int j, int[][][][] dyn) {
    dyn[1][c][i][j] = max(
            dyn[1][c][i][j],
            1 + dyn[1][c][i - 1][j - 1],
            1 + dyn[0][c - 1][i - 1][j - 1]
    );
}

/**
 * Handles the case where the current characters differ.
 * Updates the “non‑matched” DP layer (dyn[0]).
 */
private static void updateMismatch(int c, int i, int j, int[][][][] dyn) {
    dyn[0][c][i][j] = max(
            dyn[0][c][i][j],
            dyn[0][c][i - 1][j - 1],
            dyn[1][c][i - 1][j - 1]
    );
}

/**
 * After processing a cell, propagate the best achievable value to dyn[0][c][i][j].
 */
private static void propagateBest(int c, int i, int j, int[][][][] dyn) {
    dyn[0][c][i][j] = max(
            dyn[0][c][i][j],
            dyn[0][c][i - 1][j],
            dyn[0][c][i][j - 1],
            dyn[1][c][i - 1][j],
            dyn[1][c][i][j - 1]
    );
}

public static void solve(FastReader in, PrintWriter out) {
    int n = in.readInt();
    int m = in.readInt();
    int k = in.readInt();
    String s = in.readString();
    String t = in.readString();

    int[][][][] dyn = new int[2][k + 1][n + 1][m + 1];

    for (int c = 1; c <= k; c++) {
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                processCell(c, i, j, s, t, dyn);
            }
        }
    }

    int solution = 0;
    for (int c = 1; c <= k; c++) {
        solution = max(solution, dyn[0][c][n][m], dyn[1][c][n][m]);
    }
    out.println(solution);
}

/**
 * Updates the DP tables for a single cell (i, j) and a given number of
 * allowed substrings c.  The method encapsulates the original nested
 * conditional logic, preserving the exact algorithmic behaviour.
 */
private static void processCell(int c, int i, int j,
                                String s, String t,
                                int[][][][] dyn) {
    if (s.charAt(i - 1) == t.charAt(j - 1)) {
        // characters match – we may extend a matching segment
        dyn[1][c][i][j] = max(dyn[1][c][i][j],
                             1 + dyn[1][c][i - 1][j - 1],
                             1 + dyn[0][c - 1][i - 1][j - 1]);
    } else {
        // characters differ – we cannot extend a matching segment
        dyn[0][c][i][j] = max(dyn[0][c][i][j],
                             dyn[0][c][i - 1][j - 1],
                             dyn[1][c][i - 1][j - 1]);
    }

    // Propagate the best value when ending the current segment
    dyn[0][c][i][j] = max(dyn[0][c][i][j],
                         dyn[0][c][i - 1][j],
                         dyn[0][c][i][j - 1],
                         dyn[1][c][i - 1][j],
                         dyn[1][c][i][j - 1]);
}

