/**
 * Searches for the first (n, m) such that
 * sqr(n) - sqr(n / m) == target.
 * Returns an int[2] containing {n, m} or null if not found.
 */
private int[] findPair(int target) {
    for (int n = 1; n <= 36514; n++) {
        int low = 1, high = n;
        while (low <= high) {
            int mid = (low + high) >>> 1;
            int value = sqr(n) - sqr(n / mid);

            if (value < target) {
                low = mid + 1;
            } else if (value > target) {
                high = mid - 1;
            } else {
                // Guard clause – found the answer, exit early
                return new int[] { n, mid };
            }
        }
    }
    // No pair satisfies the condition
    return null;
}

