/**
 * Computes the set of rolling‑hash values for all substrings that start with {@code startPattern}
 * and end with {@code endPattern}, and whose length is at least the larger of the two pattern lengths.
 */
private static Set<Long> computeHashes(String text, String startPattern, String endPattern) {
    int textLen = text.length();

    // 1 = position of a start‑pattern, 0 = otherwise
    int[] startMarkers = markPattern(text, startPattern, true);
    // 1 = position of the last character of an end‑pattern, 0 = otherwise
    int[] endMarkers   = markPattern(text, endPattern, false);

    int minLen = Math.max(startPattern.length(), endPattern.length());
    Set<Long> hashSet = new HashSet<>();

    for (int i = 0; i < textLen; i++) {
        // guard clause – skip positions that are not a start marker
        if (startMarkers[i] != 1) {
            continue;
        }

        long rollingHash = 0L;
        for (int j = i; j < textLen; j++) {
            rollingHash = rollingHash * 31 + (text.charAt(j) - 'a' + 1);

            // guard clause – we only care when an end marker is found
            if (endMarkers[j] != 1) {
                continue;
            }

            int segmentLength = j - i + 1;
            if (segmentLength >= minLen) {
                hashSet.add(rollingHash);
            }
        }
    }
    return hashSet;
}

/**
 * Marks occurrences of {@code pattern} inside {@code text}.
 *
 * @param text        the source string
 * @param pattern     the substring to look for
 * @param markStart   if {@code true}, marks the start index of each match;
 *                    otherwise marks the index of the last character of each match
 * @return an int array where a 1 indicates a marked position
 */
private static int[] markPattern(String text, String pattern, boolean markStart) {
    int textLen = text.length();
    int[] markers = new int[textLen];

    int limit = textLen - pattern.length();
    for (int i = 0; i <= limit; i++) {
        if (text.substring(i, i + pattern.length()).equals(pattern)) {
            if (markStart) {
                markers[i] = 1;
            } else {
                markers[i + pattern.length() - 1] = 1;
            }
        }
    }
    return markers;
}

public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    String text = sc.nextLine();   // x
    String start = sc.nextLine();  // st
    String end = sc.nextLine();    // en

    Set<Long> distinctHashes = computeDistinctHashes(text, start, end);
    System.out.println(distinctHashes.size());
}

/**
 * Core algorithm – builds the start/end marker arrays, then iterates
 * over all substrings that begin with {@code start} and end with {@code end},
 * hashes them and stores the distinct values in a set.
 */
private static Set<Long> computeDistinctHashes(String text, String start, String end) {
    int n = text.length();
    int[] startMarks = buildMarks(text, start, true);
    int[] endMarks   = buildMarks(text, end, false);

    int minLength = Math.max(start.length(), end.length());
    Set<Long> hashSet = new HashSet<>();

    for (int i = 0; i < n; i++) {
        // guard clause – skip positions that are not a valid start
        if (startMarks[i] != 1) {
            continue;
        }

        long hash = 0L;
        for (int j = i; j < n; j++) {
            hash = hash * 31 + (text.charAt(j) - 'a' + 1);

            // guard clause – only consider substrings that end correctly
            if (endMarks[j] != 1) {
                continue;
            }

            int length = j - i + 1;
            if (length >= minLength) {
                hashSet.add(hash);
            }
        }
    }
    return hashSet;
}

/**
 * Builds a marker array for either the start‑pattern or the end‑pattern.
 *
 * @param text          the source string
 * @param pattern       the pattern to locate
 * @param forStart      {@code true} if building the start‑pattern array,
 *                      {@code false} for the end‑pattern array
 * @return an int[] where a cell is 1 if the pattern matches ending (forStart==false)
 *         or starting (forStart==true) at that index; otherwise 0.
 */
private static int[] buildMarks(String text, String pattern, boolean forStart) {
    int n = text.length();
    int[] marks = new int[n];
    int plen = pattern.length();

    // we can only match while the pattern fits completely inside the text
    for (int i = 0; i <= n - plen; i++) {
        if (text.substring(i, i + plen).equals(pattern)) {
            if (forStart) {
                marks[i] = 1;                     // start of a valid substring
            } else {
                marks[i + plen - 1] = 1;           // end of a valid substring
            }
        }
    }
    return marks;
}

