/**
 * Returns the maximum length of a contiguous substring of {@code s}
 * that contains at most {@code maxRep} characters different from the
 * target character (identified by {@code targetIdx}, where 0 = 'a', …, 25 = 'z').
 */
private int maxLengthWithReplacements(char[] s, int targetIdx, int maxRep) {
    int n = s.length;
    int left = 0;
    int otherChars = 0;
    int max = 0;

    for (int right = 0; right < n; right++) {
        // Guard clause: if the current character matches the target, we can
        // skip the replacement‑count logic and directly update max.
        if (s[right] - 'a' == targetIdx) {
            max = Math.max(max, right - left + 1);
            continue;
        }

        // Current character is different from the target.
        otherChars++;

        // Shrink the window until we are back within the allowed replacements.
        while (otherChars > maxRep) {
            if (s[left] - 'a' != targetIdx) {
                otherChars--;
            }
            left++;
        }

        max = Math.max(max, right - left + 1);
    }

    return max;
}

