/**
 * Counts all sub‑rectangles of the given grid that contain
 * at least {@code k} cells equal to 1.
 */
private int countRectanglesWithAtLeastKOnes(int[][] grid, int rows, int cols, int k) {
    int count = 0;
    for (int top = 0; top < rows; top++) {
        for (int left = 0; left < cols; left++) {
            for (int bottom = top; bottom < rows; bottom++) {
                for (int right = left; right < cols; right++) {
                    int sum = rectangleSum(grid, top, left, bottom, right);
                    if (sum < k) {
                        continue;               // guard clause – skip non‑qualifying rectangle
                    }
                    count++;
                }
            }
        }
    }
    return count;
}

/**
 * Returns the sum of the cells inside the rectangle
 * defined by its top‑left (top, left) and bottom‑right (bottom, right) corners.
 */
private int rectangleSum(int[][] grid, int top, int left, int bottom, int right) {
    int sum = 0;
    for (int i = top; i <= bottom; i++) {
        for (int j = left; j <= right; j++) {
            sum += grid[i][j];
        }
    }
    return sum;
}

