private boolean readLINE() throws IOException {
    // Guard clause for the initial EOF condition
    if ($readCount == EOF) {
        return false;
    }

    while (true) {
        // Scan the current buffer; if a line is finished, return true.
        if (processBufferSegment()) {
            return true;
        }

        // Buffer exhausted without newline – read the next chunk.
        $index = 0;
        $readCount = stream.read(buffer);
        if ($readCount == EOF) {
            // End of stream after processing the last segment.
            return true;
        }
    }
}

/**
 * Scans the current buffer from $index up to $readCount.
 *
 * @return true if a newline was found (or EOF reached while scanning);
 *         false if the buffer ended without a newline.
 */
private boolean processBufferSegment() {
    while ($index < $readCount) {
        if (buffer[$index] == NL) {
            // Newline found – consume it and signal completion.
            $index++;
            return true;
        }

        // Not a newline: copy the char into the line buffer,
        // expanding the buffer if necessary.
        if (itr == cBuff.length) {
            inc();
        }
        cBuff[itr++] = (char) buffer[$index++];
    }
    // No newline encountered in this segment.
    return false;
}

private boolean readLINE() throws IOException {
    // Guard: nothing left to read
    if ($readCount == EOF) {
        return false;
    }

    for (itr = 0;;) {
        // Process the current buffer
        while ($index < $readCount) {
            if (isNewLine(buffer[$index])) {
                $index++;                 // consume the newline
                return true;              // line completed
            }
            ensureCapacity();            // grow cBuff if needed
            cBuff[itr++] = (char) buffer[$index++];
        }

        // Buffer exhausted – try to read more
        if (!readMore()) {               // EOF reached while refilling
            return true;                 // last line (may be empty) is ready
        }
    }
}

/* Helper: newline test */
private boolean isNewLine(byte b) {
    return b == NL;
}

/* Helper: make sure there is room for another char in cBuff */
private void ensureCapacity() {
    if (itr == cBuff.length) {
        inc();                         // existing method that expands cBuff
    }
}

/* Helper: refill the byte buffer; returns false if EOF */
private boolean readMore() throws IOException {
    $index = 0;
    $readCount = stream.read(buffer);
    return $readCount != EOF;
}

