    for (long[] row : dp) {
        Arrays.fill(row, -1L);
    }
    for (int i = 0; i <= n; i++) {
        dp[i][0] = W;               // zero birds → only initial water
    }

    int answer = 0;
    for (int nest = 1; nest <= n; nest++) {
        answer = Math.max(answer, fillDpForNest(
                nest, totalBirds, c, cost, dp, W, B, X));
    }

    PrintWriter pw = new PrintWriter(System.out);
    pw.println(answer);
    pw.close();
}

/**
 * Fills dp[nest][*] based on dp[nest‑1][*] and returns the greatest
 * number of birds that become reachable after processing this nest.
 */
private static int fillDpForNest(int nestIdx,
                                 int maxBirds,
                                 int[] c,
                                 int[] cost,
                                 long[][] dp,
                                 long W,
                                 long B,
                                 long X) {
    int capacity = c[nestIdx - 1];               // birds that can be placed in this nest
    for (int birds = 1; birds <= maxBirds; birds++) {
        long maxM = W + birds * B;                // theoretical maximum water after feeding
        for (int x = 0; x <= capacity && x <= birds; x++) {
            long prev = dp[nestIdx - 1][birds - x];
            if (prev == -1) {
                continue;                         // guard: no feasible state to extend
            }

            long newM = Math.min(W + (birds - x) * B, prev + X)
                        - (long) cost[nestIdx - 1] * x;
            if (newM < 0) {
                continue;                         // guard: not enough water after paying costs
            }

            long candidate = Math.min(newM, maxM);
            dp[nestIdx][birds] = Math.max(dp[nestIdx][birds], candidate);
        }
    }

    // find the largest birds count that has a reachable state
    for (int b = maxBirds; b >= 1; b--) {
        if (dp[nestIdx][b] != -1) {
            return b;
        }
    }
    return 0;
}

public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    int n = sc.nextInt();
    long W = sc.nextInt(), B = sc.nextInt(), X = sc.nextInt();

    int[] c = new int[n];
    int totalBirds = 0;
    for (int i = 0; i < n; i++) {
        totalBirds += c[i] = sc.nextInt();
    }

    int[] cost = new int[n];
    for (int i = 0; i < n; i++) {
        cost[i] = sc.nextInt();
    }

    int answer = computeMaxBirds(n, W, B, X, c, cost, totalBirds);

    PrintWriter pw = new PrintWriter(System.out);
    pw.println(answer);
    pw.close();
}

/**
 * Computes the maximum number of birds that can be kept.
 */
private static int computeMaxBirds(int n, long W, long B, long X,
                                   int[] c, int[] cost, int totalBirds) {
    long[][] dp = new long[n + 1][totalBirds + 1];
    fillWithMinusOne(dp);

    // base case: zero birds ⇒ we have the initial water amount
    for (int i = 0; i <= n; i++) {
        dp[i][0] = W;
    }

    int maxAchievable = 0;

    for (int nest = 1; nest <= n; nest++) {
        int capacity = c[nest - 1];
        int nestCost = cost[nest - 1];

        for (int birds = 1; birds <= totalBirds; birds++) {
            long maxWater = W + birds * B;
            dp[nest][birds] = -1; // initialise for this (nest, birds) pair

            int maxTake = Math.min(capacity, birds);
            for (int taken = 0; taken <= maxTake; taken++) {
                long previousWater = dp[nest - 1][birds - taken];
                if (previousWater == -1) {
                    continue;                       // guard clause
                }

                long waterAfterFeeding = Math.min(W + (birds - taken) * B,
                                                  previousWater + X);
                long waterAfterCost = waterAfterFeeding - (long) nestCost * taken;
                if (waterAfterCost < 0) {
                    continue;                       // guard clause
                }

                long feasibleWater = Math.min(waterAfterCost, maxWater);
                dp[nest][birds] = Math.max(dp[nest][birds], feasibleWater);
                maxAchievable = birds;               // record the highest reachable birds
            }
        }
    }
    return maxAchievable;
}

/**
 * Utility method to fill a 2‑D long array with -1.
 */
private static void fillWithMinusOne(long[][] matrix) {
    for (long[] row : matrix) {
        Arrays.fill(row, -1L);
    }
}

public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    int n = sc.nextInt();
    long W = sc.nextInt(), B = sc.nextInt(), X = sc.nextInt();

    int[] c = new int[n];
    int totalBirds = 0;
    for (int i = 0; i < n; i++) {
        totalBirds += c[i] = sc.nextInt();
    }

    int[] cost = new int[n];
    for (int i = 0; i < n; i++) {
        cost[i] = sc.nextInt();
    }

    long[][] dp = new long[n + 1][totalBirds + 1];
    initialiseDp(dp, n, totalBirds, W);
    computeDp(dp, n, totalBirds, W, B, X, c, cost);

    int answer = findMaximumReachableBirds(dp, n, totalBirds);

    PrintWriter pw = new PrintWriter(System.out);
    pw.println(answer);
    pw.close();
}

/* initialise the DP table – set all entries to -1 and dp[i][0] = W */
private static void initialiseDp(long[][] dp, int n, int totalBirds, long W) {
    for (long[] row : dp) {
        java.util.Arrays.fill(row, -1L);
    }
    for (int i = 0; i <= n; i++) {
        dp[i][0] = W;
    }
}

/* fill the DP table */
private static void computeDp(long[][] dp, int n, int totalBirds,
                             long W, long B, long X,
                             int[] c, int[] cost) {
    for (int nest = 1; nest <= n; nest++) {
        updateDpForNest(nest, totalBirds, W, B, X, c, cost, dp);
    }
}

/* process a single nest – core logic extracted from the original loops */
private static void updateDpForNest(int nest, int totalBirds,
                                    long W, long B, long X,
                                    int[] c, int[] cost,
                                    long[][] dp) {
    for (int birds = 1; birds <= totalBirds; birds++) {
        long maxCapacity = W + birds * B;
        long best = -1L;

        int limit = Math.min(c[nest - 1], birds);
        for (int x = 0; x <= limit; x++) {
            long previous = dp[nest - 1][birds - x];
            if (previous == -1) {
                continue;               // guard clause
            }

            long afterFeeding = Math.min(W + (birds - x) * B,
                                         previous + X);
            long newM = afterFeeding - (long) cost[nest - 1] * x;
            if (newM < 0) {
                continue;               // guard clause
            }

            best = Math.max(best, Math.min(newM, maxCapacity));
        }
        dp[nest][birds] = best;
    }
}

/* after DP is filled, the answer is the largest birds count reachable */
private static int findMaximumReachableBirds(long[][] dp, int n, int totalBirds) {
    for (int birds = totalBirds; birds >= 0; birds--) {
        if (dp[n][birds] != -1) {
            return birds;
        }
    }
    return 0;
}

