long func(long n) {
    // Memoization guard
    if (hash.containsKey(n)) {
        return hash.get(n);
    }

    boolean same = false;
    long now = n;
    long res = -1;
    int maxLen = Long.toString(n).length();

    for (int dlen = maxLen; dlen >= 1; dlen--) {
        int combinations = 1 << dlen;
        for (int mask = 0; mask < combinations; mask++) {
            long d = buildNumber(mask, dlen);

            // Guard clauses – flatten the nested conditionals
            if (d == n) {
                same = true;
                continue;
            }
            if (now < d) {
                continue;
            }
            if (now % d != 0) {
                continue;
            }

            // At this point d is a valid divisor different from n
            long candidate = func(now / d) + func(d);
            res = Math.max(res, candidate);
        }
    }

    // Resolve the result after the loops
    if (same) {
        res = Math.max(res, 1);
    } else if (res == -1) {
        res = -100000000;
    }

    hash.put(n, res);
    return res;
}

/**
 * Constructs a number whose digits are either 8 or 2.
 * The binary representation of {@code mask} determines the digit:
 * 0 → 8, 1 → 2, starting from the least‑significant digit.
 */
private long buildNumber(int mask, int digitLength) {
    long value = 0;
    long ten = 1;
    for (int pos = 0; pos < digitLength; pos++) {
        if ((mask & (1 << pos)) == 0) {
            value += ten * 8;
        } else {
            value += ten * 2;
        }
        ten *= 10;
    }
    return value;
}

