/**
 * Counts ordered pairs (i, j) (i < j) whose third word also exists in the set.
 * The returned value is the raw count; the caller divides by 3 to obtain the
 * number of distinct SET triples.
 */
private static int countValidTriples(Set<String> set, String[] words, int n, int k) {
    int count = 0;
    for (int i = 1; i < n; i++) {
        for (int j = i + 1; j <= n; j++) {
            String third = buildThirdWord(words[i], words[j], k);
            if (!set.contains(third)) {
                continue;                       // guard clause – skip when no match
            }
            count++;
        }
    }
    return count;
}

/**
 * Builds the third word that completes a SET trio given two words.
 * For each position:
 *   - if the characters are equal, keep that character;
 *   - otherwise the missing character is the one not present among {'S','E','T'}.
 */
private static String buildThirdWord(String a, String b, int k) {
    StringBuilder sb = new StringBuilder(k);
    for (int pos = 0; pos < k; pos++) {
        char ca = a.charAt(pos);
        char cb = b.charAt(pos);
        if (ca == cb) {
            sb.append(ca);
        } else {
            sb.append((char) ('S' + 'E' + 'T' - ca - cb));
        }
    }
    return sb.toString();
}

