private static int findMinimumAdjustments(int[] arr) {
    int diff = arr[1] - arr[0];
    int min = Integer.MAX_VALUE;

    for (int step = diff - 2; step <= diff + 2; step++) {
        for (int adjust = -1; adjust <= 1; adjust++) {
            Integer count = evaluate(arr, step, adjust);
            if (count != null && count < min) {
                min = count;
            }
        }
    }
    return min;
}

/**
 * Evaluates a candidate progression defined by a step size and an adjustment
 * to the first element. Returns the total number of unit adjustments needed,
 * or {@code null} if the candidate is invalid (any element deviates by more than 1).
 */
private static Integer evaluate(int[] arr, int step, int adjust) {
    int totalAdjust = Math.abs(adjust);
    int expected = arr[0] + adjust; // simulated first element after adjustment

    for (int idx = 1; idx < arr.length; idx++) {
        expected += step;
        int diff = Math.abs(arr[idx] - expected);
        if (diff > 1) {
            return null; // guard clause – candidate fails
        }
        totalAdjust += diff;
    }
    return totalAdjust;
}

