/**
 * Updates dp[i+1][j][l] based on the current coin.
 * Guard clauses replace the deep nested if‑structures.
 */
private static void updateDPCell(int i, int j, int l, int coin) {
    int prevJ = j - coin;
    int prevL = l - coin;

    // Guard: if we cannot take the coin for the first sum, skip inner work
    if (prevJ >= 0) {
        dp[i + 1][j][l] |= dp[i][prevJ][l];
        // Guard: second sum also needs the coin
        if (prevL >= 0) {
            dp[i + 1][j][l] |= dp[i][prevJ][prevL];
        }
    }
    // The case of not using the current coin
    dp[i + 1][j][l] |= dp[i][j][l];
}

/**
 * Scans the DP table to fill the result array and returns the count of
 * reachable sums.
 */
private static int collectResultsAndCount(int k, int n) {
    int count = 1; // we always count sum 0 (res[0] is false initially)
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < n + 1; j++) {
            if (dp[j][k][i] && !res[i]) {
                res[i] = true;
                count++;
            }
        }
    }
    // Ensure k itself is marked reachable
    res[k] = true;
    return count;
}

