/** Updates dp[i+1][j][l] based on the current coin.
 *  Guard clauses keep the method flat and readable. */
private static void updateDP(int i, int j, int l) {
    int tmp1 = j - coins[i];
    int tmp2 = l - coins[i];

    // If the first dimension cannot use the coin, skip to the copy‑over case.
    if (tmp1 < 0) {
        dp[i + 1][j][l] |= dp[i][j][l];
        return;
    }

    // First possibility: use the coin for the first sum.
    dp[i + 1][j][l] |= dp[i][tmp1][l];

    // Second possibility: use the coin for both sums, if feasible.
    if (tmp2 >= 0) {
        dp[i + 1][j][l] |= dp[i][tmp1][tmp2];
    }

    // Always keep the “do not take this coin” state.
    dp[i + 1][j][l] |= dp[i][j][l];
}

/** Counts how many distinct sums are reachable and marks them in `res`.
 *  Returns the total count (including 0). */
private static int computeResultCount(int k, int n) {
    int cnt = 1; // sum 0 is always reachable
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < n + 1; j++) {
            if (dp[j][k][i] && !res[i]) {
                res[i] = true;
                cnt++;
            }
        }
    }
    return cnt;
}

