/**
 * Computes the value for dp[i][j] following the original nested logic.
 *
 * @param i  current index in the array
 * @param j  colour/state we are evaluating (0, 1 or 2)
 * @param a  input values
 * @param dp DP table already filled for positions > i
 * @return the minimal cost for dp[i][j]
 */
private static int computeDpCell(int i, int j, int[] a, int[][] dp) {
    // base case: take the default transition
    int best = 1 + dp[i + 1][2];

    // try the two possible bit‑positions (k = 0,1)
    for (int k = 0; k < 2; k++) {
        // guard‑clauses – skip iterations that do not satisfy the original condition
        if (((1 << k) & a[i]) == 0) {
            continue;                     // bit k is not set in a[i]
        }
        if (k == j) {
            continue;                     // same colour/state, not allowed
        }
        // update the best value using the alternative transition
        best = Math.min(best, dp[i + 1][k]);
    }
    return best;
}

