    for (int i = 0; i < m; i++) {
        in[i][1] = sc.nextInt() / sc.nextInt(); // ratio
        in[i][0] = sc.nextInt();                // length
        in[i][2] = sc.nextInt();                // value
    }
    // add the final “item”
    in[m][0] = c0;
    in[m][1] = n;
    in[m][2] = d0;

    int[][] dp = new int[n + 1][m + 1];
    int[] best = new int[n + 1];

    for (int i = 1; i <= n; i++) {
        int[] bestArray = dp[i - 1];   // current best combination up to i‑1
        int bestScore = best[i - 1];   // current best score up to i‑1

        for (int j = 0; j <= m; j++) {
            // guard clauses – flatten the logic
            if (in[j][0] > i) {
                continue;                 // cannot use this item yet
            }
            int[] prev = dp[i - in[j][0]];
            int prevScore = best[i - in[j][0]];
            if (prev[j] >= in[j][1]) {
                continue;                 // usage limit exceeded
            }
            int currentScore = prevScore + in[j][2];
            if (currentScore <= bestScore) {
                continue;                 // not an improvement
            }

            // core update – this path is reached only when all guards passed
            bestArray = prev.clone();
            bestArray[j]++;                // record usage of item j
            bestScore = currentScore;
        }

        dp[i] = bestArray;
        best[i] = bestScore;
    }

    System.out.println(best[n]);
}

