/** Return how many prime factors (including repetitions) the number `value` has. */
private static int countPrimeFactors(long value) {
    int factorCount = 0;
    for (long divisor = 2; divisor * divisor <= value; divisor++) {
        if (value % divisor != 0) {
            continue;                       // guard clause – skip non‑divisors
        }
        while (value % divisor == 0) {
            value /= divisor;
            factorCount++;
        }
    }
    if (value > 1) {
        factorCount++;                       // the remaining value is a prime
    }
    return factorCount;
}

