/** Binary‑searches the smallest mid that makes the remaining height non‑positive. */
private long findMinimumMid(long h, long[] a) {
    long low = 0, high = h, best = h;
    while (low <= high) {
        long mid = low + (high - low) / 2;

        if (canFinishWith(mid, h, a)) {
            best = mid;          // guard clause: feasible → try smaller values
            high = mid - 1;
        } else {
            low = mid + 1;       // not feasible → need larger mid
        }
    }
    return best;
}

/** Returns true if using the given “mid” value reduces the remaining height to ≤ 0. */
private boolean canFinishWith(long mid, long h, long[] a) {
    long remain = h;

    // apply the reduction for each segment
    for (int i = 1; i < a.length; i++) {
        remain -= Math.min(a[i] - a[i - 1], mid);
        if (remain <= 0) {
            return true;        // guard clause: early exit when already satisfied
        }
    }

    // final reduction for the last segment
    remain -= mid;
    return remain <= 0;
}

