/** Adds enough attack points so that (aty - dem) > 0 and returns the accrued cost. */
private static long increaseAtyUntilPositive(int aty, int dem, int cat) {
    long cost = 0;
    while (aty - dem <= 0) {
        aty++;
        cost += cat;
    }
    return cost;
}

/** Searches the whole space of possible upgrades and returns the cheapest feasible cost. */
private static int findMinimumAdditionalCost(int hpy, int aty, int dey, int hpm,
                                             int atm, int dem,
                                             int chp, int cat, int cde) {
    int bestCost = Integer.MAX_VALUE;

    for (int h = 0; h <= 10_000; h++) {
        for (int a = 0; a <= 100; a++) {
            int damYact = Math.max(aty + a - dem, 0);
            // Guard against division by zero – the original code assumes this never happens.
            if (damYact == 0) {
                continue;
            }
            int costForHa = cheapestCostForHa(h, a, hpy, hpm, damYact,
                                              atm, dey, chp, cat, cde);
            if (costForHa < bestCost) {
                bestCost = costForHa;
            }
        }
    }
    return bestCost;
}

/** For a fixed (h, a) pair, finds the smallest d that satisfies the combat condition
 *  and returns the associated total upgrade cost.
 *  Returns {@link Integer#MAX_VALUE} if no d in the range [0,99] works. */
private static int cheapestCostForHa(int h, int a, int hpy, int hpm, int damYact,
                                     int atm, int dey,
                                     int chp, int cat, int cde) {
    for (int d = 0; d < 100; d++) {
        int damMact = Math.max(atm - dey - d, 0);
        boolean conditionMet = damMact <= 0 ||
                Math.ceil((double) (hpy + h) / damMact) >
                Math.ceil((double) hpm / damYact);
        if (conditionMet) {
            return a * cat + h * chp + d * cde;   // guard clause – exit early
        }
    }
    return Integer.MAX_VALUE; // no viable d found
}

