    // search the cheapest combination of extra HP, ATK and DEF
    for (int h = 0; h <= 10000; h++) {
        for (int a = 0; a <= 100; a++) {
            int comboCost = minimalCostForCombo(
                    h, a,
                    hpy, hpm,
                    aty, dem,
                    atm, dey,
                    cat, chp, cde);
            if (comboCost < addCost) {
                addCost = comboCost;
            }
        }
    }

