/**
 * Returns the cheapest cost for a given extra HP (h) and extra ATK (a).
 * The method iterates over possible DEF increments (d) and returns as soon as
 * the combat condition is satisfied – this is the guard‑clause that replaces
 * the original nested {@code if}/{@code break} logic.
 *
 * @return minimal cost for the (h,a) pair, or {@code Integer.MAX_VALUE}
 *         if no DEF value satisfies the condition.
 */
private static int minimalCostForCombo(
        int h, int a,
        int hpy, int hpm,
        int aty, int dem,
        int atm, int dey,
        int cat, int chp, int cde) {

    for (int d = 0; d < 100; d++) {
        int damMact = Math.max(atm - dey - d, 0);
        int damYact = Math.max(aty + a - dem, 0);

        // guard clause: condition satisfied → compute and return cost
        if (damMact <= 0 ||
                Math.ceil((double) (hpy + h) / (double) damMact) >
                        Math.ceil((double) hpm / (double) damYact)) {
            return a * cat + h * chp + d * cde;
        }
    }
    // No d satisfied the condition
    return Integer.MAX_VALUE;
}

