/**
 * Reads the 'type' array while discarding the accompanying double values.
 */
private static int[] readTypes(FastReader s, int n) {
    int[] type = new int[n];
    for (int i = 0; i < n; i++) {
        type[i] = s.nextInt();
        s.nextDouble();                // consume the double that the original code ignored
    }
    return type;
}

/**
 * Returns the length of the longest non‑decreasing subsequence of 'type'.
 * The implementation uses the same O(n²) DP as the original code but
 * replaces nested conditionals with guard clauses for clarity.
 */
private static int longestNonDecreasingSubsequenceLength(int[] type) {
    int n = type.length;
    int[] dp = new int[n];
    int max = 0;

    for (int i = 0; i < n; i++) {
        dp[i] = 1;                     // each element alone forms a subsequence of length 1

        for (int j = 0; j < i; j++) {
            if (type[j] > type[i]) {
                continue;              // guard clause – skip non‑compatible previous elements
            }
            int candidate = dp[j] + 1;
            if (candidate > dp[i]) {
                dp[i] = candidate;    // update only when a longer subsequence is found
            }
        }

        if (dp[i] > max) {
            max = dp[i];
        }
    }
    return max;
}

