/**
 * Performs the BFS while keeping the maximum distance seen.
 * Returns the maximum distance when the target vertex {@code t}
 * is reached, or {@code -1} if it is unreachable.
 */
private static int computeMaxDistance(int n,
                                      ArrayList<Integer>[] graph,
                                      boolean[] city,
                                      int start,
                                      int target) {
    PriorityQueue<Que> queue = new PriorityQueue<>();
    int[] dist = new int[n + 1];
    Arrays.fill(dist, (int) 1e9);
    dist[start] = 0;
    queue.add(new Que(0, start));

    int maxDist = 0;

    while (!queue.isEmpty()) {
        int v = queue.poll().v;
        maxDist = Math.max(maxDist, dist[v]);

        for (int to : graph[v]) {
            int newDist = dist[v] + 1;

            // Guard‑clause: ignore if we cannot improve the distance
            if (newDist >= dist[to]) {
                continue;
            }

            dist[to] = newDist;
            maxDist = Math.max(maxDist, newDist);

            // Guard‑clause: target reached – return immediately
            if (to == target) {
                return maxDist;
            }

            // Reset distance to zero for city vertices
            if (city[to]) {
                dist[to] = 0;
            }

            queue.add(new Que(dist[to], to));
        }
    }

    // Target not reachable
    return -1;
}

