/**
 * Returns the number of times the running balance of parentheses reaches a new
 * minimum while scanning the string from left to right.
 *
 * The algorithm mirrors the original implementation:
 *   - '(' increases the balance, ')' decreases it.
 *   - When the balance drops below the smallest value seen so far, the answer
 *     is incremented and the new minimum is recorded.
 *
 * @param s the parenthesis string
 * @return the computed answer
 */
private static int countNewMinimumDepths(String s) {
    int balance = 0;
    int minBalance = 0;
    int answer = 0;

    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == '(') {
            balance++;
            continue;                 // guard: nothing else to do for '('
        }

        // c == ')'
        balance--;

        // guard clause – only act when a new minimum is reached
        if (balance >= minBalance) {
            continue;
        }

        answer++;
        minBalance = balance;
    }

    return answer;
}

