/**
 * Computes the number of times a new negative minimum balance is reached
 * while scanning the parenthesis string.
 *
 * @param s the input string consisting of '(' and ')'
 * @return the answer for this test case
 */
private static int computeAns(String s) {
    int cnt = 0;   // current balance
    int ans = 0;   // number of new minima encountered
    int min = 0;   // deepest negative balance seen so far

    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == '(') {
            cnt++;
            continue;               // guard clause – no further work for '('
        }

        cnt--;                       // c == ')'
        if (cnt < min) {
            ans++;
            min = cnt;
        }
    }
    return ans;
}

