}

/* Helper: reset the `used` flag on every vertex */
private static void resetUsedFlags(Vertex[] vertices) {
    for (Vertex v : vertices) {
        v.used = false;
    }
}

/* Helper: breadth‑first search that collects one connected component */
private static List<Vertex> bfsComponent(Vertex start) {
    List<Vertex> component = new ArrayList<>();
    Queue<Vertex> queue = new LinkedList<>();

    queue.offer(start);
    start.used = true;

    while (!queue.isEmpty()) {
        Vertex cur = queue.poll();
        component.add(cur);

        for (Vertex nxt : cur) {
            if (nxt.used) {
                continue;           // guard clause – ignore already visited neighbour
            }
            nxt.used = true;
            queue.offer(nxt);
        }
    }
    return component;
}

