        long totalSteps = 0;

        for (int value : a) {
            int steps = stepsToReach(value, target);
            if (steps < 0) {
                // This element cannot become the current target
                continue;
            }
            successes++;
            totalSteps += steps;

            if (successes == k) {
                // We already have enough elements, no need to examine more
                break;
            }
        }

        if (successes == k) {
            ans = Math.min(ans, totalSteps);
        }
    }

    System.out.println(ans);
    out.flush();
}

/**
 * Returns the number of times {@code value} must be divided by 2
 * to become exactly {@code target}. If it cannot become {@code target},
 * returns -1.
 */
private static int stepsToReach(int value, int target) {
    if (value == target) {
        return 0;
    }
    if (value < target) {
        return -1;
    }
    int steps = 0;
    while (value > target) {
        value /= 2;
        steps++;
    }
    return (value == target) ? steps : -1;
}

