public void solve(FastReader in, PrintWriter out) {
    int n = in.nextInt();
    int msize = in.nextInt();
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = in.nextInt();
    }

    HashMap<Integer, Integer> mp = new HashMap<>();
    HashMap<Integer, Integer> grpsize = new HashMap<>();
    for (int i = 0; i < 256; i++) {
        mp.put(i, -1);
        grpsize.put(i, 1);
    }

    int[] res = new int[n];

    for (int i = 0; i < n; i++) {
        int value = arr[i];

        // Guard clause – value already belongs to a group
        if (mp.get(value) != -1) {
            res[i] = mp.get(value);
            continue;
        }

        // Value not yet grouped → compute its group
        assignGroup(value, msize, mp, grpsize);
        res[i] = mp.get(value);
    }

    for (int i = 0; i < n; i++) {
        out.print(res[i] + " ");
    }
}

/**
 * Finds the appropriate group for {@code value} respecting the maximum
 * group size {@code msize}, updates {@code mp} (value → group start) and
 * {@code grpsize} (group start → group size) accordingly.
 *
 * The implementation mirrors the original nested logic but uses early
 * returns / breaks to keep the flow flat.
 */
private static void assignGroup(int value, int msize,
                                HashMap<Integer, Integer> mp,
                                HashMap<Integer, Integer> grpsize) {

    int leftBound = Math.max(0, value - msize + 1);
    int groupStart = value;   // tentative start of the new group
    int groupSize = -1;        // will be computed

    for (int j = value; j >= leftBound; j--) {
        Integer mapped = mp.get(j);

        if (mapped != -1) {                       // already mapped element found
            int existingSize = grpsize.get(j);
            // can we extend the existing group?
            if (existingSize + value - j <= msize) {
                groupStart = mapped;
                groupSize = existingSize + value - j;

                // propagate the new size backward while the same group start is seen
                int p = j;
                while (p >= 0 && mp.get(p).equals(groupStart)) {
                    grpsize.put(p, groupSize);
                    p--;
                }
            }
            break;                                 // stop scanning leftward
        } else {
            // still unmapped; candidate for group start
            groupStart = j;
        }
    }

    // If we never merged with an existing group, its size is the distance to the start
    if (groupSize == -1) {
        groupSize = value - groupStart + 1;
    }

    // Fill maps for the newly created (or extended) group
    for (int j = value; j >= groupStart; j--) {
        mp.put(j, groupStart);
        grpsize.put(j, groupSize);
    }
}

