/**
 * Attempts to visit the vertex reached by {@code e}.
 *
 * Guard clauses keep the logic flat:
 *   1. Return early if the vertex is already visited.
 *   2. Record the edge direction and adjust the remaining degree.
 *   3. Return early if the vertex does not yet satisfy the “half” condition
 *      or if it is the sink vertex {@code target}.
 *   4. Otherwise mark the vertex visited and push it onto the stack.
 *
 * @return {@code true} if the vertex became visited and was pushed onto the stack.
 */
private static boolean tryVisit(Edge e,
                                int[] current,
                                int[] half,
                                boolean[] visited,
                                int[] direction,
                                Stack<Integer> stack,
                                int target) {
    // Guard: already processed
    if (visited[e.b]) {
        return false;
    }

    direction[e.i] = e.d;
    current[e.b] -= e.c;

    // Guard: not ready or is the sink vertex
    if (current[e.b] != half[e.b] || e.b == target) {
        return false;
    }

    visited[e.b] = true;
    stack.push(e.b);
    return true;
}

