/**
 * Returns true if a total cost ≤ limit can be obtained by choosing
 * non‑negative integers i and j (both ≤ 299) that satisfy the problem’s
 * arithmetic constraints.
 */
private static boolean canAchieve(int limit, int[] h, int[] a, int[] d) {
    // iterate over all possible i and j (0 … 299)
    for (int i = 0; i < 300; i++) {
        // Guard: i must be large enough to beat the first opponent
        if (i + a[0] <= d[1]) {
            continue;
        }
        for (int j = 0; j < 300; j++) {
            int hp = computeHp(i, j, h, a, d);
            // Guard: if the current combination already exceeds the limit we can skip it
            if (hp * h[2] + i * a[2] + j * d[2] > limit) {
                continue;
            }
            // Found a feasible combination
            return true;
        }
    }
    return false;
}

/**
 * Computes the intermediate “hp” value used in the feasibility test.
 * The formula is taken directly from the original implementation.
 */
private static int computeHp(int i, int j, int[] h, int[] a, int[] d) {
    int numerator = h[1] + a[0] + i - d[1] - 1;
    int denominator = a[0] + i - d[1];
    int rounds = denominator == 0 ? 0 : numerator / denominator;
    int damage = a[1] - (d[0] + j);
    int base = Math.max(0, damage * rounds + 1 - h[0]);
    return base;
}

