static ArrayList<Integer> primeFac(int n) {
    int[] lp = buildLeastPrimeFactorArray(n);
    ArrayList<Integer> ans = collectPrimeFactors(n, lp);
    print(ans);
    return ans;
}

private static int[] buildLeastPrimeFactorArray(int n) {
    int[] lp = new int[n + 1];
    Arrays.fill(lp, 0);
    for (int i = 2; i <= n; i++) {
        if (lp[i] == 0) {
            markMultiples(i, n, lp);
        }
    }
    return lp;
}

private static void markMultiples(int prime, int n, int[] lp) {
    for (int j = prime; j <= n; j += prime) {
        if (lp[j] == 0) {
            lp[j] = prime;
        }
    }
}

private static ArrayList<Integer> collectPrimeFactors(int n, int[] lp) {
    ArrayList<Integer> factors = new ArrayList<>();
    int remaining = n;
    while (remaining > 1) {
        int factor = lp[remaining];
        factors.add(factor);
        remaining /= factor;
    }
    return factors;
}

