public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    PrintWriter out = new PrintWriter(System.out);
    int n = sc.nextInt();
    int[] a = new int[n];
    for (int i = 0; i < n; i++) {
        a[i] = sc.nextInt();
    }

    SparseTable s = new SparseTable(a);
    HashMap<Integer, Long> map = buildGcdFrequencyMap(a, s);

    int q = sc.nextInt();
    while (q-- > 0) {
        int x = sc.nextInt();
        out.println(map.getOrDefault(x, 0L));
    }
    out.flush();
    out.close();
}

/**
 * Builds a map where key = GCD value of a sub‑array,
 * value = total number of sub‑arrays that have this GCD.
 */
private static HashMap<Integer, Long> buildGcdFrequencyMap(int[] a, SparseTable s) {
    int n = a.length;
    HashMap<Integer, Long> map = new HashMap<>();
    for (int i = 0; i < n; i++) {
        accumulateGcdCounts(i, n, s, map);
    }
    return map;
}

/**
 * For a fixed left index {@code i}, walks forward over possible right
 * boundaries, finds stretches where the GCD stays constant, and records
 * their contribution into {@code map}.
 */
private static void accumulateGcdCounts(int i, int n, SparseTable s, HashMap<Integer, Long> map) {
    int idx = i;
    while (idx < n) {
        int g = s.query(i, idx);
        int ans = findFirstIndexWithSmallerGcd(i, idx, n, s, g);
        // contribution of the segment [idx, ans‑1] where GCD stays equal to g
        map.put(g, map.getOrDefault(g, 0L) + (long) (ans - idx));

        // move to the next segment start
        idx = ans;
        // guard clause – if we reached the end there is nothing more to process
        if (ans == n) {
            break;
        }
    }
}

/**
 * Binary‑searches the first position {@code mid} in the range {@code [idx+1, n-1]}
 * such that {@code s.query(i, mid) < targetGcd}. If no such position exists,
 * returns {@code n}.
 */
private static int findFirstIndexWithSmallerGcd(int i, int idx, int n, SparseTable s, int targetGcd) {
    int lo = idx + 1;
    int hi = n - 1;
    int answer = n; // default when condition never holds
    while (lo <= hi) {
        int mid = (lo + hi) >>> 1; // unsigned right shift as a fast divide‑by‑2
        if (s.query(i, mid) < targetGcd) {
            answer = mid;
            hi = mid - 1; // continue left to find the earliest occurrence
        } else {
            lo = mid + 1;
        }
    }
    return answer;
}

