static boolean nextPermutation(int[] a) {
    int pivot = findPivot(a);
    if (pivot == -1) {
        return false;
    }

    int successor = findSuccessor(a, pivot);
    swap(a, pivot, successor);
    reverseSuffix(a, pivot + 1);
    return true;
}

private static int findPivot(int[] a) {
    for (int i = a.length - 2; i >= 0; --i) {
        if (a[i] < a[i + 1]) {
            return i;
        }
    }
    return -1; // no next permutation
}

private static int findSuccessor(int[] a, int pivot) {
    for (int j = a.length - 1; ; --j) {
        if (a[pivot] < a[j]) {
            return j;
        }
    }
}

private static void swap(int[] a, int i, int j) {
    int tmp = a[i];
    a[i] = a[j];
    a[j] = tmp;
}

private static void reverseSuffix(int[] a, int start) {
    int i = start;
    int j = a.length - 1;
    while (i < j) {
        swap(a, i, j);
        ++i;
        --j;
    }
}

