/** Computes for every possible start index in {@code pattern}
 *  how many full cycles are completed when scanning {@code source}
 *  and where the scan ends (next start position). */
private void fillDpAndPos(char[] source, char[] pattern, int[] dp, int[] dpPos) {
    for (int start = 0; start < pattern.length; start++) {
        int curPos = start;
        for (char c : source) {
            if (c == pattern[curPos]) {
                curPos = (curPos + 1) % pattern.length;
                if (curPos == 0) {
                    dp[start]++;          // one full pattern matched
                }
            }
        }
        dpPos[start] = curPos;               // next start after scanning whole source
    }
}

/** Simulates {@code steps} repetitions using the pre‑computed tables.
 *  Returns the total number of full pattern matches accumulated. */
private long runSimulation(int steps, int[] dp, int[] dpPos) {
    long matches = 0;
    int curPos = 0;
    for (int i = 0; i < steps; i++) {
        matches += dp[curPos];
        curPos = dpPos[curPos];
    }
    return matches;
}

