                    int[] queue, int[] fromStart) {
    int queueSize = 0;
    Arrays.fill(fromStart, INF);
    fromStart[start] = 0;
    visited[start] = true;
    queue[queueSize++] = start;

    int maxDist = 0;
    int res = -1;

    for (int frontPtr = 0; frontPtr < queueSize; frontPtr++) {
        int cur = queue[frontPtr];
        for (int nxt : adj[cur]) {
            // guard clauses – skip vertices that are already discovered or forbidden
            if (shouldSkip(nxt, fromStart, cant)) {
                continue;
            }

            // enqueue the vertex
            queue[queueSize++] = nxt;
            visited[nxt] = true;
            fromStart[nxt] = fromStart[cur] + 1;

            // keep track of the farthest reachable vertex
            if (fromStart[nxt] > maxDist) {
                maxDist = fromStart[nxt];
                res = nxt;
            }
        }
    }
    return res;
}

