/**
 * Returns true if left should come after right according to natural order.
 */
private static boolean needsSwap(String left, String right) {
    return left.compareTo(right) > 0;
}

/**
 * Finds the first index j (0 ≤ j < limit) where left.charAt(j) > right.charAt(j).
 * Returns -1 if no such index exists.
 */
private static int firstDiffGreaterIndex(String left, String right, int limit) {
    for (int j = 0; j < limit; j++) {
        if (left.charAt(j) > right.charAt(j)) {
            return j;
        }
    }
    return -1;
}

/**
 * Removes the character at position idx from every string in the array.
 */
private static void deleteCharAtAll(String[] array, int idx) {
    for (int k = 0; k < array.length; k++) {
        String s = array[k];
        array[k] = s.substring(0, idx) + s.substring(idx + 1);
    }
}

