/**
 * Reads an {@code n × n} matrix of 0/1 values from the given {@link BufferedReader}.
 *
 * @param br the reader positioned at the first line of the matrix
 * @param n  the size of the square matrix
 * @return a two‑dimensional int array representing the matrix
 * @throws IOException if an I/O error occurs
 */
private static int[][] readMatrix(BufferedReader br, int n) throws IOException {
    int[][] arr = new int[n][n];
    for (int i = 0; i < n; i++) {
        String line = br.readLine();
        for (int j = 0; j < n; j++) {
            // Convert character '0'/'1' directly to int 0/1
            arr[i][j] = (line.charAt(j) == '0') ? 0 : 1;
        }
    }
    return arr;
}

