public void solve(int testNumber, FastReader s, PrintWriter w) {
    int a = s.nextInt(), b = s.nextInt(), c = s.nextInt();
    final int MX = (int) 1e5;

    int bestCost = Integer.MAX_VALUE;
    dist bestDist = new dist(0, 0, 0);

    for (int i = 1; i <= MX; i++) {
        for (int j = i; j <= MX; j += i) {
            int curCost = computeCost(a, b, c, i, j);
            if (curCost >= bestCost) {
                continue;                       // guard‑clause – skip non‑improving candidates
            }
            bestCost = curCost;
            int bestZ = chooseClosestMultiple(c, j);
            bestDist = new dist(i, j, bestZ);
        }
    }

    w.println(bestCost);
    w.println(bestDist.x + " " + bestDist.y + " " + bestDist.z);
}

/** total Manhattan distance for the given (i, j) */
private static int computeCost(int a, int b, int c, int i, int j) {
    int zDiff = distanceToClosestMultiple(c, j);
    return Math.abs(a - i) + Math.abs(j - b) + zDiff;
}

/** minimal distance from c to the nearest multiple of j */
private static int distanceToClosestMultiple(int c, int j) {
    int lower = (c / j) * j;                           // greatest multiple ≤ c
    int upper = ((c - 1) / j + 1) * j;                 // smallest multiple ≥ c
    return Math.min(Math.abs(c - lower), Math.abs(c - upper));
}

/** the multiple of j (either lower or upper) that is closest to c */
private static int chooseClosestMultiple(int c, int j) {
    int lower = (c / j) * j;
    int upper = ((c - 1) / j + 1) * j;
    return (Math.abs(c - upper) > Math.abs(c - lower)) ? lower : upper;
}

