/**
 * Evaluates both possible overlapping paths for a given pair (a,b) and
 * returns the smallest result found (or the original result if neither
 * combination improves it).
 */
private static int updateResultForPair(int a, int b, int[][] dist,
                                       int s1, int t1, int l1,
                                       int s2, int t2, int l2,
                                       int currentBest) {
    // First combination: both paths share segment a‑b in the same direction
    int path1 = dist[s1][a] + dist[a][b] + dist[b][t1];
    int path2 = dist[s2][a] + dist[a][b] + dist[b][t2];
    if (path1 <= l1 && path2 <= l2) {
        int candidate = path1 + path2 - dist[a][b]; // dist[a][b] counted twice
        currentBest = Math.min(currentBest, candidate);
    }

    // Second combination: second path traverses a‑b in opposite direction
    int path3 = dist[s1][a] + dist[a][b] + dist[b][t1];
    int path4 = dist[s2][b] + dist[b][a] + dist[a][t2];
    if (path3 <= l1 && path4 <= l2) {
        int candidate = path3 + path4 - dist[a][b]; // shared segment counted twice
        currentBest = Math.min(currentBest, candidate);
    }

    return currentBest;
}

