/** shortest path without any shared edges */
private static int initialResult(int[][] d, int s1, int t1, int s2, int t2) {
    return d[s1][t1] + d[s2][t2];
}

/** tries every pair (a,b) and keeps the minimal total length */
private static int improveResultWithOverlap(int[][] d,
                                            int s1, int t1, int l1,
                                            int s2, int t2, int l2,
                                            int currentBest) {
    int n = d.length;
    int best = currentBest;

    for (int a = 0; a < n; a++) {
        for (int b = 0; b < n; b++) {
            best = updateBestForPair(d, s1, t1, l1, s2, t2, l2, a, b, best);
        }
    }
    return best;
}

/** evaluates the two possible overlap configurations for a given (a,b) */
private static int updateBestForPair(int[][] d,
                                     int s1, int t1, int l1,
                                     int s2, int t2, int l2,
                                     int a, int b, int bestSoFar) {
    int dSA = d[s1][a];
    int dAB = d[a][b];
    int dBT = d[b][t1];
    int dSB = d[s2][a];
    int dBT2 = d[b][t2];
    int dSBAlt = d[s2][b];
    int dAT2 = d[a][t2];

    // first sharing direction: both paths go a → b
    if (dSA + dAB + dBT <= l1 && dSB + dAB + dBT2 <= l2) {
        int candidate = dSA + dSB + dAB + dBT + dBT2;
        bestSoFar = Math.min(bestSoFar, candidate);
    }

    // second sharing direction: second path goes b → a
    if (dSA + dAB + dBT <= l1 && dSBAlt + dAB + dAT2 <= l2) {
        int candidate = dSA + dSBAlt + dAB + dBT + dAT2;
        bestSoFar = Math.min(bestSoFar, candidate);
    }

    return bestSoFar;
}

public static void main(String[] args) throws Exception {
    FastScanner in = new FastScanner(System.in);

    int n = in.nextInt();
    int m = in.nextInt();

    @SuppressWarnings("unchecked")
    ArrayList<Integer>[] adj = createAdjacencyList(n);
    readEdges(in, adj, m);

    // read query parameters (convert to 0‑based indices)
    int s1 = in.nextInt() - 1;
    int t1 = in.nextInt() - 1;
    int l1 = in.nextInt();
    int s2 = in.nextInt() - 1;
    int t2 = in.nextInt() - 1;
    int l2 = in.nextInt();

    int[][] dist = computeAllPairsShortestPaths(adj);

    // impossible case – guard clause
    if (dist[s1][t1] > l1 || dist[s2][t2] > l2) {
        System.out.println(-1);
        return;
    }

    int best = dist[s1][t1] + dist[s2][t2];   // baseline: completely disjoint paths

    for (int a = 0; a < n; a++) {
        for (int b = 0; b < n; b++) {
            int candidate = evaluateVertexPair(a, b, dist,
                                                s1, t1, l1,
                                                s2, t2, l2);
            if (candidate < best) {
                best = candidate;
            }
        }
    }

    System.out.println(m - best);
}

/* -------------------------------------------------------------------- */
/* Helper methods – each encapsulates a single, well‑defined responsibility */
/* -------------------------------------------------------------------- */

private static ArrayList<Integer>[] createAdjacencyList(int n) {
    @SuppressWarnings("unchecked")
    ArrayList<Integer>[] adj = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        adj[i] = new ArrayList<>();
    }
    return adj;
}

private static void readEdges(FastScanner in, ArrayList<Integer>[] adj, int m) {
    for (int i = 0; i < m; i++) {
        int a = in.nextInt() - 1;
        int b = in.nextInt() - 1;
        adj[a].add(b);
        adj[b].add(a);
    }
}

/** Runs BFS from every vertex – O(n·(n+m)). */
private static int[][] computeAllPairsShortestPaths(ArrayList<Integer>[] adj) {
    int n = adj.length;
    int[][] all = new int[n][];
    for (int v = 0; v < n; v++) {
        all[v] = bfs(adj, v);
    }
    return all;
}

/**
 * Returns the cheapest combined length for the two routes when they share
 * the vertices (a,b) in one of the two possible orientations.
 * If the pair cannot satisfy the length limits, Integer.MAX_VALUE is returned.
 */
private static int evaluateVertexPair(int a, int b,
                                      int[][] dist,
                                      int s1, int t1, int l1,
                                      int s2, int t2, int l2) {
    int best = Integer.MAX_VALUE;

    // first orientation: both routes go a→b
    int path1 = dist[s1][a] + dist[a][b] + dist[b][t1];
    if (path1 <= l1) {
        int path2 = dist[s2][a] + dist[a][b] + dist[b][t2];
        if (path2 <= l2) {
            best = Math.min(best,
                    dist[s1][a] + dist[s2][a] + dist[a][b] + dist[b][t1] + dist[b][t2]);
        }
    }

    // second orientation: second route goes b→a
    if (path1 <= l1) {   // reuse the already‑computed path1
        int path2Alt = dist[s2][b] + dist[b][a] + dist[a][t2];
        if (path2Alt <= l2) {
            best = Math.min(best,
                    dist[s1][a] + dist[s2][b] + dist[a][b] + dist[b][t1] + dist[a][t2]);
        }
    }

    return best;
}

