public int[] roll(String order) {
    int now1 = 1;
    int now2 = 2;
    int now3 = 3;

    int[] array = getNum();

    for (int i = 0; i < order.length(); i++) {
        char dir = order.charAt(i);

        // guard‑clause: ignore any character that is not a valid direction
        if ("NESW".indexOf(dir) == -1) {
            continue;
        }

        int[] rotated = rotate(dir, now1, now2, now3);
        now1 = rotated[0];
        now2 = rotated[1];
        now3 = rotated[2];
    }

    int[] cpArray = new int[array.length];
    cpArray[1] = array[now1];
    cpArray[2] = array[now2];
    cpArray[3] = array[now3];
    cpArray[4] = array[7 - now3];
    cpArray[5] = array[7 - now2];
    cpArray[6] = array[7 - now1];
    return cpArray;
}

/**
 * Returns the updated positions after applying a single rotation.
 * The three returned values correspond to now1, now2 and now3 respectively.
 */
private int[] rotate(char direction, int now1, int now2, int now3) {
    int tmp;
    switch (direction) {
        case 'N': // north
            tmp = now1;
            now1 = now2;
            now2 = 7 - tmp;
            break;
        case 'E': // east
            tmp = now1;
            now1 = 7 - now3;
            now3 = tmp;
            break;
