/** Extracted helper that merges *node* into the current component set. */
private static void mergeNodeIntoComponents(int node,
                                            HashSet<Integer>[] adjList,
                                            Set<Integer> components) {
    Set<Integer> toRemove = new HashSet<>();

    for (int comp : components) {
        // Only act when *comp* is **not** adjacent to *node*
        if (!adjList[comp].contains(node)) {
            adjList[node].retainAll(adjList[comp]);
            toRemove.add(comp);
        }
    }

    // Remove the components that have been merged and add the current node
    components.removeAll(toRemove);
    components.add(node);
}

