/** Returns the score contributed by the characters that start at {@code offset}
 *  and are taken every {@code step} positions in {@code text}. */
private int scoreForOffset(int offset, int step, String text,
                           int winRock, int winScissors, int winPaper) {
    int localScore = 0;
    char last = '0';                     // last winning hand in this segment

    for (int i = offset; i < text.length(); i += step) {
        char now = text.charAt(i);

        // Guard‑clause: same hand as last time → reset and skip scoring
        if (now == last) {
            last = '0';
            continue;
        }

        // New hand, add its corresponding points
        switch (now) {
            case 'r':
                localScore += winPaper;   // paper beats rock
                break;
            case 's':
                localScore += winRock;    // rock beats scissors
                break;
            case 'p':
                localScore += winScissors;// scissors beats paper
                break;
            default:
                // Unexpected character – treat as no score
                break;
        }
        last = now;                      // remember this hand for the next iteration
    }
    return localScore;
}

