/** Links the cells of a single row and updates the column helpers. */
private static void linkRow(int row,
                            char[][] a,
                            int[][] L,
                            int[][] R,
                            int[] h,
                            int[][] U,
                            int[][] D) {
    int last = -1; // index of the previous non‑dot cell in the current row
    for (int col = 0; col < a[row].length; col++) {
        if (a[row][col] == '.') {
            continue; // guard clause – skip empty cells
        }

        // horizontal links
        L[row][col] = last;
        if (last != -1) {
            R[row][last] = col;
        }

        // vertical links
        U[row][col] = h[col];
        if (h[col] != -1) {
            D[h[col]][col] = row;
        }

        // update helpers for the next iteration
        last = col;
        h[col] = row;
    }

    // mark the end of the row
    if (last != -1) {
        R[row][last] = -1;
    }
}

/** Sets the down‑link of the lowest occupied cell in each column to -1. */
private static void finalizeColumnLinks(int columnCount, int[] h, int[][] D) {
    for (int col = 0; col < columnCount; col++) {
        if (h[col] != -1) {
            D[h[col]][col] = -1;
        }
    }
}

