/** Reads the grid and populates L,R,U,D links while scanning row‑by‑row. */
private static void fillMatrices(int rows,
                                 int cols,
                                 char[][] grid,
                                 int[][] down,
                                 int[][] up,
                                 int[][] left,
                                 int[][] right,
                                 int[] lastInColumn,
                                 Scanner scn) {
    for (int i = 0; i < rows; i++) {
        grid[i] = scn.next().toCharArray();
        int lastInRow = -1;                     // index of previous non‑dot in this row
        for (int j = 0; j < cols; j++) {
            if (grid[i][j] == '.') {
                continue;                       // guard clause – skip empty cells
            }
            // horizontal links
            left[i][j] = lastInRow;
            if (lastInRow != -1) {
                right[i][lastInRow] = j;
            }

            // vertical links
            up[i][j] = lastInColumn[j];
            if (lastInColumn[j] != -1) {
                down[lastInColumn[j]][j] = i;
            }

            // update helpers for next iterations
            lastInRow = j;
            lastInColumn[j] = i;
        }
        // finish horizontal chain for this row
        if (lastInRow != -1) {
            right[i][lastInRow] = -1;
        }
    }
