/**
 * Performs a BFS starting from {@code start} and returns the size of the
 * connected component that contains only edges with {@code c == 0}.
 * The {@code visited} array and the supplied queue are reused to avoid
 * unnecessary allocations.
 */
private int bfsComponentSize(int start, boolean[] visited, Deque<Integer> q) {
    visited[start] = true;
    q.add(start);
    int size = 0;

    while (!q.isEmpty()) {
        int u = q.pop();
        size++;
        for (Edge e : adj[u]) {
            if (e.c == 0 && !visited[e.v]) {
                visited[e.v] = true;
                q.add(e.v);
            }
        }
    }
    return size;
}

