/* Main DP construction – the deep nesting is moved to a tiny method. */
private void computeDP() {
    for (int len = 2; len < 19; len++) {
        for (int d = 0; d <= 9; d++) {
            for (int mask = 1; mask < 1024; mask++) {
                updateForCombination(len, d, mask);
            }
        }
    }
