/* One combination of (len, digit, previous mask).  Guard clauses keep it flat. */
private void updateForCombination(int len, int d, int mask) {
    int bit = 1 << d;
    int newMask = mask | bit;

    // Guard: ignore masks that would exceed the allowed distinct‑digit count.
    if (nbits[newMask] > k) {
        return;
    }

    // Update digit‑based DP tables.
    dcnt[len][newMask] = (int) ((dcnt[len][newMask] + dcnt[len - 1][mask]) % mod);
    long subsum = d * p10[len - 1] * dcnt[len - 1][mask] + dsum[len - 1][mask];
    dsum[len][newMask] = (dsum[len][newMask] + subsum) % mod;

    // Guard: leading zeros must not contribute to the “non‑zero” aggregates.
    if (d == 0) {
        return;
    }

    // Update aggregates that ignore leading zeros.
    scnt[len] = (scnt[len] + dcnt[len - 1][mask]) % mod;
    ssum[len] = (ssum[len] + subsum) % mod;
}

