/**
 * Updates {@code arr[i]} with the total number of prime‑factor occurrences
 * (with multiplicity) for every 2 ≤ i ≤ max.
 * The method uses a guard‑clause to skip non‑prime bases.
 */
private void buildFactorCounts(int[] arr, int max) {
    for (int i = 2; i <= max; i++) {
        if (arr[i] != 0) {
            continue;               // i is already marked → not a prime
        }
        // i is prime: add its contribution to all multiples of i
        for (int j = i; j <= max; j += i) {
            int temp = j;
            int count = 0;
            while (temp % i == 0) {
                count++;
                temp /= i;
            }
            arr[j] += count;
        }
    }
}

/**
 * Converts the raw factor counts into a prefix sum so that
 * arr[x] holds the total count for all numbers ≤ x.
 */
private void buildPrefixSums(int[] arr) {
    for (int i = 1; i < arr.length; i++) {
        arr[i] += arr[i - 1];
    }
}

