public int cs(char[][] arr, int c) {
    int n = arr.length;
    int hp = 0;
    int i = 0;

    while (i < n) {
        // Guard: not a hash → skip
        if (arr[i][c] != '#') {
            i++;
            continue;
        }

        // Guard: already found a block → invalid input
        if (hp != 0) {
            return -1;
        }

        // Count the contiguous block of '#'
        hp = countHashBlock(arr, c, i);
        // `countHashBlock` returns the index after the block
        i = nextIndexAfterBlock;
    }

    return hp;
}

/**
 * Counts a consecutive sequence of '#' characters in column {@code col}
 * starting at row {@code start}. Returns the length of the sequence and
 * updates {@code nextIndexAfterBlock} to the row index immediately after the
 * sequence.
 */
private int countHashBlock(char[][] arr, int col, int start) {
    int n = arr.length;
    int length = 0;
    int idx = start;

    while (idx < n && arr[idx][col] == '#') {
        length++;
        idx++;
    }

    // Store the index for the caller to continue scanning from
    // (simulating the original `for` loop's extra increment)
    nextIndexAfterBlock = idx;
    return length;
}

// Helper field used to pass the next index back from countHashBlock
private int nextIndexAfterBlock;

