/**
 * Counts the number of subsequences "Q A Q" (indices i < j < k)
 * in the given string.
 *
 * The algorithm runs in O(n) time and O(1) extra space.
 */
private long countQAPattern(String s) {
    // First pass: total number of 'Q' characters.
    int totalQ = 0;
    for (int i = 0; i < s.length(); i++) {
        if (s.charAt(i) == 'Q') {
            totalQ++;
        }
    }

    long result = 0;
    int seenQ = 0; // Q's encountered so far while scanning left‑to‑right.

    // Second pass: for each 'A' compute (Q before) * (Q after).
    for (int i = 0; i < s.length(); i++) {
        char ch = s.charAt(i);
        if (ch == 'Q') {
            seenQ++;                     // guard clause: advance the prefix count
        } else if (ch == 'A') {         // guard clause: handle only the relevant case
            int qBefore = seenQ;
            int qAfter = totalQ - seenQ;
            result += (long) qBefore * qAfter;
        }
        // Characters other than 'Q' or 'A' are ignored automatically.
    }
    return result;
}

