/**
 * Returns the index of the scroll that can be used at the current state.
 * The scroll must satisfy the percentage threshold and have the greatest
 * decrease value (dec). Returns -1 if no scroll qualifies.
 */
private static int findBestScrollableIndex(List<Scroll> scrolls, int cur, int max) {
    int bestIdx = -1;
    int bestDec = Integer.MIN_VALUE;
    double neededPercent = (cur * 1.0 / max) * 100;

    for (int i = 0; i < scrolls.size(); i++) {
        Scroll s = scrolls.get(i);
        if (s.percent >= neededPercent && s.dec > bestDec) {
            bestDec = s.dec;
            bestIdx = i;
        }
    }
    return bestIdx;
}

