/**
 * Generates all lucky numbers of length 1‑9, stores them in the
 * static {@code lucky} array and sorts the array.
 */
private static void generateLuckyNumbers() {
    n = 0;
    lucky = new long[(1 << 10) - 1];

    for (int digits = 1; digits <= 9; digits++) {
        int limit = 1 << digits;                 // 2^digits possibilities
        for (int mask = 0; mask < limit; mask++) {
            lucky[n++] = buildLuckyNumber(digits, mask);
        }
    }

    // The largest 10‑digit lucky number is added manually.
    lucky[lucky.length - 1] = Long.parseLong("4444444444");
    Arrays.sort(lucky);
}

/**
 * Builds a lucky number of the given length.
 * The {@code mask} encodes which positions contain a 7 (bit set)
 * or a 4 (bit cleared) when read from least‑significant bit upward.
 *
 * @param digits number of decimal digits
 * @param mask   bit mask describing the digit pattern
 * @return the constructed lucky number
 */
private static long buildLuckyNumber(int digits, int mask) {
    long value = 0;
    for (int pos = 0; pos < digits; pos++) {
        value *= 10;
        if ((mask & (1 << pos)) != 0) {
            value += 7;
        } else {
            value += 4;
        }
    }
    return value;
}

/**
 * Computes the required sum for the interval [L, R] using the
 * pre‑generated {@code lucky} array. The original loop logic is
 * preserved, but a guard clause removes the needless nesting.
 *
 * @param L lower bound (inclusive)
 * @param R upper bound (inclusive)
 * @return the computed sum
 */
private static long computeResult(long L, long R) {
    if (L > R) {
        return 0L;                                 // guard clause
    }

    long sum = 0;
    while (next(L) != next(R)) {
        int idx = next(L);
        sum += (lucky[idx] - L + 1) * lucky[idx];
        L = lucky[idx] + 1;
    }
    sum += (R - L + 1) * lucky[next(L)];
    return sum;
}

