 * updates the global counters (vers, edges, isCap, maxVers) and
 * returns the contribution of this component to the final answer.
 */
private static int processComponent(V start, List<Integer> post) {
    vers = 0;
    edges = 0;
    isCap = 0;
    go(start);                                   // marks visited vertices

    // contribution of the component ignoring capital handling
    int componentAns = (vers * (vers - 1) / 2) - (edges / 2);

    if (isCap == 1) {
        // keep the largest capital component size
        if (vers > maxVers) {
            maxVers = vers;
        }
    } else {
        // non‑capital component sizes are stored for later processing
        post.add(vers);
    }
    return componentAns;
}

/**
 * After all components have been processed, combines the previously
 * stored non‑capital component sizes with the current {@code maxVers}
 * and returns the additional answer contributed by this step.
 */
private static int computePostContribution(List<Integer> post) {
    int added = 0;
    for (Integer size : post) {
        added += maxVers * size;
        maxVers += size;
    }
    return added;
}

