public boolean nextPermutation(String[] permutateString) {
    int pivot = findPivot(permutateString);
    if (pivot == -1) {
        // No higher permutation exists
        return false;
    }

    // Reverse the suffix that follows the pivot
    reverse(permutateString, pivot + 1, permutateString.length);

    // Find the first element in the reversed suffix that is larger than the pivot
    int successor = findSuccessor(permutateString, pivot);
    swap(permutateString, pivot, successor);
    return true;
}

/**
 * Returns the index of the element that breaks the non‑increasing order
 * when scanning from right to left. If none exists, returns -1.
 */
private int findPivot(String[] arr) {
    for (int i = arr.length - 1; i >= 1; i--) {
        if (arr[i].compareTo(arr[i - 1]) > 0) {
            return i - 1;               // pivot position
        }
    }
    return -1;                         // already the highest permutation
}

/**
 * After the suffix has been reversed, returns the first index in the
 * suffix (i > pivot) whose value is greater than the pivot value.
 * The algorithm guarantees such an index exists.
 */
private int findSuccessor(String[] arr, int pivot) {
    for (int j = pivot + 1; j < arr.length; j++) {
        if (arr[pivot].compareTo(arr[j]) < 0) {
            return j;
        }
    }
    // Should never happen with a valid pivot, but keep the method contract safe.
    throw new IllegalStateException("No successor found for pivot at index " + pivot);
}

public boolean nextPermutation(String[] array) {
    int pivot = findPivot(array);
    // No pivot → the array is in the highest lexicographic order
    if (pivot == -1) {
        return false;
    }

    // Reverse the suffix that follows the pivot
    reverseSuffix(array, pivot + 1);

    // Find the smallest element in the suffix that is larger than the pivot
    int swapIdx = findSwapIndex(array, pivot);
    swap(array, pivot, swapIdx);
    return true;
}

/**
 * Returns the index i‑1 where array[i] > array[i‑1] when scanning from right to left.
 * If no such index exists the array is already the greatest permutation → return -1.
 */
private int findPivot(String[] array) {
    for (int i = array.length - 1; i >= 1; i--) {
        if (array[i].compareTo(array[i - 1]) > 0) {
            return i - 1;          // pivot found
        }
    }
    return -1;                    // no pivot
}

/**
 * Reverses the sub‑array from {@code start} (inclusive) to the end of the array.
 * Delegates to the existing {@code reverse} implementation.
 */
private void reverseSuffix(String[] array, int start) {
    // existing reverse expects (array, fromInclusive, toExclusive)
    reverse(array, start, array.length);
}

/**
 * Scans the suffix (which is now in descending order) to locate the first element
 * that is greater than {@code array[pivot]}. Because the suffix is descending,
 * the first match is the smallest element that satisfies the condition.
 */
private int findSwapIndex(String[] array, int pivot) {
    for (int i = pivot + 1; i < array.length; i++) {
        if (array[pivot].compareTo(array[i]) < 0) {
            return i;
        }
    }
    // The contract of the algorithm guarantees a match exists.
    throw new IllegalStateException("Swap index not found – algorithm invariant broken");
}

