        return;
    }

    int ans = INF;

    for (int i = 0; i + 3 <= n; i++) {
        for (int j = 0; j + 3 <= n; j++) {
            int cur = maxIn3x3(i, j, map);
            ans = Math.min(ans, cur + 1);
        }
    }

    out.println(ans == INF ? -1 : ans);
}

/** Returns the maximum value inside the 3×3 sub‑grid whose top‑left corner is (row, col). */
private int maxIn3x3(int row, int col, int[][] map) {
    int max = 0;
    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 3; j++) {
            max = Math.max(max, map[row + i][col + j]);
        }
    }
    return max;
}

