    BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
    int n = Integer.parseInt(br.readLine());

    for (int i = 0; i < n; i++) {
        String line = br.readLine();
        Tree tree = buildTree(line);
        System.out.println(tree.solve());
    }
}

/** Builds a tree from one input line. */
private static Tree buildTree(String line) {
    Tree tree = new Tree();
    Deque<Node> stack = new ArrayDeque<>();
    StringBuilder num = new StringBuilder();

    for (char c : line.toCharArray()) {
        if (c == '[') {
            handleOpenBracket(stack);
        } else if (c == ']') {
            handleCloseBracket(stack, num, tree);
        } else {
            // any other character belongs to a number token
            num.append(c);
        }
    }
    return tree;
}

/** Handles an opening bracket '['. */
private static void handleOpenBracket(Deque<Node> stack) {
    Node node = new Node();
    if (!stack.isEmpty()) {
        node.parent = stack.peek();
        stack.peek().children.add(node);
    }
    stack.push(node);
}

/** Handles a closing bracket ']'. */
private static void handleCloseBracket(Deque<Node> stack,
                                        StringBuilder num,
                                        Tree tree) {
    // If we have accumulated digits, store them on the current node.
    if (num.length() > 0) {
        stack.peek().nums.add(Integer.parseInt(num.toString()));
        num.setLength(0);
    }

    // Guard clause: more than one node on the stack → just pop.
    if (stack.size() > 1) {
        stack.pop();
        return;
    }

    // Stack size is exactly one → this node becomes the tree root.
    tree.root = stack.pop();
}

