            for (int d = 0; d < 4; ++d) {
                if (hasFiveXInDirection(i, j, d, board)) {
                    return true; // guard clause – winning line found
                }
            }
        }
    }
    return false; // no winning line anywhere
}

/**
 * Returns true if the five cells starting at (row, col) and moving in direction {@code dir}
 * are all inside the board and contain the character 'X'.
 */
private boolean hasFiveXInDirection(int row, int col, int dir, char[][] board) {
    for (int k = 0; k < 5; ++k) {
        int r = row + k * dr[dir];
        int c = col + k * dc[dir];
        if (!valid(r, c) || board[r][c] != 'X') {
            return false; // guard clause – early exit on first failure
        }
    }
    return true; // all five cells are valid and contain 'X'
}

