/**
 * Computes the prefix‑sum array of Wu‑values for a given query mask.
 * The returned array holds, at index k, the total number of strings
 * (from S) whose Wu‑value ≤ k.
 */
private static int[] computeWuPrefix(int mask, int[] S, int n) {
    int[] wu = new int[1201];
    int limit = 1 << n;
    for (int j = 0; j < limit; j++) {
        if (S[j] == 0) {
            continue;               // guard clause – skip empty entries
        }
        int val = getWuValue(mask, j);
        if (val < wu.length) {
            wu[val] += S[j];
        }
    }
    // build prefix sums
    for (int i = 1; i < wu.length; i++) {
        wu[i] += wu[i - 1];
    }
    return wu;
}

