/**
 * Parses a line containing: n m x y
 */
private static int[] parseCaseHeader(String line) {
    String[] parts = line.split(" ");
    return new int[] {
        Integer.parseInt(parts[0]), // n
        Integer.parseInt(parts[1]), // m
        Integer.parseInt(parts[2]), // x
        Integer.parseInt(parts[3])  // y
    };
}

/**
 * Counts:
 *   - ones : groups of a single isolated dot
 *   - twos : groups of two consecutive dots
 *   - totalDots : total number of '.' characters
 */
private static int[] countDotSegments(String[] grid, int n, int m) {
    int ones = 0;
    int twos = 0;
    int totalDots = 0;

    for (int i = 0; i < n; i++) {
        String row = grid[i];
        int consecutive = 0;

        for (int j = 0; j < m; j++) {
            if (row.charAt(j) == '.') {
                consecutive++;
                totalDots++;
            } else {
                ones += consecutive % 2;
                twos += consecutive / 2;
                consecutive = 0;
            }
        }
        // account for a trailing run of dots in the row
        ones += consecutive % 2;
        twos += consecutive / 2;
    }

    return new int[] { ones, twos, totalDots };
}

/**
 * Returns the minimum cost using the given pricing rules.
 * Guard‑clause short‑circuits the cheaper per‑dot price.
 */
private static int computeCost(int ones, int twos, int totalDots, int x, int y) {
    if (2 * x <= y) {
        return x * totalDots;                 // cheaper to paint every dot individually
    }
    return x * ones + y * twos;               // mix of single and double paints
}

