        Result rowResult = analyzeRow(sc.nextLine());
        totalDots += rowResult.dots;
        ones      += rowResult.ones;
        twos      += rowResult.twos;
    }

    // guard clause for the cheaper single‑dot strategy
    if (2L * x <= y) {
        return (long) x * totalDots;
    }
    // otherwise use pairs where beneficial
    return (long) x * ones + (long) y * twos;
}

/** Splits a line on whitespace and parses the first {@code count} integers. */
private static int[] readInts(String line, int count) {
    String[] parts = line.trim().split("\\s+");
    int[] ints = new int[count];
    for (int i = 0; i < count; i++) {
        ints[i] = Integer.parseInt(parts[i]);
    }
    return ints;
}

/** Analyzes a single grid row, counting total dots, leftover singles and pairs. */
private static Result analyzeRow(String row) {
    long dots = 0;
    long ones = 0;
    long twos = 0;
    long run  = 0;          // length of the current consecutive '.' segment

    for (int j = 0; j < row.length(); j++) {
        if (row.charAt(j) == '.') {
            run++;
            dots++;
        } else {
            ones += run % 2;
            twos += run / 2;
            run = 0;
        }
    }
    // handle a trailing run of dots
    ones += run % 2;
    twos += run / 2;

    return new Result(dots, ones, twos);
}

/** Simple holder for the three counters produced by {@link #analyzeRow(String)}. */
private static class Result {
    final long dots;
    final long ones;
    final long twos;

    Result(long dots, long ones, long twos) {
        this.dots = dots;
        this.ones = ones;
        this.twos = twos;
    }
}

