/**
 * Scans {@code n} rows from the supplied scanner and returns:
 * [0] total number of '.' cells,
 * [1] number of isolated single dots after pairing (odd leftovers),
 * [2] number of pairs of consecutive dots.
 */
private static long[] countDots(int n, Scanner sc) {
    long totalDots = 0;
    long oddSingles = 0;
    long pairs = 0;

    for (int i = 0; i < n; i++) {
        String row = sc.nextLine();
        int consecutive = 0;

        for (int j = 0; j < row.length(); j++) {
            if (row.charAt(j) == '.') {
                consecutive++;
                totalDots++;
            } else {
                oddSingles += consecutive % 2;
                pairs      += consecutive / 2;
                consecutive = 0;
            }
        }
        // handle trailing dots in the row
        oddSingles += consecutive % 2;
        pairs      += consecutive / 2;
    }
    return new long[] { totalDots, oddSingles, pairs };
}

