/**
 * Marks the smallest prime factor for each multiple of {@code prime}
 * that has not been marked yet.
 */
private void markMultiples(int[] ar, int prime) {
    for (int k = prime; k < ar.length; k += prime) {
        if (ar[k] == 0) {
            ar[k] = prime;
        }
    }
}

