        left = i;
        right = i;
    }
    return ans;
}

/**
 * For a starting index that holds '1', evaluates all substrings
 * up to length 20 (or the remaining string length) and counts
 * those that satisfy the condition ((right‑left) + length >= value).
 */
private static long countFromOne(String s, int start, int left, int right) {
    long added = 0;
    int maxLen = Math.min(20, s.length() - start);   // ensure we never exceed the string

    for (int len = 1; len <= maxLen; len++) {
        int value = binaryValue(s, start, len);
        if ((right - left) + len >= value) {
            added++;
        }
    }
    return added;
}

/**
 * Returns the integer value of the binary substring
 * s[start .. start+length‑1].
 */
private static int binaryValue(String s, int start, int length) {
    int val = 0;
    for (int i = start; i < start + length; i++) {
        val = (val << 1) + (s.charAt(i) == '1' ? 1 : 0);
    }
    return val;
}

