    Scanner scan = new Scanner(System.in);
    t = scan.nextInt();
    scan.nextLine();

    Map<String, Driver> nameMap = new HashMap<>();

    // 1️⃣ Build the driver collection from the input
    populateDrivers(scan, t, nameMap);

    List<Driver> drivers = new ArrayList<>(nameMap.values());
    drcnt = drivers.size();

    // 2️⃣ First ranking: points, then win counts for all positions
    Collections.sort(drivers, (d1, d2) -> compareByPointsThenWins(d1, d2, drcnt));
    System.out.println(drivers.get(0).name);

    // 3️⃣ Second ranking: wins in position 0, then points, then remaining win counts
    Collections.sort(drivers, (d1, d2) -> compareByWinsThenPoints(d1, d2, drcnt));
    System.out.println(drivers.get(0).name);
}

/* -------------------------------------------------------------
   Helper: read input and fill the map of drivers
   ------------------------------------------------------------- */
private static void populateDrivers(Scanner scan, int t, Map<String, Driver> nameMap) {
    for (int i = 0; i < t; i++) {
        int n = scan.nextInt();
        scan.nextLine();

        for (int j = 0; j < n; j++) {
            String name = scan.nextLine();

            // obtain existing Driver or create a new one
            Driver dr = nameMap.computeIfAbsent(name, Driver::new);

            // award points for the first ten positions
            if (j < 10) {
                dr.point += points[j];
            }

            // count a win (or placement) for this driver at position j
            dr.winMap.merge(j, 1, Integer::sum);
        }
    }
}

/* -------------------------------------------------------------
   Helper: compare two drivers – primary key = points,
   secondary keys = win counts for each position (0 … drcnt‑1)
   ------------------------------------------------------------- */
private static int compareByPointsThenWins(Driver d1, Driver d2, int drcnt) {
    if (d1.point != d2.point) {
        return d2.point - d1.point;               // higher points first
    }
    for (int i = 0; i < drcnt; i++) {
        int cmp = compareWinCounts(d1.winMap.get(i), d2.winMap.get(i));
        if (cmp != 0) {
            return cmp;                           // higher win count first
        }
    }
    return 0;
}

/* -------------------------------------------------------------
   Helper: compare two drivers – primary key = wins at position 0,
   secondary key = points, then wins for the remaining positions
   ------------------------------------------------------------- */
private static int compareByWinsThenPoints(Driver d1, Driver d2, int drcnt) {
    int cmp = compareWinCounts(d1.winMap.get(0), d2.winMap.get(0));
    if (cmp != 0) {
        return cmp;                               // more wins in position 0 first
    }
    if (d1.point != d2.point) {
        return d2.point - d1.point;               // higher points next
    }
    for (int i = 1; i < drcnt; i++) {
        cmp = compareWinCounts(d1.winMap.get(i), d2.winMap.get(i));
        if (cmp != 0) {
            return cmp;                           // higher win count first
        }
    }
    return 0;
}

/* -------------------------------------------------------------
   Small utility: compare two Integer win counts handling nulls
   ------------------------------------------------------------- */
private static int compareWinCounts(Integer w1, Integer w2) {
    if (w1 == null && w2 == null) {
        return 0;
    } else if (w1 == null) {
        return 1;          // null (no wins) is considered less
    } else if (w2 == null) {
        return -1;
    } else {
        return w2 - w1;    // higher win count first
    }
}

