public static void dijkstra(point source, boolean[][] vis, char[][] labyrinth, point[][] points) {
    Queue<point> queue = new PriorityQueue<>(2000001, new NodeComp());
    queue.add(source);
    vis[source.x][source.y] = true;

    while (!queue.isEmpty()) {
        point p = queue.poll();
        int x = p.x;
        int y = p.y;

        // move up
        if (x - 1 >= 0) {
            tryRelax(x - 1, y, p.remL, p.remR, labyrinth, points, vis, queue);
        }

        // move left (requires at least one left step remaining)
        if (y - 1 >= 0 && p.remL > 0) {
            tryRelax(x, y - 1, p.remL - 1, p.remR, labyrinth, points, vis, queue);
        }

        // move down
        if (x + 1 < labyrinth.length) {
            tryRelax(x + 1, y, p.remL, p.remR, labyrinth, points, vis, queue);
        }

        // move right (requires at least one right step remaining)
        if (y + 1 < labyrinth[0].length && p.remR > 0) {
            tryRelax(x, y + 1, p.remL, p.remR - 1, labyrinth, points, vis, queue);
        }
    }
}

/**
 * Attempts to relax the edge to the cell (nx,ny). If the cell is reachable,
 * updates its remaining‑left/right counters, enqueues it and marks it visited.
 */
private static void tryRelax(int nx, int ny,
                             int newRemL, int newRemR,
                             char[][] labyrinth,
                             point[][] points,
                             boolean[][] vis,
                             Queue<point> queue) {
    // Wall check
    if (labyrinth[nx][ny] == '*') {
        return;
    }

    // Relaxation according to the original problem's logic
    if (!relax(nx, ny, newRemL, newRemR, points)) {
        return;
    }

    // Uniform update of the target point
    point np = points[nx][ny];
    np.remL = newRemL;
    np.remR = newRemR;

    // Enqueue for further processing and record visitation
    queue.add(np);
    vis[nx][ny] = true;
}

