static void solve()
	{
		int n = ni(), m = ni();
		int[][] co = new int[m][];
		for(int i = 0;i < m;i++){
			co[i] = na(3);
		}
		Map<Long, Integer> map = new HashMap<>();
		for(int[] c : co){
			map.put((long)c[0]<<32|c[1], c[2]);
		}
		int[] udiag = new int[n-1];
		int[] ddiag = new int[n-1];
		int[] diag = new int[n];
		Arrays.fill(diag, -1);
		Arrays.fill(udiag, -1);
		Arrays.fill(ddiag, -1);

		int mod = 998244353;
		for(int i = 1;i <= n;i++){
			if(!map.containsKey((long)i<<32|i)){
			}else{
				diag[i-1] = map.get((long)i<<32|i);
			}
		}
		int np = 0;
		for(int i = 0;i < m;i++){
			int[] c = co[i];
			if(c[1] == c[0] + 1){
				udiag[c[0]-1] = c[2];
				continue;
			}else if(c[1] == c[0] - 1){
				ddiag[c[1]-1] = c[2];
				continue;
			}
			if(c[1] == c[0])continue;
			long inv = (long)c[1]<<32|c[0];
			if(map.containsKey(inv)){
				np += 1;
				int u = map.get(inv);
				if(u+c[2] == 1){
					if(Math.abs(c[0]-c[1]) > 2){
						out.println(0);
						return;
					}

					if(Math.abs(c[0]-c[1]) == 2){
						int r = (c[0]+c[1])/2;
						if(!map.containsKey((long)r<<32|r)){
							diag[r-1] = 1;
						}else{
							int q = map.get((long)r<<32|r);
							if(q == 0){
								out.println(0);
								return;
							}
						}
					}
				}else{
					if(Math.abs(c[0]-c[1]) == 2){
						int r = (c[0]+c[1])/2;
						if(!map.containsKey((long)r<<32|r)){
							diag[r-1] = 0;
						}else{
							int q = map.get((long)r<<32|r);
							if(q == 1){
								out.println(0);
								return;
							}
						}
					}
				}
			}else{
				np += 2;
			}
		}
		long free = (long)(n-1)*(n-2)/2-np/2;






		long[] dp = new long[2];
		if(diag[0] == 0){
			dp[0] = 1;
		}else if(diag[0] == 1){
			dp[1] = 1;
		}else{
			dp[0] = dp[1] = 1;
		}

		for(int i = 1;i < n;i++){
			{
				int fi = (udiag[i-1] >= 0 ? 1 : 0) + (ddiag[i-1] >= 0 ? 1 : 0);
				int fs = udiag[i-1] ^ ddiag[i-1];
				long[] ndp = new long[2];
				if(fi == 2){
					for(int j = 0;j < 2;j++){
						ndp[j^fs] += dp[j];
					}
				}else if(fi == 1){
					ndp[0] = (dp[0] + dp[1]) % mod;
					ndp[1] = (dp[0] + dp[1]) % mod;
				}else{
					ndp[0] = (dp[0] + dp[1])*2L % mod;
					ndp[1] = (dp[0] + dp[1])*2L % mod;
				}
				dp = ndp;
			}
			long[] ndp = new long[2];
			if(diag[i] == 0){
				ndp[0] = dp[0];
			}else if(diag[i] == 1){
				ndp[1] = dp[1];
			}else{
				ndp[0] = dp[0];
				ndp[1] = dp[1];
			}
			dp = ndp;
		}

		out.println((dp[0]+dp[1])%mod * pow(2, free, mod) % mod);
	}

