			for(int j = 0; j < C; j++)
				if(g.charAt(j) == '*')
					board[i][j] = true;
		}

		int[][] q = new int[R][C];
		int[][] w = new int[R][C];
		int[][] e = new int[R][C];
		int[][] r = new int[R][C];
		for(int i = 1; i < R-1; i++)
		{
			for(int j = 1; j < C-1; j++)
			{
				if(board[i][j])
				{
					if(board[i-1][j])
						q[i][j] = q[i-1][j] + 1;
					if(board[i][j-1])
						w[i][j] = w[i][j-1] + 1;
				}
			}
		}
		for(int i = R-2; i >= 1; i--)
		{
			for(int j = C-2; j >= 1; j--)
			{
				if(board[i][j])
				{
					if(board[i+1][j])
						e[i][j] = e[i+1][j] + 1;
					if(board[i][j+1])
						r[i][j] = r[i][j+1] + 1;
				}
			}
		}

		LinkedList<int[]> x = new LinkedList<>();
		for(int i = 1; i < R-1; i++)
		{
			for(int j = 1; j < C-1; j++)
			{
				int result = Math.min(Math.min(q[i][j], w[i][j]), Math.min(e[i][j], r[i][j]));
				if(result > 0) x.add(new int[] {i+1, j+1, result});
			}
		}

		boolean[][] comp = new boolean[R][C];
		for(int[] temp : x)
		{
			int a = temp[0]-1;
			int b = temp[1]-1;
			int size = temp[2];
			comp[a][b] = true;
			for(int i = 1; i <= size; i++)
				comp[a-i][b] = comp[a+i][b] = comp[a][b-i] = comp[a][b+i] = true;

		}

		for(int i = 0; i < R; i++)
		{
