/**
 * Processes the tree level‑by‑level, maintaining the DP tables and
 * returning the maximum achievable score.
 */
private static long computeAnswer(int n, int[] p, int[] v, int[] d,
                                 ArrayList<Integer>[] adjList, int maxD) {
    long[][] dp = new long[n][2];
    ArrayList<Integer> al = new ArrayList<Integer>();
    al.add(0);
    long ans = 0;

    while (!al.isEmpty()) {
        TreeMap<Long, Integer> before = new TreeMap<Long, Integer>();
        TreeMap<Long, Integer> after = new TreeMap<Long, Integer>();
        ArrayList<Integer> temp = new ArrayList<Integer>();

        // gather children of current frontier and populate 'after' map
        for (int cur : al) {
            for (int x : adjList[cur]) {
                temp.add(x);
                long key = dp[p[x]][1] + v[x];
                after.put(key, after.getOrDefault(key, 0) + 1);
            }
        }
        al = temp;
        Collections.sort(al, (a, b) -> v[a] - v[b]);

        // process nodes in sorted order
        for (int cur : al) {
            long curKey = dp[p[cur]][1] + v[cur];
            int cnt = after.get(curKey);
            if (cnt == 1) {
                after.remove(curKey);
            } else {
                after.put(curKey, cnt - 1);
            }

            long bestBef = before.isEmpty() ? -(int) 1e9 : before.lastKey();
            long bestAft = after.isEmpty() ? -(int) 1e9 : after.lastKey();

            dp[cur][1] = Math.max(
                Math.max(bestBef + v[cur], bestAft - v[cur]),
                getScore(cur) + dp[p[cur]][1]
            );

            if (d[cur] == maxD) {
                ans = Math.max(ans, dp[cur][1]);
            }

            long beforeKey = dp[p[cur]][1] - v[cur];
            before.put(beforeKey, before.getOrDefault(beforeKey, 0) + 1);
        }
    }

    return ans;
}

