/**
 * Returns true if the given string reads the same when mirrored,
 * according to the specific character pairs used in the original program.
 */
private static boolean isMirrored(String str) {
    int lastIndex = str.length() - 1;
    for (int i = 0; i <= lastIndex / 2; i++) {
        char left  = str.charAt(i);
        char right = str.charAt(lastIndex - i);
        if (!matches(left, right)) {
            return false;               // first mismatch → not mirrored
        }
    }
    return true;                        // all positions matched
}

/**
 * Determines whether a pair of characters satisfies the mirror rules.
 * Symmetric characters must be identical and belong to the allowed set.
 * Some characters have distinct mirror partners (e.g., b ↔ d, p ↔ q).
 */
private static boolean matches(char left, char right) {
    // Characters that are symmetric with themselves (both upper‑ and lower‑case)
    String symmetric = "AHIMOTUVWXYvhwx";
    if (left == right && symmetric.indexOf(left) >= 0) {
        return true;
    }
    // Explicit mirror pairs
    return (left == 'b' && right == 'd') ||
           (left == 'd' && right == 'b') ||
           (left == 'p' && right == 'q') ||
           (left == 'q' && right == 'p');
}

