private static void solve() {
        int firstSize = scanner.nextInt();
        int secondSize = scanner.nextInt();
        int n = Math.max(firstSize, secondSize);
        int m = Math.min(firstSize, secondSize);
        long k = scanner.nextLong();

        int[] first = new int[firstSize];
        Pair[] firstSorted = new Pair[firstSize];
        for (int i = 0; i < firstSize; i++) {
            first[i] = scanner.nextInt();
            firstSorted[i] = new Pair(i, first[i]);
        }
        Arrays.sort(firstSorted);
        int[] second = new int[secondSize];
        Pair[] secondSorted = new Pair[secondSize];
        for (int i = 0; i < secondSize; i++) {
            second[i] = scanner.nextInt();
            secondSorted[i] = new Pair(i, second[i]);
        }
        Arrays.sort(secondSorted);

        long lcm = lcm(n, m);
        Pair[] aSorted;
        Pair[] bSorted;
        int[] a;
        int[] b;
        if (firstSize > secondSize) {
            aSorted = firstSorted;
            bSorted = secondSorted;
            a = first;
            b = second;
        } else {
            aSorted = secondSorted;
            bSorted = firstSorted;
            a = second;
            b = first;
        }

        int aPointer = 0;
        int bPointer = 0;
        List<Long> daysUntilEqual = new ArrayList<>();
        while (aPointer < n && bPointer < m) {
            if (aSorted[aPointer].value == bSorted[bPointer].value) {

                int aIndex = aSorted[aPointer].index;
                int bIndex = bSorted[bPointer].index;

                int diff = (aIndex - bIndex);
                if (diff < 0) {
                    diff += n;
                }
                long x = solveLinearCongruence(m, diff, n);
                if (x != -1) {
                    daysUntilEqual.add((bIndex + x * m) + 1);
                }
                aPointer++;
                bPointer++;
            } else if (aSorted[aPointer].value < bSorted[bPointer].value) {
                aPointer++;
            } else {
                bPointer++;
            }
        }
        Collections.sort(daysUntilEqual);

        int amountEqual = daysUntilEqual.size();
        long amountWrongPerRound = lcm - amountEqual;

        long amountFullRounds = (k-1) / amountWrongPerRound;
        long result = amountFullRounds * lcm;
        k = (k-1) % amountWrongPerRound + 1;
        result += k;

        int amountEqualReachable = 0;
        for (long days: daysUntilEqual) {
            if (days <= k) {
                amountEqualReachable++;
            }
        }

        aPointer = (int) (k % n);
        bPointer = (int) (k % m);

        while (amountEqualReachable > 0) {
            if (a[aPointer] != b[bPointer]) {
                amountEqualReachable--;
            }
            aPointer = (aPointer + 1) % n;
            bPointer = (bPointer + 1) % m;
            result++;
        }

        out.println(result);
    }

