/**
 * Handles the logic of moving from cell (tr,tc) to its neighbour (nr,nc).
 * Updates the resource arrays (x, y), the distance array (lost) and
 * the priority queue (heap) according to the movement rules.
 */
private static void relaxNeighbor(int tr, int tc, int nr, int nc,
                                  int dRow, int dCol,
                                  long[][] x, long[][] y,
                                  int[][] lost,
                                  PriorityQueue<Node> heap,
                                  Node current) {
    // vertical movement (no resource consumption)
    if (dCol == 0) {
        x[nr][nc] = x[tr][tc];
        y[nr][nc] = y[tr][tc];
        if (current.l < lost[nr][nc]) {
            heap.add(new Node(nr, nc, current.l));
            lost[nr][nc] = current.l;
        }
        return;
    }

    // move left (consume one from x if possible)
    if (dCol == -1 && x[tr][tc] > 0) {
        x[nr][nc] = x[tr][tc] - 1;
        y[nr][nc] = y[tr][tc];
        if (current.l + 1 < lost[nr][nc]) {
            heap.add(new Node(nr, nc, current.l + 1));
            lost[nr][nc] = current.l + 1;
        }
        return;
    }

    // move right (consume one from y if possible)
    if (dCol == 1 && y[tr][tc] > 0) {
        x[nr][nc] = x[tr][tc];
        y[nr][nc] = y[tr][tc] - 1;
        if (current.l + 1 < lost[nr][nc]) {
            heap.add(new Node(nr, nc, current.l + 1));
            lost[nr][nc] = current.l + 1;
        }
    }
}

