/**
 * Attempts to move from (tr,tc) to each of the four orthogonal neighbours.
 * Updates the distance array {@code lost} and the priority queue {@code heap}
 * according to the problem's movement rules.
 */
private static void relaxNeighbors(int tr, int tc, Node temp,
                                   int[] ar, int[] ac,
                                   long[][] x, long[][] y,
                                   int[][] lost,
                                   PriorityQueue<Node> heap,
                                   String[] grid, int n, int m) {
    for (int i = 0; i < 4; i++) {
        int nr = tr + ar[i];
        int nc = tc + ac[i];

        if (nr < 0 || nr >= n || nc < 0 || nc >= m)
            continue;
        if (grid[nr].charAt(nc) == '*')
            continue;

        if (ac[i] == 0) {                     // vertical move, cost 0
            x[nr][nc] = x[tr][tc];
            y[nr][nc] = y[tr][tc];
            if (temp.l < lost[nr][nc]) {
                heap.add(new Node(nr, nc, temp.l));
                lost[nr][nc] = temp.l;
            }
        } else if (ac[i] == -1 && x[tr][tc] > 0) { // move left, consume one x‑token
            x[nr][nc] = x[tr][tc] - 1;
            y[nr][nc] = y[tr][tc];
            if (temp.l + 1 < lost[nr][nc]) {
                heap.add(new Node(nr, nc, temp.l + 1));
                lost[nr][nc] = temp.l + 1;
            }
        } else if (ac[i] == 1 && y[tr][tc] > 0) {  // move right, consume one y‑token
            x[nr][nc] = x[tr][tc];
            y[nr][nc] = y[tr][tc] - 1;
            if (temp.l + 1 < lost[nr][nc]) {
                heap.add(new Node(nr, nc, temp.l + 1));
                lost[nr][nc] = temp.l + 1;
            }
        }
    }
