private static void cutPiece(LinkedList<Piece> pc, int tar, int rawPos) {
    Piece temp = pc.get(tar);
    int circ = temp.h * 2 + temp.w * 2;

    int pos = rawPos % circ;
    if (pos < 0) pos += circ;

    int px = 0, py = 0;

    if (pos <= temp.w) {                     // top edge
        px = pos;
        if (px * 2 > temp.w) {
            pc.add(new Piece(temp.x + px, temp.y, temp.w - px, temp.h));
            pc.add(new Piece(temp.x, temp.y, px, temp.h));
        } else {
            pc.add(new Piece(temp.x, temp.y, px, temp.h));
            pc.add(new Piece(temp.x + px, temp.y, temp.w - px, temp.h));
        }
    } else {
        px = temp.w;
        pos -= temp.w;

        if (pos <= temp.h) {                 // right edge
            py = pos;
            if (py * 2 > temp.h) {
                pc.add(new Piece(temp.x, temp.y + py, temp.w, temp.h - py));
                pc.add(new Piece(temp.x, temp.y, temp.w, py));
            } else {
                pc.add(new Piece(temp.x, temp.y, temp.w, py));
                pc.add(new Piece(temp.x, temp.y + py, temp.w, temp.h - py));
            }
        } else {
            py = temp.h;
            pos -= temp.h;

            if (pos <= temp.w) {             // bottom edge
                px -= pos;
                if (px * 2 > temp.w) {
                    pc.add(new Piece(temp.x + px, temp.y, temp.w - px, temp.h));
                    pc.add(new Piece(temp.x, temp.y, px, temp.h));
                } else {
                    pc.add(new Piece(temp.x, temp.y, px, temp.h));
                    pc.add(new Piece(temp.x + px, temp.y, temp.w - px, temp.h));
                }
            } else {                         // left edge
                pos -= temp.w;
                px = 0;
                py = temp.h - pos;
                if (py * 2 > temp.h) {
                    pc.add(new Piece(temp.x, temp.y + py, temp.w, temp.h - py));
                    pc.add(new Piece(temp.x, temp.y, temp.w, py));
                } else {
                    pc.add(new Piece(temp.x, temp.y, temp.w, py));
                    pc.add(new Piece(temp.x, temp.y + py, temp.w, temp.h - py));
                }
            }
        }
    }

    pc.remove(tar);
}

