 * The result is stored in the provided boolean array:
 *   win[0] → true if X (first player) has a winning line,
 *   win[1] → true if 0 (second player) has a winning line.
 */
private void computeWins(String[] board, boolean[] win) {
    // rows
    for (int row = 0; row < 3; ++row) {
        if (board[row].charAt(0) == board[row].charAt(1)
                && board[row].charAt(1) == board[row].charAt(2)) {
            if (board[row].charAt(0) == 'X')
                win[0] = true;
            else if (board[row].charAt(0) == '0')
                win[1] = true;
        }
    }

    // columns
    for (int col = 0; col < 3; ++col) {
        if (board[0].charAt(col) == board[1].charAt(col)
                && board[1].charAt(col) == board[2].charAt(col)) {
            if (board[0].charAt(col) == 'X')
                win[0] = true;
            else if (board[0].charAt(col) == '0')
                win[1] = true;
        }
    }

    // main diagonal
    if (board[0].charAt(0) == board[1].charAt(1)
            && board[1].charAt(1) == board[2].charAt(2)) {
        if (board[0].charAt(0) == 'X')
            win[0] = true;
        else if (board[0].charAt(0) == '0')
