/**
 * Tries to satisfy the requirement for the bit represented by {@code mask}
 * using the current multiset of powers of two stored in {@code powers}.
 *
 * @param i      the exponent of the current bit (0‑based)
 * @param mask   1L << i
 * @param powers counts of available powers of two; modified as a side‑effect
 * @return 0 if the requirement can be satisfied by consuming existing powers,
 *         (j‑i) where j is the next higher power that is borrowed,
 *         or -1 if it is impossible.
 */
private static int handleBit(int i, long mask, int[] powers) {
    long tot = 0L;
    for (int j = 0; j <= i; j++) {
        tot += (long) powers[j] << j;   // powers[j] * (1L << j)
    }

    if (tot >= mask) {
        // Consume the needed amount from the available powers (greedy reduction)
        long val = mask;
        int start = i;
        while (val > 0 && start >= 0) {
            long unit = 1L << start;
            long available = unit * powers[start];
            if (available < val) {
                val -= available;
                powers[start] = 0;
            } else {
                long req = val / unit;
                powers[start] -= (int) req;
                val = 0;
            }
            start--;
        }
        return 0;                       // no extra steps added
    } else {
        // Need to take one from a higher power and split it down
        for (int j = i + 1; j < powers.length; j++) {
            if (powers[j] > 0) {
                powers[j]--;
                for (int k = j - 1; k >= i; k--) {
                    powers[k]++;       // split the higher power
                }
                return j - i;         // number of operations added
            }
        }
        return -1;                      // cannot satisfy this bit
    }
}

