		int n = in.nextInt();
		int place = in.nextInt();
		if (place == n + 1) {
			System.out.println(0);
			return;
		}
		int needBeHigher = n + 1 - place;
		long inf = Long.MAX_VALUE / 3;
		long ans = inf;


		int[] points = new int[n];
		int[] effort = new int[n];
		for (int i = 0; i < n; i++) {

			points[i] = in.nextInt();
			effort[i] = in.nextInt();




		}
		int[] allPoints = points.clone();
		Arrays.sort(allPoints);
		int needPoints = allPoints[n - place];
		for (int gotPoints = needPoints; gotPoints <= needPoints + 2; gotPoints++) {
			List<Integer> a = new ArrayList<>();
			List<Integer> b = new ArrayList<>();
			int c = 0;
			for (int i = 0; i < n; i++) {
				int p = points[i];
				int e = effort[i];
				if (p > gotPoints) {
					a.add(e);
				} else if (p == gotPoints || p == gotPoints - 1) {
					b.add(e);
				} else {
					a.add(e);
					c++;
				}
			}
			Collections.sort(a);
			Collections.sort(b);
			long cur = 0;
			int takeB = needBeHigher - c;
			if (takeB > b.size()) {
				continue;
			}
			if (takeB < 0) {
				takeB = 0;
			}
			int score = 0;
			int ai = 0;
			int bi = 0;
			while (takeB > 0) {
				takeB--;
				cur += b.get(bi);
				bi++;
				score++;
			}
			while (score < gotPoints) {
				if (bi < b.size() && (ai == a.size() || b.get(bi) < a.get(ai))) {
					cur += b.get(bi);
					bi++;
					score++;
				} else if (ai < a.size()) {
					cur += a.get(ai);
					ai++;
					score++;
				} else {
					break;
				}
			}
			if (score >= gotPoints) {
				ans = Math.min(ans, cur);
			}
		}






		System.out.println(ans == inf ? -1 : ans);
	}

