/**
 * Handles all logic that determines the state of vertex {@code i},
 * updates the {@code str} array and the global {@code correct} flag.
 */
private static void processVertex(int i, int n, List<List<Integer>> g, int[] str) {
    if (str[i] == 1)
        return;

    // Process neighbours that are already classified (not -1)
    for (Integer ver : g.get(i)) {
        if (str[ver] == 1 || str[ver] == -1)
            continue;
        if (str[i] == -1) {
            str[i] = (str[ver] == 0) ? 0 : 2;
        } else {
            if (str[i] != str[ver])
                correct = false;
        }
    }

    // Process non‑neighbours that are already classified (not -1)
    for (int ver = 0; ver < n; ver++) {
        if (ver == i)
            continue;
        if (g.get(i).contains(ver) || str[ver] == -1)
            continue;
        if (str[ver] == 1)
            correct = false;
        if (str[i] == -1) {
            str[i] = (str[ver] == 0) ? 2 : 0;
        } else {
            if (str[i] == str[ver])
                correct = false;
        }
    }

    // Ensure current vertex has a value
    if (str[i] == -1)
        str[i] = 0;

    // Propagate the value to still‑unassigned neighbours
    for (Integer ver : g.get(i)) {
        if (str[ver] == -1)
            str[ver] = (str[i] == 0) ? 0 : 2;
    }

    // Propagate the value to still‑unassigned non‑neighbours
    for (int ver = 0; ver < n; ver++) {
        if (ver == i)
            continue;
        if (!g.get(i).contains(ver) && str[ver] == -1) {
            str[ver] = (str[i] == 0) ? 2 : 0;
        }
    }
}

