public static void main(String[] args) throws IOException {
		Scanner sc = new Scanner(System.in);
		PrintWriter out = new PrintWriter(System.out);
		int N = sc.nextInt();
		int[] a = new int[N];
		ArrayList<Pair> ans = new ArrayList<Pair>();
		int[][] pos = new int[2][N + 1];
		int[][] pre = new int[2][N];
		Arrays.fill(pos[0], -1);
		Arrays.fill(pos[1], -1);
		int t1 = 0, t2 = 0;
		for (int i = 0; i < N; i++) {
			a[i] = sc.nextInt();
			if (i != 0) {
				pre[0][i] = pre[0][i - 1];
				pre[1][i] = pre[1][i - 1];
			}
			if (a[i] == 1) {
				pos[0][++t1] = i;
				pre[0][i]++;
			} else {
				pos[1][++t2] = i;
				pre[1][i]++;
			}
		}

		for (int t = 1; t <= N; t++) {

			int idx = -1;
			int prevIdx = -1;
			int oneWins = 0, twoWins = 0;
			while (idx < N) {
				prevIdx = idx;
				int seenOnes = idx == -1 ? 0 : pre[0][idx], seenTwos = idx == -1 ? 0 : pre[1][idx];
				if (t + seenOnes > N || t + seenTwos > N)
					break;
				int idxOne = pos[0][t + seenOnes], idxTwo = pos[1][t + seenTwos];
				int nxtIdx = -1;
				if (idxOne == -1)
					nxtIdx = idxTwo;
				else if (idxTwo == -1)
					nxtIdx = idxOne;
				else if (idxOne < idxTwo)
					nxtIdx = idxOne;
				else
					nxtIdx = idxTwo;

				idx = nxtIdx;
				if (idx == -1)
					break;
				if (a[idx] == 1)
					oneWins++;
				else
					twoWins++;
				int onesInCurrentSet = pre[0][idx] - (prevIdx == -1 ? 0 : pre[0][prevIdx]),
						twosInCurrentSet = pre[1][idx] - (prevIdx == -1 ? 0 : pre[1][prevIdx]);
				if ((a[idx] == 1 && (onesInCurrentSet > t || onesInCurrentSet <= twosInCurrentSet))
						|| a[idx] == 2 && (twosInCurrentSet > t || twosInCurrentSet <= onesInCurrentSet))
					break;
			}

			if (prevIdx == N - 1)
				if (oneWins > twoWins && a[N - 1] == 1)
					ans.add(new Pair(oneWins, t));
				else if (twoWins > oneWins && a[N - 1] == 2)
					ans.add(new Pair(twoWins, t));
		}

		Collections.sort(ans);
		out.println(ans.size());
		for (int i = 0, sz = ans.size(); i < sz; ++i) {
			Pair cur = ans.get(i);
			out.println(cur.s + " " + cur.t);
		}
		out.flush();
		out.close();

	}

