/**
 * Answers a single range query [l, r] using the pre‑computed dp and prefix sums.
 * The logic is exactly the same as the original inline implementation.
 */
private static void answerQuery(int l, int r, int[] dp,
                                long[] cumudp, long[] cumuind,
                                PrintWriter out) {
    if (dp[l] > r) {
        long ans = (long) (r + 1) * (long) (r - l + 1)
                 - (cumuind[r + 1] - cumuind[l]);
        out.println(ans);
    } else {
        int low = l;
        int high = r;
        while (low < high) {
            int mid = (low + high + 1) / 2;
            if (dp[mid] <= r) {
                low = mid;
            } else {
                high = mid - 1;
            }
        }
        int mid = low + 1;
        long ans = 0L;
        if (mid <= r) {
            ans += (long) (r + 1) * (long) (r - mid + 1)
                 - (cumuind[r + 1] - cumuind[mid]);
        }
        ans += (cumudp[low + 1] - cumudp[l])
             + (long) (low - l + 1)
             - (cumuind[low + 1] - cumuind[l]);
        out.println(ans);
    }
}

