/**
 * Computes the diameter of the connected component that contains {@code start},
 * marks all its vertices as visited, and stores the result in {@code ds.path}.
 */
private static void computeComponentDiameter(int start,
                                            ArrayList<Integer>[] adj,
                                            boolean[] visited,
                                            DisjointSet ds) {
    // First BFS: discover the whole component and obtain a farthest vertex (last)
    ArrayDeque<Integer> queue = new ArrayDeque<>();
    queue.add(start);
    visited[start] = true;
    int last = start;

    while (!queue.isEmpty()) {
        int node = queue.remove();
        last = node;
        for (int next : adj[node]) {
            if (!visited[next]) {
                visited[next] = true;
                queue.add(next);
            }
        }
    }

    // Second BFS from 'last' to compute the component's diameter
    queue.clear();
    // Encode (node, parent, distance) sequentially in the queue
    queue.add(last);
    queue.add(-1);   // parent sentinel
    queue.add(0);    // distance from start vertex

    int maxDist = 0;
    while (!queue.isEmpty()) {
        int node = queue.remove();
        int parent = queue.remove();
        int dist = queue.remove();
        maxDist = Math.max(maxDist, dist);
        for (int next : adj[node]) {
            if (next != parent) {
                queue.add(next);
                queue.add(node);
                queue.add(dist + 1);
            }
        }
    }

    ds.path[ds.find(last)] = maxDist;
}

