public static void main(String[] args) throws IOException {
    BufferedReader bf = new BufferedReader(new InputStreamReader(System.in));
    String me = bf.readLine();
    int n = Integer.parseInt(bf.readLine());

    HashMap<String, Integer> priority = new HashMap<>();

    for (int i = 0; i < n; i++) {
        String line = bf.readLine();
        processRecord(line, me, priority);
    }

    // sort keys by priority (descending)
    String[] keys = priority.keySet().toArray(new String[0]);
    for (int i = 0; i < keys.length; i++) {
        int max = 0, maxP = i;
        for (int j = i; j < keys.length; j++) {
            if (priority.get(keys[j]) > max) {
                max = priority.get(keys[j]);
                maxP = j;
            }
        }
        swap(i, keys, maxP);
    }

    // stable lexical ordering for equal priorities
    for (int i = 0; i < keys.length - 1; i++) {
        int j;
        for (j = i + 1; j < keys.length; j++) {
            if (!priority.get(keys[j]).equals(priority.get(keys[i]))) {
                break;
            }
        }
        sortLex(i, j, keys);
        i = j - 1;
    }

    for (String key : keys) {
        System.out.println(key);
    }
}

/**
 * Parses a single record line, determines the two involved persons,
 * and updates the priority map according to the action value.
 */
private static void processRecord(String line, String me,
                                 HashMap<String, Integer> priority) {
    String[] ns = line.split(" ");
    String first = ns[0];
    String second;

    // determine the "other" person (the one whose name ends with ’s)
    if (ns[2].substring(ns[2].length() - 2).equals("'s")) {
        second = ns[2].substring(0, ns[2].length() - 2);
    } else {
        second = ns[3].substring(0, ns[3].length() - 2);
    }

    if (first.equals(me) || second.equals(me)) {
        // the line involves the current user – adjust the other's priority
        if (first.equals(me)) {
            priority.merge(second, actionVal(ns[1]), Integer::sum);
        } else {
            priority.merge(first, actionVal(ns[1]), Integer::sum);
        }
    } else {
        // ensure both persons are present in the map with a default of 0
        priority.putIfAbsent(first, 0);
        priority.putIfAbsent(second, 0);
    }
}

