/**
 * Processes a single connected component of the directed/undirected graph.
 *
 * @param start the first vertex of the component
 * @param edges adjacency lists of the whole graph
 * @param seen  shared array marking vertices that have already been visited
 * @return the amount to add to the overall answer for this component
 */
private static int processComponent(int start, LinkedList<Edge>[] edges, boolean[] seen) {
    LinkedList<Integer> q = new LinkedList<>();
    Map<Integer, Integer> p = new HashMap<>();

    // First BFS: collect component vertices and count "real" outgoing edges
    q.add(start);
    seen[start] = true;
    p.put(start, 0);
    while (!q.isEmpty()) {
        int curr = q.removeFirst();
        for (Edge out : edges[curr]) {
            p.putIfAbsent(out.to, 0);
            if (out.real) {
                p.put(out.to, p.get(out.to) + 1);
            }
            if (!seen[out.to]) {
                seen[out.to] = true;
                q.add(out.to);
            }
        }
    }

    // Second phase: topological‑like removal of vertices with zero remaining real edges
    int add = 0;
    for (int v : p.keySet()) {
        if (p.get(v) == 0) {
            q.add(v);
        }
    }
    while (!q.isEmpty()) {
        int curr = q.removeFirst();
        add++;
        for (Edge out : edges[curr]) {
            if (out.real) {
                int next = p.get(out.to) - 1;
                if (next == 0) {
                    q.add(out.to);
                }
                p.put(out.to, next);
            }
        }
    }

    // If all vertices were removed in the second phase we lose one edge from the count
    return (add == p.size()) ? p.size() - 1 : p.size();
}

