/**
 * Builds an array where each element is a bitmask indicating which of the
 * required items (given in {@code name}) can be supplied by supplier {@code i}
 * at the minimal price (values stored in {@code min}).
 *
 * @param supers array of maps, one per supplier, mapping item name → price
 * @param name   array of required item names
 * @param min    map of item name → minimal price across all suppliers
 * @return an int[] where {@code bits[i]} has bit {@code j} set iff supplier {@code i}
 *         can provide {@code name[j]} at the minimal price
 */
private int[] computeBits(Map<String, Integer>[] supers, String[] name, Map<String, Integer> min) {
    int n = supers.length;
    int q = name.length;
    int[] bits = new int[n];
    for (int i = 0; i < n; i++) {
        int bit = 0;
        for (int j = 0; j < q; j++) {
            if (supers[i].containsKey(name[j]) && supers[i].get(name[j]).equals(min.get(name[j]))) {
                bit |= 1 << j;
            }
        }
        bits[i] = bit;
    }
    return bits;
}

