public void solve(int testNumber, InputReader in, PrintWriter out) {
            int n = in.nextInt();
            ar = in.nextIntArray(n);
            int sieve[] = in.sieve((int) 1e7 + 1);
            TreeSet<Integer> tr = new TreeSet<>();
            for (int i = 2; i < sieve.length; i++) {
                if (sieve[i] == i) tr.add(i);
                if (tr.size() > 2e5 + 2) {
                    break;
                }
            }

            boolean equal = true;

            for (int i = 0; i < n; i++) {
                if (!equal) {
                    ar[i] = tr.pollFirst();
                } else {
                    int val = ar[i];
                    ArrayList<Integer> prime = new ArrayList<>();
                    HashMap<Integer, Integer> hm = new HashMap<>();
                    while (val != 1) {
                        if (!hm.containsKey(sieve[val])) {
                            prime.add(sieve[val]);
                            hm.put(sieve[val], 1);
                        }
                        val = val / sieve[val];
                    }
                    boolean is = true;
                    for (int j = 0; j < prime.size(); j++) {
                        if (!tr.contains(prime.get(j))) {
                            is = false;
                            break;
                        }
                    }
                    if (!is) {
                        for (int j = ar[i] + 1; j < 2e5 + 1; j++) {
                            ArrayList<Integer> pr = new ArrayList<>();
                            HashMap<Integer, Integer> h = new HashMap<>();
                            int va = j;
                            while (va != 1) {
                                if (!h.containsKey(sieve[va])) {
                                    pr.add(sieve[va]);
                                    h.put(sieve[va], 1);
                                }
                                va = va / sieve[va];
                            }
                            boolean ans = false;
                            for (int x : pr) {
                                if (!tr.contains(x)) {
                                    ans = true;
                                    break;
                                }
                            }
                            if (!ans) {
                                ar[i] = j;
                                for (int x : pr) {
                                    tr.remove(x);
                                }
                                break;
                            }
                        }

                        equal = false;
                    } else {
                        for (int x : prime) {
                            tr.remove(x);
                        }
                    }
                }
            }
            for (int i = 0; i < n; i++) {
                out.print(ar[i] + " ");
            }


        }

