        int numQueries = nextInt();
        int[] queryType = new int[numQueries];
        int[] queryX = new int[numQueries];
        int[] queryY = new int[numQueries];
        for (int i = 0; i < numQueries; ++i) {
            queryType[i] = nextInt();
            queryX[i] = nextInt();
            queryY[i] = nextInt();
        }
        double[] koef = new double[]{0.1, 0.1, 0.1};
        double sum = 0;
        double mx = 0;
        double my = 0;
        for (int i = 0; i < 3; ++i) {
            sum += koef[i];
            mx += koef[i] * queryX[i];
            my += koef[i] * queryY[i];
        }
        mx /= sum;
        my /= sum;
        double[] alpha = new double[numQueries];
        for (int i = 0; i < numQueries; ++i) {
            alpha[i] = Math.atan2(queryY[i] - my, queryX[i] - mx);
        }
        TreeSet<Point> cur = new TreeSet<Point>();
        for (int i = 0; i < 3; ++i) {
            cur.add(new Point(queryX[i], queryY[i], alpha[i]));
        }
        for (int i = 3; i < numQueries; ++i) {
            Point p = new Point(queryX[i], queryY[i], alpha[i]);
            SortedSet<Point> before = cur.headSet(p);
            SortedSet<Point> after = cur.tailSet(p);
            if (queryType[i] == 2) {
                Point a;
                if (before.isEmpty())
                    a = cur.last();
                else
                    a = before.last();
                Point b;
                if (after.isEmpty())
                    b = cur.first();
                else
                    b = after.first();
                if (turnSign(a, p, b) <= 0) writer.println("YES"); else writer.println("NO");
            } else {
                {
                    Point a;
                    if (before.isEmpty())
                        a = cur.last();
                    else
                        a = before.last();
                    Point b;
                    if (after.isEmpty())
                        b = cur.first();
                    else
                        b = after.first();
                    if (turnSign(a, p, b) <= 0) continue;
                }
                while (true) {
                    Point a;
                    if (after.isEmpty())
                        a = cur.first();
                    else
                        a = after.first();
                    cur.remove(a);
                    Point b;
                    if (after.isEmpty())
                        b = cur.first();
                    else
                        b = after.first();
                    if (turnSign(p, a, b) > 0) {
                        cur.add(a);
                        break;
                    }
                }
                while (true) {
                    Point a;
                    if (before.isEmpty())
                        a = cur.last();
                    else
                        a = before.last();
                    cur.remove(a);
                    Point b;
                    if (before.isEmpty())
                        b = cur.last();
                    else
                        b = before.last();
                    if (turnSign(p, a, b) < 0) {
                        cur.add(a);
                        break;
                    }
                }
                cur.add(p);
            }
        }
    }

