/**
 * Builds the required palindrome according to the problem statement.
 *
 * @param zeros initial number of '0' characters that must appear
 * @param ones  initial number of '1' characters that must appear
 * @param s     the input string possibly containing '?' placeholders
 * @return the completed palindrome, or null if it cannot be formed
 */
private static String constructPalindrome(int zeros, int ones, String s) {
    int n = s.length();
    char[] c = new char[n];
    int z = zeros;
    int o = ones;

    // copy known characters and update remaining counters
    for (int i = 0; i < n; i++) {
        char cc = s.charAt(i);
        c[i] = cc;
        if (cc == '0') {
            z--;
        } else if (cc == '1') {
            o--;
        }
    }

    int f = 1; // flag indicating feasibility

    // First pass – resolve positions where only one side is known
    for (int i = 0; i < n / 2; i++) {
        char l = s.charAt(i);
        char r = s.charAt(n - i - 1);

        if ((l == '0' && r == '1') || (l == '1' && r == '0')) {
            f = 0;
            break;
        } else {
            if (l == '?' && r != '?') {
                if (r == '1') {
                    if (o > 0) {
                        c[i] = '1';
                        o--;
                    } else {
                        f = 0;
                        break;
                    }
                } else { // r == '0'
                    if (z > 0) {
                        c[i] = '0';
                        z--;
                    } else {
                        f = 0;
                        break;
                    }
                }
            } else if (r == '?' && l != '?') {
                if (l == '1') {
                    if (o > 0) {
                        c[n - i - 1] = '1';
                        o--;
                    } else {
                        f = 0;
                        break;
                    }
                } else { // l == '0'
                    if (z > 0) {
                        c[n - i - 1] = '0';
                        z--;
                    } else {
                        f = 0;
                        break;
                    }
                }
            } else {
                if (l != r) {
                    f = 0;
                    break;
                }
            }
        }
    }

    // Second pass – fill pairs where both sides are '?'
    for (int i = 0; i < n / 2 && f == 1; i++) {
        char l = s.charAt(i);
        char r = s.charAt(n - i - 1);
        if (l == '?' && r == '?') {
            char x = '3';
            if (z >= 2) {
                x = '0';
                z -= 2;
            } else if (o >= 2) {
                x = '1';
                o -= 2;
            } else {
                f = 0;
                break;
            }
            c[i] = x;
            c[n - i - 1] = x;
        }
    }

    // Handle middle character for odd length strings
    if (n % 2 != 0 && f == 1) {
        if (s.charAt(n / 2) == '?') {
            if (o > 0) {
                c[n / 2] = '1';
                o--;
            } else if (z > 0) {
                c[n / 2] = '0';
                z--;
            } else {
                f = 0;
            }
        }
    }

    // If any counters remain, construction failed
    if (o > 0 || z > 0) {
        f = 0;
    }

    return f == 1 ? new String(c) : null;
}

