      tok = new StringTokenizer(in.readLine());
      Deque<Integer> deque = new ArrayDeque<>();
      List<Integer> finalDeq = null;
      ArrayList<Pair> requests = new ArrayList<>();
      Map<Integer, Integer> ansA = new TreeMap<>();
      Map<Integer, Integer> ansB = new TreeMap<>();
      int maxVal = -1;
      int maxind = -1;
      for (int i = 0; i < n; ++i){
        a[i] = Integer.parseInt(tok.nextToken());
        deque.addLast(a[i]);
        if (maxVal < a[i]) {
          maxVal = a[i];
          maxind = i;
        }
      }

