        long m = Long.parseLong(in.readLine());
        requests.add(new Pair(qq, m));
      }

      Collections.sort(requests,  (p1, p2) -> Long.compare(p1.value, p2.value));
      int lastPerm = 0;
      int lastA = -1;
      int lastB = -1;
      for (int i = 0; i < requests.size(); ++i) {
        Pair req  = requests.get(i);
        if (req.value <= maxind) {
          if (lastPerm == req.value) {
            ansA.put(req.index, lastA);
            ansB.put(req.index, lastB);
          } else while (lastPerm < req.value) {
            ++lastPerm;
            int A = deque.pollFirst();
            int B = deque.pollFirst();
            lastA = A;
            lastB = B;
            ansA.put(req.index, A);
            ansB.put(req.index, B);
            if (A > B) {
              deque.addFirst(A);
              deque.addLast(B);
            } else {
              deque.addFirst(B);
              deque.addLast(A);
            }
          }

        } else {
          while (lastPerm < maxind) {
            ++lastPerm;
            int A = deque.pollFirst();
            int B = deque.pollFirst();
            ansA.put(req.index, A);
            ansB.put(req.index, B);
            if (A > B) {
              deque.addFirst(A);
              deque.addLast(B);
            } else {
              deque.addFirst(B);
              deque.addLast(A);
            }
          }
          if (finalDeq== null) {
            finalDeq = new ArrayList<>();
            for (Integer aa : deque) {
              finalDeq.add(aa);
            }
          }
          assert lastPerm == maxind;
          int left =(int) ((req.value - (1L +  maxind)) % ((long) (n - 1)));
          int b = finalDeq.get(1 + left);

          ansA.put(req.index, finalDeq.get(0));
          ansB.put(req.index, b);
