/**
 * Checks whether the stars form the required shape.
 * Prints “YES” if the shape is valid, otherwise prints “NO”.
 */
private static void evaluateShape(char[][] a, int startRow, int startCol, boolean[][] visited) {
    int n = a.length;
    int m = a[0].length;

    int depth = 1;          // number of rows occupied by the vertical line
    int leftCount = 0;      // stars to the left on the branching row
    int rightCount = 0;     // stars to the right on the branching row
    int branchRow = 0;      // row where the horizontal branch appears
    int i = startRow + 1;   // we already know a[startRow][startCol] is '*'

    visited[startRow][startCol] = true;

    // walk down the vertical line
    while (i < n && a[i][startCol] == '*') {
        if (a[i][startCol - 1] == '*' || a[i][startCol + 1] == '*') {
            branchRow = i;
        }
        visited[i][startCol] = true;
        i++;
        depth++;
    }

    // a valid shape needs at least three rows and a branching row
    if (depth > 2 && branchRow + 1 < n && a[branchRow + 1][startCol] == '*') {
        // count left side of the branch
        int col = startCol - 1;
        while (col >= 0 && a[branchRow][col] == '*') {
            leftCount++;
            visited[branchRow][col] = true;
            col--;
        }

        // count right side of the branch
        col = startCol + 1;
        while (col < m && a[branchRow][col] == '*') {
            rightCount++;
            visited[branchRow][col] = true;
            col++;
        }

        if (leftCount == 0 || rightCount == 0) {
            System.out.println("NO");
            return;
        }

        // verify that every '*' has been visited
        for (int r = 0; r < n; r++) {
            for (int c = 0; c < m; c++) {
                if (a[r][c] == '*' && !visited[r][c]) {
                    System.out.println("NO");
                    return;
                }
            }
        }
        System.out.println("YES");
    } else {
        System.out.println("NO");
    }
}

