		dp2=new long[1<<len2];
		rec1=new long[len1];
		rec3=new long[len1];
		rec2=new long[len2];
		for(int i=0;i<len1;i++) {
			rec1[i]=graph[i]&((1L<<len1)-1);
			long mask=graph[i]>>len1;
			rec3[i]=mask;
		}
		for(int i=0;i<len2;i++) {
			long mask=graph[i+len1]>>len1;
			rec2[i]=mask;
		}
		Arrays.fill(dp1,-1);
		Arrays.fill(dp2,-1);
		dp1[0]=0;
		dp2[0]=0;
		for(int i=0;i<1<<len1;i++) {
			if(dp1[0]!=-1) {
				for(int j=0;j<len1;j++) {
					if((i&(1<<j))==0) {
