/**
 * For a given digit, gathers all its occurrences, sorts them,
 * and updates {@code ans[digit]} with the maximal possible area.
 */
private static void evaluatePositions(int digit, int[][] grid, int n, long[] ans) {
    List<Game> all = new ArrayList<>();
    List<Game1> all1 = new ArrayList<>();
    for (int r = 0; r < n; r++) {
        for (int c = 0; c < n; c++) {
            if (grid[r][c] == digit) {
                all.add(new Game(r, c));
                all1.add(new Game1(r, c));
            }
        }
    }
    Collections.sort(all);
    Collections.sort(all1);
    if (all.size() <= 1) {
        return; // nothing to improve
    }
    int size = all.size();
    for (int i = 0; i < size; i++) {
        int y = all.get(i).y;
        int x = all.get(i).x;
        long area = (long) Math.max(y, n - 1 - y) *
                Math.max(all.get(size - 1).x - x, x - all.get(0).x);
        ans[digit] = Math.max(ans[digit], area);
    }
    for (int i = 0; i < size; i++) {
        int y = all1.get(i).y;
        int x = all1.get(i).x;
        long area = (long) Math.max(x, n - 1 - x) *
                Math.max(all1.get(size - 1).y - y, y - all1.get(0).y);
        ans[digit] = Math.max(ans[digit], area);
    }
}

