/** extracts the logic that handles a song‑event (type == 1). */
private boolean assignSong(Event e,
                           Song[] songs,
                           Singer[] singers,
                           Singer[] sortedSingers,
                           int numSingers,
                           int[] ans) {
    int l = -1;
    int r = numSingers - 1;
    int need = songs[e.id].r;

    // binary search for the first singer whose right bound >= need
    while (r - l > 1) {
        int m = (l + r) / 2;
        Singer s = sortedSingers[m];
        if (s.r >= need) {
            r = m;
        } else {
            l = m;
        }
    }
    if (sortedSingers[r].r < need) {
        return false; // no singer can cover the song
    }

    int first = r;
    l = first - 1;
    r = numSingers - 1;
    if (sum(first, numSingers - 1) == 0) {
        return false; // no available singer in the feasible range
    }

    // binary search for the leftmost singer with a positive count
    while (r - l > 1) {
        int m = (l + r) / 2;
        if (sum(first, m) > 0) {
            r = m;
        } else {
            l = m;
        }
    }
    Singer best = sortedSingers[r];
    --best.k;
    if (best.k == 0) {
        add(r, -1);
    }
    ans[e.id] = best.id;
    return true;
}

