/**
 * Performs the two‑player BFS on the graph.
 * Fills {@code dp} and {@code dpPrev} and returns true if the target state
 * (player 0 at vertex n‑1 and player 1 at vertex 0) is reachable.
 */
private static boolean bfs(int n, List<Integer>[] graph,
                           boolean[][][] dp, int[][][] dpPrev) {
    int[] q = new int[5_000_000];
    int qh = 0, qt = 0;

    dp[0][0][n - 1] = true;
    q[qt++] = 0;          // turn
    q[qt++] = 0;          // a position
    q[qt++] = n - 1;      // b position

    while (qt > qh) {
        if (dp[0][n - 1][0]) {
            break;
        }
        int turn = q[qh++];
        int a = q[qh++];
        int b = q[qh++];

        if (turn == 0) {                     // player 0 moves
            for (int to : graph[a]) {
                if (!dp[1][to][b]) {
                    dp[1][to][b] = true;
                    dpPrev[1][to][b] = a;
                    q[qt++] = 1;
                    q[qt++] = to;
                    q[qt++] = b;
                }
            }
        } else {                               // player 1 moves
            for (int to : graph[b]) {
                if (!dp[0][a][to] && a != to) {
                    dp[0][a][to] = true;
                    dpPrev[0][a][to] = b;
                    q[qt++] = 0;
                    q[qt++] = a;
                    q[qt++] = to;
                }
            }
        }
    }
    return dp[0][n - 1][0];
}

/**
 * Reconstructs the move histories for both players after a successful search.
 * The resulting histories are appended to {@code aHistory} and {@code bHistory}.
 */
private static void reconstructPath(int n, int[][][] dpPrev,
                                    List<Integer> aHistory,
                                    List<Integer> bHistory) {
    int nt = 0;          // current turn: 0 = player 0, 1 = player 1
    int na = n - 1;      // current vertex of player 0
    int nb = 0;          // current vertex of player 1

    aHistory.add(n - 1);
    bHistory.add(0);

    while (true) {
        if (na == 0 && nb == n - 1) {
            break;
        }
        int tt = 1 - nt;   // next turn
        int ta = na;
        int tb = nb;

        if (nt == 0) {      // player 0 just moved, retrieve previous b
            tb = dpPrev[nt][na][nb];
            bHistory.add(tb);
        } else {            // player 1 just moved, retrieve previous a
            ta = dpPrev[nt][na][nb];
            aHistory.add(ta);
        }

        nt = tt;
        na = ta;
        nb = tb;
    }
}

