            }
            int aa = a[i];
            int v = lp[aa], u = 1;
            int cnt = 0;
            while (lp[aa] == v) {
                cnt++;
                aa /= lp[aa];
            }
            if (cnt % 2 == 0) v = 1;
            if (aa > 1) {
                u = lp[aa];
                cnt = 0;
                while (lp[aa] == u) {
                    cnt++;
                    aa /= lp[aa];
                }
                if (cnt % 2 == 0) u = 1;
            }
            g[ind[v]].add(ind[u]);
            g[ind[u]].add(ind[v]);
            set.add(v * u);
        }
        if (set.size() != n) {
            out.println(2);
            return;
        }

        int ans = INF;
