        q = new ArrayDeque<>();
        d = new int[m];
        p = new int[m];
        for (int i = 1; i <= sq; i++) {
            if (lp[i] != i) continue;
            for (int v = 0; v < m; v++) {
                d[v] = -1;
                p[v] = -1;
            }
            int v = ind[i];
            q.addLast(v);
            d[v] = 0;
            p[v] = v;
            while (!q.isEmpty()) {
                v = q.pollFirst();
                if (d[v] + 1 >= ans) {
                    q.clear();
                    break;
