                for (int u : g[v]) {
                    if (d[u] == -1) {
                        d[u] = d[v] + 1;
                        p[u] = v;
                        q.addLast(u);
                    } else if (p[v] != u) {
                        ans = Math.min(ans, d[v] + d[u] + 1);
                    }
                }
