 * @param n         total number of elements (used as an upper bound)
 * @param map1      reference to the first colour map (to be cleaned up)
 * @param map2      reference to the second colour map (to be cleaned up)
 * @param map3      reference to the third colour map (to be cleaned up)
 */
private static void processColor(TreeMap<Integer, Integer> targetMap,
                                 int[] cursor,
                                 int n,
                                 TreeMap<Integer, Integer> map1,
                                 TreeMap<Integer, Integer> map2,
                                 TreeMap<Integer, Integer> map3) {
    if (targetMap.size() > 0) {
        cursor[0]++; // move to the next possible index
        while (cursor[0] < n && !targetMap.containsKey(cursor[0])) {
            cursor[0]++;
        }
        System.out.print(targetMap.get(cursor[0]) + " ");
        // remove the consumed entry from every map so it cannot be used again
        map1.remove(cursor[0]);
        map2.remove(cursor[0]);
        map3.remove(cursor[0]);
    } else {
        System.out.print("-1 ");
    }
}

