/**
 * Computes how many pupils can be removed while preserving the required
 * friendship condition.
 *
 * @param p                 current permutation of pupils
 * @param index             current position of each pupil in {@code p}
 * @param nasFriends        list of friends of the last pupil, sorted by index
 * @param friendsNumber     mapping from pupil id to its position in {@code nasFriends}
 * @param nasFriendsFriends for each friend in {@code nasFriends}, the set of pupils they are directly connected to
 * @return the number of removable pupils
 */
private static int computeRemovals(
        int[] p,
        int[] index,
        List<Co> nasFriends,
        int[] friendsNumber,
        List<Set<Integer>> nasFriendsFriends) {

    int current = p.length - 1;   // position of the last still‑present pupil
    int ans = 0;

    for (Co ele : nasFriends) {
        int pup = ele.p;
        int pupIndex = index[pup];
        int num = friendsNumber[pup];

        boolean canRemove = true;
        // verify that every pupil between pupIndex+1 and current‑1 is a friend of {@code pup}
        for (int i = pupIndex + 1; i < current; i++) {
            int pupils = p[i];
            if (!nasFriendsFriends.get(num).contains(pupils)) {
                canRemove = false;
                break;
            }
        }

        if (canRemove) {
            // shift the segment left by one position
            for (int i = pupIndex + 1; i < current; i++) {
                int pupils = p[i];
                p[i - 1] = pupils;
                index[pupils]--;
            }
            ans++;
            current--;   // one pupil removed, shrink the active prefix
        }
    }
    return ans;
}

