/**
 * Evaluates every possible sub‑array of {@code a}, flips the bits in that
 * sub‑array, counts the number of 1's after the flip, and returns the maximum
 * count found. The original contents of {@code a} are restored after each
 * trial using the {@code original} snapshot.
 *
 * @param a        the mutable working array
 * @param original an unchanged copy of the original array
 * @return the greatest number of 1's obtainable by flipping one contiguous sub‑array
 */
private static int findBestFlip(int[] a, int[] original) {
    int n = a.length;
    int best = Integer.MIN_VALUE;

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            // flip bits in the range [i, j]
            for (int k = i; k <= j; k++) {
                a[k] = (a[k] == 0) ? 1 : 0;
            }

            // count 1's
            int sum = 0;
            for (int value : a) {
                if (value == 1) {
                    sum++;
                }
            }
            if (sum > best) {
                best = sum;
            }

            // restore original array for the next iteration
            System.arraycopy(original, 0, a, 0, n);
        }
    }

    return best;
}

