 * choose the nearer occurrence of each value.
 *
 * @param a the positions array, a[0][i] and a[1][i] store the two positions of value i
 * @param n the number of distinct values
 * @return the accumulated distance
 */
private static long computeGreedyDistance(int[][] a, int n) {
    int s = 1, d = 1;
    long ans = 0;
    for (int i = 1; i <= n; i++) {
        int tmp_s, dif_s, tmp_d, dif_d;
