/**
 * Simulates the journey for k > 1 and returns the minimal number of
 * additional refuels required, or -1 if the trip cannot be completed.
 */
private static int calculateRefuels(int a, int b, int f, int k) {
    int before = f;          // distance from start to the fuel station
    int after  = a - f;      // distance from fuel station to the finish

    // Not enough fuel to even reach the first station
    if (b < f) {
        return -1;
    }

    int cnt  = 0;                // number of extra refuels performed
    int fuel = b - f;            // fuel left after reaching the first station

    // Simulate the round‑trips between the station and the ends,
    // except for the final segment (handled after the loop)
    for (int i = 0; i < k - 1; i++) {
        if (fuel < 0) {
            return -1;
        }

        if (i % 2 == 0) { // moving from station to the far end (after segment)
            if (fuel >= 2 * after) {
                fuel -= 2 * after;
            } else {
                cnt++;
                fuel = b - 2 * after;
            }
        } else {          // moving from far end back to the station (before segment)
            if (fuel >= 2 * before) {
                fuel -= 2 * before;
            } else {
                cnt++;
                fuel = b - 2 * before;
            }
        }
    }

    // Handle the last partial segment
    if (k % 2 == 0) { // last move is towards the start (before segment)
        if (fuel >= before) {
            fuel -= before;
        } else {
            cnt++;
        }
    } else {          // last move is towards the finish (after segment)
        if (fuel >= after) {
            fuel -= after;
        } else {
            cnt++;
        }
    }

    // If fuel ever became negative, the trip is impossible
    return (fuel < 0) ? -1 : cnt;
}

