public static void kamehameha()
    {
        int n=sc.nextInt();
        int o=0,t=0;
        for(int x=0;x<n;x++)
        {
            int a=sc.nextInt();
            if(a==1)
            {
                o++;
            }
            else
            {
                t++;
            }
        }
        ArrayList<Integer> prime=spirit();
        int i=0;
        int[] b=new int[n];
        int sum=0;
        int x=0;
        while(x<n)
        {
            int d=0;
            while(d<=0)
            {
                d = prime.get(i) - sum;
                i++;
            }
            boolean enter=false;
            int c=0;
            while(d>=2&&t>0)
            {
                enter=true;
                b[x++]=2;
                t--;
                c+=2;
                d-=2;
                if(x==n)
                {
                    break;
                }
            }
            if(d==1&&x<n&&o>0)
            {
                c++;
                enter=true;
                b[x++]=1;
                d--;
                o--;
            }

            sum+=c;
            if(!enter)
            {
                break;
            }
        }
        while(o>0)
        {
            b[x++]=1;
            o--;
        }
        while(t>0)
        {
            b[x++]=2;
            t--;
        }
        for(x=0;x<n;x++)
        {
            out.print(b[x]+" ");
        }

    }

