 * visible edges according to the problem's geometric rules.
 *
 * @param p       the sorted unique points
 * @param connect the array built in the forward pass that stores the previous
 *                point index for each point
 * @return the computed answer
 */
private long computeAns(Point[] p, int[] connect) {
    int n = p.length;
    long ans = 0;
    Pair stack[] = new Pair[n];
    int ptr = 0;

    // initialise stack with the last point
    stack[ptr++] = new Pair(n - 1, -1);

    for (int i = n - 2; i >= 0; --i) {
        while (ptr >= 2) {
            if (orientation(p[stack[ptr - 2].ind],
                            p[stack[ptr - 1].ind],
                            p[i]) > 0)
