        }

        if (ptr == 1) {
            stack[ptr] = new Pair(i, 0);
            ptr++;
        } else {
            if (orientation(p[stack[ptr - 2].ind],
                            p[stack[ptr - 1].ind],
                            p[i]) == 0)
                stack[ptr] = new Pair(i, stack[ptr - 1].parStackInd);
            else
                stack[ptr] = new Pair(i, ptr - 1);
            ptr++;
        }

        // count according to the problem's condition
        if (!(ptr >= 3 &&
              orientation(p[stack[ptr - 3].ind],
                          p[stack[ptr - 2].ind],
                          p[stack[ptr - 1].ind]) == 0)) {
            if (connect[i] == -1) {
                ans++;
