/**
 * Draws the vertical pipes, the bottom line of '+' characters and the
 * horizontal '-' that belongs to each symbol in the input string.
 *
 * @param m    the drawing canvas
 * @param xy   stored x/y coordinates for each character
 * @param s    original bracket string
 * @param maxY maximum y reached while processing the string
 * @return the greatest row index that contains drawing data (height)
 */
private static int drawVerticalConnectorsAndBase(char[][] m, int[][] xy, String s, int maxY) {
    int height = 0;
    for (int i = 0; i < s.length(); i++) {
        int cx = xy[i][0];
        int cy = xy[i][1];
        int dist = maxY - cy;

        // vertical line from current position down to maxY
        for (int j = 1; j <= dist; j++) {
            m[cy + j][cx] = '|';
        }

        // vertical line just below maxY
        m[maxY + 1][cx] = '|';
        for (int j = 1; j <= dist; j++) {
            m[maxY + 1 + j][cx] = '|';
        }

        // bottom '+' and associated '-'
        m[maxY + dist + 2][cx] = '+';
        if (s.charAt(i) == '[') {
            m[maxY + dist + 2][cx + 1] = '-';
        } else {
            m[maxY + dist + 2][cx - 1] = '-';
        }

        height = Math.max(height, maxY + dist + 2);
    }
    return height;
}

