/**
 * Determines the dice value to output for a given pair (ue, mae)
 * based on the six dice numbers provided in {@code d}.
 *
 * @param ue  the upper die value of the query
 * @param mae the adjacent die value of the query
 * @param d   array containing the six dice numbers
 * @return the dice number that should be printed
 */
private static int resolve(int ue, int mae, int[] d) {
    if (ue == d[0]) {
        if (mae == d[1]) return d[2];
        if (mae == d[2]) return d[4];
        if (mae == d[3]) return d[1];
        if (mae == d[4]) return d[3];
    } else if (ue == d[1]) {
        if (mae == d[0]) return d[3];
        if (mae == d[2]) return d[0];
        if (mae == d[3]) return d[5];
        if (mae == d[5]) return d[2];
    } else if (ue == d[2]) {
        if (mae == d[0]) return d[1];
        if (mae == d[1]) return d[5];
        if (mae == d[4]) return d[0];
        if (mae == d[5]) return d[4];
    } else if (ue == d[3]) {
        if (mae == d[0]) return d[4];
        if (mae == d[1]) return d[0];
        if (mae == d[4]) return d[5];
        if (mae == d[5]) return d[1];
    } else if (ue == d[4]) {
        if (mae == d[0]) return d[2];
