/**
 * Executes Dijkstra's algorithm for a single source node and fills the
 * {@code dist}, {@code index} and {@code list} structures for that source.
 *
 * @param srcIdx   the index (0 or 1) identifying which row of the 2‑dimensional
 *                 arrays to populate
 * @param srcNode  the graph vertex that is the source of the shortest‑path search
 * @param edges    adjacency list of the undirected weighted graph
 * @param dist     matrix storing shortest distances; {@code dist[srcIdx]} will be filled
 * @param index    matrix storing the order in which vertices are settled; {@code index[srcIdx]}
 *                 will be filled
 * @param list     matrix holding the vertex order corresponding to {@code index};
 *                 {@code list[srcIdx]} will be filled
 */
private void runDijkstra(int srcIdx, int srcNode, ArrayList<Edge>[] edges,
                         long[][] dist, int[][] index, int[][] list) {
    PriorityQueue<State> q = new PriorityQueue<>();
    Arrays.fill(dist[srcIdx], oo);
    dist[srcIdx][srcNode] = 0;
    q.offer(new State(srcNode, 0));

    int counter = 0;
    while (!q.isEmpty()) {
        State cur = q.poll();
        if (dist[srcIdx][cur.pos] < cur.dist)
            continue;
        index[srcIdx][cur.pos] = counter++;
        list[srcIdx][index[srcIdx][cur.pos]] = cur.pos;
        for (Edge e : edges[cur.pos]) {
            long nd = dist[srcIdx][cur.pos] + e.dist;
            if (dist[srcIdx][e.dest] > nd) {
                dist[srcIdx][e.dest] = nd;
                q.offer(new State(e.dest, nd));
            }
        }
    }
}

