/**
 * Builds an array of {@link Pair} objects that hold the original index and the price,
 * then sorts it first by price (ascending) and, for equal prices, by index (ascending).
 */
private static Pair[] buildSortedPairs(long[] price, int n) {
    Pair[] pair = new Pair[n];
    for (int i = 0; i < n; i++) {
        pair[i] = new Pair(i, price[i]);
    }
    Arrays.sort(pair, new Pair.First().thenComparing(new Pair.Second()));
    return pair;
}

/**
 * Executes a single purchase request.
 *
 * @param productIdx index of the requested product (0‑based)
 * @param needed     number of items the customer wants
 * @param a          remaining stock for each product (mutated)
 * @param c          price per item for each product (immutable)
 * @param pair       sorted array that yields the cheapest available product
 * @param nextIdx    single‑element array holding the current start position in {@code pair}
 * @return total cost of the order, or 0 if the order cannot be completely satisfied
 */
private static long processOrder(int productIdx,
                                 int needed,
                                 long[] a,
                                 long[] c,
                                 Pair[] pair,
                                 int[] nextIdx) {
    // take from the requested product first
    long take = Math.min(a[productIdx], needed);
    needed -= take;
    a[productIdx] -= take;
    long cost = take * c[productIdx];

    // if more items are needed, take from the cheapest remaining products
    while (nextIdx[0] < pair.length && needed > 0) {
        int curIdx = pair[nextIdx[0]].index;
        long takeFromCur = Math.min(a[curIdx], needed);
        cost += takeFromCur * c[curIdx];
        needed -= takeFromCur;
        a[curIdx] -= takeFromCur;
        if (a[curIdx] == 0) {
            nextIdx[0]++; // move pointer forward once stock is depleted
        }
    }

    // guard clause – order cannot be fulfilled
    if (needed > 0) {
        return 0L;
    }
    return cost;
}

