/** Reads a line containing *n* long values and returns them as an array. */
private static Long[] readLongArray(BufferedReader br, int n) throws IOException {
    Long[] arr = new Long[n];
    StringTokenizer st = new StringTokenizer(br.readLine());
    for (int i = 0; i < n; i++) {
        arr[i] = Long.parseLong(st.nextToken());
    }
    return arr;
}

/** Builds the Pair[] (index, price) array and sorts it by price then index. */
private static Pair[] initializePairs(Long[] price, int n) {
    Pair[] pair = new Pair[n];
    for (int i = 0; i < n; i++) {
        pair[i] = new Pair(i, price[i]);
    }
    Arrays.sort(pair, new Pair.First().thenComparing(new Pair.Second()));
    return pair;
}

/**
 * Tries to satisfy a single order.
 *
 * @param idx            index of the requested product (0‑based)
 * @param needed         amount the customer wants
 * @param stock          current stock for each product
 * @param price          price per unit for each product
 * @param pair           sorted array of products by price
 * @param nextAvailable  mutable pointer to the first product with stock > 0
 * @return total cost if the order can be fulfilled; otherwise 0
 */
private static long processOrder(int idx, int needed, Long[] stock, Long[] price,
                                 Pair[] pair, int[] nextAvailable) {
    long take = Math.min(stock[idx], (long) needed);
    needed -= take;
    stock[idx] -= take;
    long cost = take * price[idx];

    while (nextAvailable[0] < pair.length && needed > 0) {
        int cur = pair[nextAvailable[0]].index;
        take = Math.min(stock[cur], (long) needed);
        cost += take * price[cur];
        needed -= take;
        stock[cur] -= take;
        if (stock[cur] == 0) {
            nextAvailable[0]++;               // move to next product with stock
        }
    }

    // Guard clause – if we still need items, the order cannot be satisfied.
    if (needed > 0) {
        return 0L;
    }
    return cost;
}

