private boolean createsTriangle(int x, int y, boolean[][] board, int rows, int cols) {
    // top‑left corner
    if (x - 1 > 0 && y - 1 > 0) {
        if (board[x - 1][y - 1] && board[x - 1][y] && board[x][y - 1]) {
            return true;
        }
    }

    // bottom‑left corner
    if (x + 1 <= rows && y - 1 > 0) {
        if (board[x + 1][y] && board[x][y - 1] && board[x + 1][y - 1]) {
            return true;
        }
