private boolean hasCompletedSquare(int x, int y, boolean[][] point, int n, int m) {
    boolean tr = false;

    // top‑left square
    if (x - 1 > 0 && y - 1 > 0) {
        tr |= point[x - 1][y - 1] && point[x - 1][y] && point[x][y - 1];
    }

    // bottom‑left square
    if (x + 1 <= n && y - 1 > 0) {
        tr |= point[x + 1][y] && point[x][y - 1] && point[x + 1][y - 1];
    }

    // bottom‑right square
    if (x + 1 <= n && y + 1 <= m) {
        tr |= point[x + 1][y] && point[x + 1][y + 1] && point[x][y + 1];
    }

    // top‑right square
    if (x - 1 > 0 && y + 1 <= m) {
        tr |= point[x][y + 1] && point[x - 1][y + 1] && point[x - 1][y];
    }

    return tr;
}

public void solve(int testNumber, InputReader in, PrintWriter out) {
    boolean[][] point = new boolean[1001][1001];
    int n = in.nextInt();
    int m = in.nextInt();
    int k = in.nextInt();

    for (int i = 0; i < k; i++) {
        int x = in.nextInt();
        int y = in.nextInt();

        if (formsTriangle(x, y, point, n, m)) {
            out.print(i + 1);
            return;                 // guard clause – early exit when condition met
        }

        point[x][y] = true;          // record the new point after the check
    }

    out.print(0);                    // no triangle was formed
}

/**
 * Returns true if adding a point at (x, y) creates a 2×2 block with three
 * already‑present points (i.e., any of the four L‑shaped configurations).
 */
private boolean formsTriangle(int x, int y, boolean[][] grid, int maxX, int maxY) {
    // top‑left L
    if (x > 1 && y > 1) {
        if (grid[x - 1][y - 1] && grid[x - 1][y] && grid[x][y - 1]) {
            return true;
        }
    }
    // bottom‑left L
    if (x < maxX && y > 1) {
        if (grid[x + 1][y] && grid[x][y - 1] && grid[x + 1][y - 1]) {
            return true;
        }
    }
    // bottom‑right L
    if (x < maxX && y < maxY) {
        if (grid[x + 1][y] && grid[x + 1][y + 1] && grid[x][y + 1]) {
            return true;
        }
    }
    // top‑right L
    if (x > 1 && y < maxY) {
        if (grid[x][y + 1] && grid[x - 1][y + 1] && grid[x - 1][y]) {
            return true;
        }
    }
    return false;
}

