    BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
    String[] stringNumbers = reader.readLine().split(" ");
    Integer n = Integer.valueOf(stringNumbers[0]);
    Integer p = Integer.valueOf(stringNumbers[1]);

    int[] nonPalindromeIntegerArray = getIntegerArray(reader.readLine().toCharArray());
    int[] arrayClone = nonPalindromeIntegerArray.clone();
    Boolean flag = false;

    for (int i = nonPalindromeIntegerArray.length - 1; i >= 0; i--) {
        for (int j = arrayClone[i] + 1; j < p; j++) {
            if (isAllowedAt(i, j, arrayClone)) {
                arrayClone[i] = j;
                flag = true;
                break;
            }
        }
        if (flag) {
            for (int j = i + 1; j < arrayClone.length; j++) {
                // assume the position will be filled; reset flag for this iteration
                flag = true;
                if (hasForbiddenNeighbour(j, arrayClone)) {
                    flag = false;
                }
                for (int k = 0; k < 26; k++) {
                    if (canPlace(j, k, arrayClone)) {
                        flag = true;
                        arrayClone[j] = k;
                        break;
                    }
                }
                if (!flag) {
                    break;
                }
            }
            if (flag) {
                break;
            }
        }
    }

    if (flag) {
        for (int i : arrayClone) {
            System.out.print((char) (i + (int) 'a'));
        }
        System.out.println();
    } else {
        System.out.println("NO");
    }
}

/**
 * Returns true if putting {@code value} at {@code index} does NOT create a
 * conflict with the previous one or the one‑before‑previous element.
 */
private static boolean isAllowedAt(int index, int value, int[] arr) {
    return !(index > 0 && arr[index - 1] == value) && !(index > 1 && arr[index - 2] == value);
}

/**
 * Returns true when the element at {@code index} repeats the immediate
 * predecessor or the element two positions before (i.e. the current state is invalid).
 */
private static boolean hasForbiddenNeighbour(int index, int[] arr) {
    return (index >= 1 && arr[index - 1] == arr[index]) ||
           (index >= 2 && arr[index - 2] == arr[index]);
}

/**
 * Alias for {@link #isAllowedAt(int, int, int[])} used when we are trying
 * candidate values while filling the remainder of the array.
 */
private static boolean canPlace(int index, int candidate, int[] arr) {
    return isAllowedAt(index, candidate, arr);
}

