/** Builds the map of skill groups and fills each list with its values. */
private LinkedHashMap<Integer, Skills> loadSkills(int n, int m, InputReader in) {
    LinkedHashMap<Integer, Skills> skills = new LinkedHashMap<>();
    for (int i = 0; i < m; i++) {
        skills.put(i, new Skills());
    }

    for (int i = 0; i < n; i++) {
        int skillIdx = in.nextInt() - 1;   // 0‑based index
        int value    = in.nextInt();
        skills.get(skillIdx).al.add(value);
    }

    // prepare prefix sums for each skill group
    for (Skills s : skills.values()) {
        s.calcPrefixSum();
    }
    return skills;
}

/** Returns the largest size among all skill groups. */
private int computeMaxSkill(LinkedHashMap<Integer, Skills> skills) {
    int max = 0;
    for (Skills s : skills.values()) {
        max = Math.max(s.al.size(), max);
    }
    return max;
}

/** Evaluates every possible team size (1 … maxSkill) and returns the best total. */
private long computeBestTotal(LinkedHashMap<Integer, Skills> skills, int maxSkill) {
    long best = 0L;

    // we work on a mutable copy because we will delete entries that become non‑positive
    LinkedHashMap<Integer, Skills> mutable = new LinkedHashMap<>(skills);

    for (int teamSize = 1; teamSize <= maxSkill; teamSize++) {
        long currentTotal = 0L;
        Iterator<Map.Entry<Integer, Skills>> it = mutable.entrySet().iterator();

        while (it.hasNext()) {
            Map.Entry<Integer, Skills> entry = it.next();
            long sum = entry.getValue().getSum(teamSize);
            if (sum > 0) {
                currentTotal += sum;
            } else {
                it.remove(); // guard clause: discard skill groups that cannot contribute
            }
        }
        best = Math.max(best, currentTotal);
        if (mutable.isEmpty()) {
            break; // no more groups can contribute; further iterations are useless
        }
    }
    return best;
}

