/**
 * Reads the input and builds the map of skill groups.
 * Each group is identified by its index (0‑based) and stores the list of skill values.
 */
private LinkedHashMap<Integer, Skills> readSkills(InputReader in, int n, int m) {
    LinkedHashMap<Integer, Skills> skills = new LinkedHashMap<>();
    for (int i = 0; i < m; i++) {
        skills.put(i, new Skills());
    }

    for (int i = 0; i < n; i++) {
        int groupIdx = in.nextInt() - 1;   // convert to 0‑based
        int value = in.nextInt();
        skills.get(groupIdx).al.add(value);
    }
    return skills;
}

/**
 * Calculates the maximum possible team size across all groups.
 * While doing so, each group's prefix sums are prepared.
 */
private int computeMaxSkill(LinkedHashMap<Integer, Skills> skills) {
    int maxSkill = 0;
    for (Skills s : skills.values()) {
        s.calcPrefixSum();                      // prepares prefix sums
        maxSkill = Math.max(s.al.size(), maxSkill);
    }
    return maxSkill;
}

/**
 * For every team size from 1 to maxSkill, computes the total contribution
 * of groups that have a positive sum for that size.
 * Groups that become non‑positive are removed from the map to avoid future work.
 */
private long computeBestTotal(LinkedHashMap<Integer, Skills> skills, int maxSkill) {
    long bestTotal = 0L;

    for (int size = 1; size <= maxSkill; size++) {
        long currentTotal = 0L;
        List<Integer> toRemove = new ArrayList<>();

        for (Map.Entry<Integer, Skills> entry : skills.entrySet()) {
            long sum = entry.getValue().getSum(size);

            if (sum <= 0) {               // guard clause – nothing to add from this group
                toRemove.add(entry.getKey());
                continue;
            }
            currentTotal += sum;
        }

        // Remove groups that can no longer contribute for larger sizes
        for (Integer key : toRemove) {
            skills.remove(key);
        }

        bestTotal = Math.max(bestTotal, currentTotal);
    }
    return bestTotal;
}

public void solve(int testNumber, InputReader in, OutputWriter out) {
    int n = in.nextInt();
    int m = in.nextInt();

    Map<Integer, Skills> skills = initSkills(m);
    fillSkills(skills, n, in);
    int maxSkillSize = computeMaxSkillSize(skills);

    long bestTotal = 0;
    for (int teamSize = 1; teamSize <= maxSkillSize; teamSize++) {
        long currentTotal = accumulatePositiveSums(teamSize, skills);
        bestTotal = Math.max(bestTotal, currentTotal);
    }

    out.println(bestTotal <= 0 ? 0 : bestTotal);
}

/* ------------------------------------------------------------------ */
/* Helper methods – each performs one cohesive task                     */
/* ------------------------------------------------------------------ */

private Map<Integer, Skills> initSkills(int m) {
    Map<Integer, Skills> map = new LinkedHashMap<>();
    for (int i = 0; i < m; i++) {
        map.put(i, new Skills());
    }
    return map;
}

private void fillSkills(Map<Integer, Skills> skills, int n, InputReader in) {
    for (int i = 0; i < n; i++) {
        int groupId = in.nextInt() - 1;   // groups are 1‑based in the input
        int value   = in.nextInt();
        skills.get(groupId).al.add(value);
    }
}

private int computeMaxSkillSize(Map<Integer, Skills> skills) {
    int max = 0;
    for (Skills s : skills.values()) {
        s.calcPrefixSum();                 // prepares prefix sums inside Skills
        max = Math.max(s.al.size(), max);  // longest list determines loop bound
    }
    return max;
}

/**
 * For a given team size, adds up all positive contribution sums.
 * Removes a skill entry from the map if its contribution is ≤ 0
 * (guard clause performed during iteration).
 */
private long accumulatePositiveSums(int teamSize, Map<Integer, Skills> skills) {
    long total = 0;
    Iterator<Map.Entry<Integer, Skills>> it = skills.entrySet().iterator();
    while (it.hasNext()) {
        Map.Entry<Integer, Skills> entry = it.next();
        long sum = entry.getValue().getSum(teamSize);
        if (sum > 0) {
            total += sum;
        } else {
            // Guard clause: non‑positive contribution ⇒ discard this group
            it.remove();
        }
    }
    return total;
}

