import java.util.Arrays;

public static void main(String[] args) throws Exception {
    FastReader sc = new FastReader();

    int n = sc.nextInt();

    int[] a = new int[n];
    int[] b = new int[n];
    int[] ans = new int[n];
    int[] index = new int[200_001];

    Arrays.fill(ans, 0);
    Arrays.fill(index, 0);

    readFirstArray(sc, a, index);
    readSecondArray(sc, b);
    computeAnswers(a, b, index, ans);
    printAnswers(ans);
}

/* reads array `a` and fills the position‑lookup table `index` */
private static void readFirstArray(FastReader sc, int[] a, int[] index) {
    for (int i = 0; i < a.length; i++) {
        a[i] = sc.nextInt();
        // store the position of value a[i] (values are 1‑based)
        index[a[i] - 1] = i;
    }
}

/* reads array `b` */
private static void readSecondArray(FastReader sc, int[] b) {
    for (int i = 0; i < b.length; i++) {
        b[i] = sc.nextInt();
    }
}

/* core algorithm – fills `ans` based on the relationship between `a` and `b` */
private static void computeAnswers(int[] a, int[] b, int[] index, int[] ans) {
    int min = 0;
    int max = a.length - 1;               // retained for semantic parity

    for (int i = 0; i < b.length; i++) {
        int curr = index[b[i] - 1];

        // guard clause – value out of the allowed window
        if (curr < min || curr > max) {
            ans[i] = 0;
            continue;
        }

        ans[i] = curr - min + 1;
        min = curr + 1;
    }
}

/* prints the answer array on a single line */
private static void printAnswers(int[] ans) {
    for (int value : ans) {
        System.out.print(value + " ");
    }
    System.out.println();
}

