public static void solve() {
    InputReader in = new InputReader(System.in);
    PrintWriter w = new PrintWriter(System.out);
    String str = in.nextLine();

    int[] counts = countLetters(str);
    applySpecialRules(counts);
    int result = smallestCount(counts);

    w.println(result);
    w.close();
}

/**
 * Counts the occurrences of the characters that matter for the problem.
 * The order of indices is: B, u, l, b, a, s, r.
 */
private static int[] countLetters(String s) {
    int[] map = new int[7];
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        switch (c) {
            case 'B': map[0]++; break;
            case 'u': map[1]++; break;
            case 'l': map[2]++; break;
            case 'b': map[3]++; break;
            case 'a': map[4]++; break;
            case 's': map[5]++; break;
            case 'r': map[6]++; break;
            default:  // ignore any other character
        }
    }
    return map;
}

/**
 * Applies the problem‑specific rule that the counts for 'u' and 'a'
 * should be halved (integer division).
 */
private static void applySpecialRules(int[] counts) {
    counts[1] = counts[1] / 2; // 'u'
    counts[4] = counts[4] / 2; // 'a'
}

/**
 * Returns the smallest count after sorting the array.
 * A copy is sorted to keep the original ordering untouched.
 */
private static int smallestCount(int[] counts) {
    int[] copy = counts.clone();
    Arrays.sort(copy);
    return copy[0];
}

